@@ -0,0 +1,531 @@
+#!/usr/bin/env npx ts-node
+/**
+ * E-Menum End-to-End Flow Verification Script
+ *
+ * This script performs a complete verification of the application flow:
+ * 1. User Registration
+ * 2. Login & Authentication
+ * 3. Organization Creation
+ * 4. Menu Creation with Categories and Products
+ * 5. Menu Publishing
+ * 6. Order Placement
+ * 7. Order Status Workflow
+ * 8. Final Verification
+ *
+ * Usage:
+ *   npx ts-node scripts/verify-e2e-flow.ts
+ *   npm run verify:e2e
+ *
+ * Prerequisites:
+ *   - Application running at http://localhost:3000
+ *   - PostgreSQL with migrations applied
+ *   - Redis running
+ *
+ * Environment Variables:
+ *   - API_BASE_URL: Base URL for the API (default: http://localhost:3000)
+ */
+
+/* eslint-disable no-console */
+
+const BASE_URL = process.env.API_BASE_URL || 'http://localhost:3000';
+
+// Color codes for terminal output
+const colors = {
+  reset: '\x1b[0m',
+  green: '\x1b[32m',
+  red: '\x1b[31m',
+  yellow: '\x1b[33m',
+  blue: '\x1b[34m',
+  cyan: '\x1b[36m',
+  bold: '\x1b[1m',
+};
+
+// Helper functions for logging
+function log(message: string): void {
+  console.log(message);
+}
+
+function success(message: string): void {
+  console.log(`${colors.green}✓ ${message}${colors.reset}`);
+}
+
+function error(message: string): void {
+  console.log(`${colors.red}✗ ${message}${colors.reset}`);
+}
+
+function info(message: string): void {
+  console.log(`${colors.cyan}ℹ ${message}${colors.reset}`);
+}
+
+function header(message: string): void {
+  console.log(`\n${colors.bold}${colors.blue}═══════════════════════════════════════${colors.reset}`);
+  console.log(`${colors.bold}${colors.blue}  ${message}${colors.reset}`);
+  console.log(`${colors.bold}${colors.blue}═══════════════════════════════════════${colors.reset}\n`);
+}
+
+function subheader(message: string): void {
+  console.log(`\n${colors.yellow}── ${message} ──${colors.reset}\n`);
+}
+
+// API helper
+async function api(method: string, path: string, options: {
+  body?: Record<string, unknown>;
+  token?: string;
+  orgId?: string;
+} = {}): Promise<{ status: number; body: Record<string, unknown> }> {
+  const headers: Record<string, string> = {
+    'Content-Type': 'application/json',
+  };
+
+  if (options.token) {
+    headers['Authorization'] = `Bearer ${options.token}`;
+  }
+
+  if (options.orgId) {
+    headers['X-Organization-Id'] = options.orgId;
+  }
+
+  const response = await fetch(`${BASE_URL}${path}`, {
+    method,
+    headers,
+    body: options.body ? JSON.stringify(options.body) : undefined,
+  });
+
+  let body: Record<string, unknown> = {};
+  const contentType = response.headers.get('content-type');
+  if (contentType && contentType.includes('application/json')) {
+    body = await response.json() as Record<string, unknown>;
+  }
+
+  return { status: response.status, body };
+}
+
+// Test context
+interface TestContext {
+  email: string;
+  password: string;
+  accessToken: string;
+  userId: string;
+  organizationId: string;
+  menuId: string;
+  categoryId: string;
+  productId: string;
+  tableId: string;
+  orderId: string;
+  orderNumber: string;
+  startTime: number;
+}
+
+// Generate unique test data
+function generateTestData(): { email: string; password: string; orgName: string } {
+  const timestamp = Date.now();
+  return {
+    email: `e2e.verify.${timestamp}@example.com`,
+    password: 'VerifyTest123!',
+    orgName: `Verify Org ${timestamp}`,
+  };
+}
+
+// Main verification function
+async function runVerification(): Promise<void> {
+  const testData = generateTestData();
+  const ctx: TestContext = {
+    email: testData.email,
+    password: testData.password,
+    accessToken: '',
+    userId: '',
+    organizationId: '',
+    menuId: '',
+    categoryId: '',
+    productId: '',
+    tableId: '',
+    orderId: '',
+    orderNumber: '',
+    startTime: Date.now(),
+  };
+
+  let stepCount = 0;
+  let successCount = 0;
+  let failureCount = 0;
+
+  function step(name: string): void {
+    stepCount++;
+    info(`Step ${stepCount}: ${name}`);
+  }
+
+  header('E-Menum E2E Flow Verification');
+  info(`Base URL: ${BASE_URL}`);
+  info(`Test Email: ${testData.email}`);
+  info(`Test Organization: ${testData.orgName}`);
+
+  try {
+    // ─────────────────────────────────────────────────────────────────────────
+    // Phase 1: Authentication
+    // ─────────────────────────────────────────────────────────────────────────
+    subheader('Phase 1: Authentication');
+
+    // Step 1: Register
+    step('Register new user');
+    const registerRes = await api('POST', '/api/v1/auth/register', {
+      body: {
+        email: testData.email,
+        password: testData.password,
+        passwordConfirm: testData.password,
+        firstName: 'E2E',
+        lastName: 'Verify',
+        acceptTerms: true,
+      },
+    });
+
+    if (registerRes.status === 201 && (registerRes.body as Record<string, unknown>).success) {
+      ctx.userId = ((registerRes.body as Record<string, { userId: string }>).data).userId;
+      success(`User registered: ${ctx.userId}`);
+      successCount++;
+    } else {
+      error(`Registration failed: ${JSON.stringify(registerRes.body)}`);
+      failureCount++;
+    }
+
+    // Step 2: Login
+    step('Login with credentials');
+    const loginRes = await api('POST', '/api/v1/auth/login', {
+      body: {
+        email: testData.email,
+        password: testData.password,
+        rememberMe: true,
+      },
+    });
+
+    if (loginRes.status === 200 && (loginRes.body as Record<string, unknown>).success) {
+      const data = (loginRes.body as Record<string, { tokens: { accessToken: string }; user: { id: string } }>).data;
+      ctx.accessToken = data.tokens.accessToken;
+      ctx.userId = data.user.id;
+      success(`Login successful, token received`);
+      successCount++;
+    } else {
+      error(`Login failed: ${JSON.stringify(loginRes.body)}`);
+      failureCount++;
+      throw new Error('Cannot continue without login');
+    }
+
+    // Step 3: Get current user
+    step('Verify current user profile');
+    const meRes = await api('GET', '/api/v1/auth/me', { token: ctx.accessToken });
+
+    if (meRes.status === 200 && (meRes.body as Record<string, unknown>).success) {
+      success(`Profile verified: ${((meRes.body as Record<string, { email: string }>).data).email}`);
+      successCount++;
+    } else {
+      error(`Profile verification failed`);
+      failureCount++;
+    }
+
+    // ─────────────────────────────────────────────────────────────────────────
+    // Phase 2: Organization
+    // ─────────────────────────────────────────────────────────────────────────
+    subheader('Phase 2: Organization Creation');
+
+    // Step 4: Create organization
+    step('Create organization');
+    const orgRes = await api('POST', '/api/v1/organizations', {
+      token: ctx.accessToken,
+      body: {
+        name: testData.orgName,
+        email: `org.${testData.email}`,
+        phone: '+90 555 999 8888',
+        address: 'Verification Street, Istanbul',
+        description: 'E2E Verification Organization',
+      },
+    });
+
+    if (orgRes.status === 201 && (orgRes.body as Record<string, unknown>).success) {
+      ctx.organizationId = ((orgRes.body as Record<string, { organization: { id: string } }>).data).organization.id;
+      success(`Organization created: ${ctx.organizationId}`);
+      successCount++;
+    } else {
+      error(`Organization creation failed: ${JSON.stringify(orgRes.body)}`);
+      failureCount++;
+      throw new Error('Cannot continue without organization');
+    }
+
+    // ─────────────────────────────────────────────────────────────────────────
+    // Phase 3: Menu Creation
+    // ─────────────────────────────────────────────────────────────────────────
+    subheader('Phase 3: Menu Creation');
+
+    // Step 5: Create menu
+    step('Create menu');
+    const menuRes = await api('POST', '/api/v1/menus', {
+      token: ctx.accessToken,
+      orgId: ctx.organizationId,
+      body: {
+        name: 'Verification Menu',
+        description: 'Menu for E2E verification',
+        settings: {
+          showPrices: true,
+          enableOrdering: true,
+          showAllergens: true,
+        },
+      },
+    });
+
+    if (menuRes.status === 201 && (menuRes.body as Record<string, unknown>).success) {
+      ctx.menuId = ((menuRes.body as Record<string, { menu: { id: string } }>).data).menu.id;
+      success(`Menu created: ${ctx.menuId}`);
+      successCount++;
+    } else {
+      error(`Menu creation failed: ${JSON.stringify(menuRes.body)}`);
+      failureCount++;
+      throw new Error('Cannot continue without menu');
+    }
+
+    // Step 6: Create category
+    step('Create category');
+    const catRes = await api('POST', '/api/v1/categories', {
+      token: ctx.accessToken,
+      orgId: ctx.organizationId,
+      body: {
+        menuId: ctx.menuId,
+        name: 'Main Dishes',
+        description: 'Our signature dishes',
+      },
+    });
+
+    if (catRes.status === 201 && (catRes.body as Record<string, unknown>).success) {
+      ctx.categoryId = ((catRes.body as Record<string, { category: { id: string } }>).data).category.id;
+      success(`Category created: ${ctx.categoryId}`);
+      successCount++;
+    } else {
+      error(`Category creation failed: ${JSON.stringify(catRes.body)}`);
+      failureCount++;
+      throw new Error('Cannot continue without category');
+    }
+
+    // Step 7: Create product
+    step('Create product with variants and modifiers');
+    const prodRes = await api('POST', '/api/v1/products', {
+      token: ctx.accessToken,
+      orgId: ctx.organizationId,
+      body: {
+        categoryId: ctx.categoryId,
+        name: 'Signature Burger',
+        description: 'Our famous signature burger',
+        basePrice: 175.00,
+        isActive: true,
+        isAvailable: true,
+        variants: [
+          { name: 'Regular', price: 175.00, isActive: true },
+          { name: 'Double', price: 250.00, isActive: true },
+        ],
+        modifiers: [
+          { name: 'Extra Cheese', price: 25.00, isActive: true },
+          { name: 'Jalapeño', price: 15.00, isActive: true },
+        ],
+      },
+    });
+
+    if (prodRes.status === 201 && (prodRes.body as Record<string, unknown>).success) {
+      ctx.productId = ((prodRes.body as Record<string, { product: { id: string } }>).data).product.id;
+      success(`Product created: ${ctx.productId}`);
+      successCount++;
+    } else {
+      error(`Product creation failed: ${JSON.stringify(prodRes.body)}`);
+      failureCount++;
+      throw new Error('Cannot continue without product');
+    }
+
+    // ─────────────────────────────────────────────────────────────────────────
+    // Phase 4: Menu Publishing
+    // ─────────────────────────────────────────────────────────────────────────
+    subheader('Phase 4: Menu Publishing');
+
+    // Step 8: Publish menu
+    step('Publish menu with QR code generation');
+    const publishRes = await api('POST', `/api/v1/menus/${ctx.menuId}/publish`, {
+      token: ctx.accessToken,
+      orgId: ctx.organizationId,
+      body: {
+        generateQrCode: true,
+      },
+    });
+
+    if (publishRes.status === 200 && (publishRes.body as Record<string, unknown>).success) {
+      success(`Menu published successfully`);
+      successCount++;
+    } else {
+      error(`Menu publishing failed: ${JSON.stringify(publishRes.body)}`);
+      failureCount++;
+    }
+
+    // ─────────────────────────────────────────────────────────────────────────
+    // Phase 5: Order Placement
+    // ─────────────────────────────────────────────────────────────────────────
+    subheader('Phase 5: Order Placement');
+
+    // Step 9: Create order
+    step('Place order');
+    const orderRes = await api('POST', '/api/v1/orders', {
+      token: ctx.accessToken,
+      orgId: ctx.organizationId,
+      body: {
+        type: 'DINE_IN',
+        items: [
+          {
+            productId: ctx.productId,
+            quantity: 2,
+            notes: 'Well done please',
+          },
+        ],
+        notes: 'E2E Verification Order',
+      },
+    });
+
+    if (orderRes.status === 201 && (orderRes.body as Record<string, unknown>).success) {
+      const orderData = (orderRes.body as Record<string, { order: { id: string; orderNumber: string } }>).data;
+      ctx.orderId = orderData.order.id;
+      ctx.orderNumber = orderData.order.orderNumber;
+      success(`Order placed: ${ctx.orderNumber} (${ctx.orderId})`);
+      successCount++;
+    } else {
+      error(`Order creation failed: ${JSON.stringify(orderRes.body)}`);
+      failureCount++;
+      throw new Error('Cannot continue without order');
+    }
+
+    // ─────────────────────────────────────────────────────────────────────────
+    // Phase 6: Order Status Workflow
+    // ─────────────────────────────────────────────────────────────────────────
+    subheader('Phase 6: Order Status Workflow');
+
+    const statusTransitions = [
+      { action: 'confirm', expectedStatus: 'CONFIRMED' },
+      { action: 'prepare', expectedStatus: 'PREPARING' },
+      { action: 'ready', expectedStatus: 'READY' },
+      { action: 'deliver', expectedStatus: 'DELIVERED' },
+      { action: 'complete', expectedStatus: 'COMPLETED' },
+    ];
+
+    for (const transition of statusTransitions) {
+      step(`${transition.action} order → ${transition.expectedStatus}`);
+      const statusRes = await api('POST', `/api/v1/orders/${ctx.orderId}/${transition.action}`, {
+        token: ctx.accessToken,
+        orgId: ctx.organizationId,
+      });
+
+      if (statusRes.status === 200 && (statusRes.body as Record<string, unknown>).success) {
+        const order = ((statusRes.body as Record<string, { order: { status: string } }>).data).order;
+        if (order.status === transition.expectedStatus) {
+          success(`Order status: ${transition.expectedStatus}`);
+          successCount++;
+        } else {
+          error(`Expected ${transition.expectedStatus}, got ${order.status}`);
+          failureCount++;
+        }
+      } else {
+        error(`Status change failed: ${JSON.stringify(statusRes.body)}`);
+        failureCount++;
+      }
+    }
+
+    // ─────────────────────────────────────────────────────────────────────────
+    // Phase 7: Final Verification
+    // ─────────────────────────────────────────────────────────────────────────
+    subheader('Phase 7: Final Verification');
+
+    // Step: Verify order in list
+    step('Verify order appears in order list');
+    const listRes = await api('GET', '/api/v1/orders?page=1&perPage=10', {
+      token: ctx.accessToken,
+      orgId: ctx.organizationId,
+    });
+
+    if (listRes.status === 200 && (listRes.body as Record<string, unknown>).success) {
+      const orders = (listRes.body as Record<string, Array<{ id: string }>>).data;
+      const found = orders.find((o) => o.id === ctx.orderId);
+      if (found) {
+        success(`Order found in list: ${ctx.orderId}`);
+        successCount++;
+      } else {
+        error(`Order not found in list`);
+        failureCount++;
+      }
+    } else {
+      error(`Order list failed`);
+      failureCount++;
+    }
+
+    // Step: Get order statistics
+    step('Verify order statistics');
+    const statsRes = await api('GET', '/api/v1/orders/statistics', {
+      token: ctx.accessToken,
+      orgId: ctx.organizationId,
+    });
+
+    if (statsRes.status === 200 && (statsRes.body as Record<string, unknown>).success) {
+      success(`Order statistics retrieved`);
+      successCount++;
+    } else {
+      error(`Statistics failed`);
+      failureCount++;
+    }
+
+    // ─────────────────────────────────────────────────────────────────────────
+    // Phase 8: Cleanup & Summary
+    // ─────────────────────────────────────────────────────────────────────────
+    subheader('Phase 8: Cleanup');
+
+    // Logout
+    step('Logout');
+    const logoutRes = await api('POST', '/api/v1/auth/logout', {
+      token: ctx.accessToken,
+      body: {},
+    });
+
+    if (logoutRes.status === 204) {
+      success(`Logged out successfully`);
+      successCount++;
+    } else {
+      error(`Logout failed`);
+      failureCount++;
+    }
+
+  } catch (err) {
+    error(`Verification failed with error: ${(err as Error).message}`);
+    failureCount++;
+  }
+
+  // ─────────────────────────────────────────────────────────────────────────
+  // Summary
+  // ─────────────────────────────────────────────────────────────────────────
+  const duration = ((Date.now() - ctx.startTime) / 1000).toFixed(2);
+
+  header('Verification Summary');
+  log(`Total Steps: ${stepCount}`);
+  log(`${colors.green}Passed: ${successCount}${colors.reset}`);
+  log(`${colors.red}Failed: ${failureCount}${colors.reset}`);
+  log(`Duration: ${duration}s`);
+  log('');
+
+  if (failureCount === 0) {
+    success('All verification steps passed! ✨');
+    log('');
+    log('Test Data Created:');
+    log(`  User ID: ${ctx.userId}`);
+    log(`  Organization ID: ${ctx.organizationId}`);
+    log(`  Menu ID: ${ctx.menuId}`);
+    log(`  Category ID: ${ctx.categoryId}`);
+    log(`  Product ID: ${ctx.productId}`);
+    log(`  Order ID: ${ctx.orderId}`);
+    log(`  Order Number: ${ctx.orderNumber}`);
+    process.exit(0);
+  } else {
+    error(`Verification completed with ${failureCount} failure(s)`);
+    process.exit(1);
+  }
+}
+
+// Run verification
+runVerification().catch((err) => {
+  error(`Verification script error: ${(err as Error).message}`);
+  process.exit(1);
+});

