+/**
+ * E2E Test API Client Helper
+ *
+ * Provides a wrapper around supertest for making authenticated API calls
+ * in end-to-end tests.
+ *
+ * @module __tests__/e2e/helpers/api-client
+ */
+
+import supertest from 'supertest';
+
+/**
+ * API Client configuration
+ */
+export interface ApiClientConfig {
+  baseUrl: string;
+  timeout?: number;
+}
+
+/**
+ * Authentication state
+ */
+export interface AuthState {
+  accessToken: string;
+  refreshToken: string;
+  userId: string;
+  organizationId: string;
+}
+
+/**
+ * API Client for E2E tests
+ */
+export class ApiClient {
+  private agent: supertest.Agent;
+  private authState: Partial<AuthState> = {};
+
+  constructor(config: ApiClientConfig) {
+    this.agent = supertest.agent(config.baseUrl);
+    if (config.timeout) {
+      this.agent.timeout(config.timeout);
+    }
+  }
+
+  /**
+   * Set authentication state
+   */
+  setAuth(auth: Partial<AuthState>): void {
+    this.authState = { ...this.authState, ...auth };
+  }
+
+  /**
+   * Clear authentication state
+   */
+  clearAuth(): void {
+    this.authState = {};
+  }
+
+  /**
+   * Get current auth state
+   */
+  getAuthState(): Partial<AuthState> {
+    return { ...this.authState };
+  }
+
+  /**
+   * Make a GET request
+   */
+  async get(path: string): Promise<supertest.Response> {
+    let request = this.agent.get(path);
+    request = this.applyAuth(request);
+    return request;
+  }
+
+  /**
+   * Make a POST request
+   */
+  async post(path: string, data?: unknown): Promise<supertest.Response> {
+    let request = this.agent.post(path);
+    request = this.applyAuth(request);
+    if (data) {
+      request = request.send(data);
+    }
+    return request;
+  }
+
+  /**
+   * Make a PUT request
+   */
+  async put(path: string, data?: unknown): Promise<supertest.Response> {
+    let request = this.agent.put(path);
+    request = this.applyAuth(request);
+    if (data) {
+      request = request.send(data);
+    }
+    return request;
+  }
+
+  /**
+   * Make a PATCH request
+   */
+  async patch(path: string, data?: unknown): Promise<supertest.Response> {
+    let request = this.agent.patch(path);
+    request = this.applyAuth(request);
+    if (data) {
+      request = request.send(data);
+    }
+    return request;
+  }
+
+  /**
+   * Make a DELETE request
+   */
+  async delete(path: string): Promise<supertest.Response> {
+    let request = this.agent.delete(path);
+    request = this.applyAuth(request);
+    return request;
+  }
+
+  /**
+   * Apply authentication headers to request
+   */
+  private applyAuth(request: supertest.Test): supertest.Test {
+    if (this.authState.accessToken) {
+      request = request.set('Authorization', `Bearer ${this.authState.accessToken}`);
+    }
+    if (this.authState.organizationId) {
+      request = request.set('X-Organization-Id', this.authState.organizationId);
+    }
+    return request;
+  }
+
+  /**
+   * Register a new user
+   */
+  async register(data: {
+    email: string;
+    password: string;
+    firstName: string;
+    lastName: string;
+  }): Promise<supertest.Response> {
+    return this.agent
+      .post('/api/v1/auth/register')
+      .send({
+        email: data.email,
+        password: data.password,
+        passwordConfirm: data.password,
+        firstName: data.firstName,
+        lastName: data.lastName,
+        acceptTerms: true,
+      });
+  }
+
+  /**
+   * Login with credentials
+   */
+  async login(email: string, password: string): Promise<supertest.Response> {
+    const response = await this.agent
+      .post('/api/v1/auth/login')
+      .send({
+        email,
+        password,
+        rememberMe: true,
+      });
+
+    if (response.status === 200 && response.body.success) {
+      this.setAuth({
+        accessToken: response.body.data.tokens.accessToken,
+        userId: response.body.data.user.id,
+      });
+
+      // Extract refresh token from cookies
+      const cookies = response.headers['set-cookie'];
+      if (cookies) {
+        const refreshCookie = Array.isArray(cookies)
+          ? cookies.find((c: string) => c.startsWith('refreshToken='))
+          : undefined;
+        if (refreshCookie) {
+          const match = refreshCookie.match(/refreshToken=([^;]+)/);
+          if (match) {
+            this.setAuth({ refreshToken: match[1] });
+          }
+        }
+      }
+    }
+
+    return response;
+  }
+
+  /**
+   * Logout
+   */
+  async logout(): Promise<supertest.Response> {
+    const response = await this.post('/api/v1/auth/logout', {});
+    this.clearAuth();
+    return response;
+  }
+}
+
+/**
+ * Create an API client instance
+ */
+export function createApiClient(baseUrl?: string): ApiClient {
+  return new ApiClient({
+    baseUrl: baseUrl || process.env.API_BASE_URL || 'http://localhost:3000',
+    timeout: 30000,
+  });
+}

