@@ -0,0 +1,305 @@
+/**
+ * Database Configuration
+ *
+ * Prisma client singleton for E-Menum.
+ * Ensures a single database connection pool is used across the application.
+ *
+ * @module config/database
+ */
+
+import { PrismaClient } from '@prisma/client';
+import { env, isDevelopment } from '@/config/env';
+
+// -----------------------------------------------------------------------------
+// Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Prisma log levels for query logging
+ */
+type PrismaLogLevel = 'query' | 'info' | 'warn' | 'error';
+
+/**
+ * Prisma log event definition
+ */
+interface PrismaLogEvent {
+  message: string;
+  target: string;
+  timestamp: Date;
+}
+
+/**
+ * Prisma query event definition
+ */
+interface PrismaQueryEvent {
+  query: string;
+  params: string;
+  duration: number;
+  target: string;
+}
+
+// -----------------------------------------------------------------------------
+// Global Declaration
+// -----------------------------------------------------------------------------
+
+/**
+ * Global prisma instance declaration for hot reload support in development.
+ * This prevents connection exhaustion during development with hot reloading.
+ */
+declare global {
+  // eslint-disable-next-line no-var
+  var prisma: PrismaClient | undefined;
+}
+
+// -----------------------------------------------------------------------------
+// Prisma Client Configuration
+// -----------------------------------------------------------------------------
+
+/**
+ * Gets the appropriate log levels based on environment
+ */
+function getLogLevels(): PrismaLogLevel[] {
+  if (env.ENABLE_QUERY_LOGGING) {
+    return ['query', 'info', 'warn', 'error'];
+  }
+
+  if (isDevelopment()) {
+    return ['warn', 'error'];
+  }
+
+  return ['error'];
+}
+
+/**
+ * Creates a configured Prisma client instance
+ */
+function createPrismaClient(): PrismaClient {
+  const logLevels = getLogLevels();
+
+  const client = new PrismaClient({
+    log: logLevels.map((level) => ({
+      emit: 'event' as const,
+      level,
+    })),
+    datasources: {
+      db: {
+        url: env.DATABASE_URL,
+      },
+    },
+  });
+
+  // Attach event listeners for logging
+  if (env.ENABLE_QUERY_LOGGING) {
+    client.$on('query' as never, (event: PrismaQueryEvent) => {
+      // eslint-disable-next-line no-console
+      console.log(`[Prisma Query] ${event.query}`);
+      // eslint-disable-next-line no-console
+      console.log(`[Prisma Params] ${event.params}`);
+      // eslint-disable-next-line no-console
+      console.log(`[Prisma Duration] ${event.duration}ms`);
+    });
+  }
+
+  client.$on('warn' as never, (event: PrismaLogEvent) => {
+    // eslint-disable-next-line no-console
+    console.warn(`[Prisma Warning] ${event.message}`);
+  });
+
+  client.$on('error' as never, (event: PrismaLogEvent) => {
+    // eslint-disable-next-line no-console
+    console.error(`[Prisma Error] ${event.message}`);
+  });
+
+  return client;
+}
+
+// -----------------------------------------------------------------------------
+// Singleton Export
+// -----------------------------------------------------------------------------
+
+/**
+ * Prisma client singleton instance.
+ *
+ * In development, the client is stored on globalThis to prevent
+ * connection exhaustion during hot module reloading (HMR).
+ *
+ * In production, a new client is created once at startup.
+ *
+ * @example
+ * ```typescript
+ * import { prisma } from '@/config/database';
+ *
+ * // Use in services
+ * const users = await prisma.user.findMany({
+ *   where: { organizationId: ctx.organization.id }
+ * });
+ *
+ * // Multi-tenant queries (ALWAYS include organizationId)
+ * const menus = await prisma.menu.findMany({
+ *   where: { organizationId: orgId, deletedAt: null }
+ * });
+ * ```
+ */
+export const prisma = globalThis.prisma ?? createPrismaClient();
+
+// Store on globalThis in development for HMR support
+if (isDevelopment()) {
+  globalThis.prisma = prisma;
+}
+
+// -----------------------------------------------------------------------------
+// Connection Management
+// -----------------------------------------------------------------------------
+
+/**
+ * Connects to the database.
+ * Call this during application startup to verify connectivity.
+ *
+ * @throws {Error} When database connection fails
+ */
+export async function connectDatabase(): Promise<void> {
+  try {
+    await prisma.$connect();
+    // eslint-disable-next-line no-console
+    console.log('[Database] Connected successfully');
+  } catch (error) {
+    // eslint-disable-next-line no-console
+    console.error('[Database] Connection failed:', error);
+    throw error;
+  }
+}
+
+/**
+ * Disconnects from the database.
+ * Call this during graceful shutdown.
+ */
+export async function disconnectDatabase(): Promise<void> {
+  try {
+    await prisma.$disconnect();
+    // eslint-disable-next-line no-console
+    console.log('[Database] Disconnected successfully');
+  } catch (error) {
+    // eslint-disable-next-line no-console
+    console.error('[Database] Disconnect failed:', error);
+    throw error;
+  }
+}
+
+/**
+ * Checks database connectivity by running a simple query.
+ * Useful for health checks and readiness probes.
+ *
+ * @returns True if database is accessible, false otherwise
+ */
+export async function isDatabaseHealthy(): Promise<boolean> {
+  try {
+    await prisma.$queryRaw`SELECT 1`;
+    return true;
+  } catch {
+    return false;
+  }
+}
+
+// -----------------------------------------------------------------------------
+// Transaction Helpers
+// -----------------------------------------------------------------------------
+
+/**
+ * Type for Prisma interactive transaction client
+ */
+export type TransactionClient = Parameters<Parameters<typeof prisma.$transaction>[0]>[0];
+
+/**
+ * Executes a callback within a database transaction.
+ * Automatically rolls back on error.
+ *
+ * @param fn - Callback function receiving transaction client
+ * @param options - Optional transaction options
+ * @returns Promise resolving to callback result
+ *
+ * @example
+ * ```typescript
+ * const result = await withTransaction(async (tx) => {
+ *   const menu = await tx.menu.create({ data: { ... } });
+ *   const category = await tx.category.create({ data: { menuId: menu.id, ... } });
+ *   return { menu, category };
+ * });
+ * ```
+ */
+export async function withTransaction<T>(
+  fn: (tx: TransactionClient) => Promise<T>,
+  options?: {
+    maxWait?: number;
+    timeout?: number;
+    isolationLevel?: 'ReadUncommitted' | 'ReadCommitted' | 'RepeatableRead' | 'Serializable';
+  }
+): Promise<T> {
+  return prisma.$transaction(fn, {
+    maxWait: options?.maxWait ?? 5000,
+    timeout: options?.timeout ?? 10000,
+    isolationLevel: options?.isolationLevel,
+  });
+}
+
+// -----------------------------------------------------------------------------
+// Soft Delete Helpers
+// -----------------------------------------------------------------------------
+
+/**
+ * Default filter for excluding soft-deleted records.
+ * Use this in all queries to maintain soft delete consistency.
+ *
+ * @example
+ * ```typescript
+ * const activeMenus = await prisma.menu.findMany({
+ *   where: { ...notDeleted, organizationId: orgId }
+ * });
+ * ```
+ */
+export const notDeleted = { deletedAt: null } as const;
+
+/**
+ * Filter for including only soft-deleted records.
+ *
+ * @example
+ * ```typescript
+ * const deletedMenus = await prisma.menu.findMany({
+ *   where: { ...onlyDeleted, organizationId: orgId }
+ * });
+ * ```
+ */
+export const onlyDeleted = { deletedAt: { not: null } } as const;
+
+/**
+ * Generates a soft delete update payload.
+ *
+ * @returns Object with deletedAt timestamp for soft delete
+ *
+ * @example
+ * ```typescript
+ * await prisma.menu.update({
+ *   where: { id },
+ *   data: softDelete()
+ * });
+ * ```
+ */
+export function softDelete(): { deletedAt: Date } {
+  return { deletedAt: new Date() };
+}
+
+/**
+ * Generates a restore (un-delete) update payload.
+ *
+ * @returns Object with null deletedAt for restore
+ *
+ * @example
+ * ```typescript
+ * await prisma.menu.update({
+ *   where: { id },
+ *   data: restore()
+ * });
+ * ```
+ */
+export function restore(): { deletedAt: null } {
+  return { deletedAt: null };
+}

