@@ -0,0 +1,578 @@
+/**
+ * Base Controller with Response Helpers
+ *
+ * Abstract base class for all controllers in E-Menum.
+ * Provides standardized API response formatting following API_CONTRACTS.md.
+ *
+ * @module core/base/base.controller
+ *
+ * @example
+ * ```typescript
+ * @JsonController('/api/v1/menus')
+ * @injectable()
+ * export class MenuController extends BaseController {
+ *   constructor(
+ *     @inject(MenuService) private menuService: MenuService,
+ *   ) {
+ *     super();
+ *   }
+ *
+ *   @Get('/')
+ *   @Authorized(['menu.view'])
+ *   async list(
+ *     @CurrentOrg() org: Organization,
+ *     @QueryParams() query: ListMenusQuery,
+ *   ): Promise<ApiResponse<Menu[]>> {
+ *     const result = await this.menuService.findAll(org.id, query);
+ *     return this.paginated(result);
+ *   }
+ *
+ *   @Post('/')
+ *   @Authorized(['menu.create'])
+ *   async create(
+ *     @CurrentOrg() org: Organization,
+ *     @Body() data: CreateMenuDto,
+ *   ): Promise<ApiResponse<Menu>> {
+ *     const menu = await this.menuService.create(org.id, data);
+ *     return this.created(menu);
+ *   }
+ * }
+ * ```
+ */
+
+import { Response } from 'express';
+
+import { PaginatedResult } from '@/core/base/base.repository';
+import { AppException, ValidationError } from '@/core/exceptions/app.exception';
+
+// -----------------------------------------------------------------------------
+// Types & Interfaces
+// -----------------------------------------------------------------------------
+
+/**
+ * Standard API success response format
+ */
+export interface ApiResponse<T> {
+  /** Indicates the request was successful */
+  success: true;
+  /** Response payload */
+  data: T;
+}
+
+/**
+ * Paginated API response format with metadata
+ */
+export interface PaginatedApiResponse<T> {
+  /** Indicates the request was successful */
+  success: true;
+  /** Array of response items */
+  data: T[];
+  /** Pagination metadata */
+  meta: PaginationMeta;
+}
+
+/**
+ * Pagination metadata structure
+ */
+export interface PaginationMeta {
+  /** Current page number (1-indexed) */
+  page: number;
+  /** Items per page */
+  perPage: number;
+  /** Total number of items */
+  total: number;
+  /** Total number of pages */
+  totalPages: number;
+  /** Whether there is a next page */
+  hasNextPage: boolean;
+  /** Whether there is a previous page */
+  hasPrevPage: boolean;
+}
+
+/**
+ * Standard API error response format
+ */
+export interface ApiErrorResponse {
+  /** Indicates the request failed */
+  success: false;
+  /** Error details */
+  error: ApiError;
+}
+
+/**
+ * Error details structure
+ */
+export interface ApiError {
+  /** Machine-readable error code for i18n */
+  code: string;
+  /** Human-readable error message */
+  message: string;
+  /** Field-level validation errors (if applicable) */
+  details?: ValidationError[];
+  /** Request ID for debugging/support */
+  requestId?: string;
+  /** Error timestamp in ISO 8601 format */
+  timestamp: string;
+  /** Retry-after seconds (for rate limiting) */
+  retryAfter?: number;
+}
+
+/**
+ * No content response (used for DELETE operations)
+ */
+export type NoContentResponse = void;
+
+/**
+ * Request with organization context
+ */
+export interface RequestWithOrg {
+  /** Organization context from tenant middleware */
+  organization?: {
+    id: string;
+    name?: string;
+    slug?: string;
+  };
+  /** Authenticated user */
+  user?: {
+    id: string;
+    email?: string;
+    roles?: string[];
+  };
+  /** Request ID for correlation */
+  requestId?: string;
+}
+
+// -----------------------------------------------------------------------------
+// Response Helpers
+// -----------------------------------------------------------------------------
+
+/**
+ * Creates a success response
+ *
+ * @param data - Response payload
+ * @returns Formatted success response
+ */
+export function successResponse<T>(data: T): ApiResponse<T> {
+  return {
+    success: true,
+    data,
+  };
+}
+
+/**
+ * Creates a paginated response with metadata
+ *
+ * @param result - Paginated result from repository/service
+ * @returns Formatted paginated response
+ */
+export function paginatedResponse<T>(result: PaginatedResult<T>): PaginatedApiResponse<T> {
+  const { page, perPage, total, totalPages } = result.meta;
+
+  return {
+    success: true,
+    data: result.data,
+    meta: {
+      page,
+      perPage,
+      total,
+      totalPages,
+      hasNextPage: page < totalPages,
+      hasPrevPage: page > 1,
+    },
+  };
+}
+
+/**
+ * Creates an error response from an AppException
+ *
+ * @param error - Application exception
+ * @param requestId - Optional request ID for correlation
+ * @returns Formatted error response
+ */
+export function errorResponse(error: AppException, requestId?: string): ApiErrorResponse {
+  const details = error.details as { errors?: ValidationError[] } | undefined;
+
+  return {
+    success: false,
+    error: {
+      code: error.code,
+      message: error.details?.message as string || error.message,
+      details: details?.errors,
+      requestId,
+      timestamp: new Date().toISOString(),
+      retryAfter: error.details?.retryAfter as number | undefined,
+    },
+  };
+}
+
+// -----------------------------------------------------------------------------
+// Base Controller Class
+// -----------------------------------------------------------------------------
+
+/**
+ * Abstract base controller with standardized response helpers.
+ *
+ * This class provides a consistent API response format across all controllers,
+ * following the specifications in API_CONTRACTS.md.
+ *
+ * @remarks
+ * - All success responses use `{ success: true, data: ... }` format
+ * - Paginated responses include `meta` with pagination info
+ * - Error responses use `{ success: false, error: { code, message, ... } }` format
+ * - HTTP status codes follow REST conventions (200, 201, 204, 4xx, 5xx)
+ *
+ * @example
+ * ```typescript
+ * @JsonController('/api/v1/products')
+ * @injectable()
+ * export class ProductController extends BaseController {
+ *   constructor(
+ *     @inject(ProductService) private productService: ProductService,
+ *   ) {
+ *     super();
+ *   }
+ *
+ *   @Get('/:id')
+ *   @Authorized(['menu.view'])
+ *   async get(
+ *     @Param('id') id: string,
+ *     @CurrentOrg() org: Organization,
+ *   ): Promise<ApiResponse<Product>> {
+ *     const product = await this.productService.findByIdOrThrow(id, org.id);
+ *     return this.success(product);
+ *   }
+ * }
+ * ```
+ */
+export abstract class BaseController {
+  // ---------------------------------------------------------------------------
+  // Success Response Helpers
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Creates a standard success response (HTTP 200)
+   *
+   * @param data - Response payload
+   * @returns Formatted success response
+   *
+   * @example
+   * ```typescript
+   * @Get('/:id')
+   * async get(@Param('id') id: string): Promise<ApiResponse<Menu>> {
+   *   const menu = await this.menuService.findByIdOrThrow(id, orgId);
+   *   return this.success(menu);
+   * }
+   * ```
+   */
+  protected success<T>(data: T): ApiResponse<T> {
+    return successResponse(data);
+  }
+
+  /**
+   * Creates a paginated success response (HTTP 200)
+   *
+   * @param result - Paginated result from service/repository
+   * @returns Formatted paginated response with metadata
+   *
+   * @example
+   * ```typescript
+   * @Get('/')
+   * async list(@QueryParams() query: ListQuery): Promise<PaginatedApiResponse<Menu>> {
+   *   const result = await this.menuService.findAll(orgId, query);
+   *   return this.paginated(result);
+   * }
+   * ```
+   */
+  protected paginated<T>(result: PaginatedResult<T>): PaginatedApiResponse<T> {
+    return paginatedResponse(result);
+  }
+
+  /**
+   * Creates a created response (HTTP 201)
+   *
+   * @param data - Created resource
+   * @param res - Optional Express response to set Location header
+   * @param location - Optional Location header value
+   * @returns Formatted success response
+   *
+   * @example
+   * ```typescript
+   * @Post('/')
+   * async create(
+   *   @Body() data: CreateMenuDto,
+   *   @Res() res: Response,
+   * ): Promise<ApiResponse<Menu>> {
+   *   const menu = await this.menuService.create(orgId, data);
+   *   return this.created(menu, res, `/api/v1/menus/${menu.id}`);
+   * }
+   * ```
+   */
+  protected created<T>(data: T, res?: Response, location?: string): ApiResponse<T> {
+    if (res) {
+      res.status(201);
+      if (location) {
+        res.setHeader('Location', location);
+      }
+    }
+    return successResponse(data);
+  }
+
+  /**
+   * Sends a no content response (HTTP 204)
+   *
+   * @param res - Express response object
+   *
+   * @remarks
+   * This method sends the response directly and returns void.
+   * Use for DELETE operations where no body is returned.
+   *
+   * @example
+   * ```typescript
+   * @Delete('/:id')
+   * async delete(
+   *   @Param('id') id: string,
+   *   @Res() res: Response,
+   * ): Promise<void> {
+   *   await this.menuService.delete(id, orgId);
+   *   return this.noContent(res);
+   * }
+   * ```
+   */
+  protected noContent(res: Response): NoContentResponse {
+    res.status(204).send();
+  }
+
+  // ---------------------------------------------------------------------------
+  // Error Response Helpers
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Creates an error response
+   *
+   * @param error - Application exception
+   * @param requestId - Optional request ID for correlation
+   * @returns Formatted error response
+   *
+   * @remarks
+   * In most cases, errors should be thrown and handled by the global
+   * error middleware. Use this method for custom error response formatting.
+   *
+   * @example
+   * ```typescript
+   * if (!isValid) {
+   *   return this.error(AppException.validation([
+   *     { field: 'name', message: 'Name is required' }
+   *   ]));
+   * }
+   * ```
+   */
+  protected error(error: AppException, requestId?: string): ApiErrorResponse {
+    return errorResponse(error, requestId);
+  }
+
+  // ---------------------------------------------------------------------------
+  // Utility Helpers
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Extracts the organization ID from the request context
+   *
+   * @param req - Request with organization context
+   * @returns Organization ID
+   * @throws {AppException} When organization context is missing
+   *
+   * @example
+   * ```typescript
+   * @Get('/')
+   * async list(@Req() req: Request): Promise<ApiResponse<Menu[]>> {
+   *   const orgId = this.getOrganizationId(req);
+   *   // ...
+   * }
+   * ```
+   */
+  protected getOrganizationId(req: RequestWithOrg): string {
+    if (!req.organization?.id) {
+      throw new AppException('TENANT_CONTEXT_MISSING', 400, {
+        message: 'Organization context is required',
+      });
+    }
+    return req.organization.id;
+  }
+
+  /**
+   * Extracts the current user ID from the request context
+   *
+   * @param req - Request with user context
+   * @returns User ID or undefined
+   *
+   * @example
+   * ```typescript
+   * @Post('/')
+   * async create(@Req() req: Request): Promise<ApiResponse<Menu>> {
+   *   const userId = this.getUserId(req);
+   *   // ...
+   * }
+   * ```
+   */
+  protected getUserId(req: RequestWithOrg): string | undefined {
+    return req.user?.id;
+  }
+
+  /**
+   * Extracts the request ID for error correlation
+   *
+   * @param req - Request object
+   * @returns Request ID or undefined
+   *
+   * @example
+   * ```typescript
+   * const requestId = this.getRequestId(req);
+   * ```
+   */
+  protected getRequestId(req: RequestWithOrg): string | undefined {
+    return req.requestId;
+  }
+
+  /**
+   * Creates pagination metadata from query parameters
+   *
+   * @param query - Query parameters with optional page and perPage
+   * @returns Normalized pagination parameters
+   *
+   * @example
+   * ```typescript
+   * @Get('/')
+   * async list(@QueryParams() query: ListQuery): Promise<PaginatedApiResponse<Menu>> {
+   *   const pagination = this.normalizePagination(query);
+   *   const result = await this.menuService.findAll(orgId, pagination);
+   *   return this.paginated(result);
+   * }
+   * ```
+   */
+  protected normalizePagination(query: { page?: number; perPage?: number }): {
+    page: number;
+    perPage: number;
+  } {
+    const page = Math.max(1, query.page || 1);
+    const perPage = Math.min(100, Math.max(1, query.perPage || 20));
+    return { page, perPage };
+  }
+
+  /**
+   * Normalizes sorting parameters from query
+   *
+   * @param query - Query parameters with optional sort
+   * @param allowedFields - Array of allowed sort fields
+   * @param defaultField - Default sort field
+   * @returns Normalized sort parameters
+   *
+   * @example
+   * ```typescript
+   * const sort = this.normalizeSort(query, ['name', 'createdAt'], 'createdAt');
+   * ```
+   */
+  protected normalizeSort<T extends string>(
+    query: { sort?: string; sortBy?: string; sortOrder?: 'asc' | 'desc' },
+    allowedFields: T[],
+    defaultField: T = 'createdAt' as T
+  ): { sortBy: T; sortOrder: 'asc' | 'desc' } {
+    let sortBy = defaultField;
+    let sortOrder: 'asc' | 'desc' = 'desc';
+
+    // Handle sort=field or sort=-field format
+    if (query.sort) {
+      const isDescending = query.sort.startsWith('-');
+      const field = (isDescending ? query.sort.slice(1) : query.sort) as T;
+
+      if (allowedFields.includes(field)) {
+        sortBy = field;
+        sortOrder = isDescending ? 'desc' : 'asc';
+      }
+    } else if (query.sortBy) {
+      // Handle sortBy and sortOrder format
+      if (allowedFields.includes(query.sortBy as T)) {
+        sortBy = query.sortBy as T;
+        sortOrder = query.sortOrder || 'desc';
+      }
+    }
+
+    return { sortBy, sortOrder };
+  }
+
+  /**
+   * Builds a Location header URL for created resources
+   *
+   * @param baseUrl - Base URL path
+   * @param id - Resource ID
+   * @returns Full URL path
+   *
+   * @example
+   * ```typescript
+   * const location = this.buildLocation('/api/v1/menus', menu.id);
+   * // Returns: /api/v1/menus/mnu_123
+   * ```
+   */
+  protected buildLocation(baseUrl: string, id: string): string {
+    return `${baseUrl}/${id}`;
+  }
+
+  /**
+   * Validates that required fields are present in the request body
+   *
+   * @param body - Request body
+   * @param requiredFields - Array of required field names
+   * @throws {AppException} When required fields are missing
+   *
+   * @example
+   * ```typescript
+   * @Post('/')
+   * async create(@Body() body: any): Promise<ApiResponse<Menu>> {
+   *   this.validateRequired(body, ['name', 'description']);
+   *   // ...
+   * }
+   * ```
+   */
+  protected validateRequired(
+    body: Record<string, unknown>,
+    requiredFields: string[]
+  ): void {
+    const errors: ValidationError[] = [];
+
+    for (const field of requiredFields) {
+      if (body[field] === undefined || body[field] === null || body[field] === '') {
+        errors.push({
+          field,
+          message: `${field} is required`,
+          rule: 'required',
+        });
+      }
+    }
+
+    if (errors.length > 0) {
+      throw AppException.validation(errors);
+    }
+  }
+}
+
+// -----------------------------------------------------------------------------
+// Exports
+// -----------------------------------------------------------------------------
+
+export {
+  // Types
+  ApiResponse,
+  PaginatedApiResponse,
+  PaginationMeta,
+  ApiErrorResponse,
+  ApiError,
+  NoContentResponse,
+  RequestWithOrg,
+
+  // Standalone functions
+  successResponse,
+  paginatedResponse,
+  errorResponse,
+
+  // Base class
+  BaseController,
+};

