+/**
+ * Application Bootstrap
+ *
+ * Orchestrates the E-Menum application startup sequence.
+ * Handles environment validation, service connections, DI registration,
+ * module loading, and graceful shutdown.
+ *
+ * Startup Sequence:
+ * 1. Validate environment configuration
+ * 2. Connect to database (PostgreSQL)
+ * 3. Connect to cache (Redis)
+ * 4. Register core DI services
+ * 5. Discover and load modules
+ * 6. Activate enabled modules
+ * 7. Start HTTP server
+ *
+ * @module core/kernel/bootstrap
+ */
+
+import { env, isDevelopment, isProduction } from '@/config/env';
+import { prisma, connectDatabase, disconnectDatabase, isDatabaseHealthy } from '@/config/database';
+import { redis, connectRedis, disconnectRedis, isRedisHealthy } from '@/config/redis';
+import { registerCoreServices, appContainer, TOKENS, registerInstance } from '@/core/kernel/container';
+import { ModuleLoader, createModuleLoader } from '@/core/kernel/module-loader';
+
+// -----------------------------------------------------------------------------
+// Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Bootstrap phase enumeration
+ */
+export type BootstrapPhase =
+  | 'idle'
+  | 'environment'
+  | 'database'
+  | 'cache'
+  | 'container'
+  | 'modules'
+  | 'server'
+  | 'ready'
+  | 'shutdown'
+  | 'error';
+
+/**
+ * Bootstrap status information
+ */
+export interface BootstrapStatus {
+  phase: BootstrapPhase;
+  startedAt: Date;
+  readyAt?: Date;
+  error?: string;
+  services: {
+    database: boolean;
+    cache: boolean;
+    modules: number;
+  };
+}
+
+/**
+ * Bootstrap options
+ */
+export interface BootstrapOptions {
+  /** Skip module loading (useful for testing) */
+  skipModules?: boolean;
+  /** Skip database connection */
+  skipDatabase?: boolean;
+  /** Skip Redis connection */
+  skipCache?: boolean;
+  /** Custom module paths for testing */
+  modulePaths?: string[];
+  /** Callback when bootstrap is complete */
+  onReady?: () => void | Promise<void>;
+  /** Callback when shutdown is initiated */
+  onShutdown?: () => void | Promise<void>;
+}
+
+/**
+ * Bootstrap result returned on successful startup
+ */
+export interface BootstrapResult {
+  status: BootstrapStatus;
+  moduleLoader: ModuleLoader;
+  shutdown: () => Promise<void>;
+}
+
+// -----------------------------------------------------------------------------
+// Bootstrap State
+// -----------------------------------------------------------------------------
+
+/** Current bootstrap status */
+let currentStatus: BootstrapStatus = {
+  phase: 'idle',
+  startedAt: new Date(),
+  services: {
+    database: false,
+    cache: false,
+    modules: 0,
+  },
+};
+
+/** Module loader instance */
+let moduleLoader: ModuleLoader | null = null;
+
+/** Flag to prevent multiple shutdowns */
+let isShuttingDown = false;
+
+// -----------------------------------------------------------------------------
+// Bootstrap Phases
+// -----------------------------------------------------------------------------
+
+/**
+ * Updates and logs the current bootstrap phase.
+ *
+ * @param phase - New phase to set
+ * @param message - Optional message to log
+ */
+function setPhase(phase: BootstrapPhase, message?: string): void {
+  currentStatus.phase = phase;
+
+  const timestamp = new Date().toISOString();
+  const prefix = `[Bootstrap][${timestamp}]`;
+
+  if (message) {
+    // eslint-disable-next-line no-console
+    console.log(`${prefix} ${phase.toUpperCase()}: ${message}`);
+  } else {
+    // eslint-disable-next-line no-console
+    console.log(`${prefix} Entering phase: ${phase}`);
+  }
+}
+
+/**
+ * Phase 1: Validate environment configuration.
+ * Environment is already validated by env.ts import, but we log success here.
+ */
+async function bootstrapEnvironment(): Promise<void> {
+  setPhase('environment', `Running in ${env.NODE_ENV} mode`);
+
+  // Log critical config (non-sensitive)
+  // eslint-disable-next-line no-console
+  console.log(`[Bootstrap] App: ${env.APP_NAME} (${env.APP_DOMAIN})`);
+  // eslint-disable-next-line no-console
+  console.log(`[Bootstrap] Port: ${env.PORT}`);
+  // eslint-disable-next-line no-console
+  console.log(`[Bootstrap] Log Level: ${env.LOG_LEVEL}`);
+}
+
+/**
+ * Phase 2: Connect to PostgreSQL database.
+ */
+async function bootstrapDatabase(): Promise<void> {
+  setPhase('database', 'Connecting to PostgreSQL...');
+
+  await connectDatabase();
+
+  // Verify connection with health check
+  const healthy = await isDatabaseHealthy();
+  if (!healthy) {
+    throw new Error('Database connection established but health check failed');
+  }
+
+  currentStatus.services.database = true;
+  // eslint-disable-next-line no-console
+  console.log('[Bootstrap] Database connected and healthy');
+}
+
+/**
+ * Phase 3: Connect to Redis cache.
+ */
+async function bootstrapCache(): Promise<void> {
+  setPhase('cache', 'Connecting to Redis...');
+
+  await connectRedis();
+
+  // Verify connection with health check
+  const healthy = await isRedisHealthy();
+  if (!healthy) {
+    throw new Error('Redis connection established but health check failed');
+  }
+
+  currentStatus.services.cache = true;
+  // eslint-disable-next-line no-console
+  console.log('[Bootstrap] Redis connected and healthy');
+}
+
+/**
+ * Phase 4: Register core services with DI container.
+ */
+async function bootstrapContainer(): Promise<void> {
+  setPhase('container', 'Registering core services...');
+
+  // Register Prisma and Redis (done in registerCoreServices)
+  registerCoreServices();
+
+  // eslint-disable-next-line no-console
+  console.log('[Bootstrap] DI container initialized');
+}
+
+/**
+ * Phase 5: Discover and load application modules.
+ */
+async function bootstrapModules(options: BootstrapOptions = {}): Promise<void> {
+  setPhase('modules', 'Loading modules...');
+
+  // Create module loader
+  moduleLoader = createModuleLoader(prisma);
+
+  // Set custom module paths if provided (for testing)
+  if (options.modulePaths && options.modulePaths.length > 0) {
+    moduleLoader.setModulesBasePath(options.modulePaths[0]);
+  }
+
+  // Register module loader with DI container
+  registerInstance(TOKENS.ModuleLoader, moduleLoader);
+
+  // Discover all modules
+  const discoveredIds = await moduleLoader.discoverModules();
+  // eslint-disable-next-line no-console
+  console.log(`[Bootstrap] Discovered ${discoveredIds.length} modules`);
+
+  // Load modules in dependency order
+  const loadResults = await moduleLoader.loadAllModules();
+
+  let loadedCount = 0;
+  let errorCount = 0;
+
+  for (const [moduleId, result] of loadResults) {
+    if (result.success) {
+      loadedCount++;
+    } else {
+      errorCount++;
+      // eslint-disable-next-line no-console
+      console.error(`[Bootstrap] Failed to load module '${moduleId}': ${result.error}`);
+    }
+  }
+
+  // Activate enabled modules
+  let activatedCount = 0;
+  const loadedModules = moduleLoader.getModulesByStatus('loaded');
+
+  for (const module of loadedModules) {
+    if (module.manifest.enabled) {
+      try {
+        await moduleLoader.activateModule(module.manifest.id);
+        activatedCount++;
+      } catch (error) {
+        // eslint-disable-next-line no-console
+        console.error(
+          `[Bootstrap] Failed to activate module '${module.manifest.id}':`,
+          error instanceof Error ? error.message : 'Unknown error'
+        );
+      }
+    }
+  }
+
+  currentStatus.services.modules = activatedCount;
+
+  // Log module statistics
+  const stats = moduleLoader.getStats();
+  // eslint-disable-next-line no-console
+  console.log(`[Bootstrap] Modules: ${loadedCount} loaded, ${activatedCount} active, ${errorCount} errors`);
+  // eslint-disable-next-line no-console
+  console.log(`[Bootstrap] By category: ${JSON.stringify(stats.byCategory)}`);
+}
+
+// -----------------------------------------------------------------------------
+// Graceful Shutdown
+// -----------------------------------------------------------------------------
+
+/**
+ * Performs graceful shutdown of all services.
+ * Called automatically on SIGTERM/SIGINT or manually via returned shutdown function.
+ *
+ * @param options - Bootstrap options for shutdown callbacks
+ */
+async function gracefulShutdown(options: BootstrapOptions = {}): Promise<void> {
+  // Prevent multiple shutdown attempts
+  if (isShuttingDown) {
+    // eslint-disable-next-line no-console
+    console.log('[Bootstrap] Shutdown already in progress...');
+    return;
+  }
+
+  isShuttingDown = true;
+  setPhase('shutdown', 'Initiating graceful shutdown...');
+
+  // Call shutdown callback if provided
+  if (options.onShutdown) {
+    try {
+      await options.onShutdown();
+    } catch (error) {
+      // eslint-disable-next-line no-console
+      console.error('[Bootstrap] Shutdown callback error:', error);
+    }
+  }
+
+  // Deactivate all modules
+  if (moduleLoader) {
+    const activeModules = moduleLoader.getActiveModules();
+    // Deactivate in reverse dependency order
+    for (const module of [...activeModules].reverse()) {
+      // Skip core modules (they should be last)
+      if (module.manifest.core) continue;
+
+      try {
+        await moduleLoader.deactivateModule(module.manifest.id);
+        // eslint-disable-next-line no-console
+        console.log(`[Bootstrap] Deactivated module: ${module.manifest.id}`);
+      } catch {
+        // Ignore errors during shutdown
+      }
+    }
+  }
+
+  // Disconnect from Redis
+  try {
+    await disconnectRedis();
+  } catch (error) {
+    // eslint-disable-next-line no-console
+    console.error('[Bootstrap] Redis disconnect error:', error);
+  }
+
+  // Disconnect from database
+  try {
+    await disconnectDatabase();
+  } catch (error) {
+    // eslint-disable-next-line no-console
+    console.error('[Bootstrap] Database disconnect error:', error);
+  }
+
+  // eslint-disable-next-line no-console
+  console.log('[Bootstrap] Shutdown complete');
+}
+
+/**
+ * Registers process signal handlers for graceful shutdown.
+ *
+ * @param options - Bootstrap options
+ */
+function registerShutdownHandlers(options: BootstrapOptions): void {
+  // Handle SIGTERM (Docker stop, k8s termination)
+  process.on('SIGTERM', async () => {
+    // eslint-disable-next-line no-console
+    console.log('\n[Bootstrap] Received SIGTERM');
+    await gracefulShutdown(options);
+    process.exit(0);
+  });
+
+  // Handle SIGINT (Ctrl+C)
+  process.on('SIGINT', async () => {
+    // eslint-disable-next-line no-console
+    console.log('\n[Bootstrap] Received SIGINT');
+    await gracefulShutdown(options);
+    process.exit(0);
+  });
+
+  // Handle uncaught exceptions
+  process.on('uncaughtException', async (error) => {
+    // eslint-disable-next-line no-console
+    console.error('[Bootstrap] Uncaught exception:', error);
+    await gracefulShutdown(options);
+    process.exit(1);
+  });
+
+  // Handle unhandled promise rejections
+  process.on('unhandledRejection', async (reason) => {
+    // eslint-disable-next-line no-console
+    console.error('[Bootstrap] Unhandled rejection:', reason);
+    await gracefulShutdown(options);
+    process.exit(1);
+  });
+}
+
+// -----------------------------------------------------------------------------
+// Main Bootstrap Function
+// -----------------------------------------------------------------------------
+
+/**
+ * Main bootstrap function that orchestrates the application startup.
+ *
+ * @param options - Bootstrap configuration options
+ * @returns Bootstrap result with status and shutdown function
+ * @throws {Error} When any bootstrap phase fails
+ *
+ * @example
+ * ```typescript
+ * import { bootstrap } from '@/core/kernel/bootstrap';
+ *
+ * async function main() {
+ *   try {
+ *     const { status, moduleLoader, shutdown } = await bootstrap({
+ *       onReady: () => console.log('Application is ready!'),
+ *       onShutdown: () => console.log('Application is shutting down...'),
+ *     });
+ *
+ *     console.log(`Loaded ${status.services.modules} modules`);
+ *   } catch (error) {
+ *     console.error('Failed to start application:', error);
+ *     process.exit(1);
+ *   }
+ * }
+ * ```
+ */
+export async function bootstrap(options: BootstrapOptions = {}): Promise<BootstrapResult> {
+  currentStatus = {
+    phase: 'idle',
+    startedAt: new Date(),
+    services: {
+      database: false,
+      cache: false,
+      modules: 0,
+    },
+  };
+
+  isShuttingDown = false;
+
+  // eslint-disable-next-line no-console
+  console.log('\n========================================');
+  // eslint-disable-next-line no-console
+  console.log('     E-Menum Application Bootstrap');
+  // eslint-disable-next-line no-console
+  console.log('========================================\n');
+
+  try {
+    // Phase 1: Environment
+    await bootstrapEnvironment();
+
+    // Phase 2: Database (optional)
+    if (!options.skipDatabase) {
+      await bootstrapDatabase();
+    } else {
+      // eslint-disable-next-line no-console
+      console.log('[Bootstrap] Skipping database connection');
+    }
+
+    // Phase 3: Cache (optional)
+    if (!options.skipCache) {
+      await bootstrapCache();
+    } else {
+      // eslint-disable-next-line no-console
+      console.log('[Bootstrap] Skipping cache connection');
+    }
+
+    // Phase 4: DI Container
+    await bootstrapContainer();
+
+    // Phase 5: Modules (optional)
+    if (!options.skipModules) {
+      await bootstrapModules(options);
+    } else {
+      // eslint-disable-next-line no-console
+      console.log('[Bootstrap] Skipping module loading');
+      // Create empty module loader for consistency
+      moduleLoader = createModuleLoader(prisma);
+      registerInstance(TOKENS.ModuleLoader, moduleLoader);
+    }
+
+    // Register shutdown handlers
+    registerShutdownHandlers(options);
+
+    // Mark as ready
+    currentStatus.phase = 'ready';
+    currentStatus.readyAt = new Date();
+
+    const startupTimeMs = currentStatus.readyAt.getTime() - currentStatus.startedAt.getTime();
+
+    // eslint-disable-next-line no-console
+    console.log('\n========================================');
+    // eslint-disable-next-line no-console
+    console.log(`  Application ready in ${startupTimeMs}ms`);
+    // eslint-disable-next-line no-console
+    console.log(`  Environment: ${env.NODE_ENV}`);
+    // eslint-disable-next-line no-console
+    console.log(`  Database: ${currentStatus.services.database ? 'Connected' : 'Skipped'}`);
+    // eslint-disable-next-line no-console
+    console.log(`  Cache: ${currentStatus.services.cache ? 'Connected' : 'Skipped'}`);
+    // eslint-disable-next-line no-console
+    console.log(`  Modules: ${currentStatus.services.modules} active`);
+    // eslint-disable-next-line no-console
+    console.log('========================================\n');
+
+    // Call ready callback if provided
+    if (options.onReady) {
+      await options.onReady();
+    }
+
+    return {
+      status: { ...currentStatus },
+      moduleLoader: moduleLoader!,
+      shutdown: () => gracefulShutdown(options),
+    };
+  } catch (error) {
+    currentStatus.phase = 'error';
+    currentStatus.error = error instanceof Error ? error.message : 'Unknown bootstrap error';
+
+    // eslint-disable-next-line no-console
+    console.error('\n========================================');
+    // eslint-disable-next-line no-console
+    console.error('  BOOTSTRAP FAILED');
+    // eslint-disable-next-line no-console
+    console.error(`  Error: ${currentStatus.error}`);
+    // eslint-disable-next-line no-console
+    console.error('========================================\n');
+
+    // Attempt graceful cleanup even on error
+    await gracefulShutdown(options);
+
+    throw error;
+  }
+}
+
+// -----------------------------------------------------------------------------
+// Status & Health Checks
+// -----------------------------------------------------------------------------
+
+/**
+ * Gets the current bootstrap status.
+ *
+ * @returns Current status object
+ */
+export function getBootstrapStatus(): BootstrapStatus {
+  return { ...currentStatus };
+}
+
+/**
+ * Checks if the application is ready to handle requests.
+ *
+ * @returns True if application is in ready state
+ */
+export function isApplicationReady(): boolean {
+  return currentStatus.phase === 'ready';
+}
+
+/**
+ * Performs comprehensive health check of all services.
+ *
+ * @returns Health check result
+ *
+ * @example
+ * ```typescript
+ * // In health check endpoint
+ * app.get('/health', async (req, res) => {
+ *   const health = await healthCheck();
+ *   const statusCode = health.healthy ? 200 : 503;
+ *   res.status(statusCode).json(health);
+ * });
+ * ```
+ */
+export async function healthCheck(): Promise<{
+  healthy: boolean;
+  status: BootstrapPhase;
+  services: {
+    database: { connected: boolean; healthy: boolean };
+    cache: { connected: boolean; healthy: boolean };
+    modules: { count: number; active: number };
+  };
+  uptime: number;
+}> {
+  const dbHealthy = await isDatabaseHealthy();
+  const cacheHealthy = await isRedisHealthy();
+
+  const moduleCount = moduleLoader?.getAllModules().length ?? 0;
+  const activeCount = moduleLoader?.getActiveModules().length ?? 0;
+
+  const healthy =
+    currentStatus.phase === 'ready' && dbHealthy && cacheHealthy;
+
+  return {
+    healthy,
+    status: currentStatus.phase,
+    services: {
+      database: {
+        connected: currentStatus.services.database,
+        healthy: dbHealthy,
+      },
+      cache: {
+        connected: currentStatus.services.cache,
+        healthy: cacheHealthy,
+      },
+      modules: {
+        count: moduleCount,
+        active: activeCount,
+      },
+    },
+    uptime: currentStatus.startedAt
+      ? Math.floor((Date.now() - currentStatus.startedAt.getTime()) / 1000)
+      : 0,
+  };
+}
+
+// -----------------------------------------------------------------------------
+// Quick Start Helper
+// -----------------------------------------------------------------------------
+
+/**
+ * Convenience function for quick application bootstrap.
+ * Logs minimal output and returns a simple interface.
+ *
+ * @returns Promise that resolves when application is ready
+ *
+ * @example
+ * ```typescript
+ * import { quickBootstrap } from '@/core/kernel/bootstrap';
+ *
+ * // In main.ts
+ * await quickBootstrap();
+ * // Application is now ready
+ * ```
+ */
+export async function quickBootstrap(): Promise<void> {
+  await bootstrap({
+    onReady: () => {
+      if (isProduction()) {
+        // eslint-disable-next-line no-console
+        console.log(`[E-Menum] Ready at ${env.APP_URL}`);
+      }
+    },
+  });
+}
+
+// -----------------------------------------------------------------------------
+// Exports
+// -----------------------------------------------------------------------------
+
+export type { BootstrapOptions, BootstrapResult };

