+/**
+ * Module Loader
+ *
+ * WordPress-style module discovery, validation, and lifecycle management for E-Menum.
+ * Handles module manifest parsing, dependency resolution, and dynamic loading.
+ *
+ * Module Lifecycle: discover → validate → resolve dependencies → load → register → ready
+ *
+ * @module core/kernel/module-loader
+ */
+
+import { z } from 'zod';
+import { injectable, inject } from 'tsyringe';
+import * as fs from 'fs';
+import * as path from 'path';
+import { TOKENS } from '@/core/kernel/container';
+import type { PrismaClient } from '@prisma/client';
+
+// -----------------------------------------------------------------------------
+// Module Manifest Schema (Zod)
+// -----------------------------------------------------------------------------
+
+/**
+ * Module category types
+ */
+export const ModuleCategorySchema = z.enum(['core', 'feature', 'ai', 'integration', 'example', 'stub']);
+export type ModuleCategory = z.infer<typeof ModuleCategorySchema>;
+
+/**
+ * Module status types
+ */
+export const ModuleStatusSchema = z.enum(['discovered', 'validated', 'loaded', 'active', 'disabled', 'error']);
+export type ModuleStatus = z.infer<typeof ModuleStatusSchema>;
+
+/**
+ * Module dependencies schema
+ */
+const ModuleDependenciesSchema = z.object({
+  required: z.array(z.string()).default([]),
+  optional: z.array(z.string()).default([]),
+});
+
+/**
+ * Module routes schema
+ */
+const ModuleRoutesSchema = z.object({
+  prefix: z.string().optional(),
+  admin: z.string().optional(),
+  public: z.string().optional(),
+});
+
+/**
+ * Module database schema
+ */
+const ModuleDatabaseSchema = z.object({
+  schema: z.string().optional(),
+  migrations: z.boolean().default(false),
+});
+
+/**
+ * Module hooks schema
+ */
+const ModuleHooksSchema = z.object({
+  onEnable: z.string().optional(),
+  onDisable: z.string().optional(),
+  onInstall: z.string().optional(),
+  onUninstall: z.string().optional(),
+});
+
+/**
+ * Module admin menu schema
+ */
+const ModuleAdminMenuSchema = z.object({
+  label: z.string(),
+  icon: z.string().optional(),
+  position: z.number().int().default(100),
+});
+
+/**
+ * Module admin configuration schema
+ */
+const ModuleAdminSchema = z.object({
+  menu: ModuleAdminMenuSchema.optional(),
+});
+
+/**
+ * Module events schema
+ */
+const ModuleEventsSchema = z.object({
+  emits: z.array(z.string()).default([]),
+  listens: z.array(z.string()).default([]),
+});
+
+/**
+ * Module plan restrictions schema
+ */
+const ModulePlanRestrictionsSchema = z.object({
+  minPlan: z.string().optional(),
+  features: z.record(z.string()).default({}),
+});
+
+/**
+ * Complete module manifest schema (module.json)
+ */
+export const ModuleManifestSchema = z.object({
+  // Required fields
+  id: z.string().min(1).regex(/^[a-z0-9-]+$/, 'Module ID must be lowercase alphanumeric with hyphens'),
+  name: z.string().min(1),
+  displayName: z.string().min(1),
+  version: z.string().regex(/^\d+\.\d+\.\d+$/, 'Version must follow semver (x.y.z)'),
+  description: z.string().min(1),
+
+  // Optional fields with defaults
+  author: z.string().default('E-Menum'),
+  category: ModuleCategorySchema.default('feature'),
+  enabled: z.boolean().default(true),
+  priority: z.number().int().default(100),
+  core: z.boolean().default(false), // Core modules cannot be disabled
+
+  // Nested configurations
+  dependencies: ModuleDependenciesSchema.default({ required: [], optional: [] }),
+  permissions: z.array(z.string()).default([]),
+  routes: ModuleRoutesSchema.default({}),
+  database: ModuleDatabaseSchema.default({ migrations: false }),
+  hooks: ModuleHooksSchema.default({}),
+  admin: ModuleAdminSchema.default({}),
+  events: ModuleEventsSchema.default({ emits: [], listens: [] }),
+  planRestrictions: ModulePlanRestrictionsSchema.default({}),
+});
+
+export type ModuleManifest = z.infer<typeof ModuleManifestSchema>;
+
+// -----------------------------------------------------------------------------
+// Module Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Loaded module information
+ */
+export interface LoadedModule {
+  /** Module manifest data */
+  manifest: ModuleManifest;
+  /** Module directory path */
+  path: string;
+  /** Current module status */
+  status: ModuleStatus;
+  /** Error message if status is 'error' */
+  error?: string;
+  /** Timestamp when module was loaded */
+  loadedAt?: Date;
+  /** Module instance (if loaded) */
+  instance?: ModuleInstance;
+}
+
+/**
+ * Module instance interface that modules must implement
+ */
+export interface ModuleInstance {
+  /** Module initialization (called on load) */
+  onLoad?(): Promise<void>;
+  /** Module activation (called when enabled) */
+  onEnable?(): Promise<void>;
+  /** Module deactivation (called when disabled) */
+  onDisable?(): Promise<void>;
+  /** Module cleanup (called on unload) */
+  onUnload?(): Promise<void>;
+  /** Get module routes for registration */
+  getRoutes?(): unknown[];
+  /** Get module controllers for registration */
+  getControllers?(): unknown[];
+}
+
+/**
+ * Module definition file structure
+ */
+export interface ModuleDefinition {
+  /** Module class that implements ModuleInstance */
+  default?: new () => ModuleInstance;
+  /** Module metadata */
+  metadata?: ModuleManifest;
+}
+
+/**
+ * Module load result
+ */
+export interface ModuleLoadResult {
+  success: boolean;
+  module?: LoadedModule;
+  error?: string;
+}
+
+/**
+ * Dependency resolution result
+ */
+export interface DependencyResolutionResult {
+  resolved: boolean;
+  loadOrder: string[];
+  missing: string[];
+  circular: string[];
+}
+
+// -----------------------------------------------------------------------------
+// Module Loader Service
+// -----------------------------------------------------------------------------
+
+/**
+ * ModuleLoader handles discovery, validation, and lifecycle management of modules.
+ *
+ * @example
+ * ```typescript
+ * import { ModuleLoader } from '@/core/kernel/module-loader';
+ *
+ * const loader = container.resolve(ModuleLoader);
+ * await loader.discoverModules();
+ * await loader.loadAllModules();
+ * ```
+ */
+@injectable()
+export class ModuleLoader {
+  /** Registry of all discovered modules */
+  private modules: Map<string, LoadedModule> = new Map();
+
+  /** Base path for module discovery */
+  private modulesBasePath: string;
+
+  /** Module directory patterns */
+  private static readonly MODULE_DIRS = ['_core', '_examples', '_stubs', ''] as const;
+
+  /** Manifest filename */
+  private static readonly MANIFEST_FILE = 'module.json';
+
+  constructor(
+    @inject(TOKENS.PrismaClient) private prisma: PrismaClient
+  ) {
+    // Set base path relative to project root
+    this.modulesBasePath = path.resolve(process.cwd(), 'src', 'modules');
+  }
+
+  // ---------------------------------------------------------------------------
+  // Discovery
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Discovers all modules in the modules directory.
+   * Scans for module.json manifests and validates them.
+   *
+   * @returns Array of discovered module IDs
+   */
+  async discoverModules(): Promise<string[]> {
+    const discoveredIds: string[] = [];
+
+    for (const dir of ModuleLoader.MODULE_DIRS) {
+      const searchPath = dir ? path.join(this.modulesBasePath, dir) : this.modulesBasePath;
+
+      if (!fs.existsSync(searchPath)) {
+        continue;
+      }
+
+      const entries = fs.readdirSync(searchPath, { withFileTypes: true });
+
+      for (const entry of entries) {
+        // Skip non-directories and special directories
+        if (!entry.isDirectory() || entry.name.startsWith('.')) {
+          continue;
+        }
+
+        // Skip module category directories when scanning root
+        if (dir === '' && ModuleLoader.MODULE_DIRS.includes(entry.name as typeof ModuleLoader.MODULE_DIRS[number])) {
+          continue;
+        }
+
+        const modulePath = path.join(searchPath, entry.name);
+        const manifestPath = path.join(modulePath, ModuleLoader.MANIFEST_FILE);
+
+        if (fs.existsSync(manifestPath)) {
+          const result = await this.loadModuleManifest(manifestPath, modulePath);
+          if (result.success && result.module) {
+            this.modules.set(result.module.manifest.id, result.module);
+            discoveredIds.push(result.module.manifest.id);
+          }
+        }
+      }
+    }
+
+    return discoveredIds;
+  }
+
+  /**
+   * Loads and validates a module manifest file.
+   *
+   * @param manifestPath - Path to module.json
+   * @param modulePath - Path to module directory
+   * @returns Module load result
+   */
+  private async loadModuleManifest(manifestPath: string, modulePath: string): Promise<ModuleLoadResult> {
+    try {
+      const manifestContent = fs.readFileSync(manifestPath, 'utf-8');
+      const rawManifest = JSON.parse(manifestContent);
+
+      // Validate manifest with Zod
+      const parseResult = ModuleManifestSchema.safeParse(rawManifest);
+
+      if (!parseResult.success) {
+        const errors = parseResult.error.errors.map((e) => `${e.path.join('.')}: ${e.message}`).join(', ');
+        return {
+          success: false,
+          error: `Invalid manifest: ${errors}`,
+        };
+      }
+
+      const manifest = parseResult.data;
+
+      // Determine category from path
+      const category = this.detectCategoryFromPath(modulePath);
+      if (category) {
+        manifest.category = category;
+      }
+
+      // Core modules in _core directory are always marked as core
+      if (modulePath.includes('/_core/') || modulePath.includes('\\_core\\')) {
+        manifest.core = true;
+        manifest.category = 'core';
+      }
+
+      const loadedModule: LoadedModule = {
+        manifest,
+        path: modulePath,
+        status: 'discovered',
+      };
+
+      return { success: true, module: loadedModule };
+    } catch (error) {
+      return {
+        success: false,
+        error: error instanceof Error ? error.message : 'Unknown error loading manifest',
+      };
+    }
+  }
+
+  /**
+   * Detects module category from its file path.
+   *
+   * @param modulePath - Module directory path
+   * @returns Detected category or undefined
+   */
+  private detectCategoryFromPath(modulePath: string): ModuleCategory | undefined {
+    if (modulePath.includes('/_core/') || modulePath.includes('\\_core\\')) {
+      return 'core';
+    }
+    if (modulePath.includes('/_examples/') || modulePath.includes('\\_examples\\')) {
+      return 'example';
+    }
+    if (modulePath.includes('/_stubs/') || modulePath.includes('\\_stubs\\')) {
+      return 'stub';
+    }
+    if (modulePath.includes('/ai/') || modulePath.includes('\\ai\\')) {
+      return 'ai';
+    }
+    if (modulePath.includes('/integrations/') || modulePath.includes('\\integrations\\')) {
+      return 'integration';
+    }
+    return 'feature';
+  }
+
+  // ---------------------------------------------------------------------------
+  // Dependency Resolution
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Resolves module dependencies and determines load order.
+   * Uses topological sort to ensure dependencies are loaded first.
+   *
+   * @param moduleIds - Module IDs to resolve (defaults to all discovered)
+   * @returns Dependency resolution result
+   */
+  resolveDependencies(moduleIds?: string[]): DependencyResolutionResult {
+    const targetIds = moduleIds || Array.from(this.modules.keys());
+    const resolved: string[] = [];
+    const missing: string[] = [];
+    const circular: string[] = [];
+    const visiting = new Set<string>();
+    const visited = new Set<string>();
+
+    const visit = (moduleId: string): boolean => {
+      if (visited.has(moduleId)) {
+        return true;
+      }
+
+      if (visiting.has(moduleId)) {
+        circular.push(moduleId);
+        return false;
+      }
+
+      const module = this.modules.get(moduleId);
+      if (!module) {
+        missing.push(moduleId);
+        return false;
+      }
+
+      visiting.add(moduleId);
+
+      // Visit required dependencies first
+      for (const depId of module.manifest.dependencies.required) {
+        if (!visit(depId)) {
+          return false;
+        }
+      }
+
+      // Visit optional dependencies (don't fail if missing)
+      for (const depId of module.manifest.dependencies.optional) {
+        if (this.modules.has(depId)) {
+          visit(depId);
+        }
+      }
+
+      visiting.delete(moduleId);
+      visited.add(moduleId);
+      resolved.push(moduleId);
+
+      return true;
+    };
+
+    for (const moduleId of targetIds) {
+      visit(moduleId);
+    }
+
+    return {
+      resolved: missing.length === 0 && circular.length === 0,
+      loadOrder: resolved,
+      missing: [...new Set(missing)],
+      circular: [...new Set(circular)],
+    };
+  }
+
+  // ---------------------------------------------------------------------------
+  // Module Loading
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Loads all discovered modules in dependency order.
+   *
+   * @returns Map of module IDs to load results
+   */
+  async loadAllModules(): Promise<Map<string, ModuleLoadResult>> {
+    const results = new Map<string, ModuleLoadResult>();
+    const resolution = this.resolveDependencies();
+
+    if (!resolution.resolved) {
+      // Report missing dependencies
+      for (const missing of resolution.missing) {
+        results.set(missing, {
+          success: false,
+          error: `Missing dependency: ${missing}`,
+        });
+      }
+
+      // Report circular dependencies
+      for (const circular of resolution.circular) {
+        results.set(circular, {
+          success: false,
+          error: `Circular dependency detected: ${circular}`,
+        });
+      }
+    }
+
+    // Load modules in resolved order
+    for (const moduleId of resolution.loadOrder) {
+      const result = await this.loadModule(moduleId);
+      results.set(moduleId, result);
+    }
+
+    return results;
+  }
+
+  /**
+   * Loads a single module by ID.
+   *
+   * @param moduleId - Module ID to load
+   * @returns Module load result
+   */
+  async loadModule(moduleId: string): Promise<ModuleLoadResult> {
+    const module = this.modules.get(moduleId);
+
+    if (!module) {
+      return {
+        success: false,
+        error: `Module not found: ${moduleId}`,
+      };
+    }
+
+    // Check if already loaded
+    if (module.status === 'loaded' || module.status === 'active') {
+      return { success: true, module };
+    }
+
+    try {
+      // Validate dependencies are loaded
+      for (const depId of module.manifest.dependencies.required) {
+        const dep = this.modules.get(depId);
+        if (!dep || (dep.status !== 'loaded' && dep.status !== 'active')) {
+          throw new Error(`Required dependency not loaded: ${depId}`);
+        }
+      }
+
+      // Try to load the module definition file
+      const moduleFilePath = path.join(module.path, `${module.manifest.id}.module.ts`);
+      const indexFilePath = path.join(module.path, 'index.ts');
+
+      let moduleInstance: ModuleInstance | undefined;
+
+      // Attempt to dynamically import the module (if exists)
+      const definitionPath = fs.existsSync(moduleFilePath)
+        ? moduleFilePath
+        : fs.existsSync(indexFilePath)
+          ? indexFilePath
+          : null;
+
+      if (definitionPath) {
+        try {
+          // Dynamic import for module instantiation
+          const moduleDefinition: ModuleDefinition = await import(definitionPath);
+
+          if (moduleDefinition.default) {
+            moduleInstance = new moduleDefinition.default();
+
+            // Call onLoad hook if exists
+            if (moduleInstance.onLoad) {
+              await moduleInstance.onLoad();
+            }
+          }
+        } catch {
+          // Module file exists but failed to import - log but don't fail
+          // This allows stub modules without implementation
+        }
+      }
+
+      // Update module state
+      module.status = 'loaded';
+      module.loadedAt = new Date();
+      module.instance = moduleInstance;
+
+      this.modules.set(moduleId, module);
+
+      return { success: true, module };
+    } catch (error) {
+      module.status = 'error';
+      module.error = error instanceof Error ? error.message : 'Unknown error';
+      this.modules.set(moduleId, module);
+
+      return {
+        success: false,
+        module,
+        error: module.error,
+      };
+    }
+  }
+
+  // ---------------------------------------------------------------------------
+  // Module Activation/Deactivation
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Activates a loaded module.
+   *
+   * @param moduleId - Module ID to activate
+   * @returns Success status
+   */
+  async activateModule(moduleId: string): Promise<boolean> {
+    const module = this.modules.get(moduleId);
+
+    if (!module) {
+      throw new Error(`Module not found: ${moduleId}`);
+    }
+
+    if (module.status !== 'loaded' && module.status !== 'disabled') {
+      throw new Error(`Module ${moduleId} is not in a loadable state (current: ${module.status})`);
+    }
+
+    try {
+      // Call onEnable hook if exists
+      if (module.instance?.onEnable) {
+        await module.instance.onEnable();
+      }
+
+      module.status = 'active';
+      this.modules.set(moduleId, module);
+
+      return true;
+    } catch (error) {
+      module.status = 'error';
+      module.error = error instanceof Error ? error.message : 'Activation failed';
+      this.modules.set(moduleId, module);
+      return false;
+    }
+  }
+
+  /**
+   * Deactivates an active module.
+   *
+   * @param moduleId - Module ID to deactivate
+   * @returns Success status
+   */
+  async deactivateModule(moduleId: string): Promise<boolean> {
+    const module = this.modules.get(moduleId);
+
+    if (!module) {
+      throw new Error(`Module not found: ${moduleId}`);
+    }
+
+    // Core modules cannot be deactivated
+    if (module.manifest.core) {
+      throw new Error(`Cannot deactivate core module: ${moduleId}`);
+    }
+
+    if (module.status !== 'active') {
+      throw new Error(`Module ${moduleId} is not active (current: ${module.status})`);
+    }
+
+    // Check if other active modules depend on this one
+    const dependents = this.getModuleDependents(moduleId);
+    const activeDependents = dependents.filter(
+      (depId) => this.modules.get(depId)?.status === 'active'
+    );
+
+    if (activeDependents.length > 0) {
+      throw new Error(
+        `Cannot deactivate ${moduleId}: other active modules depend on it: ${activeDependents.join(', ')}`
+      );
+    }
+
+    try {
+      // Call onDisable hook if exists
+      if (module.instance?.onDisable) {
+        await module.instance.onDisable();
+      }
+
+      module.status = 'disabled';
+      this.modules.set(moduleId, module);
+
+      return true;
+    } catch (error) {
+      module.status = 'error';
+      module.error = error instanceof Error ? error.message : 'Deactivation failed';
+      this.modules.set(moduleId, module);
+      return false;
+    }
+  }
+
+  // ---------------------------------------------------------------------------
+  // Module Queries
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets a loaded module by ID.
+   *
+   * @param moduleId - Module ID
+   * @returns Loaded module or undefined
+   */
+  getModule(moduleId: string): LoadedModule | undefined {
+    return this.modules.get(moduleId);
+  }
+
+  /**
+   * Gets all loaded modules.
+   *
+   * @returns Array of all loaded modules
+   */
+  getAllModules(): LoadedModule[] {
+    return Array.from(this.modules.values());
+  }
+
+  /**
+   * Gets modules by status.
+   *
+   * @param status - Module status to filter by
+   * @returns Array of modules with the specified status
+   */
+  getModulesByStatus(status: ModuleStatus): LoadedModule[] {
+    return this.getAllModules().filter((m) => m.status === status);
+  }
+
+  /**
+   * Gets modules by category.
+   *
+   * @param category - Module category to filter by
+   * @returns Array of modules in the specified category
+   */
+  getModulesByCategory(category: ModuleCategory): LoadedModule[] {
+    return this.getAllModules().filter((m) => m.manifest.category === category);
+  }
+
+  /**
+   * Gets active modules only.
+   *
+   * @returns Array of active modules
+   */
+  getActiveModules(): LoadedModule[] {
+    return this.getModulesByStatus('active');
+  }
+
+  /**
+   * Gets core modules.
+   *
+   * @returns Array of core modules
+   */
+  getCoreModules(): LoadedModule[] {
+    return this.getAllModules().filter((m) => m.manifest.core);
+  }
+
+  /**
+   * Gets modules that depend on a specific module.
+   *
+   * @param moduleId - Module ID to find dependents for
+   * @returns Array of module IDs that depend on the specified module
+   */
+  getModuleDependents(moduleId: string): string[] {
+    const dependents: string[] = [];
+
+    for (const [id, module] of this.modules) {
+      if (id === moduleId) continue;
+
+      const { required, optional } = module.manifest.dependencies;
+      if (required.includes(moduleId) || optional.includes(moduleId)) {
+        dependents.push(id);
+      }
+    }
+
+    return dependents;
+  }
+
+  /**
+   * Checks if a module is available (loaded and active).
+   *
+   * @param moduleId - Module ID to check
+   * @returns True if module is active
+   */
+  isModuleActive(moduleId: string): boolean {
+    const module = this.modules.get(moduleId);
+    return module?.status === 'active';
+  }
+
+  /**
+   * Gets all registered permissions from active modules.
+   *
+   * @returns Array of permission strings
+   */
+  getAllPermissions(): string[] {
+    const permissions: string[] = [];
+
+    for (const module of this.getActiveModules()) {
+      permissions.push(...module.manifest.permissions);
+    }
+
+    return [...new Set(permissions)];
+  }
+
+  /**
+   * Gets all admin menu items from active modules.
+   *
+   * @returns Array of admin menu configurations
+   */
+  getAdminMenuItems(): Array<{ moduleId: string; menu: NonNullable<ModuleManifest['admin']['menu']> }> {
+    const items: Array<{ moduleId: string; menu: NonNullable<ModuleManifest['admin']['menu']> }> = [];
+
+    for (const module of this.getActiveModules()) {
+      if (module.manifest.admin.menu) {
+        items.push({
+          moduleId: module.manifest.id,
+          menu: module.manifest.admin.menu,
+        });
+      }
+    }
+
+    // Sort by position
+    return items.sort((a, b) => a.menu.position - b.menu.position);
+  }
+
+  // ---------------------------------------------------------------------------
+  // Utility Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Resets the module registry.
+   * Use only in test environments.
+   */
+  reset(): void {
+    this.modules.clear();
+  }
+
+  /**
+   * Gets module loader statistics.
+   *
+   * @returns Module statistics
+   */
+  getStats(): {
+    total: number;
+    byStatus: Record<ModuleStatus, number>;
+    byCategory: Record<ModuleCategory, number>;
+  } {
+    const stats = {
+      total: this.modules.size,
+      byStatus: {} as Record<ModuleStatus, number>,
+      byCategory: {} as Record<ModuleCategory, number>,
+    };
+
+    // Initialize counters
+    for (const status of ModuleStatusSchema.options) {
+      stats.byStatus[status] = 0;
+    }
+    for (const category of ModuleCategorySchema.options) {
+      stats.byCategory[category] = 0;
+    }
+
+    // Count modules
+    for (const module of this.modules.values()) {
+      stats.byStatus[module.status]++;
+      stats.byCategory[module.manifest.category]++;
+    }
+
+    return stats;
+  }
+
+  /**
+   * Sets the base path for module discovery.
+   * Useful for testing with different module directories.
+   *
+   * @param basePath - New base path
+   */
+  setModulesBasePath(basePath: string): void {
+    this.modulesBasePath = basePath;
+  }
+
+  /**
+   * Gets the current modules base path.
+   *
+   * @returns Current base path
+   */
+  getModulesBasePath(): string {
+    return this.modulesBasePath;
+  }
+}
+
+// -----------------------------------------------------------------------------
+// Module Loader Singleton Helper
+// -----------------------------------------------------------------------------
+
+/**
+ * Creates and initializes a ModuleLoader instance.
+ * Use this for bootstrapping the application.
+ *
+ * @param prisma - Prisma client instance
+ * @returns Initialized ModuleLoader
+ *
+ * @example
+ * ```typescript
+ * const loader = createModuleLoader(prisma);
+ * await loader.discoverModules();
+ * await loader.loadAllModules();
+ * ```
+ */
+export function createModuleLoader(prisma: PrismaClient): ModuleLoader {
+  // Create instance directly (for bootstrap before DI is ready)
+  const loader = new ModuleLoader(prisma);
+  return loader;
+}
+
+// -----------------------------------------------------------------------------
+// Re-exports
+// -----------------------------------------------------------------------------
+
+export type {
+  LoadedModule,
+  ModuleInstance,
+  ModuleDefinition,
+  ModuleLoadResult,
+  DependencyResolutionResult,
+};

diff --git a/src/core/middleware/auth.middleware.ts b/src/core/middleware/auth.middleware.ts
new file mode 100644
index 0000000..9850e0a
--- /dev/null
+++ b/src/core/middleware/auth.middleware.ts
@@ -0,0 +1,587 @@
+/**
+ * JWT Authentication Middleware
+ *
+ * Handles JWT token verification and user authentication.
+ * Implements the security model from SECURITY_MODEL.md.
+ *
+ * @module core/middleware/auth
+ */
+
+import { Request, Response, NextFunction, RequestHandler } from 'express';
+import jwt, { JwtPayload, TokenExpiredError, JsonWebTokenError } from 'jsonwebtoken';
+import { env } from '@/config/env';
+import { AppException } from '@/core/exceptions/app.exception';
+
+// -----------------------------------------------------------------------------
+// Type Definitions
+// -----------------------------------------------------------------------------
+
+/**
+ * JWT Access Token Payload structure
+ * Follows SECURITY_MODEL.md specification
+ */
+export interface JwtTokenPayload extends JwtPayload {
+  /** User ID (sub claim) */
+  sub: string;
+  /** Organization ID */
+  org: string;
+  /** Primary role (e.g., 'owner', 'manager', 'staff', 'viewer') */
+  role: string;
+  /** Cached permissions array */
+  permissions: string[];
+  /** Token ID for revocation tracking */
+  jti: string;
+  /** Issued at timestamp */
+  iat: number;
+  /** Expiry timestamp */
+  exp: number;
+}
+
+/**
+ * Authenticated user context attached to Request
+ */
+export interface AuthUser {
+  /** User ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Primary role */
+  role: string;
+  /** Cached permissions */
+  permissions: string[];
+  /** Token ID */
+  tokenId: string;
+}
+
+/**
+ * Extended Express Request with authentication context
+ */
+export interface AuthenticatedRequest extends Request {
+  /** Authenticated user information */
+  user?: AuthUser;
+  /** JWT token payload */
+  tokenPayload?: JwtTokenPayload;
+}
+
+// -----------------------------------------------------------------------------
+// Token Verification
+// -----------------------------------------------------------------------------
+
+/**
+ * Verifies a JWT access token and returns the decoded payload.
+ * Uses HS256 algorithm with the JWT_SECRET from environment.
+ *
+ * @param token - JWT access token string
+ * @returns Decoded token payload
+ * @throws AppException for invalid/expired tokens
+ *
+ * @example
+ * ```typescript
+ * try {
+ *   const payload = verifyToken(token);
+ *   console.log(`User ID: ${payload.sub}`);
+ * } catch (error) {
+ *   // Handle invalid token
+ * }
+ * ```
+ */
+export function verifyToken(token: string): JwtTokenPayload {
+  try {
+    const payload = jwt.verify(token, env.JWT_SECRET, {
+      algorithms: ['HS256'],
+    }) as JwtTokenPayload;
+
+    // Validate required claims
+    if (!payload.sub || !payload.org || !payload.role) {
+      throw AppException.invalidToken();
+    }
+
+    return payload;
+  } catch (error) {
+    if (error instanceof TokenExpiredError) {
+      throw AppException.tokenExpired();
+    }
+
+    if (error instanceof JsonWebTokenError) {
+      throw AppException.invalidToken();
+    }
+
+    // Re-throw AppException as-is
+    if (error instanceof AppException) {
+      throw error;
+    }
+
+    // Wrap unknown errors
+    throw AppException.invalidToken();
+  }
+}
+
+/**
+ * Extracts the bearer token from the Authorization header.
+ *
+ * @param authHeader - Authorization header value
+ * @returns Token string or null if not found
+ *
+ * @example
+ * ```typescript
+ * const token = extractBearerToken('Bearer eyJhbGc...');
+ * // token = 'eyJhbGc...'
+ * ```
+ */
+export function extractBearerToken(authHeader: string | undefined): string | null {
+  if (!authHeader) {
+    return null;
+  }
+
+  const parts = authHeader.split(' ');
+
+  if (parts.length !== 2 || parts[0].toLowerCase() !== 'bearer') {
+    return null;
+  }
+
+  return parts[1];
+}
+
+// -----------------------------------------------------------------------------
+// Middleware Functions
+// -----------------------------------------------------------------------------
+
+/**
+ * Authentication middleware that requires a valid JWT token.
+ * Extracts user information from token and attaches to request.
+ *
+ * @throws AppException.unauthorized() when no token is provided
+ * @throws AppException.invalidToken() when token is malformed
+ * @throws AppException.tokenExpired() when token has expired
+ *
+ * @example
+ * ```typescript
+ * import { authMiddleware } from '@/core/middleware/auth.middleware';
+ *
+ * // Protect a route
+ * router.get('/protected', authMiddleware, (req, res) => {
+ *   const user = (req as AuthenticatedRequest).user;
+ *   res.json({ userId: user.id });
+ * });
+ * ```
+ */
+export const authMiddleware: RequestHandler = (
+  req: Request,
+  _res: Response,
+  next: NextFunction
+): void => {
+  try {
+    // Extract token from Authorization header
+    const token = extractBearerToken(req.headers.authorization);
+
+    if (!token) {
+      throw AppException.unauthorized('Authorization token required');
+    }
+
+    // Verify token and get payload
+    const payload = verifyToken(token);
+
+    // Attach user information to request
+    const authReq = req as AuthenticatedRequest;
+    authReq.user = {
+      id: payload.sub,
+      organizationId: payload.org,
+      role: payload.role,
+      permissions: payload.permissions || [],
+      tokenId: payload.jti,
+    };
+    authReq.tokenPayload = payload;
+
+    next();
+  } catch (error) {
+    next(error);
+  }
+};
+
+/**
+ * Optional authentication middleware that doesn't require a token.
+ * If a valid token is present, user info is attached to request.
+ * If no token or invalid token, request continues without user context.
+ *
+ * @example
+ * ```typescript
+ * import { optionalAuthMiddleware } from '@/core/middleware/auth.middleware';
+ *
+ * // Route accessible with or without authentication
+ * router.get('/menu/:slug', optionalAuthMiddleware, (req, res) => {
+ *   const user = (req as AuthenticatedRequest).user;
+ *   if (user) {
+ *     // Show personalized content
+ *   }
+ * });
+ * ```
+ */
+export const optionalAuthMiddleware: RequestHandler = (
+  req: Request,
+  _res: Response,
+  next: NextFunction
+): void => {
+  try {
+    // Extract token from Authorization header
+    const token = extractBearerToken(req.headers.authorization);
+
+    if (token) {
+      try {
+        // Verify token and get payload
+        const payload = verifyToken(token);
+
+        // Attach user information to request
+        const authReq = req as AuthenticatedRequest;
+        authReq.user = {
+          id: payload.sub,
+          organizationId: payload.org,
+          role: payload.role,
+          permissions: payload.permissions || [],
+          tokenId: payload.jti,
+        };
+        authReq.tokenPayload = payload;
+      } catch {
+        // Token is invalid - continue without user context
+        // This is intentional for optional auth
+      }
+    }
+
+    next();
+  } catch (error) {
+    // For optional auth, never fail - just continue
+    next();
+  }
+};
+
+/**
+ * Creates a middleware that requires specific roles.
+ * Must be used after authMiddleware.
+ *
+ * @param roles - Array of allowed roles
+ * @returns Express middleware function
+ * @throws AppException.forbidden() when user role is not in allowed roles
+ *
+ * @example
+ * ```typescript
+ * import { authMiddleware, requireRoles } from '@/core/middleware/auth.middleware';
+ *
+ * // Only allow owners and managers
+ * router.delete(
+ *   '/menu/:id',
+ *   authMiddleware,
+ *   requireRoles(['owner', 'manager']),
+ *   deleteMenuHandler
+ * );
+ * ```
+ */
+export function requireRoles(roles: string[]): RequestHandler {
+  return (req: Request, _res: Response, next: NextFunction): void => {
+    const authReq = req as AuthenticatedRequest;
+
+    if (!authReq.user) {
+      next(AppException.unauthorized('Authentication required'));
+      return;
+    }
+
+    if (!roles.includes(authReq.user.role)) {
+      next(AppException.forbidden(`Role '${authReq.user.role}' is not permitted for this action`));
+      return;
+    }
+
+    next();
+  };
+}
+
+/**
+ * Creates a middleware that requires specific permissions.
+ * Must be used after authMiddleware.
+ *
+ * @param permissions - Array of required permissions (all must be present)
+ * @returns Express middleware function
+ * @throws AppException.forbidden() when user lacks required permissions
+ *
+ * @example
+ * ```typescript
+ * import { authMiddleware, requirePermissions } from '@/core/middleware/auth.middleware';
+ *
+ * // Require menu.create permission
+ * router.post(
+ *   '/menu',
+ *   authMiddleware,
+ *   requirePermissions(['menu.create']),
+ *   createMenuHandler
+ * );
+ * ```
+ */
+export function requirePermissions(permissions: string[]): RequestHandler {
+  return (req: Request, _res: Response, next: NextFunction): void => {
+    const authReq = req as AuthenticatedRequest;
+
+    if (!authReq.user) {
+      next(AppException.unauthorized('Authentication required'));
+      return;
+    }
+
+    const userPermissions = authReq.user.permissions;
+    const missingPermissions = permissions.filter((p) => !userPermissions.includes(p));
+
+    if (missingPermissions.length > 0) {
+      next(AppException.forbidden(`Missing permissions: ${missingPermissions.join(', ')}`));
+      return;
+    }
+
+    next();
+  };
+}
+
+// -----------------------------------------------------------------------------
+// Token Generation Helpers
+// -----------------------------------------------------------------------------
+
+/**
+ * Options for generating JWT access tokens
+ */
+export interface GenerateTokenOptions {
+  /** User ID */
+  userId: string;
+  /** Organization ID */
+  organizationId: string;
+  /** User role */
+  role: string;
+  /** User permissions array */
+  permissions: string[];
+  /** Token ID for revocation tracking */
+  tokenId: string;
+}
+
+/**
+ * Generates a JWT access token.
+ * Access tokens are short-lived (default 15 minutes).
+ *
+ * @param options - Token generation options
+ * @returns Signed JWT access token
+ *
+ * @example
+ * ```typescript
+ * const token = generateAccessToken({
+ *   userId: 'usr_123',
+ *   organizationId: 'org_456',
+ *   role: 'owner',
+ *   permissions: ['menu.view', 'menu.create'],
+ *   tokenId: 'tok_789',
+ * });
+ * ```
+ */
+export function generateAccessToken(options: GenerateTokenOptions): string {
+  const payload: Omit<JwtTokenPayload, 'iat' | 'exp'> = {
+    sub: options.userId,
+    org: options.organizationId,
+    role: options.role,
+    permissions: options.permissions,
+    jti: options.tokenId,
+  };
+
+  return jwt.sign(payload, env.JWT_SECRET, {
+    algorithm: 'HS256',
+    expiresIn: env.JWT_ACCESS_EXPIRY,
+  });
+}
+
+/**
+ * Generates a JWT refresh token.
+ * Refresh tokens are longer-lived (default 7 days) and used to obtain new access tokens.
+ *
+ * @param userId - User ID
+ * @param tokenId - Token ID for revocation tracking
+ * @returns Signed JWT refresh token
+ *
+ * @example
+ * ```typescript
+ * const refreshToken = generateRefreshToken('usr_123', 'rtok_456');
+ * // Store in httpOnly cookie
+ * res.cookie('refreshToken', refreshToken, { httpOnly: true, secure: true });
+ * ```
+ */
+export function generateRefreshToken(userId: string, tokenId: string): string {
+  const payload = {
+    sub: userId,
+    jti: tokenId,
+    type: 'refresh',
+  };
+
+  return jwt.sign(payload, env.JWT_REFRESH_SECRET, {
+    algorithm: 'HS256',
+    expiresIn: env.JWT_REFRESH_EXPIRY,
+  });
+}
+
+/**
+ * Refresh token payload structure
+ */
+export interface RefreshTokenPayload extends JwtPayload {
+  /** User ID */
+  sub: string;
+  /** Token ID */
+  jti: string;
+  /** Token type marker */
+  type: 'refresh';
+}
+
+/**
+ * Verifies a JWT refresh token.
+ *
+ * @param token - Refresh token string
+ * @returns Decoded refresh token payload
+ * @throws AppException for invalid/expired tokens
+ *
+ * @example
+ * ```typescript
+ * try {
+ *   const payload = verifyRefreshToken(refreshToken);
+ *   // Issue new access token for payload.sub
+ * } catch (error) {
+ *   // Redirect to login
+ * }
+ * ```
+ */
+export function verifyRefreshToken(token: string): RefreshTokenPayload {
+  try {
+    const payload = jwt.verify(token, env.JWT_REFRESH_SECRET, {
+      algorithms: ['HS256'],
+    }) as RefreshTokenPayload;
+
+    // Validate token type
+    if (payload.type !== 'refresh') {
+      throw AppException.invalidToken();
+    }
+
+    if (!payload.sub || !payload.jti) {
+      throw AppException.invalidToken();
+    }
+
+    return payload;
+  } catch (error) {
+    if (error instanceof TokenExpiredError) {
+      throw new AppException('INVALID_REFRESH_TOKEN', 401, {
+        message: 'Refresh token has expired',
+      });
+    }
+
+    if (error instanceof JsonWebTokenError) {
+      throw new AppException('INVALID_REFRESH_TOKEN', 401, {
+        message: 'Invalid refresh token',
+      });
+    }
+
+    if (error instanceof AppException) {
+      throw error;
+    }
+
+    throw new AppException('INVALID_REFRESH_TOKEN', 401, {
+      message: 'Invalid refresh token',
+    });
+  }
+}
+
+// -----------------------------------------------------------------------------
+// Utility Functions
+// -----------------------------------------------------------------------------
+
+/**
+ * Gets the authenticated user from request.
+ * Throws if user is not authenticated.
+ *
+ * @param req - Express request object
+ * @returns Authenticated user context
+ * @throws AppException.unauthorized() if not authenticated
+ *
+ * @example
+ * ```typescript
+ * const user = getAuthUser(req);
+ * const menus = await menuService.findAll(user.organizationId);
+ * ```
+ */
+export function getAuthUser(req: Request): AuthUser {
+  const authReq = req as AuthenticatedRequest;
+
+  if (!authReq.user) {
+    throw AppException.unauthorized('Authentication required');
+  }
+
+  return authReq.user;
+}
+
+/**
+ * Gets the authenticated user from request, or undefined if not authenticated.
+ *
+ * @param req - Express request object
+ * @returns Authenticated user context or undefined
+ *
+ * @example
+ * ```typescript
+ * const user = getAuthUserOptional(req);
+ * if (user) {
+ *   // Show personalized content
+ * }
+ * ```
+ */
+export function getAuthUserOptional(req: Request): AuthUser | undefined {
+  return (req as AuthenticatedRequest).user;
+}
+
+/**
+ * Checks if the request has a specific permission.
+ *
+ * @param req - Express request object
+ * @param permission - Permission to check
+ * @returns True if user has the permission
+ *
+ * @example
+ * ```typescript
+ * if (hasPermission(req, 'menu.delete')) {
+ *   // Show delete button
+ * }
+ * ```
+ */
+export function hasPermission(req: Request, permission: string): boolean {
+  const user = getAuthUserOptional(req);
+  return user ? user.permissions.includes(permission) : false;
+}
+
+/**
+ * Checks if the request has a specific role.
+ *
+ * @param req - Express request object
+ * @param role - Role to check
+ * @returns True if user has the role
+ *
+ * @example
+ * ```typescript
+ * if (hasRole(req, 'owner')) {
+ *   // Show admin controls
+ * }
+ * ```
+ */
+export function hasRole(req: Request, role: string): boolean {
+  const user = getAuthUserOptional(req);
+  return user ? user.role === role : false;
+}
+
+/**
+ * Checks if the request user has any of the specified roles.
+ *
+ * @param req - Express request object
+ * @param roles - Roles to check
+ * @returns True if user has any of the roles
+ *
+ * @example
+ * ```typescript
+ * if (hasAnyRole(req, ['owner', 'manager'])) {
+ *   // Show management controls
+ * }
+ * ```
+ */
+export function hasAnyRole(req: Request, roles: string[]): boolean {
+  const user = getAuthUserOptional(req);
+  return user ? roles.includes(user.role) : false;
+}

