+/**
+ * Rate Limiting Middleware
+ *
+ * Implements request rate limiting using Redis-backed sliding window algorithm.
+ * Follows the rate limit specifications from CONSTRAINTS.md section 2.4.
+ *
+ * Rate Limits:
+ * - Public endpoints: 60 requests/minute
+ * - Authenticated users: 300 requests/minute
+ * - Webhook endpoints: 10 requests/minute
+ *
+ * @module core/middleware/rate-limit
+ */
+
+import { Request, Response, NextFunction, RequestHandler } from 'express';
+import { RateLimiterRedis, RateLimiterRes, IRateLimiterOptions } from 'rate-limiter-flexible';
+import { redis } from '@/config/redis';
+import { AppException } from '@/core/exceptions/app.exception';
+import { AuthenticatedRequest, AuthUser } from '@/core/middleware/auth.middleware';
+
+// -----------------------------------------------------------------------------
+// Type Definitions
+// -----------------------------------------------------------------------------
+
+/**
+ * Rate limit tier configuration
+ */
+export type RateLimitTier = 'public' | 'authenticated' | 'webhook' | 'custom';
+
+/**
+ * Rate limit configuration options
+ */
+export interface RateLimitOptions {
+  /** Maximum number of requests allowed */
+  points: number;
+  /** Time window in seconds */
+  duration: number;
+  /** Key prefix for Redis storage */
+  keyPrefix: string;
+  /** Custom key generator function */
+  keyGenerator?: (req: Request) => string;
+  /** Whether to skip rate limiting for certain requests */
+  skip?: (req: Request) => boolean;
+  /** Custom handler for rate limit exceeded */
+  handler?: (req: Request, res: Response, next: NextFunction, retryAfter: number) => void;
+  /** Block duration in seconds when limit exceeded (0 = no blocking) */
+  blockDuration?: number;
+}
+
+/**
+ * Rate limit info attached to response headers
+ */
+export interface RateLimitInfo {
+  /** Maximum requests allowed */
+  limit: number;
+  /** Remaining requests in current window */
+  remaining: number;
+  /** Timestamp when rate limit resets */
+  resetTime: Date;
+  /** Retry after seconds (only when limited) */
+  retryAfter?: number;
+}
+
+/**
+ * Extended request with rate limit info
+ */
+export interface RateLimitedRequest extends Request {
+  /** Rate limit information for the current request */
+  rateLimit?: RateLimitInfo;
+}
+
+// -----------------------------------------------------------------------------
+// Default Configurations
+// -----------------------------------------------------------------------------
+
+/**
+ * Default rate limit configurations per tier
+ * Based on CONSTRAINTS.md API Rate Limiting section
+ */
+export const RATE_LIMIT_DEFAULTS: Record<RateLimitTier, Omit<RateLimitOptions, 'keyPrefix'>> = {
+  /** Public endpoints: 60 requests per minute */
+  public: {
+    points: 60,
+    duration: 60,
+    blockDuration: 0,
+  },
+  /** Authenticated users: 300 requests per minute */
+  authenticated: {
+    points: 300,
+    duration: 60,
+    blockDuration: 0,
+  },
+  /** Webhook endpoints: 10 requests per minute (stricter) */
+  webhook: {
+    points: 10,
+    duration: 60,
+    blockDuration: 60, // Block for 1 minute when exceeded
+  },
+  /** Custom tier - uses provided options */
+  custom: {
+    points: 100,
+    duration: 60,
+    blockDuration: 0,
+  },
+};
+
+// -----------------------------------------------------------------------------
+// Rate Limiter Instances
+// -----------------------------------------------------------------------------
+
+/**
+ * Cache for rate limiter instances by key prefix
+ */
+const rateLimiterCache = new Map<string, RateLimiterRedis>();
+
+/**
+ * Creates or retrieves a rate limiter instance
+ *
+ * @param options - Rate limiter configuration
+ * @returns RateLimiterRedis instance
+ */
+function getRateLimiter(options: RateLimitOptions): RateLimiterRedis {
+  const cacheKey = `${options.keyPrefix}:${options.points}:${options.duration}`;
+
+  let limiter = rateLimiterCache.get(cacheKey);
+  if (limiter) {
+    return limiter;
+  }
+
+  const limiterOptions: IRateLimiterOptions = {
+    storeClient: redis,
+    keyPrefix: options.keyPrefix,
+    points: options.points,
+    duration: options.duration,
+    blockDuration: options.blockDuration || 0,
+    inmemoryBlockOnConsumed: options.points + 1,
+    insuranceLimiter: undefined, // Will use memory fallback if Redis fails
+  };
+
+  limiter = new RateLimiterRedis(limiterOptions);
+  rateLimiterCache.set(cacheKey, limiter);
+
+  return limiter;
+}
+
+// -----------------------------------------------------------------------------
+// Key Generators
+// -----------------------------------------------------------------------------
+
+/**
+ * Generates rate limit key based on IP address
+ *
+ * @param req - Express request object
+ * @returns Rate limit key
+ */
+export function generateIpKey(req: Request): string {
+  // Check for forwarded IP (behind proxy/load balancer)
+  const forwarded = req.headers['x-forwarded-for'];
+  const ip = forwarded
+    ? (Array.isArray(forwarded) ? forwarded[0] : forwarded.split(',')[0]).trim()
+    : req.ip || req.socket.remoteAddress || 'unknown';
+
+  return `ip:${ip}`;
+}
+
+/**
+ * Generates rate limit key based on authenticated user ID
+ *
+ * @param req - Express request object
+ * @returns Rate limit key based on user ID or IP
+ */
+export function generateUserKey(req: Request): string {
+  const authReq = req as AuthenticatedRequest;
+  if (authReq.user?.id) {
+    return `user:${authReq.user.id}`;
+  }
+  // Fallback to IP if user not authenticated
+  return generateIpKey(req);
+}
+
+/**
+ * Generates rate limit key based on organization ID
+ *
+ * @param req - Express request object
+ * @returns Rate limit key based on organization ID or IP
+ */
+export function generateOrgKey(req: Request): string {
+  const authReq = req as AuthenticatedRequest;
+  if (authReq.user?.organizationId) {
+    return `org:${authReq.user.organizationId}`;
+  }
+  // Fallback to IP if organization not set
+  return generateIpKey(req);
+}
+
+/**
+ * Generates rate limit key based on endpoint path
+ *
+ * @param req - Express request object
+ * @returns Rate limit key based on path + IP/user
+ */
+export function generateEndpointKey(req: Request): string {
+  const authReq = req as AuthenticatedRequest;
+  const path = req.path.replace(/\/[a-f0-9-]{36}/gi, '/:id'); // Normalize UUIDs
+  const identifier = authReq.user?.id || generateIpKey(req);
+  return `endpoint:${req.method}:${path}:${identifier}`;
+}
+
+// -----------------------------------------------------------------------------
+// Middleware Functions
+// -----------------------------------------------------------------------------
+
+/**
+ * Creates a rate limiting middleware with custom options.
+ *
+ * @param options - Rate limit configuration
+ * @returns Express middleware function
+ *
+ * @example
+ * ```typescript
+ * import { createRateLimiter } from '@/core/middleware/rate-limit.middleware';
+ *
+ * // Custom rate limit: 10 requests per 5 minutes
+ * const strictLimit = createRateLimiter({
+ *   points: 10,
+ *   duration: 300,
+ *   keyPrefix: 'ratelimit:strict',
+ * });
+ *
+ * router.post('/sensitive-action', strictLimit, handler);
+ * ```
+ */
+export function createRateLimiter(options: RateLimitOptions): RequestHandler {
+  return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
+    try {
+      // Check if request should skip rate limiting
+      if (options.skip?.(req)) {
+        next();
+        return;
+      }
+
+      // Get rate limiter instance
+      const limiter = getRateLimiter(options);
+
+      // Generate key for this request
+      const keyGenerator = options.keyGenerator || generateIpKey;
+      const key = keyGenerator(req);
+
+      try {
+        // Try to consume a point
+        const rateLimiterRes = await limiter.consume(key);
+
+        // Attach rate limit info to request
+        const rateLimitedReq = req as RateLimitedRequest;
+        rateLimitedReq.rateLimit = {
+          limit: options.points,
+          remaining: rateLimiterRes.remainingPoints,
+          resetTime: new Date(Date.now() + rateLimiterRes.msBeforeNext),
+        };
+
+        // Set rate limit headers
+        setRateLimitHeaders(res, rateLimitedReq.rateLimit);
+
+        next();
+      } catch (rejRes) {
+        // Rate limit exceeded
+        if (rejRes instanceof RateLimiterRes) {
+          const retryAfter = Math.ceil(rejRes.msBeforeNext / 1000);
+
+          // Attach rate limit info to request
+          const rateLimitedReq = req as RateLimitedRequest;
+          rateLimitedReq.rateLimit = {
+            limit: options.points,
+            remaining: 0,
+            resetTime: new Date(Date.now() + rejRes.msBeforeNext),
+            retryAfter,
+          };
+
+          // Set rate limit headers
+          setRateLimitHeaders(res, rateLimitedReq.rateLimit);
+
+          // Use custom handler or default
+          if (options.handler) {
+            options.handler(req, res, next, retryAfter);
+          } else {
+            next(AppException.rateLimited(retryAfter));
+          }
+        } else {
+          // Unexpected error - let request through but log
+          next();
+        }
+      }
+    } catch (error) {
+      // On error, fail open (let request through)
+      // This prevents rate limiting issues from blocking all traffic
+      next();
+    }
+  };
+}
+
+/**
+ * Rate limiting middleware for public endpoints.
+ * Limits: 60 requests per minute per IP
+ *
+ * @example
+ * ```typescript
+ * import { rateLimit } from '@/core/middleware/rate-limit.middleware';
+ *
+ * // Apply to public routes
+ * router.get('/menu/:slug', rateLimit.public, getPublicMenuHandler);
+ * ```
+ */
+export const rateLimitPublic: RequestHandler = createRateLimiter({
+  ...RATE_LIMIT_DEFAULTS.public,
+  keyPrefix: 'ratelimit:public',
+  keyGenerator: generateIpKey,
+});
+
+/**
+ * Rate limiting middleware for authenticated endpoints.
+ * Limits: 300 requests per minute per user
+ *
+ * @example
+ * ```typescript
+ * import { rateLimit } from '@/core/middleware/rate-limit.middleware';
+ *
+ * // Apply to authenticated routes
+ * router.get('/api/v1/menus', authMiddleware, rateLimit.authenticated, getMenusHandler);
+ * ```
+ */
+export const rateLimitAuthenticated: RequestHandler = createRateLimiter({
+  ...RATE_LIMIT_DEFAULTS.authenticated,
+  keyPrefix: 'ratelimit:auth',
+  keyGenerator: generateUserKey,
+});
+
+/**
+ * Rate limiting middleware for webhook endpoints.
+ * Limits: 10 requests per minute per IP, 1 minute block on exceed
+ *
+ * @example
+ * ```typescript
+ * import { rateLimit } from '@/core/middleware/rate-limit.middleware';
+ *
+ * // Apply to webhook routes
+ * router.post('/webhooks/payment', rateLimit.webhook, paymentWebhookHandler);
+ * ```
+ */
+export const rateLimitWebhook: RequestHandler = createRateLimiter({
+  ...RATE_LIMIT_DEFAULTS.webhook,
+  keyPrefix: 'ratelimit:webhook',
+  keyGenerator: generateIpKey,
+});
+
+/**
+ * Rate limiting middleware for organization-scoped endpoints.
+ * Limits: 300 requests per minute per organization
+ *
+ * @example
+ * ```typescript
+ * import { rateLimit } from '@/core/middleware/rate-limit.middleware';
+ *
+ * // Apply to organization routes
+ * router.get('/api/v1/orders', authMiddleware, tenantMiddleware, rateLimit.organization, getOrdersHandler);
+ * ```
+ */
+export const rateLimitOrganization: RequestHandler = createRateLimiter({
+  ...RATE_LIMIT_DEFAULTS.authenticated,
+  keyPrefix: 'ratelimit:org',
+  keyGenerator: generateOrgKey,
+});
+
+/**
+ * Rate limiting namespace for convenient access
+ *
+ * @example
+ * ```typescript
+ * import { rateLimit } from '@/core/middleware/rate-limit.middleware';
+ *
+ * app.use('/api/v1/public', rateLimit.public);
+ * app.use('/api/v1', authMiddleware, rateLimit.authenticated);
+ * ```
+ */
+export const rateLimit = {
+  public: rateLimitPublic,
+  authenticated: rateLimitAuthenticated,
+  webhook: rateLimitWebhook,
+  organization: rateLimitOrganization,
+  custom: createRateLimiter,
+};
+
+// -----------------------------------------------------------------------------
+// Specialized Rate Limiters
+// -----------------------------------------------------------------------------
+
+/**
+ * Creates a strict rate limiter for sensitive operations.
+ * Use for login attempts, password resets, etc.
+ *
+ * @param options - Partial rate limit options to override defaults
+ * @returns Express middleware function
+ *
+ * @example
+ * ```typescript
+ * import { createStrictRateLimiter } from '@/core/middleware/rate-limit.middleware';
+ *
+ * // 5 login attempts per 15 minutes
+ * const loginLimiter = createStrictRateLimiter({
+ *   points: 5,
+ *   duration: 900,
+ *   blockDuration: 900,
+ * });
+ *
+ * router.post('/auth/login', loginLimiter, loginHandler);
+ * ```
+ */
+export function createStrictRateLimiter(
+  options: Partial<RateLimitOptions> = {}
+): RequestHandler {
+  return createRateLimiter({
+    points: options.points ?? 5,
+    duration: options.duration ?? 900, // 15 minutes
+    keyPrefix: options.keyPrefix ?? 'ratelimit:strict',
+    keyGenerator: options.keyGenerator ?? generateIpKey,
+    blockDuration: options.blockDuration ?? 900, // Block for 15 minutes
+    skip: options.skip,
+    handler: options.handler,
+  });
+}
+
+/**
+ * Creates a rate limiter for file upload endpoints.
+ *
+ * @param options - Partial rate limit options to override defaults
+ * @returns Express middleware function
+ *
+ * @example
+ * ```typescript
+ * import { createUploadRateLimiter } from '@/core/middleware/rate-limit.middleware';
+ *
+ * // 10 uploads per minute per user
+ * router.post('/media/upload', authMiddleware, createUploadRateLimiter(), uploadHandler);
+ * ```
+ */
+export function createUploadRateLimiter(
+  options: Partial<RateLimitOptions> = {}
+): RequestHandler {
+  return createRateLimiter({
+    points: options.points ?? 10,
+    duration: options.duration ?? 60,
+    keyPrefix: options.keyPrefix ?? 'ratelimit:upload',
+    keyGenerator: options.keyGenerator ?? generateUserKey,
+    blockDuration: options.blockDuration ?? 60,
+    skip: options.skip,
+    handler: options.handler,
+  });
+}
+
+/**
+ * Creates a rate limiter for AI/expensive operations.
+ *
+ * @param options - Partial rate limit options to override defaults
+ * @returns Express middleware function
+ *
+ * @example
+ * ```typescript
+ * import { createAIRateLimiter } from '@/core/middleware/rate-limit.middleware';
+ *
+ * // 30 AI requests per hour per organization
+ * router.post('/ai/generate', authMiddleware, tenantMiddleware, createAIRateLimiter(), aiGenerateHandler);
+ * ```
+ */
+export function createAIRateLimiter(
+  options: Partial<RateLimitOptions> = {}
+): RequestHandler {
+  return createRateLimiter({
+    points: options.points ?? 30,
+    duration: options.duration ?? 3600, // 1 hour
+    keyPrefix: options.keyPrefix ?? 'ratelimit:ai',
+    keyGenerator: options.keyGenerator ?? generateOrgKey,
+    blockDuration: options.blockDuration ?? 0,
+    skip: options.skip,
+    handler: options.handler,
+  });
+}
+
+// -----------------------------------------------------------------------------
+// Response Headers
+// -----------------------------------------------------------------------------
+
+/**
+ * Sets standard rate limit headers on response.
+ *
+ * @param res - Express response object
+ * @param info - Rate limit information
+ */
+export function setRateLimitHeaders(res: Response, info: RateLimitInfo): void {
+  res.setHeader('X-RateLimit-Limit', info.limit.toString());
+  res.setHeader('X-RateLimit-Remaining', info.remaining.toString());
+  res.setHeader('X-RateLimit-Reset', Math.floor(info.resetTime.getTime() / 1000).toString());
+
+  if (info.retryAfter !== undefined) {
+    res.setHeader('Retry-After', info.retryAfter.toString());
+  }
+}
+
+// -----------------------------------------------------------------------------
+// Utility Functions
+// -----------------------------------------------------------------------------
+
+/**
+ * Gets rate limit info from request.
+ *
+ * @param req - Express request object
+ * @returns Rate limit info or undefined if not set
+ *
+ * @example
+ * ```typescript
+ * const rateLimitInfo = getRateLimitInfo(req);
+ * if (rateLimitInfo && rateLimitInfo.remaining < 10) {
+ *   // Warn user about approaching rate limit
+ * }
+ * ```
+ */
+export function getRateLimitInfo(req: Request): RateLimitInfo | undefined {
+  return (req as RateLimitedRequest).rateLimit;
+}
+
+/**
+ * Checks if request is rate limited.
+ *
+ * @param req - Express request object
+ * @returns True if rate limited
+ */
+export function isRateLimited(req: Request): boolean {
+  const info = getRateLimitInfo(req);
+  return info ? info.remaining === 0 && info.retryAfter !== undefined : false;
+}
+
+/**
+ * Clears rate limit for a specific key.
+ * Useful for resetting after successful authentication.
+ *
+ * @param keyPrefix - Rate limiter key prefix
+ * @param key - Specific key to clear
+ *
+ * @example
+ * ```typescript
+ * // Clear login rate limit after successful login
+ * await clearRateLimit('ratelimit:strict', `ip:${req.ip}`);
+ * ```
+ */
+export async function clearRateLimit(keyPrefix: string, key: string): Promise<void> {
+  try {
+    await redis.del(`${keyPrefix}:${key}`);
+  } catch {
+    // Silently fail - rate limit will naturally expire
+  }
+}
+
+/**
+ * Clears all rate limiters from cache.
+ * Useful for testing and server shutdown.
+ */
+export function clearRateLimiterCache(): void {
+  rateLimiterCache.clear();
+}
+
+/**
+ * Creates a skip function based on paths.
+ *
+ * @param paths - Array of paths or path patterns to skip
+ * @returns Skip function for rate limiter
+ *
+ * @example
+ * ```typescript
+ * const limiter = createRateLimiter({
+ *   ...RATE_LIMIT_DEFAULTS.public,
+ *   keyPrefix: 'ratelimit:api',
+ *   skip: skipPaths(['/health', '/ready', '/api/docs']),
+ * });
+ * ```
+ */
+export function skipPaths(paths: string[]): (req: Request) => boolean {
+  return (req: Request): boolean => {
+    return paths.some((path) => {
+      if (path.endsWith('*')) {
+        return req.path.startsWith(path.slice(0, -1));
+      }
+      return req.path === path;
+    });
+  };
+}
+
+/**
+ * Creates a skip function that skips for whitelisted IPs.
+ *
+ * @param ips - Array of IP addresses to whitelist
+ * @returns Skip function for rate limiter
+ *
+ * @example
+ * ```typescript
+ * const limiter = createRateLimiter({
+ *   ...RATE_LIMIT_DEFAULTS.public,
+ *   keyPrefix: 'ratelimit:api',
+ *   skip: skipIps(['127.0.0.1', '::1']),
+ * });
+ * ```
+ */
+export function skipIps(ips: string[]): (req: Request) => boolean {
+  return (req: Request): boolean => {
+    const forwarded = req.headers['x-forwarded-for'];
+    const clientIp = forwarded
+      ? (Array.isArray(forwarded) ? forwarded[0] : forwarded.split(',')[0]).trim()
+      : req.ip || req.socket.remoteAddress || '';
+
+    return ips.includes(clientIp);
+  };
+}
+
+/**
+ * Combines multiple skip functions with OR logic.
+ *
+ * @param skipFns - Array of skip functions
+ * @returns Combined skip function
+ *
+ * @example
+ * ```typescript
+ * const limiter = createRateLimiter({
+ *   ...RATE_LIMIT_DEFAULTS.public,
+ *   keyPrefix: 'ratelimit:api',
+ *   skip: combineSkipFunctions([
+ *     skipPaths(['/health', '/ready']),
+ *     skipIps(['127.0.0.1']),
+ *   ]),
+ * });
+ * ```
+ */
+export function combineSkipFunctions(
+  skipFns: Array<(req: Request) => boolean>
+): (req: Request) => boolean {
+  return (req: Request): boolean => {
+    return skipFns.some((fn) => fn(req));
+  };
+}

diff --git a/src/core/middleware/tenant.middleware.ts b/src/core/middleware/tenant.middleware.ts
new file mode 100644
index 0000000..93536a5
--- /dev/null
+++ b/src/core/middleware/tenant.middleware.ts
@@ -0,0 +1,674 @@
+/**
+ * Tenant Context Middleware
+ *
+ * Handles multi-tenant context resolution and organization loading.
+ * Implements the multi-tenancy model from DATABASE_SCHEMA.md section 4.
+ *
+ * This middleware:
+ * 1. Extracts organizationId from authenticated user (set by auth middleware)
+ * 2. Loads the full organization entity from database
+ * 3. Validates organization is active and not suspended/deleted
+ * 4. Attaches organization to request for use in services/controllers
+ *
+ * @module core/middleware/tenant
+ */
+
+import { Request, Response, NextFunction, RequestHandler } from 'express';
+import { prisma, notDeleted } from '@/config/database';
+import { AppException } from '@/core/exceptions/app.exception';
+import { AuthenticatedRequest, AuthUser } from '@/core/middleware/auth.middleware';
+
+// -----------------------------------------------------------------------------
+// Type Definitions
+// -----------------------------------------------------------------------------
+
+/**
+ * Organization status enum (matches Prisma enum)
+ */
+export type OrganizationStatus = 'ACTIVE' | 'SUSPENDED' | 'DELETED';
+
+/**
+ * Organization entity attached to request
+ * Contains the full organization data from database
+ */
+export interface TenantOrganization {
+  /** Organization ID (CUID) */
+  id: string;
+  /** Organization display name */
+  name: string;
+  /** URL-safe slug (unique) */
+  slug: string;
+  /** Primary contact email */
+  email: string;
+  /** Contact phone (optional) */
+  phone: string | null;
+  /** Logo URL (optional) */
+  logo: string | null;
+  /** Organization settings (JSON) */
+  settings: Record<string, unknown>;
+  /** Organization status */
+  status: OrganizationStatus;
+  /** Subscription plan ID (optional) */
+  planId: string | null;
+  /** Trial end date (optional) */
+  trialEndsAt: Date | null;
+  /** Creation timestamp */
+  createdAt: Date;
+  /** Last update timestamp */
+  updatedAt: Date;
+}
+
+/**
+ * Extended Express Request with tenant context
+ * Extends AuthenticatedRequest to include organization
+ */
+export interface TenantRequest extends AuthenticatedRequest {
+  /** Authenticated user information */
+  user: AuthUser;
+  /** Current organization (tenant) context */
+  organization: TenantOrganization;
+}
+
+/**
+ * Extended Express Request with optional tenant context
+ * Used for routes that may or may not have tenant context
+ */
+export interface OptionalTenantRequest extends AuthenticatedRequest {
+  /** Authenticated user information (optional) */
+  user?: AuthUser;
+  /** Current organization (tenant) context (optional) */
+  organization?: TenantOrganization;
+}
+
+// -----------------------------------------------------------------------------
+// Organization Cache (Simple in-memory, replace with Redis in production)
+// -----------------------------------------------------------------------------
+
+/**
+ * Simple in-memory organization cache
+ * TTL: 5 minutes (300000ms)
+ *
+ * In production, this should be replaced with Redis cache
+ * using the cache helpers from redis.ts
+ */
+const organizationCache = new Map<
+  string,
+  { data: TenantOrganization; expiresAt: number }
+>();
+const CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes
+
+/**
+ * Gets an organization from cache if valid
+ */
+function getCachedOrganization(orgId: string): TenantOrganization | null {
+  const cached = organizationCache.get(orgId);
+  if (cached && cached.expiresAt > Date.now()) {
+    return cached.data;
+  }
+  // Remove expired entry
+  if (cached) {
+    organizationCache.delete(orgId);
+  }
+  return null;
+}
+
+/**
+ * Sets an organization in cache
+ */
+function setCachedOrganization(org: TenantOrganization): void {
+  organizationCache.set(org.id, {
+    data: org,
+    expiresAt: Date.now() + CACHE_TTL_MS,
+  });
+}
+
+/**
+ * Invalidates an organization from cache
+ * Call this when organization is updated
+ */
+export function invalidateOrganizationCache(orgId: string): void {
+  organizationCache.delete(orgId);
+}
+
+/**
+ * Clears the entire organization cache
+ * Call this on server shutdown or for testing
+ */
+export function clearOrganizationCache(): void {
+  organizationCache.clear();
+}
+
+// -----------------------------------------------------------------------------
+// Organization Loading
+// -----------------------------------------------------------------------------
+
+/**
+ * Loads an organization from database by ID
+ *
+ * @param orgId - Organization ID to load
+ * @param useCache - Whether to use cache (default: true)
+ * @returns Organization entity or null if not found
+ *
+ * @example
+ * ```typescript
+ * const org = await loadOrganization('org_123');
+ * if (!org) {
+ *   throw AppException.tenantNotFound('org_123');
+ * }
+ * ```
+ */
+export async function loadOrganization(
+  orgId: string,
+  useCache: boolean = true
+): Promise<TenantOrganization | null> {
+  // Check cache first
+  if (useCache) {
+    const cached = getCachedOrganization(orgId);
+    if (cached) {
+      return cached;
+    }
+  }
+
+  // Load from database
+  const organization = await prisma.organization.findFirst({
+    where: {
+      id: orgId,
+      ...notDeleted,
+    },
+    select: {
+      id: true,
+      name: true,
+      slug: true,
+      email: true,
+      phone: true,
+      logo: true,
+      settings: true,
+      status: true,
+      planId: true,
+      trialEndsAt: true,
+      createdAt: true,
+      updatedAt: true,
+    },
+  });
+
+  if (!organization) {
+    return null;
+  }
+
+  // Transform to TenantOrganization type
+  const tenantOrg: TenantOrganization = {
+    id: organization.id,
+    name: organization.name,
+    slug: organization.slug,
+    email: organization.email,
+    phone: organization.phone,
+    logo: organization.logo,
+    settings: organization.settings as Record<string, unknown>,
+    status: organization.status as OrganizationStatus,
+    planId: organization.planId,
+    trialEndsAt: organization.trialEndsAt,
+    createdAt: organization.createdAt,
+    updatedAt: organization.updatedAt,
+  };
+
+  // Cache the result
+  if (useCache) {
+    setCachedOrganization(tenantOrg);
+  }
+
+  return tenantOrg;
+}
+
+/**
+ * Loads an organization from database by slug
+ *
+ * @param slug - Organization slug to load
+ * @returns Organization entity or null if not found
+ *
+ * @example
+ * ```typescript
+ * const org = await loadOrganizationBySlug('my-restaurant');
+ * ```
+ */
+export async function loadOrganizationBySlug(
+  slug: string
+): Promise<TenantOrganization | null> {
+  const organization = await prisma.organization.findFirst({
+    where: {
+      slug,
+      ...notDeleted,
+    },
+    select: {
+      id: true,
+      name: true,
+      slug: true,
+      email: true,
+      phone: true,
+      logo: true,
+      settings: true,
+      status: true,
+      planId: true,
+      trialEndsAt: true,
+      createdAt: true,
+      updatedAt: true,
+    },
+  });
+
+  if (!organization) {
+    return null;
+  }
+
+  const tenantOrg: TenantOrganization = {
+    id: organization.id,
+    name: organization.name,
+    slug: organization.slug,
+    email: organization.email,
+    phone: organization.phone,
+    logo: organization.logo,
+    settings: organization.settings as Record<string, unknown>,
+    status: organization.status as OrganizationStatus,
+    planId: organization.planId,
+    trialEndsAt: organization.trialEndsAt,
+    createdAt: organization.createdAt,
+    updatedAt: organization.updatedAt,
+  };
+
+  // Also cache by ID
+  setCachedOrganization(tenantOrg);
+
+  return tenantOrg;
+}
+
+// -----------------------------------------------------------------------------
+// Middleware Functions
+// -----------------------------------------------------------------------------
+
+/**
+ * Tenant context middleware that loads the organization for authenticated users.
+ * Must be used after authMiddleware.
+ *
+ * This middleware:
+ * 1. Extracts organizationId from req.user (set by auth middleware)
+ * 2. Loads the organization from database
+ * 3. Validates organization is ACTIVE
+ * 4. Attaches organization to req.organization
+ *
+ * @throws AppException.unauthorized() when user is not authenticated
+ * @throws AppException.tenantNotFound() when organization doesn't exist
+ * @throws AppException.tenantAccessDenied() when organization is suspended
+ *
+ * @example
+ * ```typescript
+ * import { authMiddleware } from '@/core/middleware/auth.middleware';
+ * import { tenantMiddleware, TenantRequest } from '@/core/middleware/tenant.middleware';
+ *
+ * // Protect a route with tenant context
+ * router.get(
+ *   '/menus',
+ *   authMiddleware,
+ *   tenantMiddleware,
+ *   async (req, res) => {
+ *     const { organization } = req as TenantRequest;
+ *     // Use organization.id in queries
+ *     const menus = await menuService.findAll(organization.id);
+ *   }
+ * );
+ * ```
+ */
+export const tenantMiddleware: RequestHandler = async (
+  req: Request,
+  _res: Response,
+  next: NextFunction
+): Promise<void> => {
+  try {
+    const authReq = req as AuthenticatedRequest;
+
+    // Ensure user is authenticated
+    if (!authReq.user) {
+      throw AppException.unauthorized('Authentication required for tenant context');
+    }
+
+    const { organizationId } = authReq.user;
+
+    // Platform users (super_admin, admin) may not have an organizationId
+    // They need to specify the organization explicitly via header or query
+    if (!organizationId) {
+      // Check for X-Organization-Id header (for platform users)
+      const headerOrgId = req.headers['x-organization-id'] as string | undefined;
+      if (headerOrgId) {
+        const organization = await loadOrganization(headerOrgId);
+        if (!organization) {
+          throw AppException.tenantNotFound(headerOrgId);
+        }
+        if (organization.status !== 'ACTIVE') {
+          throw AppException.tenantAccessDenied(headerOrgId);
+        }
+        (req as OptionalTenantRequest).organization = organization;
+        next();
+        return;
+      }
+
+      // No organization context available
+      throw AppException.badRequest(
+        'Organization context required. Provide X-Organization-Id header.'
+      );
+    }
+
+    // Load organization from database
+    const organization = await loadOrganization(organizationId);
+
+    if (!organization) {
+      throw AppException.tenantNotFound(organizationId);
+    }
+
+    // Validate organization status
+    if (organization.status === 'SUSPENDED') {
+      throw AppException.tenantAccessDenied(organizationId);
+    }
+
+    if (organization.status === 'DELETED') {
+      throw AppException.tenantNotFound(organizationId);
+    }
+
+    // Attach organization to request
+    (req as TenantRequest).organization = organization;
+
+    next();
+  } catch (error) {
+    next(error);
+  }
+};
+
+/**
+ * Optional tenant context middleware that loads organization if user is authenticated.
+ * Does not fail if user is not authenticated or has no organization.
+ *
+ * Use this for routes that can work with or without tenant context
+ * (e.g., public menu viewing where authenticated users get personalized content).
+ *
+ * @example
+ * ```typescript
+ * import { optionalAuthMiddleware } from '@/core/middleware/auth.middleware';
+ * import { optionalTenantMiddleware, OptionalTenantRequest } from '@/core/middleware/tenant.middleware';
+ *
+ * router.get(
+ *   '/m/:slug',
+ *   optionalAuthMiddleware,
+ *   optionalTenantMiddleware,
+ *   async (req, res) => {
+ *     const { organization } = req as OptionalTenantRequest;
+ *     if (organization) {
+ *       // Show personalized menu for tenant user
+ *     } else {
+ *       // Show public menu
+ *     }
+ *   }
+ * );
+ * ```
+ */
+export const optionalTenantMiddleware: RequestHandler = async (
+  req: Request,
+  _res: Response,
+  next: NextFunction
+): Promise<void> => {
+  try {
+    const authReq = req as AuthenticatedRequest;
+
+    // If user is not authenticated, continue without organization context
+    if (!authReq.user) {
+      next();
+      return;
+    }
+
+    const { organizationId } = authReq.user;
+
+    // If user has no organization (platform user), continue without context
+    if (!organizationId) {
+      // Try to get organization from header
+      const headerOrgId = req.headers['x-organization-id'] as string | undefined;
+      if (headerOrgId) {
+        try {
+          const organization = await loadOrganization(headerOrgId);
+          if (organization && organization.status === 'ACTIVE') {
+            (req as OptionalTenantRequest).organization = organization;
+          }
+        } catch {
+          // Silently fail for optional tenant context
+        }
+      }
+      next();
+      return;
+    }
+
+    // Try to load organization
+    try {
+      const organization = await loadOrganization(organizationId);
+      if (organization && organization.status === 'ACTIVE') {
+        (req as OptionalTenantRequest).organization = organization;
+      }
+    } catch {
+      // Silently fail for optional tenant context
+    }
+
+    next();
+  } catch {
+    // For optional middleware, never fail - just continue
+    next();
+  }
+};
+
+/**
+ * Tenant resolution middleware that loads organization from slug parameter.
+ * Use this for public routes like menu display (/m/:slug).
+ *
+ * @param slugParam - The route parameter name containing the organization slug (default: 'slug')
+ * @returns Express middleware function
+ *
+ * @example
+ * ```typescript
+ * import { resolveBySlug, OptionalTenantRequest } from '@/core/middleware/tenant.middleware';
+ *
+ * // Public menu route
+ * router.get('/m/:slug', resolveBySlug('slug'), async (req, res) => {
+ *   const { organization } = req as OptionalTenantRequest;
+ *   if (!organization) {
+ *     return res.status(404).render('404');
+ *   }
+ *   // Render menu for organization
+ * });
+ * ```
+ */
+export function resolveBySlug(slugParam: string = 'slug'): RequestHandler {
+  return async (
+    req: Request,
+    _res: Response,
+    next: NextFunction
+  ): Promise<void> => {
+    try {
+      const slug = req.params[slugParam];
+
+      if (!slug) {
+        next();
+        return;
+      }
+
+      const organization = await loadOrganizationBySlug(slug);
+
+      if (organization && organization.status === 'ACTIVE') {
+        (req as OptionalTenantRequest).organization = organization;
+      }
+
+      next();
+    } catch (error) {
+      next(error);
+    }
+  };
+}
+
+/**
+ * Middleware that requires a specific organization status.
+ * Must be used after tenantMiddleware.
+ *
+ * @param allowedStatuses - Array of allowed organization statuses
+ * @returns Express middleware function
+ *
+ * @example
+ * ```typescript
+ * router.post(
+ *   '/orders',
+ *   authMiddleware,
+ *   tenantMiddleware,
+ *   requireOrgStatus(['ACTIVE']),
+ *   createOrderHandler
+ * );
+ * ```
+ */
+export function requireOrgStatus(allowedStatuses: OrganizationStatus[]): RequestHandler {
+  return (req: Request, _res: Response, next: NextFunction): void => {
+    const tenantReq = req as OptionalTenantRequest;
+
+    if (!tenantReq.organization) {
+      next(AppException.badRequest('Organization context required'));
+      return;
+    }
+
+    if (!allowedStatuses.includes(tenantReq.organization.status)) {
+      next(
+        AppException.tenantAccessDenied(tenantReq.organization.id)
+      );
+      return;
+    }
+
+    next();
+  };
+}
+
+// -----------------------------------------------------------------------------
+// Utility Functions
+// -----------------------------------------------------------------------------
+
+/**
+ * Gets the organization from request.
+ * Throws if organization context is not set.
+ *
+ * @param req - Express request object
+ * @returns Organization context
+ * @throws AppException.badRequest() if organization is not set
+ *
+ * @example
+ * ```typescript
+ * const org = getOrganization(req);
+ * const menus = await menuService.findAll(org.id);
+ * ```
+ */
+export function getOrganization(req: Request): TenantOrganization {
+  const tenantReq = req as OptionalTenantRequest;
+
+  if (!tenantReq.organization) {
+    throw AppException.badRequest('Organization context required');
+  }
+
+  return tenantReq.organization;
+}
+
+/**
+ * Gets the organization from request, or undefined if not set.
+ *
+ * @param req - Express request object
+ * @returns Organization context or undefined
+ *
+ * @example
+ * ```typescript
+ * const org = getOrganizationOptional(req);
+ * if (org) {
+ *   // Show organization-specific content
+ * }
+ * ```
+ */
+export function getOrganizationOptional(req: Request): TenantOrganization | undefined {
+  return (req as OptionalTenantRequest).organization;
+}
+
+/**
+ * Gets the organization ID from request.
+ * Throws if organization context is not set.
+ *
+ * @param req - Express request object
+ * @returns Organization ID string
+ * @throws AppException.badRequest() if organization is not set
+ *
+ * @example
+ * ```typescript
+ * const orgId = getOrganizationId(req);
+ * const menus = await prisma.menu.findMany({
+ *   where: { organizationId: orgId, deletedAt: null }
+ * });
+ * ```
+ */
+export function getOrganizationId(req: Request): string {
+  return getOrganization(req).id;
+}
+
+/**
+ * Checks if the request has organization context.
+ *
+ * @param req - Express request object
+ * @returns True if organization context is set
+ *
+ * @example
+ * ```typescript
+ * if (hasOrganization(req)) {
+ *   const org = getOrganization(req);
+ * }
+ * ```
+ */
+export function hasOrganization(req: Request): boolean {
+  return (req as OptionalTenantRequest).organization !== undefined;
+}
+
+/**
+ * Checks if the current organization has a specific status.
+ *
+ * @param req - Express request object
+ * @param status - Status to check
+ * @returns True if organization has the specified status
+ *
+ * @example
+ * ```typescript
+ * if (isOrgStatus(req, 'ACTIVE')) {
+ *   // Organization is active
+ * }
+ * ```
+ */
+export function isOrgStatus(req: Request, status: OrganizationStatus): boolean {
+  const org = getOrganizationOptional(req);
+  return org ? org.status === status : false;
+}
+
+/**
+ * Validates that the given organization ID matches the current tenant context.
+ * Use this to prevent cross-tenant data access.
+ *
+ * @param req - Express request object
+ * @param organizationId - Organization ID to validate
+ * @throws AppException.tenantAccessDenied() if IDs don't match
+ *
+ * @example
+ * ```typescript
+ * // In a service method
+ * validateTenantAccess(req, resource.organizationId);
+ * ```
+ */
+export function validateTenantAccess(req: Request, organizationId: string): void {
+  const currentOrg = getOrganizationOptional(req);
+
+  if (!currentOrg) {
+    throw AppException.badRequest('Organization context required');
+  }
+
+  if (currentOrg.id !== organizationId) {
+    // Log potential security issue
+    // logger.warn('Cross-tenant access attempt', { currentOrg: currentOrg.id, targetOrg: organizationId });
+    throw AppException.tenantAccessDenied(organizationId);
+  }
+}

diff --git a/src/core/services/auth.service.ts b/src/core/services/auth.service.ts
new file mode 100644
index 0000000..45aadb6
--- /dev/null
+++ b/src/core/services/auth.service.ts
@@ -0,0 +1,826 @@
+/**
+ * Authentication Service
+ *
+ * Core authentication service for E-Menum.
+ * Handles JWT token generation/validation, password hashing,
+ * session management, and authentication flows.
+ *
+ * @module core/services/auth
+ *
+ * @example
+ * ```typescript
+ * import { AuthService } from '@/core/services/auth.service';
+ * import { resolve, TOKENS } from '@/core/kernel/container';
+ *
+ * const authService = resolve<AuthService>(TOKENS.AuthService);
+ *
+ * // Hash password on registration
+ * const hashedPassword = await authService.hashPassword('user-password');
+ *
+ * // Validate login credentials
+ * const tokens = await authService.login('user@example.com', 'password', user);
+ *
+ * // Refresh access token
+ * const newAccessToken = await authService.refreshAccessToken(refreshToken);
+ * ```
+ */
+
+import bcrypt from 'bcrypt';
+import crypto from 'crypto';
+import { injectable, inject } from 'tsyringe';
+import Redis from 'ioredis';
+
+import { env, getAccessTokenExpiryMs, getRefreshTokenExpiryMs } from '@/config/env';
+import { TOKENS } from '@/core/kernel/container';
+import { AppException } from '@/core/exceptions/app.exception';
+import {
+  generateAccessToken,
+  generateRefreshToken,
+  verifyRefreshToken,
+  GenerateTokenOptions,
+  JwtTokenPayload,
+  RefreshTokenPayload,
+} from '@/core/middleware/auth.middleware';
+
+// -----------------------------------------------------------------------------
+// Types & Interfaces
+// -----------------------------------------------------------------------------
+
+/**
+ * User data required for token generation
+ */
+export interface TokenUser {
+  /** User ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** User's primary role */
+  role: string;
+  /** User's permissions array */
+  permissions: string[];
+}
+
+/**
+ * Authentication result with access and refresh tokens
+ */
+export interface AuthTokens {
+  /** JWT access token (short-lived, 15 min default) */
+  accessToken: string;
+  /** JWT refresh token (long-lived, 7 days default) */
+  refreshToken: string;
+  /** Access token expiry time in milliseconds */
+  expiresIn: number;
+  /** Token type (always 'Bearer') */
+  tokenType: 'Bearer';
+}
+
+/**
+ * Session information stored in Redis
+ */
+export interface SessionData {
+  /** User ID */
+  userId: string;
+  /** Organization ID */
+  organizationId: string;
+  /** User role at session creation */
+  role: string;
+  /** Token ID for this session */
+  tokenId: string;
+  /** IP address of the client */
+  ipAddress?: string;
+  /** User agent string */
+  userAgent?: string;
+  /** Session creation timestamp */
+  createdAt: string;
+  /** Last activity timestamp */
+  lastActivityAt: string;
+}
+
+/**
+ * Password reset token data
+ */
+export interface ResetTokenData {
+  /** User ID */
+  userId: string;
+  /** User email */
+  email: string;
+  /** Token creation timestamp */
+  createdAt: string;
+}
+
+/**
+ * Email verification token data
+ */
+export interface VerificationTokenData {
+  /** User ID */
+  userId: string;
+  /** Email to verify */
+  email: string;
+  /** Token creation timestamp */
+  createdAt: string;
+}
+
+// -----------------------------------------------------------------------------
+// Constants
+// -----------------------------------------------------------------------------
+
+/** Redis key prefix for refresh tokens */
+const REFRESH_TOKEN_PREFIX = 'auth:refresh:';
+
+/** Redis key prefix for blacklisted tokens */
+const BLACKLIST_PREFIX = 'auth:blacklist:';
+
+/** Redis key prefix for user sessions */
+const SESSION_PREFIX = 'auth:session:';
+
+/** Redis key prefix for password reset tokens */
+const RESET_TOKEN_PREFIX = 'auth:reset:';
+
+/** Redis key prefix for email verification tokens */
+const VERIFY_TOKEN_PREFIX = 'auth:verify:';
+
+/** Password reset token validity in seconds (1 hour) */
+const RESET_TOKEN_TTL = 60 * 60;
+
+/** Email verification token validity in seconds (24 hours) */
+const VERIFY_TOKEN_TTL = 24 * 60 * 60;
+
+// -----------------------------------------------------------------------------
+// Auth Service Class
+// -----------------------------------------------------------------------------
+
+/**
+ * Authentication service for E-Menum.
+ *
+ * Handles all authentication-related operations including:
+ * - Password hashing and verification
+ * - JWT token generation and validation
+ * - Session management
+ * - Token revocation (logout)
+ * - Password reset tokens
+ * - Email verification tokens
+ *
+ * @example
+ * ```typescript
+ * @injectable()
+ * export class UserController {
+ *   constructor(
+ *     @inject(TOKENS.AuthService) private authService: AuthService,
+ *   ) {}
+ *
+ *   async login(email: string, password: string) {
+ *     const user = await this.userService.findByEmail(email);
+ *     if (!user) throw AppException.invalidCredentials();
+ *
+ *     const isValid = await this.authService.verifyPassword(password, user.passwordHash);
+ *     if (!isValid) throw AppException.invalidCredentials();
+ *
+ *     return this.authService.generateTokenPair(user);
+ *   }
+ * }
+ * ```
+ */
+@injectable()
+export class AuthService {
+  /**
+   * Creates a new AuthService instance
+   *
+   * @param redis - Redis client for session management
+   */
+  constructor(@inject(TOKENS.Redis) private readonly redis: Redis) {}
+
+  // ---------------------------------------------------------------------------
+  // Password Management
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Hashes a password using bcrypt.
+   *
+   * @param password - Plain text password to hash
+   * @returns Hashed password string
+   *
+   * @example
+   * ```typescript
+   * const hashedPassword = await authService.hashPassword('my-secure-password');
+   * // Store hashedPassword in database
+   * ```
+   */
+  async hashPassword(password: string): Promise<string> {
+    const saltRounds = env.BCRYPT_ROUNDS;
+    return bcrypt.hash(password, saltRounds);
+  }
+
+  /**
+   * Verifies a password against a bcrypt hash.
+   *
+   * @param password - Plain text password to verify
+   * @param hash - Bcrypt hash to verify against
+   * @returns True if password matches, false otherwise
+   *
+   * @example
+   * ```typescript
+   * const isValid = await authService.verifyPassword('my-password', user.passwordHash);
+   * if (!isValid) {
+   *   throw AppException.invalidCredentials();
+   * }
+   * ```
+   */
+  async verifyPassword(password: string, hash: string): Promise<boolean> {
+    return bcrypt.compare(password, hash);
+  }
+
+  // ---------------------------------------------------------------------------
+  // Token Generation
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Generates a unique token ID for JWT tracking.
+   *
+   * @returns Unique token ID string
+   */
+  generateTokenId(): string {
+    return `tok_${crypto.randomUUID()}`;
+  }
+
+  /**
+   * Generates an access and refresh token pair for a user.
+   *
+   * @param user - User data for token payload
+   * @param sessionInfo - Optional session metadata (IP, user agent)
+   * @returns Authentication tokens object
+   *
+   * @example
+   * ```typescript
+   * const tokens = await authService.generateTokenPair({
+   *   id: user.id,
+   *   organizationId: user.organizationId,
+   *   role: 'owner',
+   *   permissions: ['menu.view', 'menu.create', 'menu.update'],
+   * });
+   *
+   * // Return tokens to client
+   * res.json({
+   *   accessToken: tokens.accessToken,
+   *   refreshToken: tokens.refreshToken,
+   *   expiresIn: tokens.expiresIn,
+   * });
+   * ```
+   */
+  async generateTokenPair(
+    user: TokenUser,
+    sessionInfo?: { ipAddress?: string; userAgent?: string }
+  ): Promise<AuthTokens> {
+    const tokenId = this.generateTokenId();
+    const refreshTokenId = this.generateTokenId();
+
+    // Generate access token
+    const tokenOptions: GenerateTokenOptions = {
+      userId: user.id,
+      organizationId: user.organizationId,
+      role: user.role,
+      permissions: user.permissions,
+      tokenId,
+    };
+
+    const accessToken = generateAccessToken(tokenOptions);
+    const refreshToken = generateRefreshToken(user.id, refreshTokenId);
+
+    // Store refresh token in Redis for validation
+    const refreshTtl = Math.floor(getRefreshTokenExpiryMs() / 1000);
+    await this.storeRefreshToken(refreshTokenId, {
+      userId: user.id,
+      organizationId: user.organizationId,
+      tokenId,
+      createdAt: new Date().toISOString(),
+    });
+
+    // Store session data
+    await this.createSession(user, tokenId, sessionInfo);
+
+    return {
+      accessToken,
+      refreshToken,
+      expiresIn: getAccessTokenExpiryMs(),
+      tokenType: 'Bearer',
+    };
+  }
+
+  /**
+   * Generates only an access token (for token refresh flow).
+   *
+   * @param user - User data for token payload
+   * @param tokenId - Token ID for tracking
+   * @returns Access token string
+   */
+  generateToken(user: TokenUser, tokenId: string): string {
+    const tokenOptions: GenerateTokenOptions = {
+      userId: user.id,
+      organizationId: user.organizationId,
+      role: user.role,
+      permissions: user.permissions,
+      tokenId,
+    };
+
+    return generateAccessToken(tokenOptions);
+  }
+
+  // ---------------------------------------------------------------------------
+  // Token Refresh
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Refreshes an access token using a valid refresh token.
+   *
+   * @param refreshToken - JWT refresh token
+   * @param getUserData - Callback to fetch current user data
+   * @returns New authentication tokens
+   * @throws {AppException} If refresh token is invalid or revoked
+   *
+   * @example
+   * ```typescript
+   * const newTokens = await authService.refreshAccessToken(
+   *   req.cookies.refreshToken,
+   *   async (userId) => {
+   *     const user = await userService.findById(userId);
+   *     return {
+   *       id: user.id,
+   *       organizationId: user.organizationId,
+   *       role: user.role,
+   *       permissions: await permissionService.getPermissions(user.role),
+   *     };
+   *   }
+   * );
+   * ```
+   */
+  async refreshAccessToken(
+    refreshToken: string,
+    getUserData: (userId: string) => Promise<TokenUser>
+  ): Promise<AuthTokens> {
+    // Verify refresh token
+    let payload: RefreshTokenPayload;
+    try {
+      payload = verifyRefreshToken(refreshToken);
+    } catch {
+      throw new AppException('INVALID_REFRESH_TOKEN', 401, {
+        message: 'Invalid or expired refresh token',
+      });
+    }
+
+    // Check if refresh token is stored and valid
+    const storedData = await this.getRefreshTokenData(payload.jti);
+    if (!storedData) {
+      throw new AppException('INVALID_REFRESH_TOKEN', 401, {
+        message: 'Refresh token has been revoked',
+      });
+    }
+
+    // Get current user data (roles/permissions may have changed)
+    const user = await getUserData(payload.sub);
+
+    // Revoke old refresh token (single use)
+    await this.revokeRefreshToken(payload.jti);
+
+    // Generate new token pair
+    return this.generateTokenPair(user);
+  }
+
+  // ---------------------------------------------------------------------------
+  // Token Revocation (Logout)
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Revokes an access token by adding it to the blacklist.
+   *
+   * @param tokenPayload - Decoded JWT payload
+   *
+   * @example
+   * ```typescript
+   * // On logout
+   * await authService.revokeAccessToken(req.tokenPayload);
+   * ```
+   */
+  async revokeAccessToken(tokenPayload: JwtTokenPayload): Promise<void> {
+    const { jti, exp } = tokenPayload;
+
+    // Calculate TTL until token would naturally expire
+    const now = Math.floor(Date.now() / 1000);
+    const ttl = exp - now;
+
+    if (ttl > 0) {
+      await this.redis.setex(`${BLACKLIST_PREFIX}${jti}`, ttl, '1');
+    }
+
+    // Also delete the session
+    await this.deleteSession(tokenPayload.sub, jti);
+  }
+
+  /**
+   * Revokes a refresh token.
+   *
+   * @param refreshTokenId - Refresh token ID (jti claim)
+   */
+  async revokeRefreshToken(refreshTokenId: string): Promise<void> {
+    await this.redis.del(`${REFRESH_TOKEN_PREFIX}${refreshTokenId}`);
+  }
+
+  /**
+   * Revokes all tokens for a user (force logout from all devices).
+   *
+   * @param userId - User ID to revoke all tokens for
+   *
+   * @example
+   * ```typescript
+   * // When password is changed
+   * await authService.revokeAllUserTokens(userId);
+   * ```
+   */
+  async revokeAllUserTokens(userId: string): Promise<void> {
+    // Delete all sessions for user
+    const sessionPattern = `${SESSION_PREFIX}${userId}:*`;
+    const sessionKeys = await this.scanKeys(sessionPattern);
+    if (sessionKeys.length > 0) {
+      await this.redis.del(...sessionKeys);
+    }
+
+    // Delete all refresh tokens for user
+    const refreshPattern = `${REFRESH_TOKEN_PREFIX}*`;
+    const refreshKeys = await this.scanKeys(refreshPattern);
+
+    for (const key of refreshKeys) {
+      const data = await this.redis.get(key);
+      if (data) {
+        try {
+          const parsed = JSON.parse(data);
+          if (parsed.userId === userId) {
+            await this.redis.del(key);
+          }
+        } catch {
+          // Skip invalid data
+        }
+      }
+    }
+  }
+
+  /**
+   * Checks if an access token has been revoked.
+   *
+   * @param tokenId - Token ID (jti claim)
+   * @returns True if token is blacklisted
+   */
+  async isTokenRevoked(tokenId: string): Promise<boolean> {
+    const exists = await this.redis.exists(`${BLACKLIST_PREFIX}${tokenId}`);
+    return exists === 1;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Session Management
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Creates a new session record.
+   *
+   * @param user - User data
+   * @param tokenId - Token ID for this session
+   * @param info - Optional session metadata
+   */
+  private async createSession(
+    user: TokenUser,
+    tokenId: string,
+    info?: { ipAddress?: string; userAgent?: string }
+  ): Promise<void> {
+    const session: SessionData = {
+      userId: user.id,
+      organizationId: user.organizationId,
+      role: user.role,
+      tokenId,
+      ipAddress: info?.ipAddress,
+      userAgent: info?.userAgent,
+      createdAt: new Date().toISOString(),
+      lastActivityAt: new Date().toISOString(),
+    };
+
+    const ttl = Math.floor(getRefreshTokenExpiryMs() / 1000);
+    await this.redis.setex(
+      `${SESSION_PREFIX}${user.id}:${tokenId}`,
+      ttl,
+      JSON.stringify(session)
+    );
+  }
+
+  /**
+   * Updates session last activity timestamp.
+   *
+   * @param userId - User ID
+   * @param tokenId - Token ID
+   */
+  async updateSessionActivity(userId: string, tokenId: string): Promise<void> {
+    const key = `${SESSION_PREFIX}${userId}:${tokenId}`;
+    const data = await this.redis.get(key);
+
+    if (data) {
+      try {
+        const session = JSON.parse(data) as SessionData;
+        session.lastActivityAt = new Date().toISOString();
+        const ttl = await this.redis.ttl(key);
+        if (ttl > 0) {
+          await this.redis.setex(key, ttl, JSON.stringify(session));
+        }
+      } catch {
+        // Skip if data is invalid
+      }
+    }
+  }
+
+  /**
+   * Gets all active sessions for a user.
+   *
+   * @param userId - User ID
+   * @returns Array of session data
+   */
+  async getUserSessions(userId: string): Promise<SessionData[]> {
+    const pattern = `${SESSION_PREFIX}${userId}:*`;
+    const keys = await this.scanKeys(pattern);
+
+    const sessions: SessionData[] = [];
+    for (const key of keys) {
+      const data = await this.redis.get(key);
+      if (data) {
+        try {
+          sessions.push(JSON.parse(data) as SessionData);
+        } catch {
+          // Skip invalid data
+        }
+      }
+    }
+
+    return sessions;
+  }
+
+  /**
+   * Deletes a specific session.
+   *
+   * @param userId - User ID
+   * @param tokenId - Token ID
+   */
+  private async deleteSession(userId: string, tokenId: string): Promise<void> {
+    await this.redis.del(`${SESSION_PREFIX}${userId}:${tokenId}`);
+  }
+
+  // ---------------------------------------------------------------------------
+  // Password Reset
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Generates a password reset token.
+   *
+   * @param userId - User ID
+   * @param email - User email
+   * @returns Reset token string
+   *
+   * @example
+   * ```typescript
+   * const resetToken = await authService.generatePasswordResetToken(user.id, user.email);
+   * // Send email with reset link containing token
+   * await emailService.sendPasswordReset(user.email, resetToken);
+   * ```
+   */
+  async generatePasswordResetToken(userId: string, email: string): Promise<string> {
+    // Invalidate any existing reset tokens for this user
+    await this.redis.del(`${RESET_TOKEN_PREFIX}${userId}`);
+
+    const token = crypto.randomBytes(32).toString('hex');
+    const tokenData: ResetTokenData = {
+      userId,
+      email,
+      createdAt: new Date().toISOString(),
+    };
+
+    // Store token with user ID as key for easy lookup and invalidation
+    await this.redis.setex(
+      `${RESET_TOKEN_PREFIX}${token}`,
+      RESET_TOKEN_TTL,
+      JSON.stringify(tokenData)
+    );
+
+    // Also store reverse mapping for invalidation
+    await this.redis.setex(`${RESET_TOKEN_PREFIX}${userId}`, RESET_TOKEN_TTL, token);
+
+    return token;
+  }
+
+  /**
+   * Verifies a password reset token.
+   *
+   * @param token - Reset token to verify
+   * @returns Token data if valid
+   * @throws {AppException} If token is invalid or expired
+   *
+   * @example
+   * ```typescript
+   * const tokenData = await authService.verifyPasswordResetToken(token);
+   * // Token is valid, proceed with password update
+   * await userService.updatePassword(tokenData.userId, newPassword);
+   * await authService.invalidatePasswordResetToken(token);
+   * ```
+   */
+  async verifyPasswordResetToken(token: string): Promise<ResetTokenData> {
+    const data = await this.redis.get(`${RESET_TOKEN_PREFIX}${token}`);
+
+    if (!data) {
+      throw new AppException('INVALID_RESET_TOKEN', 401, {
+        message: 'Password reset token is invalid or has expired',
+      });
+    }
+
+    try {
+      return JSON.parse(data) as ResetTokenData;
+    } catch {
+      throw new AppException('INVALID_RESET_TOKEN', 401, {
+        message: 'Password reset token is malformed',
+      });
+    }
+  }
+
+  /**
+   * Invalidates a password reset token after use.
+   *
+   * @param token - Reset token to invalidate
+   */
+  async invalidatePasswordResetToken(token: string): Promise<void> {
+    const data = await this.redis.get(`${RESET_TOKEN_PREFIX}${token}`);
+    if (data) {
+      try {
+        const tokenData = JSON.parse(data) as ResetTokenData;
+        await this.redis.del(`${RESET_TOKEN_PREFIX}${tokenData.userId}`);
+      } catch {
+        // Ignore parsing errors
+      }
+    }
+    await this.redis.del(`${RESET_TOKEN_PREFIX}${token}`);
+  }
+
+  // ---------------------------------------------------------------------------
+  // Email Verification
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Generates an email verification token.
+   *
+   * @param userId - User ID
+   * @param email - Email to verify
+   * @returns Verification token string
+   *
+   * @example
+   * ```typescript
+   * const verifyToken = await authService.generateEmailVerificationToken(user.id, user.email);
+   * // Send verification email
+   * await emailService.sendVerification(user.email, verifyToken);
+   * ```
+   */
+  async generateEmailVerificationToken(userId: string, email: string): Promise<string> {
+    // Invalidate any existing verification tokens for this user
+    const existingToken = await this.redis.get(`${VERIFY_TOKEN_PREFIX}user:${userId}`);
+    if (existingToken) {
+      await this.redis.del(`${VERIFY_TOKEN_PREFIX}${existingToken}`);
+    }
+
+    const token = crypto.randomBytes(32).toString('hex');
+    const tokenData: VerificationTokenData = {
+      userId,
+      email,
+      createdAt: new Date().toISOString(),
+    };
+
+    // Store token
+    await this.redis.setex(
+      `${VERIFY_TOKEN_PREFIX}${token}`,
+      VERIFY_TOKEN_TTL,
+      JSON.stringify(tokenData)
+    );
+
+    // Store reverse mapping for invalidation
+    await this.redis.setex(`${VERIFY_TOKEN_PREFIX}user:${userId}`, VERIFY_TOKEN_TTL, token);
+
+    return token;
+  }
+
+  /**
+   * Verifies an email verification token.
+   *
+   * @param token - Verification token to verify
+   * @returns Token data if valid
+   * @throws {AppException} If token is invalid or expired
+   */
+  async verifyEmailVerificationToken(token: string): Promise<VerificationTokenData> {
+    const data = await this.redis.get(`${VERIFY_TOKEN_PREFIX}${token}`);
+
+    if (!data) {
+      throw new AppException('INVALID_TOKEN', 401, {
+        message: 'Email verification token is invalid or has expired',
+      });
+    }
+
+    try {
+      return JSON.parse(data) as VerificationTokenData;
+    } catch {
+      throw new AppException('INVALID_TOKEN', 401, {
+        message: 'Email verification token is malformed',
+      });
+    }
+  }
+
+  /**
+   * Invalidates an email verification token after use.
+   *
+   * @param token - Verification token to invalidate
+   */
+  async invalidateEmailVerificationToken(token: string): Promise<void> {
+    const data = await this.redis.get(`${VERIFY_TOKEN_PREFIX}${token}`);
+    if (data) {
+      try {
+        const tokenData = JSON.parse(data) as VerificationTokenData;
+        await this.redis.del(`${VERIFY_TOKEN_PREFIX}user:${tokenData.userId}`);
+      } catch {
+        // Ignore parsing errors
+      }
+    }
+    await this.redis.del(`${VERIFY_TOKEN_PREFIX}${token}`);
+  }
+
+  // ---------------------------------------------------------------------------
+  // Refresh Token Storage
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Stores refresh token data in Redis.
+   *
+   * @param tokenId - Refresh token ID
+   * @param data - Data to store
+   */
+  private async storeRefreshToken(
+    tokenId: string,
+    data: { userId: string; organizationId: string; tokenId: string; createdAt: string }
+  ): Promise<void> {
+    const ttl = Math.floor(getRefreshTokenExpiryMs() / 1000);
+    await this.redis.setex(
+      `${REFRESH_TOKEN_PREFIX}${tokenId}`,
+      ttl,
+      JSON.stringify(data)
+    );
+  }
+
+  /**
+   * Gets stored refresh token data.
+   *
+   * @param tokenId - Refresh token ID
+   * @returns Token data or null if not found
+   */
+  private async getRefreshTokenData(
+    tokenId: string
+  ): Promise<{ userId: string; organizationId: string; tokenId: string; createdAt: string } | null> {
+    const data = await this.redis.get(`${REFRESH_TOKEN_PREFIX}${tokenId}`);
+    if (!data) {
+      return null;
+    }
+
+    try {
+      return JSON.parse(data);
+    } catch {
+      return null;
+    }
+  }
+
+  // ---------------------------------------------------------------------------
+  // Utility Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Scans Redis keys matching a pattern.
+   * Uses SCAN for memory-efficient iteration.
+   *
+   * @param pattern - Key pattern to match
+   * @returns Array of matching keys
+   */
+  private async scanKeys(pattern: string): Promise<string[]> {
+    const keys: string[] = [];
+    let cursor = '0';
+
+    do {
+      const [nextCursor, batch] = await this.redis.scan(cursor, 'MATCH', pattern, 'COUNT', 100);
+      cursor = nextCursor;
+      keys.push(...batch);
+    } while (cursor !== '0');
+
+    return keys;
+  }
+
+  /**
+   * Generates a secure random token.
+   *
+   * @param length - Token length in bytes (default: 32)
+   * @returns Hex-encoded random token
+   */
+  generateSecureToken(length = 32): string {
+    return crypto.randomBytes(length).toString('hex');
+  }
+}

