+/**
+ * Event Service
+ *
+ * Core event bus service for E-Menum using EventEmitter2.
+ * Provides a typed event system for cross-module communication
+ * following the event-driven architecture pattern.
+ *
+ * @module core/services/event
+ *
+ * @example
+ * ```typescript
+ * import { EventService } from '@/core/services/event.service';
+ * import { resolve, TOKENS } from '@/core/kernel/container';
+ *
+ * const eventService = resolve<EventService>(TOKENS.EventService);
+ *
+ * // Subscribe to events
+ * eventService.on('menu.created', async (payload) => {
+ *   console.log('Menu created:', payload.menuId);
+ * });
+ *
+ * // Emit events
+ * await eventService.emit('menu.created', { menuId: 'menu_123', orgId: 'org_456' });
+ * ```
+ */
+
+import { injectable } from 'tsyringe';
+import { EventEmitter2, Listener, OnOptions } from 'eventemitter2';
+
+// -----------------------------------------------------------------------------
+// Type Definitions
+// -----------------------------------------------------------------------------
+
+/**
+ * Base payload structure for all domain events.
+ * All event payloads should extend this interface.
+ */
+export interface BaseEventPayload {
+  /** Timestamp when event was emitted */
+  timestamp?: string;
+  /** Organization ID for tenant context */
+  organizationId?: string;
+  /** User ID who triggered the event */
+  userId?: string;
+  /** Additional metadata */
+  metadata?: Record<string, unknown>;
+}
+
+/**
+ * Menu-related event payloads
+ */
+export interface MenuCreatedPayload extends BaseEventPayload {
+  menuId: string;
+}
+
+export interface MenuUpdatedPayload extends BaseEventPayload {
+  menuId: string;
+  changes?: string[];
+}
+
+export interface MenuDeletedPayload extends BaseEventPayload {
+  menuId: string;
+}
+
+export interface MenuPublishedPayload extends BaseEventPayload {
+  menuId: string;
+  isPublic: boolean;
+}
+
+/**
+ * Category-related event payloads
+ */
+export interface CategoryCreatedPayload extends BaseEventPayload {
+  categoryId: string;
+  menuId: string;
+}
+
+export interface CategoryUpdatedPayload extends BaseEventPayload {
+  categoryId: string;
+  menuId: string;
+}
+
+export interface CategoryDeletedPayload extends BaseEventPayload {
+  categoryId: string;
+  menuId: string;
+}
+
+/**
+ * Product-related event payloads
+ */
+export interface ProductCreatedPayload extends BaseEventPayload {
+  productId: string;
+  categoryId: string;
+}
+
+export interface ProductUpdatedPayload extends BaseEventPayload {
+  productId: string;
+  changes?: string[];
+}
+
+export interface ProductDeletedPayload extends BaseEventPayload {
+  productId: string;
+  categoryId: string;
+}
+
+/**
+ * Order-related event payloads
+ */
+export interface OrderCreatedPayload extends BaseEventPayload {
+  orderId: string;
+  tableId?: string;
+  customerId?: string;
+}
+
+export interface OrderUpdatedPayload extends BaseEventPayload {
+  orderId: string;
+  previousStatus?: string;
+  newStatus?: string;
+}
+
+export interface OrderCompletedPayload extends BaseEventPayload {
+  orderId: string;
+  totalAmount?: number;
+}
+
+export interface OrderCancelledPayload extends BaseEventPayload {
+  orderId: string;
+  reason?: string;
+}
+
+/**
+ * User-related event payloads
+ */
+export interface UserCreatedPayload extends BaseEventPayload {
+  userId: string;
+  email: string;
+  role?: string;
+}
+
+export interface UserUpdatedPayload extends BaseEventPayload {
+  userId: string;
+  changes?: string[];
+}
+
+export interface UserDeletedPayload extends BaseEventPayload {
+  userId: string;
+}
+
+export interface UserLoginPayload extends BaseEventPayload {
+  userId: string;
+  ipAddress?: string;
+  userAgent?: string;
+}
+
+export interface UserLogoutPayload extends BaseEventPayload {
+  userId: string;
+}
+
+/**
+ * Organization-related event payloads
+ */
+export interface OrganizationCreatedPayload extends BaseEventPayload {
+  organizationId: string;
+  ownerId: string;
+}
+
+export interface OrganizationUpdatedPayload extends BaseEventPayload {
+  organizationId: string;
+  changes?: string[];
+}
+
+export interface OrganizationDeletedPayload extends BaseEventPayload {
+  organizationId: string;
+}
+
+/**
+ * Subscription-related event payloads
+ */
+export interface SubscriptionCreatedPayload extends BaseEventPayload {
+  subscriptionId: string;
+  planId: string;
+}
+
+export interface SubscriptionUpdatedPayload extends BaseEventPayload {
+  subscriptionId: string;
+  previousPlan?: string;
+  newPlan?: string;
+}
+
+export interface SubscriptionCancelledPayload extends BaseEventPayload {
+  subscriptionId: string;
+  reason?: string;
+}
+
+/**
+ * Module-related event payloads
+ */
+export interface ModuleEnabledPayload extends BaseEventPayload {
+  moduleId: string;
+  version?: string;
+}
+
+export interface ModuleDisabledPayload extends BaseEventPayload {
+  moduleId: string;
+}
+
+export interface ModuleInstalledPayload extends BaseEventPayload {
+  moduleId: string;
+  version?: string;
+}
+
+export interface ModuleUninstalledPayload extends BaseEventPayload {
+  moduleId: string;
+}
+
+/**
+ * Notification-related event payloads
+ */
+export interface NotificationCreatedPayload extends BaseEventPayload {
+  notificationId: string;
+  type: string;
+  recipientId: string;
+}
+
+/**
+ * Media-related event payloads
+ */
+export interface MediaUploadedPayload extends BaseEventPayload {
+  mediaId: string;
+  filename: string;
+  mimeType: string;
+}
+
+export interface MediaDeletedPayload extends BaseEventPayload {
+  mediaId: string;
+}
+
+/**
+ * Domain events map with typed payloads.
+ * Add new events and their payload types here.
+ */
+export interface DomainEvents {
+  // Menu events
+  'menu.created': MenuCreatedPayload;
+  'menu.updated': MenuUpdatedPayload;
+  'menu.deleted': MenuDeletedPayload;
+  'menu.published': MenuPublishedPayload;
+
+  // Category events
+  'category.created': CategoryCreatedPayload;
+  'category.updated': CategoryUpdatedPayload;
+  'category.deleted': CategoryDeletedPayload;
+
+  // Product events
+  'product.created': ProductCreatedPayload;
+  'product.updated': ProductUpdatedPayload;
+  'product.deleted': ProductDeletedPayload;
+
+  // Order events
+  'order.created': OrderCreatedPayload;
+  'order.updated': OrderUpdatedPayload;
+  'order.completed': OrderCompletedPayload;
+  'order.cancelled': OrderCancelledPayload;
+
+  // User events
+  'user.created': UserCreatedPayload;
+  'user.updated': UserUpdatedPayload;
+  'user.deleted': UserDeletedPayload;
+  'user.login': UserLoginPayload;
+  'user.logout': UserLogoutPayload;
+
+  // Organization events
+  'organization.created': OrganizationCreatedPayload;
+  'organization.updated': OrganizationUpdatedPayload;
+  'organization.deleted': OrganizationDeletedPayload;
+
+  // Subscription events
+  'subscription.created': SubscriptionCreatedPayload;
+  'subscription.updated': SubscriptionUpdatedPayload;
+  'subscription.cancelled': SubscriptionCancelledPayload;
+
+  // Module events
+  'module.enabled': ModuleEnabledPayload;
+  'module.disabled': ModuleDisabledPayload;
+  'module.installed': ModuleInstalledPayload;
+  'module.uninstalled': ModuleUninstalledPayload;
+
+  // Notification events
+  'notification.created': NotificationCreatedPayload;
+
+  // Media events
+  'media.uploaded': MediaUploadedPayload;
+  'media.deleted': MediaDeletedPayload;
+}
+
+/**
+ * Event names as a union type
+ */
+export type DomainEventName = keyof DomainEvents;
+
+/**
+ * Event handler type for typed event handlers
+ */
+export type EventHandler<T extends DomainEventName> = (
+  payload: DomainEvents[T]
+) => void | Promise<void>;
+
+/**
+ * Wildcard event handler for listening to all events
+ */
+export type WildcardEventHandler = (
+  eventName: string,
+  payload: BaseEventPayload
+) => void | Promise<void>;
+
+/**
+ * Event subscription options
+ */
+export interface EventSubscriptionOptions extends OnOptions {
+  /** If true, listener will be called at most once */
+  once?: boolean;
+  /** If true, listener will be prepended to the listeners array */
+  prepend?: boolean;
+  /** Async mode - if true, listeners run asynchronously */
+  async?: boolean;
+  /** Promise mode - if true, emit will wait for all listeners */
+  promisify?: boolean;
+}
+
+/**
+ * Event listener statistics
+ */
+export interface EventStats {
+  /** Total number of events emitted */
+  totalEmitted: number;
+  /** Events emitted by name */
+  emittedByEvent: Record<string, number>;
+  /** Total number of active listeners */
+  totalListeners: number;
+  /** Listeners by event name */
+  listenersByEvent: Record<string, number>;
+}
+
+// -----------------------------------------------------------------------------
+// Event Service Class
+// -----------------------------------------------------------------------------
+
+/**
+ * Event service for E-Menum.
+ *
+ * Provides a typed event bus for cross-module communication.
+ * Uses EventEmitter2 for advanced features like wildcards,
+ * namespaces, and async/await support.
+ *
+ * Key features:
+ * - Typed event payloads with TypeScript
+ * - Async event handling with Promise support
+ * - Wildcard listeners for debugging/logging
+ * - Event statistics tracking
+ * - Namespaced events (e.g., 'menu.*')
+ *
+ * @example
+ * ```typescript
+ * @injectable()
+ * export class MenuService {
+ *   constructor(
+ *     @inject(TOKENS.EventService) private events: EventService,
+ *   ) {}
+ *
+ *   async create(data: CreateMenuDto, orgId: string): Promise<Menu> {
+ *     const menu = await this.prisma.menu.create({ data });
+ *
+ *     // Emit event for other modules to react
+ *     await this.events.emit('menu.created', {
+ *       menuId: menu.id,
+ *       organizationId: orgId,
+ *     });
+ *
+ *     return menu;
+ *   }
+ * }
+ * ```
+ */
+@injectable()
+export class EventService {
+  /** Internal EventEmitter2 instance */
+  private readonly emitter: EventEmitter2;
+
+  /** Event statistics */
+  private stats: EventStats = {
+    totalEmitted: 0,
+    emittedByEvent: {},
+    totalListeners: 0,
+    listenersByEvent: {},
+  };
+
+  /**
+   * Creates a new EventService instance.
+   * Configures EventEmitter2 with recommended settings for domain events.
+   */
+  constructor() {
+    this.emitter = new EventEmitter2({
+      // Enable wildcard listeners (e.g., 'menu.*')
+      wildcard: true,
+      // Use '.' as namespace delimiter
+      delimiter: '.',
+      // Allow 'newListener' event for debugging
+      newListener: false,
+      // Allow 'removeListener' event
+      removeListener: false,
+      // Maximum number of listeners per event (0 = unlimited)
+      maxListeners: 20,
+      // Log warnings when listener count exceeds max
+      verboseMemoryLeak: true,
+      // Ignore errors in listeners (we handle them ourselves)
+      ignoreErrors: false,
+    });
+
+    // Handle uncaught listener errors
+    this.emitter.on('error', this.handleError.bind(this));
+  }
+
+  // ---------------------------------------------------------------------------
+  // Event Emission
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Emits a typed domain event.
+   *
+   * @param event - Event name from DomainEvents
+   * @param payload - Event payload (type-checked against DomainEvents)
+   * @returns True if event had listeners, false otherwise
+   *
+   * @example
+   * ```typescript
+   * await eventService.emit('menu.created', {
+   *   menuId: 'menu_123',
+   *   organizationId: 'org_456',
+   * });
+   * ```
+   */
+  async emit<E extends DomainEventName>(
+    event: E,
+    payload: Omit<DomainEvents[E], 'timestamp'>
+  ): Promise<boolean> {
+    // Add timestamp to payload
+    const enrichedPayload: DomainEvents[E] = {
+      ...payload,
+      timestamp: new Date().toISOString(),
+    } as DomainEvents[E];
+
+    // Track statistics
+    this.stats.totalEmitted++;
+    this.stats.emittedByEvent[event] = (this.stats.emittedByEvent[event] || 0) + 1;
+
+    // Emit with async support - wait for all listeners
+    return this.emitter.emitAsync(event, enrichedPayload).then(
+      (results) => results.length > 0,
+      (error) => {
+        this.handleError(error);
+        return false;
+      }
+    );
+  }
+
+  /**
+   * Emits an event synchronously (fire-and-forget).
+   * Use this for non-critical events where you don't need to wait.
+   *
+   * @param event - Event name
+   * @param payload - Event payload
+   * @returns True if event had listeners
+   *
+   * @example
+   * ```typescript
+   * eventService.emitSync('user.login', { userId: 'user_123' });
+   * ```
+   */
+  emitSync<E extends DomainEventName>(
+    event: E,
+    payload: Omit<DomainEvents[E], 'timestamp'>
+  ): boolean {
+    const enrichedPayload: DomainEvents[E] = {
+      ...payload,
+      timestamp: new Date().toISOString(),
+    } as DomainEvents[E];
+
+    this.stats.totalEmitted++;
+    this.stats.emittedByEvent[event] = (this.stats.emittedByEvent[event] || 0) + 1;
+
+    return this.emitter.emit(event, enrichedPayload);
+  }
+
+  /**
+   * Emits a custom (untyped) event.
+   * Use this for dynamic or module-specific events not in DomainEvents.
+   *
+   * @param event - Event name string
+   * @param payload - Event payload
+   * @returns True if event had listeners
+   *
+   * @example
+   * ```typescript
+   * await eventService.emitCustom('analytics.pageview', { path: '/menu' });
+   * ```
+   */
+  async emitCustom(event: string, payload: BaseEventPayload): Promise<boolean> {
+    const enrichedPayload: BaseEventPayload = {
+      ...payload,
+      timestamp: new Date().toISOString(),
+    };
+
+    this.stats.totalEmitted++;
+    this.stats.emittedByEvent[event] = (this.stats.emittedByEvent[event] || 0) + 1;
+
+    return this.emitter.emitAsync(event, enrichedPayload).then(
+      (results) => results.length > 0,
+      (error) => {
+        this.handleError(error);
+        return false;
+      }
+    );
+  }
+
+  // ---------------------------------------------------------------------------
+  // Event Subscription
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Subscribes to a typed domain event.
+   *
+   * @param event - Event name from DomainEvents
+   * @param handler - Event handler function
+   * @param options - Subscription options
+   * @returns Unsubscribe function
+   *
+   * @example
+   * ```typescript
+   * const unsubscribe = eventService.on('menu.created', async (payload) => {
+   *   console.log('Menu created:', payload.menuId);
+   *   await notificationService.sendMenuCreatedNotification(payload);
+   * });
+   *
+   * // Later, to unsubscribe:
+   * unsubscribe();
+   * ```
+   */
+  on<E extends DomainEventName>(
+    event: E,
+    handler: EventHandler<E>,
+    options?: EventSubscriptionOptions
+  ): () => void {
+    const listener = handler as Listener;
+
+    if (options?.once) {
+      this.emitter.once(event, listener);
+    } else if (options?.prepend) {
+      this.emitter.prependListener(event, listener);
+    } else {
+      this.emitter.on(event, listener);
+    }
+
+    // Update statistics
+    this.updateListenerStats();
+
+    // Return unsubscribe function
+    return () => {
+      this.emitter.off(event, listener);
+      this.updateListenerStats();
+    };
+  }
+
+  /**
+   * Subscribes to an event and automatically unsubscribes after first call.
+   *
+   * @param event - Event name
+   * @param handler - Event handler
+   * @returns Unsubscribe function
+   *
+   * @example
+   * ```typescript
+   * eventService.once('user.created', (payload) => {
+   *   // This will only be called once
+   * });
+   * ```
+   */
+  once<E extends DomainEventName>(
+    event: E,
+    handler: EventHandler<E>
+  ): () => void {
+    return this.on(event, handler, { once: true });
+  }
+
+  /**
+   * Subscribes to multiple events with a single handler.
+   *
+   * @param events - Array of event names
+   * @param handler - Event handler
+   * @returns Unsubscribe function for all events
+   *
+   * @example
+   * ```typescript
+   * const unsubscribe = eventService.onMany(
+   *   ['menu.created', 'menu.updated', 'menu.deleted'],
+   *   (payload) => {
+   *     console.log('Menu changed');
+   *   }
+   * );
+   * ```
+   */
+  onMany<E extends DomainEventName>(
+    events: E[],
+    handler: EventHandler<E>
+  ): () => void {
+    const unsubscribers = events.map((event) => this.on(event, handler));
+
+    return () => {
+      unsubscribers.forEach((unsub) => unsub());
+    };
+  }
+
+  /**
+   * Subscribes to events matching a wildcard pattern.
+   *
+   * @param pattern - Wildcard pattern (e.g., 'menu.*')
+   * @param handler - Wildcard event handler
+   * @returns Unsubscribe function
+   *
+   * @example
+   * ```typescript
+   * eventService.onWildcard('menu.*', (eventName, payload) => {
+   *   console.log(`Event ${eventName}:`, payload);
+   * });
+   * ```
+   */
+  onWildcard(
+    pattern: string,
+    handler: WildcardEventHandler
+  ): () => void {
+    const listener: Listener = (payload: BaseEventPayload) => {
+      // Get the actual event name from the listener context
+      const eventName = this.emitter.event as string;
+      handler(eventName, payload);
+    };
+
+    this.emitter.on(pattern, listener);
+    this.updateListenerStats();
+
+    return () => {
+      this.emitter.off(pattern, listener);
+      this.updateListenerStats();
+    };
+  }
+
+  /**
+   * Subscribes to all events (debugging/logging).
+   *
+   * @param handler - Handler that receives all events
+   * @returns Unsubscribe function
+   *
+   * @example
+   * ```typescript
+   * // Log all domain events
+   * eventService.onAny((eventName, payload) => {
+   *   logger.debug(`Event: ${eventName}`, payload);
+   * });
+   * ```
+   */
+  onAny(handler: WildcardEventHandler): () => void {
+    const listener: Listener = (payload: BaseEventPayload) => {
+      const eventName = this.emitter.event as string;
+      handler(eventName, payload);
+    };
+
+    this.emitter.onAny(listener);
+    this.updateListenerStats();
+
+    return () => {
+      this.emitter.offAny(listener);
+      this.updateListenerStats();
+    };
+  }
+
+  // ---------------------------------------------------------------------------
+  // Unsubscription
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Removes a specific handler from an event.
+   *
+   * @param event - Event name
+   * @param handler - Handler to remove
+   */
+  off<E extends DomainEventName>(event: E, handler: EventHandler<E>): void {
+    this.emitter.off(event, handler as Listener);
+    this.updateListenerStats();
+  }
+
+  /**
+   * Removes all handlers for a specific event.
+   *
+   * @param event - Event name
+   *
+   * @example
+   * ```typescript
+   * eventService.removeAllListeners('menu.created');
+   * ```
+   */
+  removeAllListeners(event?: DomainEventName): void {
+    if (event) {
+      this.emitter.removeAllListeners(event);
+    } else {
+      this.emitter.removeAllListeners();
+    }
+    this.updateListenerStats();
+  }
+
+  // ---------------------------------------------------------------------------
+  // Utilities
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets the number of listeners for an event.
+   *
+   * @param event - Event name
+   * @returns Number of listeners
+   */
+  listenerCount(event: DomainEventName): number {
+    return this.emitter.listenerCount(event);
+  }
+
+  /**
+   * Gets all registered event names.
+   *
+   * @returns Array of event names with registered listeners
+   */
+  eventNames(): string[] {
+    return this.emitter.eventNames() as string[];
+  }
+
+  /**
+   * Gets event statistics.
+   *
+   * @returns Event statistics object
+   *
+   * @example
+   * ```typescript
+   * const stats = eventService.getStats();
+   * console.log('Total events emitted:', stats.totalEmitted);
+   * ```
+   */
+  getStats(): EventStats {
+    return { ...this.stats };
+  }
+
+  /**
+   * Resets event statistics.
+   */
+  resetStats(): void {
+    this.stats = {
+      totalEmitted: 0,
+      emittedByEvent: {},
+      totalListeners: this.stats.totalListeners,
+      listenersByEvent: { ...this.stats.listenersByEvent },
+    };
+  }
+
+  /**
+   * Waits for an event to be emitted.
+   * Returns a Promise that resolves with the event payload.
+   *
+   * @param event - Event name to wait for
+   * @param timeout - Optional timeout in milliseconds
+   * @returns Promise that resolves with event payload
+   *
+   * @example
+   * ```typescript
+   * const payload = await eventService.waitFor('menu.created', 5000);
+   * console.log('Menu was created:', payload.menuId);
+   * ```
+   */
+  waitFor<E extends DomainEventName>(
+    event: E,
+    timeout?: number
+  ): Promise<DomainEvents[E]> {
+    return new Promise((resolve, reject) => {
+      let timeoutId: NodeJS.Timeout | undefined;
+
+      const handler: EventHandler<E> = (payload) => {
+        if (timeoutId) {
+          clearTimeout(timeoutId);
+        }
+        resolve(payload);
+      };
+
+      this.once(event, handler);
+
+      if (timeout) {
+        timeoutId = setTimeout(() => {
+          this.off(event, handler);
+          reject(new Error(`Timeout waiting for event: ${event}`));
+        }, timeout);
+      }
+    });
+  }
+
+  /**
+   * Gets the underlying EventEmitter2 instance.
+   * Use this for advanced features not exposed by EventService.
+   *
+   * @returns EventEmitter2 instance
+   */
+  getEmitter(): EventEmitter2 {
+    return this.emitter;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Private Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Handles errors from event listeners.
+   *
+   * @param error - Error that occurred
+   */
+  private handleError(error: unknown): void {
+    // In production, use a proper logger
+    // eslint-disable-next-line no-console
+    console.error('[EventService] Listener error:', error);
+  }
+
+  /**
+   * Updates listener statistics.
+   */
+  private updateListenerStats(): void {
+    const eventNames = this.emitter.eventNames() as string[];
+    let totalListeners = 0;
+    const listenersByEvent: Record<string, number> = {};
+
+    for (const event of eventNames) {
+      const count = this.emitter.listenerCount(event);
+      listenersByEvent[event] = count;
+      totalListeners += count;
+    }
+
+    this.stats.totalListeners = totalListeners;
+    this.stats.listenersByEvent = listenersByEvent;
+  }
+}

