+/**
+ * Permission Service
+ *
+ * Core permission service for E-Menum using CASL.
+ * Handles RBAC (Role-Based) and ABAC (Attribute-Based) access control
+ * as defined in SECURITY_MODEL.md.
+ *
+ * @module core/services/permission
+ *
+ * @example
+ * ```typescript
+ * import { PermissionService } from '@/core/services/permission.service';
+ * import { resolve, TOKENS } from '@/core/kernel/container';
+ *
+ * const permissionService = resolve<PermissionService>(TOKENS.PermissionService);
+ *
+ * // Build ability for user
+ * const ability = permissionService.defineAbilitiesFor(user, organization, 'professional');
+ *
+ * // Check permissions
+ * if (ability.can('create', 'Menu')) {
+ *   // User can create menus
+ * }
+ *
+ * // Get permissions for role
+ * const permissions = permissionService.getPermissionsForRole('manager');
+ * ```
+ */
+
+import { injectable } from 'tsyringe';
+import {
+  AbilityBuilder,
+  MongoAbility,
+  createMongoAbility,
+} from '@casl/ability';
+import { AppException } from '@/core/exceptions/app.exception';
+
+// -----------------------------------------------------------------------------
+// Type Definitions
+// -----------------------------------------------------------------------------
+
+/**
+ * Available actions for permission checks
+ * Follows CRUD + custom action patterns from SECURITY_MODEL.md
+ */
+export type PermissionAction =
+  | 'manage'    // Full control (create, read, update, delete)
+  | 'create'
+  | 'read'
+  | 'update'
+  | 'delete'
+  | 'publish'   // Publish/unpublish resources
+  | 'view'      // Same as read, but for UI distinction
+  | 'export'    // Export data
+  | 'import'    // Import data
+  | 'use'       // Use a feature (e.g., AI)
+  | 'access';   // Access a resource/feature
+
+/**
+ * Subject types for CASL ability definitions
+ * Maps to resource types in the system
+ */
+export type PermissionSubject =
+  | 'all'
+  | 'Organization'
+  | 'Branch'
+  | 'User'
+  | 'Role'
+  | 'Menu'
+  | 'Category'
+  | 'Product'
+  | 'Order'
+  | 'Table'
+  | 'QRCode'
+  | 'Media'
+  | 'Notification'
+  | 'Subscription'
+  | 'Analytics'
+  | 'AI'
+  | 'Module'
+  | 'Settings'
+  | 'AuditLog';
+
+/**
+ * All available subjects (excluding 'all')
+ */
+export const PERMISSION_SUBJECTS: Exclude<PermissionSubject, 'all'>[] = [
+  'Organization',
+  'Branch',
+  'User',
+  'Role',
+  'Menu',
+  'Category',
+  'Product',
+  'Order',
+  'Table',
+  'QRCode',
+  'Media',
+  'Notification',
+  'Subscription',
+  'Analytics',
+  'AI',
+  'Module',
+  'Settings',
+  'AuditLog',
+];
+
+/**
+ * All available actions (excluding 'manage')
+ */
+export const PERMISSION_ACTIONS: Exclude<PermissionAction, 'manage'>[] = [
+  'create',
+  'read',
+  'update',
+  'delete',
+  'publish',
+  'view',
+  'export',
+  'import',
+  'use',
+  'access',
+];
+
+/**
+ * CASL Ability type for this application
+ */
+export type AppAbility = MongoAbility<[PermissionAction, PermissionSubject]>;
+
+/**
+ * Plan tier type for plan-based restrictions
+ */
+export type PlanTier = 'free' | 'starter' | 'professional' | 'business' | 'enterprise';
+
+/**
+ * Plan tier hierarchy (index = level, higher = more permissions)
+ */
+export const PLAN_HIERARCHY: PlanTier[] = ['free', 'starter', 'professional', 'business', 'enterprise'];
+
+/**
+ * Platform-level roles (system-wide access)
+ */
+export const PLATFORM_ROLES = ['super_admin', 'admin', 'sales', 'support'] as const;
+export type PlatformRole = typeof PLATFORM_ROLES[number];
+
+/**
+ * Organization-level roles (tenant-scoped)
+ */
+export const ORGANIZATION_ROLES = ['owner', 'manager', 'staff', 'cashier', 'viewer'] as const;
+export type OrganizationRole = typeof ORGANIZATION_ROLES[number];
+
+/**
+ * All available roles
+ */
+export type UserRole = PlatformRole | OrganizationRole;
+
+/**
+ * User context for ability building
+ */
+export interface PermissionUser {
+  /** User ID */
+  id: string;
+  /** User's primary role */
+  role: string;
+  /** Whether user is a platform admin */
+  isPlatformAdmin?: boolean;
+}
+
+/**
+ * Organization context for ability building
+ */
+export interface PermissionOrganization {
+  /** Organization ID */
+  id: string;
+  /** Organization settings (may contain planTier) */
+  settings?: Record<string, unknown> | null;
+  /** Disabled features for this organization */
+  disabledFeatures?: string[];
+  /** Admin-granted overrides */
+  overrides?: Array<{
+    action: PermissionAction;
+    resource: PermissionSubject;
+    conditions?: Record<string, unknown>;
+  }>;
+}
+
+/**
+ * Permission definition for a role
+ */
+export interface RolePermission {
+  /** Permission action */
+  action: PermissionAction;
+  /** Permission subject */
+  subject: PermissionSubject;
+  /** Optional conditions for ABAC */
+  conditions?: Record<string, unknown>;
+  /** Whether this is a denial */
+  inverted?: boolean;
+}
+
+// -----------------------------------------------------------------------------
+// Permission Service Class
+// -----------------------------------------------------------------------------
+
+/**
+ * Permission service for E-Menum.
+ *
+ * Handles all permission-related operations including:
+ * - Building CASL abilities for users
+ * - Role-based permission lookups
+ * - Plan-based access restrictions
+ * - Permission checking utilities
+ *
+ * Implements the ability builder pattern from SECURITY_MODEL.md section 3.4.
+ *
+ * @example
+ * ```typescript
+ * @injectable()
+ * export class MenuController {
+ *   constructor(
+ *     @inject(TOKENS.PermissionService) private permissionService: PermissionService,
+ *   ) {}
+ *
+ *   async createMenu(req: Request) {
+ *     const ability = this.permissionService.defineAbilitiesFor(
+ *       req.user,
+ *       req.organization,
+ *       'professional'
+ *     );
+ *
+ *     if (ability.cannot('create', 'Menu')) {
+ *       throw AppException.forbidden('create Menu');
+ *     }
+ *
+ *     // Proceed with menu creation
+ *   }
+ * }
+ * ```
+ */
+@injectable()
+export class PermissionService {
+  // ---------------------------------------------------------------------------
+  // Plan Level Utilities
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets the numeric level of a plan tier.
+   *
+   * @param tier - Plan tier name
+   * @returns Numeric level (0-4)
+   *
+   * @example
+   * ```typescript
+   * const level = permissionService.getPlanLevel('professional'); // 2
+   * ```
+   */
+  getPlanLevel(tier: PlanTier | string | null | undefined): number {
+    if (!tier) return 0;
+    const index = PLAN_HIERARCHY.indexOf(tier as PlanTier);
+    return index >= 0 ? index : 0;
+  }
+
+  /**
+   * Checks if a plan tier meets the minimum required tier.
+   *
+   * @param currentTier - Current plan tier
+   * @param requiredTier - Minimum required tier
+   * @returns True if current tier meets or exceeds required tier
+   *
+   * @example
+   * ```typescript
+   * if (permissionService.meetsMinimumPlan('professional', 'starter')) {
+   *   // Professional >= Starter, returns true
+   * }
+   * ```
+   */
+  meetsMinimumPlan(
+    currentTier: PlanTier | string | null | undefined,
+    requiredTier: PlanTier
+  ): boolean {
+    return this.getPlanLevel(currentTier) >= this.getPlanLevel(requiredTier);
+  }
+
+  /**
+   * Gets the minimum plan required for a feature.
+   *
+   * @param feature - Feature name
+   * @returns Minimum plan tier, or 'free' if no restriction
+   *
+   * @example
+   * ```typescript
+   * const minPlan = permissionService.getMinimumPlanForFeature('ai');
+   * // Returns 'professional'
+   * ```
+   */
+  getMinimumPlanForFeature(feature: string): PlanTier {
+    const featurePlanMap: Record<string, PlanTier> = {
+      'ai': 'professional',
+      'ai.content': 'professional',
+      'ai.image': 'professional',
+      'ai.query': 'professional',
+      'branch': 'business',
+      'api.access': 'business',
+      'analytics.export': 'starter',
+      'custom.domain': 'business',
+      'white.label': 'enterprise',
+      'sso': 'enterprise',
+    };
+
+    return featurePlanMap[feature] || 'free';
+  }
+
+  // ---------------------------------------------------------------------------
+  // Role Utilities
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Checks if a role is a platform-level role.
+   *
+   * @param role - Role name to check
+   * @returns True if role is a platform role
+   *
+   * @example
+   * ```typescript
+   * permissionService.isPlatformRole('super_admin'); // true
+   * permissionService.isPlatformRole('owner'); // false
+   * ```
+   */
+  isPlatformRole(role: string): boolean {
+    return PLATFORM_ROLES.includes(role as PlatformRole);
+  }
+
+  /**
+   * Checks if a role is an organization-level role.
+   *
+   * @param role - Role name to check
+   * @returns True if role is an organization role
+   *
+   * @example
+   * ```typescript
+   * permissionService.isOrganizationRole('manager'); // true
+   * permissionService.isOrganizationRole('admin'); // false
+   * ```
+   */
+  isOrganizationRole(role: string): boolean {
+    return ORGANIZATION_ROLES.includes(role as OrganizationRole);
+  }
+
+  /**
+   * Gets the default permissions for a role.
+   *
+   * @param role - Role name
+   * @returns Array of permission strings (e.g., ['menu.create', 'menu.read'])
+   *
+   * @example
+   * ```typescript
+   * const permissions = permissionService.getPermissionsForRole('staff');
+   * // Returns ['menu.read', 'menu.update', 'order.manage', ...]
+   * ```
+   */
+  getPermissionsForRole(role: string): string[] {
+    const rolePermissions: Record<string, string[]> = {
+      // Platform roles
+      super_admin: ['all.manage'],
+      admin: [
+        'organization.manage',
+        'user.manage',
+        'subscription.manage',
+        'auditlog.view',
+        'module.manage',
+        'settings.manage',
+      ],
+      sales: [
+        'organization.view',
+        'organization.create',
+        'user.view',
+        'subscription.view',
+      ],
+      support: [
+        'organization.view',
+        'user.view',
+        'order.view',
+        'menu.view',
+      ],
+
+      // Organization roles
+      owner: [
+        'organization.manage',
+        'branch.manage',
+        'user.manage',
+        'role.manage',
+        'menu.manage',
+        'category.manage',
+        'product.manage',
+        'order.manage',
+        'table.manage',
+        'qrcode.manage',
+        'media.manage',
+        'notification.manage',
+        'subscription.manage',
+        'analytics.view',
+        'analytics.export',
+        'ai.use',
+        'settings.manage',
+        'auditlog.view',
+      ],
+      manager: [
+        'organization.read',
+        'branch.manage',
+        'user.manage',
+        'menu.manage',
+        'category.manage',
+        'product.manage',
+        'order.manage',
+        'table.manage',
+        'qrcode.manage',
+        'media.manage',
+        'notification.read',
+        'analytics.view',
+        'analytics.export',
+        'settings.view',
+      ],
+      staff: [
+        'organization.read',
+        'menu.read',
+        'menu.update',
+        'category.read',
+        'category.update',
+        'product.read',
+        'product.update',
+        'order.manage',
+        'table.manage',
+        'qrcode.read',
+        'media.create',
+        'media.read',
+        'notification.read',
+      ],
+      cashier: [
+        'organization.read',
+        'menu.read',
+        'category.read',
+        'product.read',
+        'order.create',
+        'order.read',
+        'order.update',
+        'table.read',
+        'table.update',
+        'qrcode.read',
+      ],
+      viewer: [
+        'organization.read',
+        'menu.read',
+        'category.read',
+        'product.read',
+        'order.read',
+        'table.read',
+        'qrcode.read',
+        'analytics.view',
+      ],
+    };
+
+    return rolePermissions[role] || [];
+  }
+
+  // ---------------------------------------------------------------------------
+  // CASL Ability Builder
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Defines CASL abilities for a user based on their role and organization.
+   * Implements the ability builder pattern from SECURITY_MODEL.md section 3.4.
+   *
+   * @param user - Authenticated user context
+   * @param organization - Organization/tenant context (optional for platform users)
+   * @param planTier - Organization's subscription plan tier
+   * @returns CASL ability instance
+   *
+   * @example
+   * ```typescript
+   * const ability = permissionService.defineAbilitiesFor(user, organization, 'professional');
+   * if (ability.can('create', 'Menu')) {
+   *   // User can create menus
+   * }
+   * ```
+   */
+  defineAbilitiesFor(
+    user: PermissionUser,
+    organization?: PermissionOrganization,
+    planTier?: PlanTier | string | null
+  ): AppAbility {
+    const { can, cannot, build } = new AbilityBuilder<AppAbility>(createMongoAbility);
+
+    // -------------------------------------------------------------------------
+    // Platform Admin Roles (System-wide access)
+    // -------------------------------------------------------------------------
+
+    if (user.role === 'super_admin') {
+      // Super admin has full access to everything
+      can('manage', 'all');
+      return build();
+    }
+
+    if (user.role === 'admin') {
+      // Admin can manage most platform resources
+      can('manage', 'Organization');
+      can('manage', 'User');
+      can('manage', 'Subscription');
+      can('view', 'AuditLog');
+      can('manage', 'Module');
+      can('manage', 'Settings');
+      return build();
+    }
+
+    if (user.role === 'sales') {
+      // Sales can view organizations and manage CRM
+      can('view', 'Organization');
+      can('create', 'Organization');
+      can('view', 'User');
+      can('view', 'Subscription');
+      return build();
+    }
+
+    if (user.role === 'support') {
+      // Support can view and help with issues
+      can('view', 'Organization');
+      can('view', 'User');
+      can('view', 'Order');
+      can('view', 'Menu');
+      return build();
+    }
+
+    // -------------------------------------------------------------------------
+    // Organization Roles (Tenant-scoped access)
+    // -------------------------------------------------------------------------
+
+    // For non-platform roles, organization context is required
+    if (!organization) {
+      // No permissions without organization context
+      return build();
+    }
+
+    const orgId = organization.id;
+
+    // Base tenant isolation - CRITICAL: Always scope to organization
+    // All following rules implicitly apply this condition
+    const orgCondition = { organizationId: orgId };
+
+    switch (user.role) {
+      case 'owner':
+        // Owner has full access within their organization
+        can('manage', 'Organization', { id: orgId });
+        can('manage', 'Branch', orgCondition);
+        can('manage', 'User', orgCondition);
+        can('manage', 'Role', orgCondition);
+        can('manage', 'Menu', orgCondition);
+        can('manage', 'Category', orgCondition);
+        can('manage', 'Product', orgCondition);
+        can('manage', 'Order', orgCondition);
+        can('manage', 'Table', orgCondition);
+        can('manage', 'QRCode', orgCondition);
+        can('manage', 'Media', orgCondition);
+        can('manage', 'Notification', orgCondition);
+        can('manage', 'Subscription', orgCondition);
+        can('view', 'Analytics', orgCondition);
+        can('export', 'Analytics', orgCondition);
+        can('use', 'AI', orgCondition);
+        can('manage', 'Settings', orgCondition);
+        can('view', 'AuditLog', orgCondition);
+        break;
+
+      case 'manager':
+        // Manager can manage most resources except billing
+        can('read', 'Organization', { id: orgId });
+        can('manage', 'Branch', orgCondition);
+        can('manage', 'User', { ...orgCondition, role: { $ne: 'owner' } });
+        can('manage', 'Menu', orgCondition);
+        can('manage', 'Category', orgCondition);
+        can('manage', 'Product', orgCondition);
+        can('manage', 'Order', orgCondition);
+        can('manage', 'Table', orgCondition);
+        can('manage', 'QRCode', orgCondition);
+        can('manage', 'Media', orgCondition);
+        can('read', 'Notification', orgCondition);
+        can('view', 'Analytics', orgCondition);
+        can('export', 'Analytics', orgCondition);
+        can('view', 'Settings', orgCondition);
+        // Managers cannot manage billing/subscription
+        cannot('manage', 'Subscription');
+        break;
+
+      case 'staff':
+        // Staff can manage orders and update menus
+        can('read', 'Organization', { id: orgId });
+        can('read', 'Menu', orgCondition);
+        can('update', 'Menu', orgCondition);
+        can('read', 'Category', orgCondition);
+        can('update', 'Category', orgCondition);
+        can('read', 'Product', orgCondition);
+        can('update', 'Product', orgCondition);
+        can('manage', 'Order', orgCondition);
+        can('manage', 'Table', orgCondition);
+        can('read', 'QRCode', orgCondition);
+        can('create', 'Media', orgCondition);
+        can('read', 'Media', orgCondition);
+        can('read', 'Notification', orgCondition);
+        // Staff cannot delete menus/products or manage users
+        cannot('delete', 'Menu');
+        cannot('delete', 'Category');
+        cannot('delete', 'Product');
+        cannot('manage', 'User');
+        break;
+
+      case 'cashier':
+        // Cashier can handle orders and tables
+        can('read', 'Organization', { id: orgId });
+        can('read', 'Menu', orgCondition);
+        can('read', 'Category', orgCondition);
+        can('read', 'Product', orgCondition);
+        can('create', 'Order', orgCondition);
+        can('read', 'Order', orgCondition);
+        can('update', 'Order', orgCondition);
+        can('read', 'Table', orgCondition);
+        can('update', 'Table', orgCondition);
+        can('read', 'QRCode', orgCondition);
+        // Cashier cannot modify menu items or cancel orders
+        cannot('delete', 'Order');
+        break;
+
+      case 'viewer':
+        // Viewer has read-only access
+        can('read', 'Organization', { id: orgId });
+        can('read', 'Menu', orgCondition);
+        can('read', 'Category', orgCondition);
+        can('read', 'Product', orgCondition);
+        can('read', 'Order', orgCondition);
+        can('read', 'Table', orgCondition);
+        can('read', 'QRCode', orgCondition);
+        can('view', 'Analytics', orgCondition);
+        break;
+
+      default:
+        // Unknown role - minimal permissions
+        can('read', 'Organization', { id: orgId });
+        break;
+    }
+
+    // -------------------------------------------------------------------------
+    // Plan-Based Restrictions (ABAC Layer)
+    // -------------------------------------------------------------------------
+
+    const currentPlanLevel = this.getPlanLevel(planTier);
+
+    // AI features require professional plan or higher
+    if (currentPlanLevel < this.getPlanLevel('professional')) {
+      cannot('use', 'AI');
+    }
+
+    // Branch management requires business plan or higher
+    if (currentPlanLevel < this.getPlanLevel('business')) {
+      cannot('manage', 'Branch');
+      cannot('create', 'Branch');
+    }
+
+    // API access restrictions (for external API usage)
+    if (currentPlanLevel < this.getPlanLevel('business')) {
+      cannot('access', 'all');
+    }
+
+    // Analytics export requires starter plan or higher
+    if (currentPlanLevel < this.getPlanLevel('starter')) {
+      cannot('export', 'Analytics');
+    }
+
+    // -------------------------------------------------------------------------
+    // Feature Flags (Organization-specific disabled features)
+    // -------------------------------------------------------------------------
+
+    if (organization.disabledFeatures) {
+      for (const feature of organization.disabledFeatures) {
+        // Parse feature string (e.g., 'ai' → cannot use AI)
+        const [subject, action] = this.parseFeatureString(feature);
+        if (subject && action) {
+          cannot(action, subject);
+        }
+      }
+    }
+
+    // -------------------------------------------------------------------------
+    // Admin Overrides (Granted permissions)
+    // -------------------------------------------------------------------------
+
+    if (organization.overrides) {
+      for (const override of organization.overrides) {
+        can(override.action, override.resource, override.conditions);
+      }
+    }
+
+    return build();
+  }
+
+  /**
+   * Creates an empty ability with no permissions.
+   * Useful for anonymous users or error states.
+   *
+   * @returns Empty CASL ability instance
+   */
+  createEmptyAbility(): AppAbility {
+    return createMongoAbility<[PermissionAction, PermissionSubject]>([]);
+  }
+
+  /**
+   * Creates an ability for anonymous/public access.
+   * Only allows reading public resources.
+   *
+   * @param organizationId - Optional organization ID for public menu access
+   * @returns CASL ability for anonymous users
+   */
+  createAnonymousAbility(organizationId?: string): AppAbility {
+    const { can, build } = new AbilityBuilder<AppAbility>(createMongoAbility);
+
+    if (organizationId) {
+      const orgCondition = { organizationId };
+      can('read', 'Menu', { ...orgCondition, isPublic: true });
+      can('read', 'Category', orgCondition);
+      can('read', 'Product', { ...orgCondition, isActive: true });
+    }
+
+    return build();
+  }
+
+  // ---------------------------------------------------------------------------
+  // Permission Checking Utilities
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Checks if a user can perform an action on a subject.
+   *
+   * @param ability - CASL ability instance
+   * @param action - Action to check
+   * @param subject - Subject/resource to check
+   * @returns True if action is allowed
+   *
+   * @example
+   * ```typescript
+   * if (permissionService.can(ability, 'create', 'Menu')) {
+   *   // Show create button
+   * }
+   * ```
+   */
+  can(
+    ability: AppAbility,
+    action: PermissionAction,
+    subject: PermissionSubject
+  ): boolean {
+    return ability.can(action, subject);
+  }
+
+  /**
+   * Checks if a user cannot perform an action on a subject.
+   *
+   * @param ability - CASL ability instance
+   * @param action - Action to check
+   * @param subject - Subject/resource to check
+   * @returns True if action is denied
+   */
+  cannot(
+    ability: AppAbility,
+    action: PermissionAction,
+    subject: PermissionSubject
+  ): boolean {
+    return ability.cannot(action, subject);
+  }
+
+  /**
+   * Asserts that a user can perform an action, throwing if not.
+   *
+   * @param ability - CASL ability instance
+   * @param action - Action to check
+   * @param subject - Subject/resource to check
+   * @throws AppException.forbidden() if action is denied
+   *
+   * @example
+   * ```typescript
+   * // In a service method
+   * permissionService.assertCan(ability, 'delete', 'Menu');
+   * // If we get here, user has permission
+   * await this.menuRepository.delete(menuId);
+   * ```
+   */
+  assertCan(
+    ability: AppAbility,
+    action: PermissionAction,
+    subject: PermissionSubject
+  ): void {
+    if (ability.cannot(action, subject)) {
+      throw AppException.forbidden(`${action} ${subject}`);
+    }
+  }
+
+  /**
+   * Asserts that a user meets the minimum plan requirement.
+   *
+   * @param planTier - Current plan tier
+   * @param requiredTier - Minimum required tier
+   * @param feature - Feature name for error message
+   * @throws AppException.insufficientPlan() if plan is insufficient
+   */
+  assertMinimumPlan(
+    planTier: PlanTier | string | null | undefined,
+    requiredTier: PlanTier,
+    feature: string
+  ): void {
+    if (!this.meetsMinimumPlan(planTier, requiredTier)) {
+      throw AppException.insufficientPlan(feature, requiredTier);
+    }
+  }
+
+  // ---------------------------------------------------------------------------
+  // Permission Packing (for JWT tokens)
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Packs an ability into an array of permission strings.
+   * Useful for sending permissions to frontend or storing in JWT.
+   *
+   * @param ability - CASL ability instance
+   * @returns Array of permission strings (e.g., ['menu.create', 'menu.read'])
+   *
+   * @example
+   * ```typescript
+   * const ability = permissionService.defineAbilitiesFor(user, org, 'pro');
+   * const permissions = permissionService.packPermissions(ability);
+   * // permissions = ['menu.create', 'menu.read', 'menu.update', ...]
+   * ```
+   */
+  packPermissions(ability: AppAbility): string[] {
+    const permissions: string[] = [];
+
+    for (const subject of PERMISSION_SUBJECTS) {
+      for (const action of PERMISSION_ACTIONS) {
+        if (ability.can(action, subject)) {
+          permissions.push(`${subject.toLowerCase()}.${action}`);
+        }
+      }
+      // Check for manage (full control)
+      if (ability.can('manage', subject)) {
+        permissions.push(`${subject.toLowerCase()}.manage`);
+      }
+    }
+
+    // Check for 'all' subject
+    if (ability.can('manage', 'all')) {
+      permissions.push('all.manage');
+    }
+
+    // Remove duplicates and sort
+    return [...new Set(permissions)].sort();
+  }
+
+  /**
+   * Unpacks permission strings into an ability.
+   * Useful for rebuilding ability from JWT token.
+   *
+   * Note: This creates a simplified ability without conditions.
+   * For full ABAC support, use defineAbilitiesFor instead.
+   *
+   * @param permissions - Array of permission strings
+   * @returns CASL ability instance
+   *
+   * @example
+   * ```typescript
+   * const permissions = ['menu.create', 'menu.read', 'order.manage'];
+   * const ability = permissionService.unpackPermissions(permissions);
+   * ```
+   */
+  unpackPermissions(permissions: string[]): AppAbility {
+    const { can, build } = new AbilityBuilder<AppAbility>(createMongoAbility);
+
+    for (const permission of permissions) {
+      const [subject, action] = this.parsePermissionString(permission);
+      if (subject && action) {
+        can(action, subject);
+      }
+    }
+
+    return build();
+  }
+
+  // ---------------------------------------------------------------------------
+  // Private Helper Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Parses a permission string into subject and action.
+   *
+   * @param permission - Permission string (e.g., 'menu.create')
+   * @returns Tuple of [subject, action] or [null, null] if invalid
+   */
+  private parsePermissionString(
+    permission: string
+  ): [PermissionSubject | null, PermissionAction | null] {
+    const parts = permission.split('.');
+    if (parts.length !== 2) {
+      return [null, null];
+    }
+
+    const [subjectLower, actionLower] = parts;
+
+    // Handle 'all' subject
+    if (subjectLower === 'all') {
+      if (actionLower === 'manage') {
+        return ['all', 'manage'];
+      }
+      return [null, null];
+    }
+
+    // Find matching subject (case-insensitive)
+    const subject = PERMISSION_SUBJECTS.find(
+      s => s.toLowerCase() === subjectLower
+    );
+
+    // Find matching action
+    const action = [...PERMISSION_ACTIONS, 'manage' as const].find(
+      a => a === actionLower
+    ) as PermissionAction | undefined;
+
+    if (!subject || !action) {
+      return [null, null];
+    }
+
+    return [subject, action];
+  }
+
+  /**
+   * Parses a feature string into subject and action.
+   *
+   * @param feature - Feature string (e.g., 'ai', 'analytics.export')
+   * @returns Tuple of [subject, action] or [null, null] if invalid
+   */
+  private parseFeatureString(
+    feature: string
+  ): [PermissionSubject | null, PermissionAction | null] {
+    // Some features are just a subject name (implying 'use' action)
+    if (!feature.includes('.')) {
+      const subject = PERMISSION_SUBJECTS.find(
+        s => s.toLowerCase() === feature.toLowerCase()
+      );
+      if (subject) {
+        return [subject, 'use'];
+      }
+      return [null, null];
+    }
+
+    return this.parsePermissionString(feature);
+  }
+
+  /**
+   * Gets all possible permission strings for documentation.
+   *
+   * @returns Array of all permission strings
+   */
+  getAllPermissionStrings(): string[] {
+    const permissions: string[] = [];
+
+    for (const subject of PERMISSION_SUBJECTS) {
+      for (const action of PERMISSION_ACTIONS) {
+        permissions.push(`${subject.toLowerCase()}.${action}`);
+      }
+      permissions.push(`${subject.toLowerCase()}.manage`);
+    }
+
+    permissions.push('all.manage');
+
+    return permissions.sort();
+  }
+}

