+      const result = await service.changePassword(mockUser.id, validChangePasswordData);
+
+      // Assert
+      expect(result.message).toContain('successfully');
+      expect(result.sessionsRevoked).toBe(true);
+      expect(mockAuthService.verifyPassword).toHaveBeenCalledWith(
+        validChangePasswordData.currentPassword,
+        mockUser.passwordHash
+      );
+      expect(mockAuthService.hashPassword).toHaveBeenCalledWith(validChangePasswordData.newPassword);
+      expect(mockAuthService.revokeAllUserTokens).toHaveBeenCalledWith(mockUser.id);
+    });
+
+    it('should throw error when user not found', async () => {
+      // Arrange
+      mockPrisma.user.findUnique.mockResolvedValue(null);
+
+      // Act & Assert
+      await expect(service.changePassword('nonexistent_user', validChangePasswordData)).rejects.toThrow(
+        AppException
+      );
+    });
+
+    it('should throw error when current password is incorrect', async () => {
+      // Arrange
+      const mockUser = createMockUser();
+      mockPrisma.user.findUnique.mockResolvedValue(mockUser);
+      mockAuthService.verifyPassword.mockResolvedValue(false);
+
+      // Act & Assert
+      await expect(service.changePassword(mockUser.id, validChangePasswordData)).rejects.toThrow(
+        AppException
+      );
+    });
+  });
+
+  // ---------------------------------------------------------------------------
+  // Session Management Tests
+  // ---------------------------------------------------------------------------
+
+  describe('getSessions', () => {
+    it('should return user sessions with current session marked', async () => {
+      // Arrange
+      const mockSessions = [
+        {
+          tokenId: 'token_1',
+          userId: 'user_123',
+          organizationId: 'org_123',
+          role: 'owner',
+          ipAddress: '192.168.1.1',
+          userAgent: 'Chrome',
+          createdAt: new Date().toISOString(),
+          lastActivityAt: new Date().toISOString(),
+        },
+        {
+          tokenId: 'token_2',
+          userId: 'user_123',
+          organizationId: 'org_123',
+          role: 'owner',
+          ipAddress: '192.168.1.2',
+          userAgent: 'Firefox',
+          createdAt: new Date().toISOString(),
+          lastActivityAt: new Date().toISOString(),
+        },
+      ];
+      mockAuthService.getUserSessions.mockResolvedValue(mockSessions);
+
+      // Act
+      const result = await service.getSessions('user_123', 'token_1');
+
+      // Assert
+      expect(result).toHaveLength(2);
+      expect(result[0]?.isCurrent).toBe(true);
+      expect(result[1]?.isCurrent).toBe(false);
+    });
+  });
+
+  describe('revokeSession', () => {
+    it('should revoke a specific session', async () => {
+      // Arrange
+      const mockSessions = [
+        {
+          tokenId: 'token_1',
+          userId: 'user_123',
+          organizationId: 'org_123',
+          role: 'owner',
+          ipAddress: '192.168.1.1',
+          userAgent: 'Chrome',
+          createdAt: new Date().toISOString(),
+          lastActivityAt: new Date().toISOString(),
+        },
+      ];
+      mockAuthService.getUserSessions.mockResolvedValue(mockSessions);
+      mockEventService.emitCustom.mockResolvedValue(undefined);
+
+      // Act
+      await service.revokeSession('user_123', 'token_1');
+
+      // Assert
+      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
+        'auth.session.revoked',
+        expect.objectContaining({
+          userId: 'user_123',
+          sessionId: 'token_1',
+        })
+      );
+    });
+
+    it('should throw error when session not found', async () => {
+      // Arrange
+      mockAuthService.getUserSessions.mockResolvedValue([]);
+
+      // Act & Assert
+      await expect(service.revokeSession('user_123', 'nonexistent_token')).rejects.toThrow(AppException);
+    });
+  });
+});

diff --git a/src/modules/_core/auth/auth.module.ts b/src/modules/_core/auth/auth.module.ts
