@@ -0,0 +1,394 @@
+/**
+ * Auth Module Definition
+ *
+ * Core authentication module for E-Menum.
+ * Provides JWT-based authentication, session management,
+ * password handling, and token lifecycle management.
+ *
+ * This is a CORE module - it cannot be disabled.
+ *
+ * @module modules/_core/auth/auth.module
+ *
+ * @example
+ * ```typescript
+ * import { AuthModule } from '@/modules/_core/auth/auth.module';
+ *
+ * // Module is automatically discovered and loaded by ModuleLoader
+ * // Access module instance via DI container
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+import { TOKENS, registerSingleton, appContainer } from '@/core/kernel/container';
+import type { ModuleInstance } from '@/core/kernel/module-loader';
+import type { EventService } from '@/core/services/event.service';
+
+import { AuthController } from '@/modules/_core/auth/auth.controller';
+import { AuthModuleService } from '@/modules/_core/auth/auth.service';
+import { authRoutes } from '@/modules/_core/auth/auth.routes';
+import type { AuthModuleSettings } from '@/modules/_core/auth/auth.types';
+
+// -----------------------------------------------------------------------------
+// Module Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Auth module context for lifecycle hooks
+ */
+export interface AuthModuleContext {
+  /** Event service for pub/sub */
+  events: EventService;
+  /** Module settings */
+  settings: AuthModuleSettings;
+  /** Logger function */
+  log: (message: string) => void;
+}
+
+/**
+ * Auth module hook definitions
+ */
+export interface AuthModuleHooks {
+  /** Called before login attempt */
+  beforeLogin?: (data: { email: string; ipAddress?: string }) => Promise<void>;
+  /** Called after successful login */
+  afterLogin?: (data: { userId: string; sessionId: string }) => Promise<void>;
+  /** Called before logout */
+  beforeLogout?: (data: { userId: string; allDevices: boolean }) => Promise<void>;
+  /** Called after logout */
+  afterLogout?: (data: { userId: string; allDevices: boolean }) => Promise<void>;
+  /** Called before token refresh */
+  beforeTokenRefresh?: (data: { userId: string }) => Promise<void>;
+  /** Called after token refresh */
+  afterTokenRefresh?: (data: { userId: string }) => Promise<void>;
+  /** Called before password reset */
+  beforePasswordReset?: (data: { userId: string }) => Promise<void>;
+  /** Called after password reset */
+  afterPasswordReset?: (data: { userId: string }) => Promise<void>;
+}
+
+// -----------------------------------------------------------------------------
+// Auth Module Class
+// -----------------------------------------------------------------------------
+
+/**
+ * Authentication Module
+ *
+ * Core module providing authentication infrastructure for E-Menum.
+ * Handles user authentication, token management, and session control.
+ *
+ * Features:
+ * - JWT-based authentication with access/refresh tokens
+ * - Session management (multi-device support)
+ * - Password reset flow
+ * - Email verification flow
+ * - Secure token storage and rotation
+ *
+ * @example
+ * ```typescript
+ * // Module is automatically loaded by ModuleLoader
+ * // Use AuthModuleService for business logic
+ * const authService = container.resolve('AuthModuleService');
+ * await authService.login({ email, password });
+ * ```
+ */
+@injectable()
+export class AuthModule implements ModuleInstance {
+  // ---------------------------------------------------------------------------
+  // Static Properties
+  // ---------------------------------------------------------------------------
+
+  /** Module ID */
+  static readonly id = 'auth';
+
+  /** Module name */
+  static readonly name = 'Authentication Module';
+
+  /** Module version */
+  static readonly version = '1.0.0';
+
+  /** Is core module (cannot be disabled) */
+  static readonly isCore = true;
+
+  /** Module routes configuration */
+  static readonly routes = authRoutes;
+
+  /** Providers (services) to register */
+  static readonly providers = [AuthModuleService];
+
+  /** Controllers to register */
+  static readonly controllers = [AuthController];
+
+  // ---------------------------------------------------------------------------
+  // Instance Properties
+  // ---------------------------------------------------------------------------
+
+  /** Module hooks registry */
+  private hooks: AuthModuleHooks = {};
+
+  /** Module initialized flag */
+  private initialized = false;
+
+  constructor(
+    @inject(TOKENS.EventService) private readonly eventService: EventService
+  ) {}
+
+  // ---------------------------------------------------------------------------
+  // ModuleInstance Lifecycle Hooks
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Called when module is loaded.
+   * Registers services with DI container.
+   */
+  async onLoad(): Promise<void> {
+    this.log('Loading auth module...');
+
+    // Register AuthModuleService with DI container
+    if (!appContainer.isRegistered('AuthModuleService')) {
+      registerSingleton('AuthModuleService', AuthModuleService);
+    }
+
+    this.log('Auth module loaded');
+  }
+
+  /**
+   * Called when module is enabled/activated.
+   * Sets up event listeners and registers routes.
+   */
+  async onEnable(): Promise<void> {
+    if (this.initialized) {
+      this.log('Auth module already initialized');
+      return;
+    }
+
+    this.log('Enabling auth module...');
+
+    // Subscribe to relevant events
+    this.setupEventListeners();
+
+    this.initialized = true;
+    this.log('Auth module enabled');
+
+    // Emit module activated event
+    await this.eventService.emitCustom('module.activated', {
+      moduleId: AuthModule.id,
+      timestamp: new Date().toISOString(),
+    });
+  }
+
+  /**
+   * Called when module is disabled/deactivated.
+   * Core modules cannot be fully disabled, but this handles graceful pause.
+   */
+  async onDisable(): Promise<void> {
+    this.log('Auth module disable requested (core module - limited action)');
+
+    // Core modules cannot be fully disabled
+    // This would only be called during shutdown
+
+    this.initialized = false;
+    this.log('Auth module disabled');
+  }
+
+  /**
+   * Called when module is unloaded.
+   * Cleans up resources.
+   */
+  async onUnload(): Promise<void> {
+    this.log('Unloading auth module...');
+
+    // Clear hooks
+    this.hooks = {};
+
+    this.log('Auth module unloaded');
+  }
+
+  // ---------------------------------------------------------------------------
+  // ModuleInstance Interface Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Returns module routes for registration with Express.
+   *
+   * @returns Route configuration array
+   */
+  getRoutes(): unknown[] {
+    return [authRoutes];
+  }
+
+  /**
+   * Returns module controllers for registration with routing-controllers.
+   *
+   * @returns Controller class array
+   */
+  getControllers(): unknown[] {
+    return AuthModule.controllers;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Hook System
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets current module hooks.
+   *
+   * @returns Module hooks object
+   */
+  getHooks(): AuthModuleHooks {
+    return { ...this.hooks };
+  }
+
+  /**
+   * Registers a hook handler.
+   *
+   * @param hookName - Name of the hook
+   * @param handler - Hook handler function
+   *
+   * @example
+   * ```typescript
+   * authModule.registerHook('afterLogin', async (data) => {
+   *   console.log('User logged in:', data.userId);
+   * });
+   * ```
+   */
+  registerHook<K extends keyof AuthModuleHooks>(
+    hookName: K,
+    handler: AuthModuleHooks[K]
+  ): void {
+    this.hooks[hookName] = handler;
+    this.log(`Registered hook: ${hookName}`);
+  }
+
+  /**
+   * Unregisters a hook handler.
+   *
+   * @param hookName - Name of the hook to unregister
+   */
+  unregisterHook(hookName: keyof AuthModuleHooks): void {
+    delete this.hooks[hookName];
+    this.log(`Unregistered hook: ${hookName}`);
+  }
+
+  /**
+   * Executes a hook if registered.
+   *
+   * @param hookName - Name of the hook
+   * @param data - Data to pass to the hook
+   */
+  async executeHook<K extends keyof AuthModuleHooks>(
+    hookName: K,
+    data: Parameters<NonNullable<AuthModuleHooks[K]>>[0]
+  ): Promise<void> {
+    const hook = this.hooks[hookName];
+    if (hook) {
+      try {
+        await (hook as (data: typeof data) => Promise<void>)(data);
+      } catch (error) {
+        this.log(`Hook execution error (${hookName}): ${error instanceof Error ? error.message : 'Unknown error'}`);
+      }
+    }
+  }
+
+  // ---------------------------------------------------------------------------
+  // Event Listeners
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Sets up event listeners for the auth module.
+   */
+  private setupEventListeners(): void {
+    // Listen for user-related events that may require auth actions
+    this.eventService.on('user.deleted', async (payload) => {
+      this.log(`User deleted event received: ${payload.userId}`);
+      // Could trigger session cleanup, etc.
+    });
+
+    // Listen for organization-related events
+    this.eventService.on('organization.deleted', async (payload) => {
+      this.log(`Organization deleted event received: ${payload.organizationId}`);
+      // Could trigger session cleanup for all org users
+    });
+
+    this.log('Event listeners set up');
+  }
+
+  // ---------------------------------------------------------------------------
+  // Module Settings
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets default module settings.
+   *
+   * @returns Default auth module settings
+   */
+  static getDefaultSettings(): AuthModuleSettings {
+    return {
+      accessTokenExpiry: '15m',
+      refreshTokenExpiry: '7d',
+      passwordMinLength: 8,
+      passwordRequireUppercase: true,
+      passwordRequireLowercase: true,
+      passwordRequireNumber: true,
+      passwordRequireSpecial: false,
+      maxLoginAttempts: 10,
+      lockoutDuration: 1800, // 30 minutes
+      sessionMaxCount: 5,
+      enableEmailVerification: true,
+      enablePasswordReset: true,
+    };
+  }
+
+  // ---------------------------------------------------------------------------
+  // Utility Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Logs a message with module prefix.
+   *
+   * @param message - Message to log
+   */
+  private log(message: string): void {
+    // eslint-disable-next-line no-console
+    console.log(`[AuthModule] ${message}`);
+  }
+
+  /**
+   * Checks if module is initialized.
+   *
+   * @returns True if module is initialized
+   */
+  isInitialized(): boolean {
+    return this.initialized;
+  }
+
+  /**
+   * Gets module metadata.
+   *
+   * @returns Module metadata object
+   */
+  static getMetadata() {
+    return {
+      id: AuthModule.id,
+      name: AuthModule.name,
+      version: AuthModule.version,
+      isCore: AuthModule.isCore,
+      routes: AuthModule.routes,
+      providers: AuthModule.providers.map((p) => p.name),
+      controllers: AuthModule.controllers.map((c) => c.name),
+    };
+  }
+}
+
+// -----------------------------------------------------------------------------
+// Module Exports
+// -----------------------------------------------------------------------------
+
+/**
+ * Default export for module loader dynamic import
+ */
+export default AuthModule;
+
+/**
+ * Export module metadata
+ */
+export const metadata = AuthModule.getMetadata();

diff --git a/src/modules/_core/auth/auth.types.ts b/src/modules/_core/auth/auth.types.ts
