@@ -0,0 +1,389 @@
+/**
+ * Branch Module Definition
+ *
+ * Core branch management module for E-Menum.
+ * Provides multi-location support, branch hierarchy, and branch-specific settings.
+ *
+ * This is a CORE module - it cannot be disabled.
+ *
+ * @module modules/_core/branch/branch.module
+ *
+ * @example
+ * ```typescript
+ * import { BranchModule } from '@/modules/_core/branch/branch.module';
+ *
+ * // Module is automatically discovered and loaded by ModuleLoader
+ * // Access module instance via DI container
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+import { TOKENS, registerSingleton, appContainer } from '@/core/kernel/container';
+import type { ModuleInstance } from '@/core/kernel/module-loader';
+import type { EventService } from '@/core/services/event.service';
+
+import { BranchController } from '@/modules/_core/branch/branch.controller';
+import { BranchService } from '@/modules/_core/branch/branch.service';
+import { BranchRepository } from '@/modules/_core/branch/branch.repository';
+import { branchRoutes } from '@/modules/_core/branch/branch.routes';
+import type { BranchModuleSettings } from '@/modules/_core/branch/branch.types';
+
+// -----------------------------------------------------------------------------
+// Module Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Branch module context for lifecycle hooks
+ */
+export interface BranchModuleContext {
+  /** Event service for pub/sub */
+  events: EventService;
+  /** Module settings */
+  settings: BranchModuleSettings;
+  /** Logger function */
+  log: (message: string) => void;
+}
+
+/**
+ * Branch module hook definitions
+ */
+export interface BranchModuleHooks {
+  /** Called before branch creation */
+  beforeCreate?: (data: { name: string; code: string; organizationId: string }) => Promise<void>;
+  /** Called after branch creation */
+  afterCreate?: (data: { branchId: string; organizationId: string }) => Promise<void>;
+  /** Called before branch update */
+  beforeUpdate?: (data: { branchId: string; organizationId: string }) => Promise<void>;
+  /** Called after branch update */
+  afterUpdate?: (data: { branchId: string; organizationId: string }) => Promise<void>;
+  /** Called before branch deletion */
+  beforeDelete?: (data: { branchId: string; organizationId: string }) => Promise<void>;
+  /** Called after branch deletion */
+  afterDelete?: (data: { branchId: string; organizationId: string }) => Promise<void>;
+}
+
+// -----------------------------------------------------------------------------
+// Branch Module Class
+// -----------------------------------------------------------------------------
+
+/**
+ * Branch Module
+ *
+ * Core module providing branch/location management for E-Menum.
+ * Handles multi-location support, branch hierarchy, and branch-specific settings.
+ *
+ * Features:
+ * - Branch CRUD operations with tenant isolation
+ * - Hierarchical structure (parent/child relationships)
+ * - Branch-specific settings (operating hours, features, display)
+ * - Status management (active, inactive, suspended)
+ * - Code uniqueness enforcement
+ * - Soft delete with restore capability
+ *
+ * @example
+ * ```typescript
+ * // Module is automatically loaded by ModuleLoader
+ * // Use BranchService for business logic
+ * const branchService = container.resolve('BranchService');
+ * await branchService.create('org_123', { name: 'Downtown', code: 'DOWNTOWN' });
+ * ```
+ */
+@injectable()
+export class BranchModule implements ModuleInstance {
+  // ---------------------------------------------------------------------------
+  // Static Properties
+  // ---------------------------------------------------------------------------
+
+  /** Module ID */
+  static readonly id = 'branch';
+
+  /** Module name */
+  static readonly name = 'Branch Module';
+
+  /** Module version */
+  static readonly version = '1.0.0';
+
+  /** Is core module (cannot be disabled) */
+  static readonly isCore = true;
+
+  /** Module routes configuration */
+  static readonly routes = branchRoutes;
+
+  /** Providers (services) to register */
+  static readonly providers = [BranchService, BranchRepository];
+
+  /** Controllers to register */
+  static readonly controllers = [BranchController];
+
+  // ---------------------------------------------------------------------------
+  // Instance Properties
+  // ---------------------------------------------------------------------------
+
+  /** Module hooks registry */
+  private hooks: BranchModuleHooks = {};
+
+  /** Module initialized flag */
+  private initialized = false;
+
+  constructor(
+    @inject(TOKENS.EventService) private readonly eventService: EventService
+  ) {}
+
+  // ---------------------------------------------------------------------------
+  // ModuleInstance Lifecycle Hooks
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Called when module is loaded.
+   * Registers services with DI container.
+   */
+  async onLoad(): Promise<void> {
+    this.log('Loading branch module...');
+
+    // Register BranchRepository with DI container
+    if (!appContainer.isRegistered('BranchRepository')) {
+      registerSingleton('BranchRepository', BranchRepository);
+    }
+
+    // Register BranchService with DI container
+    if (!appContainer.isRegistered('BranchService')) {
+      registerSingleton('BranchService', BranchService);
+    }
+
+    this.log('Branch module loaded');
+  }
+
+  /**
+   * Called when module is enabled/activated.
+   * Sets up event listeners and registers routes.
+   */
+  async onEnable(): Promise<void> {
+    if (this.initialized) {
+      this.log('Branch module already initialized');
+      return;
+    }
+
+    this.log('Enabling branch module...');
+
+    // Subscribe to relevant events
+    this.setupEventListeners();
+
+    this.initialized = true;
+    this.log('Branch module enabled');
+
+    // Emit module activated event
+    await this.eventService.emitCustom('module.activated', {
+      moduleId: BranchModule.id,
+      timestamp: new Date().toISOString(),
+    });
+  }
+
+  /**
+   * Called when module is disabled/deactivated.
+   * Core modules cannot be fully disabled, but this handles graceful pause.
+   */
+  async onDisable(): Promise<void> {
+    this.log('Branch module disable requested (core module - limited action)');
+
+    // Core modules cannot be fully disabled
+    // This would only be called during shutdown
+
+    this.initialized = false;
+    this.log('Branch module disabled');
+  }
+
+  /**
+   * Called when module is unloaded.
+   * Cleans up resources.
+   */
+  async onUnload(): Promise<void> {
+    this.log('Unloading branch module...');
+
+    // Clear hooks
+    this.hooks = {};
+
+    this.log('Branch module unloaded');
+  }
+
+  // ---------------------------------------------------------------------------
+  // ModuleInstance Interface Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Returns module routes for registration with Express.
+   *
+   * @returns Route configuration array
+   */
+  getRoutes(): unknown[] {
+    return [branchRoutes];
+  }
+
+  /**
+   * Returns module controllers for registration with routing-controllers.
+   *
+   * @returns Controller class array
+   */
+  getControllers(): unknown[] {
+    return BranchModule.controllers;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Hook System
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets current module hooks.
+   *
+   * @returns Module hooks object
+   */
+  getHooks(): BranchModuleHooks {
+    return { ...this.hooks };
+  }
+
+  /**
+   * Registers a hook handler.
+   *
+   * @param hookName - Name of the hook
+   * @param handler - Hook handler function
+   *
+   * @example
+   * ```typescript
+   * branchModule.registerHook('afterCreate', async (data) => {
+   *   console.log('Branch created:', data.branchId);
+   * });
+   * ```
+   */
+  registerHook<K extends keyof BranchModuleHooks>(
+    hookName: K,
+    handler: BranchModuleHooks[K]
+  ): void {
+    this.hooks[hookName] = handler;
+    this.log(`Registered hook: ${hookName}`);
+  }
+
+  /**
+   * Unregisters a hook handler.
+   *
+   * @param hookName - Name of the hook to unregister
+   */
+  unregisterHook(hookName: keyof BranchModuleHooks): void {
+    delete this.hooks[hookName];
+    this.log(`Unregistered hook: ${hookName}`);
+  }
+
+  /**
+   * Executes a hook if registered.
+   *
+   * @param hookName - Name of the hook
+   * @param data - Data to pass to the hook
+   */
+  async executeHook<K extends keyof BranchModuleHooks>(
+    hookName: K,
+    data: Parameters<NonNullable<BranchModuleHooks[K]>>[0]
+  ): Promise<void> {
+    const hook = this.hooks[hookName];
+    if (hook) {
+      try {
+        await (hook as (data: typeof data) => Promise<void>)(data);
+      } catch (error) {
+        this.log(`Hook execution error (${hookName}): ${error instanceof Error ? error.message : 'Unknown error'}`);
+      }
+    }
+  }
+
+  // ---------------------------------------------------------------------------
+  // Event Listeners
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Sets up event listeners for the branch module.
+   */
+  private setupEventListeners(): void {
+    // Listen for organization creation to potentially create a default branch
+    this.eventService.on('organization.created', async (payload) => {
+      this.log(`Organization created event received: ${payload.organizationId}`);
+      // Could trigger automatic creation of default/main branch
+    });
+
+    // Listen for subscription changes that might affect branch limits
+    this.eventService.on('subscription.plan.changed', async (payload) => {
+      this.log(`Plan changed event received for org: ${payload.organizationId}`);
+      // Could validate branch count against new plan limits
+    });
+
+    this.log('Event listeners set up');
+  }
+
+  // ---------------------------------------------------------------------------
+  // Module Settings
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets default module settings.
+   *
+   * @returns Default branch module settings
+   */
+  static getDefaultSettings(): BranchModuleSettings {
+    return {
+      defaultBranchCode: 'MAIN',
+      allowBranchHierarchy: true,
+      maxHierarchyDepth: 3,
+      requireUniqueCode: true,
+      inheritParentSettings: true,
+    };
+  }
+
+  // ---------------------------------------------------------------------------
+  // Utility Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Logs a message with module prefix.
+   *
+   * @param message - Message to log
+   */
+  private log(message: string): void {
+    // eslint-disable-next-line no-console
+    console.log(`[BranchModule] ${message}`);
+  }
+
+  /**
+   * Checks if module is initialized.
+   *
+   * @returns True if module is initialized
+   */
+  isInitialized(): boolean {
+    return this.initialized;
+  }
+
+  /**
+   * Gets module metadata.
+   *
+   * @returns Module metadata object
+   */
+  static getMetadata() {
+    return {
+      id: BranchModule.id,
+      name: BranchModule.name,
+      version: BranchModule.version,
+      isCore: BranchModule.isCore,
+      routes: BranchModule.routes,
+      providers: BranchModule.providers.map((p) => p.name),
+      controllers: BranchModule.controllers.map((c) => c.name),
+    };
+  }
+}
+
+// -----------------------------------------------------------------------------
+// Module Exports
+// -----------------------------------------------------------------------------
+
+/**
+ * Default export for module loader dynamic import
+ */
+export default BranchModule;
+
+/**
+ * Export module metadata
+ */
+export const metadata = BranchModule.getMetadata();

diff --git a/src/modules/_core/branch/branch.repository.ts b/src/modules/_core/branch/branch.repository.ts
