--- /dev/null
+++ b/src/modules/_core/branch/branch.repository.ts
@@ -0,0 +1,695 @@
+/**
+ * Branch Repository
+ *
+ * Data access layer for Branch entities.
+ * Provides tenant-scoped database operations with hierarchy support.
+ *
+ * @module modules/_core/branch/branch.repository
+ *
+ * @example
+ * ```typescript
+ * import { BranchRepository } from '@/modules/_core/branch/branch.repository';
+ *
+ * const repo = container.resolve('BranchRepository');
+ * const branch = await repo.findByCode('org_123', 'MAIN');
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+import { PrismaClient, Prisma } from '@prisma/client';
+
+import { TOKENS } from '@/core/kernel/container';
+import { AppException } from '@/core/exceptions/app.exception';
+import { notDeleted, softDelete } from '@/config/database';
+
+import type {
+  Branch,
+  BranchWithRelations,
+  BranchListParams,
+  BranchSummary,
+  BranchStatus,
+} from '@/modules/_core/branch/branch.types';
+
+// -----------------------------------------------------------------------------
+// Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Paginated result type
+ */
+export interface PaginatedResult<T> {
+  /** Array of entities */
+  data: T[];
+  /** Pagination metadata */
+  meta: {
+    page: number;
+    perPage: number;
+    total: number;
+    totalPages: number;
+  };
+}
+
+/**
+ * Create branch data (input for repository)
+ */
+export interface CreateBranchData {
+  name: string;
+  code: string;
+  description?: string | null;
+  phone?: string | null;
+  email?: string | null;
+  address?: Prisma.JsonValue;
+  settings?: Prisma.JsonValue;
+  status?: BranchStatus;
+  parentId?: string | null;
+  sortOrder?: number;
+  isMain?: boolean;
+}
+
+/**
+ * Update branch data (input for repository)
+ */
+export interface UpdateBranchData {
+  name?: string;
+  code?: string;
+  description?: string | null;
+  phone?: string | null;
+  email?: string | null;
+  address?: Prisma.JsonValue;
+  settings?: Prisma.JsonValue;
+  status?: BranchStatus;
+  parentId?: string | null;
+  sortOrder?: number;
+  isMain?: boolean;
+}
+
+// -----------------------------------------------------------------------------
+// Constants
+// -----------------------------------------------------------------------------
+
+const DEFAULT_PER_PAGE = 20;
+const MAX_PER_PAGE = 100;
+
+// -----------------------------------------------------------------------------
+// Branch Repository
+// -----------------------------------------------------------------------------
+
+/**
+ * Repository for Branch entity operations.
+ *
+ * Handles all database operations for branches including:
+ * - CRUD operations with tenant isolation
+ * - Hierarchy management (parent/child relationships)
+ * - Code uniqueness enforcement
+ * - Pagination and search
+ *
+ * @remarks
+ * All operations require organizationId for tenant isolation.
+ * Soft delete is enforced on all operations.
+ *
+ * @example
+ * ```typescript
+ * @injectable()
+ * class BranchService {
+ *   constructor(
+ *     @inject('BranchRepository') private repo: BranchRepository
+ *   ) {}
+ *
+ *   async getByCode(orgId: string, code: string) {
+ *     return this.repo.findByCode(orgId, code);
+ *   }
+ * }
+ * ```
+ */
+@injectable()
+export class BranchRepository {
+  constructor(
+    @inject(TOKENS.PrismaClient) private readonly prisma: PrismaClient
+  ) {}
+
+  // ---------------------------------------------------------------------------
+  // Read Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Finds all branches for an organization with pagination and filtering
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param params - Query parameters (pagination, sorting, filtering)
+   * @returns Paginated list of branches
+   *
+   * @example
+   * ```typescript
+   * const result = await repo.findAll('org_123', {
+   *   page: 1,
+   *   perPage: 10,
+   *   status: 'ACTIVE',
+   *   sortBy: 'sortOrder',
+   * });
+   * ```
+   */
+  async findAll(
+    organizationId: string,
+    params: BranchListParams = {}
+  ): Promise<PaginatedResult<Branch>> {
+    const {
+      page = 1,
+      perPage = DEFAULT_PER_PAGE,
+      status,
+      parentId,
+      isMain,
+      search,
+      includeDeleted = false,
+      sortBy = 'sortOrder',
+      sortOrder = 'asc',
+    } = params;
+
+    // Normalize pagination
+    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
+    const normalizedPage = Math.max(1, page);
+    const skip = (normalizedPage - 1) * normalizedPerPage;
+
+    // Build where clause
+    const where: Prisma.BranchWhereInput = {
+      organizationId,
+      ...(includeDeleted ? {} : notDeleted),
+      ...(status && { status }),
+      ...(parentId !== undefined && { parentId }),
+      ...(isMain !== undefined && { isMain }),
+      ...(search && {
+        OR: [
+          { name: { contains: search, mode: 'insensitive' } },
+          { code: { contains: search, mode: 'insensitive' } },
+        ],
+      }),
+    };
+
+    // Build orderBy
+    const orderBy: Prisma.BranchOrderByWithRelationInput = {
+      [sortBy]: sortOrder,
+    };
+
+    // Execute count and find in parallel
+    const [total, data] = await Promise.all([
+      this.prisma.branch.count({ where }),
+      this.prisma.branch.findMany({
+        where,
+        orderBy,
+        skip,
+        take: normalizedPerPage,
+      }),
+    ]);
+
+    return {
+      data: data as Branch[],
+      meta: {
+        page: normalizedPage,
+        perPage: normalizedPerPage,
+        total,
+        totalPages: Math.ceil(total / normalizedPerPage),
+      },
+    };
+  }
+
+  /**
+   * Finds all branches as summaries (for dropdowns, etc.)
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param params - Optional filtering params
+   * @returns Array of branch summaries
+   */
+  async findAllSummaries(
+    organizationId: string,
+    params: Partial<BranchListParams> = {}
+  ): Promise<BranchSummary[]> {
+    const { status, parentId, includeDeleted = false } = params;
+
+    const where: Prisma.BranchWhereInput = {
+      organizationId,
+      ...(includeDeleted ? {} : notDeleted),
+      ...(status && { status }),
+      ...(parentId !== undefined && { parentId }),
+    };
+
+    const branches = await this.prisma.branch.findMany({
+      where,
+      select: {
+        id: true,
+        name: true,
+        code: true,
+        status: true,
+        isMain: true,
+        parentId: true,
+        address: true,
+        createdAt: true,
+        _count: {
+          select: {
+            children: true,
+          },
+        },
+      },
+      orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+    });
+
+    return branches.map((branch) => {
+      const address = branch.address as { city?: string } | null;
+      return {
+        id: branch.id,
+        name: branch.name,
+        code: branch.code,
+        status: branch.status as BranchStatus,
+        isMain: branch.isMain,
+        parentId: branch.parentId,
+        city: address?.city,
+        childCount: branch._count.children,
+        createdAt: branch.createdAt,
+      };
+    });
+  }
+
+  /**
+   * Finds a branch by ID with tenant isolation
+   *
+   * @param id - Branch ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Branch or null
+   */
+  async findById(id: string, organizationId: string): Promise<Branch | null> {
+    const result = await this.prisma.branch.findFirst({
+      where: { id, organizationId, ...notDeleted },
+    });
+
+    return result as Branch | null;
+  }
+
+  /**
+   * Finds a branch by ID with relations
+   *
+   * @param id - Branch ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Branch with relations or null
+   */
+  async findByIdWithRelations(
+    id: string,
+    organizationId: string
+  ): Promise<BranchWithRelations | null> {
+    const result = await this.prisma.branch.findFirst({
+      where: { id, organizationId, ...notDeleted },
+      include: {
+        parent: true,
+        children: {
+          where: notDeleted,
+          orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+        },
+        organization: {
+          select: {
+            id: true,
+            name: true,
+            slug: true,
+          },
+        },
+        _count: {
+          select: {
+            children: true,
+            menus: true,
+            tables: true,
+            orders: true,
+          },
+        },
+      },
+    });
+
+    return result as BranchWithRelations | null;
+  }
+
+  /**
+   * Finds a branch by ID or throws
+   *
+   * @param id - Branch ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Branch
+   * @throws {AppException} If not found
+   */
+  async findByIdOrThrow(id: string, organizationId: string): Promise<Branch> {
+    const branch = await this.findById(id, organizationId);
+
+    if (!branch) {
+      throw AppException.notFound('Branch', id);
+    }
+
+    return branch;
+  }
+
+  /**
+   * Finds a branch by code within an organization
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param code - Branch code
+   * @returns Branch or null
+   */
+  async findByCode(organizationId: string, code: string): Promise<Branch | null> {
+    const result = await this.prisma.branch.findFirst({
+      where: { organizationId, code: code.toUpperCase(), ...notDeleted },
+    });
+
+    return result as Branch | null;
+  }
+
+  /**
+   * Finds the main branch for an organization
+   *
+   * @param organizationId - Organization ID
+   * @returns Main branch or null
+   */
+  async findMainBranch(organizationId: string): Promise<Branch | null> {
+    const result = await this.prisma.branch.findFirst({
+      where: { organizationId, isMain: true, ...notDeleted },
+    });
+
+    return result as Branch | null;
+  }
+
+  /**
+   * Finds all root branches (no parent) for an organization
+   *
+   * @param organizationId - Organization ID
+   * @returns Array of root branches
+   */
+  async findRootBranches(organizationId: string): Promise<Branch[]> {
+    const result = await this.prisma.branch.findMany({
+      where: { organizationId, parentId: null, ...notDeleted },
+      orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+    });
+
+    return result as Branch[];
+  }
+
+  /**
+   * Finds all child branches of a parent
+   *
+   * @param organizationId - Organization ID
+   * @param parentId - Parent branch ID
+   * @returns Array of child branches
+   */
+  async findChildren(organizationId: string, parentId: string): Promise<Branch[]> {
+    const result = await this.prisma.branch.findMany({
+      where: { organizationId, parentId, ...notDeleted },
+      orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+    });
+
+    return result as Branch[];
+  }
+
+  /**
+   * Checks if a branch code exists within an organization
+   *
+   * @param organizationId - Organization ID
+   * @param code - Code to check
+   * @param excludeId - Optional ID to exclude from check
+   * @returns True if code exists
+   */
+  async codeExists(
+    organizationId: string,
+    code: string,
+    excludeId?: string
+  ): Promise<boolean> {
+    const count = await this.prisma.branch.count({
+      where: {
+        organizationId,
+        code: code.toUpperCase(),
+        ...notDeleted,
+        ...(excludeId && { id: { not: excludeId } }),
+      },
+    });
+
+    return count > 0;
+  }
+
+  /**
+   * Counts branches for an organization
+   *
+   * @param organizationId - Organization ID
+   * @param status - Optional status to filter
+   * @returns Count
+   */
+  async count(organizationId: string, status?: BranchStatus): Promise<number> {
+    return this.prisma.branch.count({
+      where: {
+        organizationId,
+        ...notDeleted,
+        ...(status && { status }),
+      },
+    });
+  }
+
+  /**
+   * Gets the hierarchy depth of a branch
+   *
+   * @param organizationId - Organization ID
+   * @param branchId - Branch ID
+   * @returns Depth level (0 for root)
+   */
+  async getHierarchyDepth(organizationId: string, branchId: string): Promise<number> {
+    let depth = 0;
+    let currentId: string | null = branchId;
+
+    while (currentId) {
+      const branch = await this.prisma.branch.findFirst({
+        where: { id: currentId, organizationId, ...notDeleted },
+        select: { parentId: true },
+      });
+
+      if (!branch || !branch.parentId) {
+        break;
+      }
+
+      depth++;
+      currentId = branch.parentId;
+    }
+
+    return depth;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Write Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Creates a new branch
+   *
+   * @param organizationId - Organization ID for tenant association
+   * @param data - Create data
+   * @returns Created branch
+   */
+  async create(organizationId: string, data: CreateBranchData): Promise<Branch> {
+    const result = await this.prisma.branch.create({
+      data: {
+        organizationId,
+        name: data.name,
+        code: data.code.toUpperCase(),
+        description: data.description || null,
+        phone: data.phone || null,
+        email: data.email?.toLowerCase() || null,
+        address: data.address || null,
+        settings: data.settings || {},
+        status: data.status || 'ACTIVE',
+        parentId: data.parentId || null,
+        sortOrder: data.sortOrder ?? 0,
+        isMain: data.isMain ?? false,
+      },
+    });
+
+    return result as Branch;
+  }
+
+  /**
+   * Updates a branch
+   *
+   * @param id - Branch ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @param data - Update data
+   * @returns Updated branch
+   * @throws {AppException} If not found
+   */
+  async update(
+    id: string,
+    organizationId: string,
+    data: UpdateBranchData
+  ): Promise<Branch> {
+    // Verify exists
+    await this.findByIdOrThrow(id, organizationId);
+
+    const result = await this.prisma.branch.update({
+      where: { id },
+      data: {
+        ...(data.name !== undefined && { name: data.name }),
+        ...(data.code !== undefined && { code: data.code.toUpperCase() }),
+        ...(data.description !== undefined && { description: data.description }),
+        ...(data.phone !== undefined && { phone: data.phone }),
+        ...(data.email !== undefined && { email: data.email?.toLowerCase() || null }),
+        ...(data.address !== undefined && { address: data.address }),
+        ...(data.settings !== undefined && { settings: data.settings }),
+        ...(data.status !== undefined && { status: data.status }),
+        ...(data.parentId !== undefined && { parentId: data.parentId }),
+        ...(data.sortOrder !== undefined && { sortOrder: data.sortOrder }),
+        ...(data.isMain !== undefined && { isMain: data.isMain }),
+      },
+    });
+
+    return result as Branch;
+  }
+
+  /**
+   * Updates branch settings (merge)
+   *
+   * @param id - Branch ID
+   * @param organizationId - Organization ID
+   * @param settings - Settings to merge
+   * @returns Updated branch
+   */
+  async updateSettings(
+    id: string,
+    organizationId: string,
+    settings: Prisma.JsonValue
+  ): Promise<Branch> {
+    const branch = await this.findByIdOrThrow(id, organizationId);
+
+    // Merge settings
+    const currentSettings = (branch.settings as Record<string, unknown>) || {};
+    const newSettings = settings as Record<string, unknown>;
+    const mergedSettings = this.deepMerge(currentSettings, newSettings);
+
+    const result = await this.prisma.branch.update({
+      where: { id },
+      data: { settings: mergedSettings },
+    });
+
+    return result as Branch;
+  }
+
+  /**
+   * Updates branch status
+   *
+   * @param id - Branch ID
+   * @param organizationId - Organization ID
+   * @param status - New status
+   * @returns Updated branch
+   */
+  async updateStatus(
+    id: string,
+    organizationId: string,
+    status: BranchStatus
+  ): Promise<Branch> {
+    await this.findByIdOrThrow(id, organizationId);
+
+    const result = await this.prisma.branch.update({
+      where: { id },
+      data: { status },
+    });
+
+    return result as Branch;
+  }
+
+  /**
+   * Sets a branch as the main branch (and unsets others)
+   *
+   * @param id - Branch ID to set as main
+   * @param organizationId - Organization ID
+   * @returns Updated branch
+   */
+  async setAsMain(id: string, organizationId: string): Promise<Branch> {
+    await this.findByIdOrThrow(id, organizationId);
+
+    // Unset any existing main branch and set the new one
+    await this.prisma.$transaction([
+      this.prisma.branch.updateMany({
+        where: { organizationId, isMain: true, ...notDeleted },
+        data: { isMain: false },
+      }),
+      this.prisma.branch.update({
+        where: { id },
+        data: { isMain: true },
+      }),
+    ]);
+
+    // Fetch and return the updated branch
+    return this.findByIdOrThrow(id, organizationId);
+  }
+
+  // ---------------------------------------------------------------------------
+  // Delete Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Soft deletes a branch
+   *
+   * @param id - Branch ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Deleted branch
+   * @throws {AppException} If not found
+   */
+  async softDelete(id: string, organizationId: string): Promise<Branch> {
+    await this.findByIdOrThrow(id, organizationId);
+
+    const result = await this.prisma.branch.update({
+      where: { id },
+      data: softDelete(),
+    });
+
+    return result as Branch;
+  }
+
+  /**
+   * Restores a soft-deleted branch
+   *
+   * @param id - Branch ID
+   * @param organizationId - Organization ID
+   * @returns Restored branch
+   */
+  async restore(id: string, organizationId: string): Promise<Branch> {
+    // Find including deleted
+    const branch = await this.prisma.branch.findFirst({
+      where: { id, organizationId },
+    });
+
+    if (!branch) {
+      throw AppException.notFound('Branch', id);
+    }
+
+    const result = await this.prisma.branch.update({
+      where: { id },
+      data: { deletedAt: null },
+    });
+
+    return result as Branch;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Helper Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Deep merges two objects
+   */
+  private deepMerge(
+    target: Record<string, unknown>,
+    source: Record<string, unknown>
+  ): Record<string, unknown> {
+    const result = { ...target };
+
+    for (const [key, value] of Object.entries(source)) {
+      if (value !== undefined && value !== null) {
+        if (typeof value === 'object' && !Array.isArray(value)) {
+          result[key] = this.deepMerge(
+            (result[key] as Record<string, unknown>) || {},
+            value as Record<string, unknown>
+          );
+        } else {
+          result[key] = value;
+        }
+      }
+    }
+
+    return result;
+  }
+}

