+ * import { BranchService } from '@/modules/_core/branch/branch.service';
+ * import { resolve } from '@/core/kernel/container';
+ *
+ * const branchService = resolve<BranchService>('BranchService');
+ *
+ * // Create a new branch
+ * const result = await branchService.create('org_123', {
+ *   name: 'Downtown Location',
+ *   code: 'DOWNTOWN',
+ * });
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+import { Prisma } from '@prisma/client';
+
+import { TOKENS } from '@/core/kernel/container';
+import { AppException } from '@/core/exceptions/app.exception';
+import { EventService } from '@/core/services/event.service';
+
+import { BranchRepository, PaginatedResult } from '@/modules/_core/branch/branch.repository';
+
+import type {
+  Branch,
+  BranchWithRelations,
+  CreateBranchRequest,
+  CreateBranchResponse,
+  UpdateBranchRequest,
+  UpdateBranchResponse,
+  UpdateBranchSettingsRequest,
+  UpdateBranchSettingsResponse,
+  ChangeBranchStatusRequest,
+  ChangeBranchStatusResponse,
+  BranchListParams,
+  BranchSummary,
+  BranchSettings,
+  BranchStatus,
+} from '@/modules/_core/branch/branch.types';
+
+import {
+  createBranchSchema,
+  updateBranchSchema,
+  updateBranchSettingsSchema,
+  changeBranchStatusSchema,
+  branchListQuerySchema,
+  generateBranchCode,
+  type CreateBranchInput,
+  type UpdateBranchInput,
+  type UpdateBranchSettingsInput,
+  type ChangeBranchStatusInput,
+  type BranchListQueryInput,
+} from '@/modules/_core/branch/branch.schema';
+
+// -----------------------------------------------------------------------------
+// Types
+// -----------------------------------------------------------------------------
+
+/**
+ * User context for operations
+ */
+interface UserContext {
+  /** User ID making the request */
+  userId?: string;
+  /** Whether user is a platform admin */
+  isPlatformAdmin?: boolean;
+}
+
+// -----------------------------------------------------------------------------
+// Constants
+// -----------------------------------------------------------------------------
+
+/** Maximum hierarchy depth allowed */
+const MAX_HIERARCHY_DEPTH = 5;
+
+// -----------------------------------------------------------------------------
+// Branch Service
+// -----------------------------------------------------------------------------
+
+/**
+ * Branch module business logic service.
+ *
+ * Handles all branch-related business operations including:
+ * - Branch CRUD operations with tenant isolation
+ * - Settings management
+ * - Status changes
+ * - Hierarchy management (parent/child relationships)
+ *
+ * @example
+ * ```typescript
+ * @injectable()
+ * class SomeController {
+ *   constructor(
+ *     @inject('BranchService') private branchService: BranchService,
+ *   ) {}
+ *
+ *   async handleCreate(req: Request, res: Response) {
+ *     const result = await this.branchService.create(req.orgId, req.body);
+ *     res.json(result);
+ *   }
+ * }
+ * ```
+ */
+@injectable()
+export class BranchService {
+  constructor(
+    @inject('BranchRepository') private readonly repository: BranchRepository,
+    @inject(TOKENS.EventService) private readonly eventService: EventService
+  ) {}
+
+  // ---------------------------------------------------------------------------
+  // Read Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Lists branches for an organization with pagination and filtering.
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param params - Query parameters
+   * @returns Paginated list of branches
+   *
+   * @example
+   * ```typescript
+   * const result = await branchService.list('org_123', {
+   *   page: 1,
+   *   perPage: 10,
+   *   status: 'ACTIVE',
+   * });
+   * ```
+   */
+  async list(
+    organizationId: string,
+    params: BranchListParams
+  ): Promise<PaginatedResult<Branch>> {
+    const validated = this.validateInput(params, branchListQuerySchema) as BranchListQueryInput;
+    return this.repository.findAll(organizationId, validated);
+  }
+
+  /**
+   * Lists branch summaries (for dropdowns, etc.).
+   *
+   * @param organizationId - Organization ID
+   * @param params - Optional filtering params
+   * @returns Array of branch summaries
+   */
+  async listSummaries(
+    organizationId: string,
+    params?: Partial<BranchListParams>
+  ): Promise<BranchSummary[]> {
+    return this.repository.findAllSummaries(organizationId, params);
+  }
+
+  /**
+   * Gets a branch by ID.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Branch ID
+   * @returns Branch or null
