+   * @throws {AppException} If not found
+   */
+  async getByIdOrThrow(organizationId: string, id: string): Promise<Branch> {
+    return this.repository.findByIdOrThrow(id, organizationId);
+  }
+
+  /**
+   * Gets a branch by code.
+   *
+   * @param organizationId - Organization ID
+   * @param code - Branch code
+   * @returns Branch or null
+   */
+  async getByCode(organizationId: string, code: string): Promise<Branch | null> {
+    return this.repository.findByCode(organizationId, code);
+  }
+
+  /**
+   * Gets the main branch for an organization.
+   *
+   * @param organizationId - Organization ID
+   * @returns Main branch or null
+   */
+  async getMainBranch(organizationId: string): Promise<Branch | null> {
+    return this.repository.findMainBranch(organizationId);
+  }
+
+  /**
+   * Gets branch settings.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Branch ID
+   * @returns Branch settings
+   * @throws {AppException} If not found
+   */
+  async getSettings(organizationId: string, id: string): Promise<BranchSettings> {
+    const branch = await this.repository.findByIdOrThrow(id, organizationId);
