+  }
+
+  /**
+   * Counts branches for an organization.
+   *
+   * @param organizationId - Organization ID
+   * @param status - Optional status filter
+   * @returns Count
+   */
+  async count(organizationId: string, status?: BranchStatus): Promise<number> {
+    return this.repository.count(organizationId, status);
+  }
+
+  // ---------------------------------------------------------------------------
+  // Write Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Creates a new branch.
+   *
+   * Validates input, generates code if needed, checks hierarchy depth,
+   * creates branch, and emits creation event.
+   *
+   * @param organizationId - Organization ID
+   * @param data - Create request data
+   * @param context - User context
+   * @returns Created branch response
+   * @throws {AppException} If code already exists or hierarchy is invalid
+   *
+   * @example
+   * ```typescript
+   * const result = await branchService.create('org_123', {
+   *   name: 'Downtown Location',
+   *   code: 'DOWNTOWN',
+   * });
+   * console.log('Created:', result.branch.id);
+   * ```
+   */
+  async create(
+    organizationId: string,
+    data: CreateBranchRequest,
+    context?: UserContext
+  ): Promise<CreateBranchResponse> {
+    // Validate input
+    const validated = this.validateInput(data, createBranchSchema) as CreateBranchInput;
+
+    // Generate code if not provided
+    let code = validated.code;
+    if (!code) {
+      code = generateBranchCode(validated.name);
+      // Ensure uniqueness
+      let counter = 1;
+      const baseCode = code;
+      while (await this.repository.codeExists(organizationId, code)) {
+        code = `${baseCode}-${counter}`;
+        counter++;
+      }
+    } else {
+      // Check if provided code exists
+      if (await this.repository.codeExists(organizationId, code)) {
+        throw AppException.alreadyExists('Branch code', code);
+      }
+    }
+
+    // Validate hierarchy depth if parent is specified
+    if (validated.parentId) {
+      // Verify parent exists
+      await this.repository.findByIdOrThrow(validated.parentId, organizationId);
+
+      // Check hierarchy depth
+      const depth = await this.repository.getHierarchyDepth(organizationId, validated.parentId);
+      if (depth >= MAX_HIERARCHY_DEPTH) {
+        throw new AppException('BRANCH_HIERARCHY_TOO_DEEP', 400, {
+          message: `Maximum hierarchy depth of ${MAX_HIERARCHY_DEPTH} exceeded`,
+          maxDepth: MAX_HIERARCHY_DEPTH,
+          currentDepth: depth,
+        });
+      }
+    }
+
+    // If this is the first branch or marked as main, handle main status
+    const branchCount = await this.repository.count(organizationId);
+    const isMain = validated.isMain ?? branchCount === 0;
+
+    // Create branch
+    const branch = await this.repository.create(organizationId, {
+      name: validated.name,
+      code,
+      description: validated.description || null,
+      phone: validated.phone || null,
+      email: validated.email || null,
+      address: (validated.address || null) as Prisma.JsonValue,
+      settings: (validated.settings || {}) as Prisma.JsonValue,
+      status: 'ACTIVE',
+      parentId: validated.parentId || null,
+      sortOrder: validated.sortOrder ?? 0,
+      isMain,
+    });
+
+    // Emit creation event
+    await this.eventService.emitCustom('branch.created', {
+      branchId: branch.id,
+      organizationId,
+      name: branch.name,
+      code: branch.code,
