+      message: 'Branch created successfully.',
+    };
+  }
+
+  /**
+   * Updates a branch.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Branch ID
+   * @param data - Update request data
+   * @param context - User context
+   * @returns Updated branch response
+   * @throws {AppException} If not found or code conflicts
+   */
+  async update(
+    organizationId: string,
+    id: string,
+    data: UpdateBranchRequest,
+    context?: UserContext
+  ): Promise<UpdateBranchResponse> {
+    // Validate input
+    const validated = this.validateInput(data, updateBranchSchema) as UpdateBranchInput;
+
+    // Get current branch
+    const current = await this.repository.findByIdOrThrow(id, organizationId);
+
+    // Check code uniqueness if changing
+    if (validated.code && validated.code.toUpperCase() !== current.code) {
+      if (await this.repository.codeExists(organizationId, validated.code, id)) {
+        throw AppException.alreadyExists('Branch code', validated.code);
+      }
+    }
+
+    // Validate hierarchy if parent is changing
+    if (validated.parentId !== undefined && validated.parentId !== current.parentId) {
+      if (validated.parentId) {
+        // Cannot set self as parent
+        if (validated.parentId === id) {
+          throw new AppException('INVALID_PARENT', 400, {
+            message: 'A branch cannot be its own parent',
+          });
+        }
+
+        // Verify new parent exists
+        await this.repository.findByIdOrThrow(validated.parentId, organizationId);
+
+        // Check hierarchy depth
+        const depth = await this.repository.getHierarchyDepth(organizationId, validated.parentId);
+        if (depth >= MAX_HIERARCHY_DEPTH) {
+          throw new AppException('BRANCH_HIERARCHY_TOO_DEEP', 400, {
+            message: `Maximum hierarchy depth of ${MAX_HIERARCHY_DEPTH} exceeded`,
+          });
+        }
+
+        // Ensure we're not creating a circular reference
+        const wouldCreateCircle = await this.wouldCreateCircularReference(
+          organizationId,
+          id,
+          validated.parentId
+        );
+        if (wouldCreateCircle) {
+          throw new AppException('CIRCULAR_HIERARCHY', 400, {
+            message: 'This would create a circular hierarchy',
+          });
+        }
+      }
+    }
+
+    // Build update data
+    const updateData: Record<string, unknown> = {};
+    if (validated.name !== undefined) updateData.name = validated.name;
+    if (validated.code !== undefined) updateData.code = validated.code;
+    if (validated.description !== undefined) updateData.description = validated.description;
+    if (validated.phone !== undefined) updateData.phone = validated.phone;
+    if (validated.email !== undefined) updateData.email = validated.email;
+    if (validated.address !== undefined) updateData.address = validated.address;
+    if (validated.parentId !== undefined) updateData.parentId = validated.parentId;
+    if (validated.sortOrder !== undefined) updateData.sortOrder = validated.sortOrder;
+    if (validated.isMain !== undefined) updateData.isMain = validated.isMain;
+
+    // Update branch
+    const branch = await this.repository.update(id, organizationId, updateData);
+
+    // If setting as main, unset others
+    if (validated.isMain === true) {
+      await this.repository.setAsMain(id, organizationId);
+    }
+
+    // Emit update event
+    await this.eventService.emitCustom('branch.updated', {
+      branchId: branch.id,
+      organizationId,
+      changes: updateData,
+      updatedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return {
+      branch,
+      message: 'Branch updated successfully.',
+    };
+  }
+
+  /**
+   * Updates branch settings.
+   *
+   * Settings are merged with existing settings, not replaced.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Branch ID
+   * @param data - Settings update request
+   * @param context - User context
+   * @returns Updated settings response
+   */
+  async updateSettings(
+    organizationId: string,
+    id: string,
+    data: UpdateBranchSettingsRequest,
+    context?: UserContext
+  ): Promise<UpdateBranchSettingsResponse> {
+    // Validate input
+    const validated = this.validateInput(data, updateBranchSettingsSchema) as UpdateBranchSettingsInput;
+
+    // Get current settings
+    const current = await this.repository.findByIdOrThrow(id, organizationId);
+    const previousSettings = current.settings;
+
+    // Update settings (merge)
+    const branch = await this.repository.updateSettings(
+      id,
+      organizationId,
+      validated.settings as Prisma.JsonValue
+    );
+
+    // Emit settings update event
+    await this.eventService.emitCustom('branch.settings.updated', {
+      branchId: branch.id,
+      organizationId,
+      previousSettings,
+      newSettings: branch.settings,
+      updatedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return {
+      settings: branch.settings,
+      message: 'Branch settings updated successfully.',
+    };
+  }
+
+  /**
+   * Changes branch status.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Branch ID
+   * @param data - Status change request
+   * @param context - User context
+   * @returns Status change response
+   */
+  async changeStatus(
+    organizationId: string,
+    id: string,
+    data: ChangeBranchStatusRequest,
+    context?: UserContext
+  ): Promise<ChangeBranchStatusResponse> {
+    // Validate input
+    const validated = this.validateInput(data, changeBranchStatusSchema) as ChangeBranchStatusInput;
+
+    // Get current branch
+    const current = await this.repository.findByIdOrThrow(id, organizationId);
+    const previousStatus = current.status;
+
+    // Check if status is actually changing
+    if (previousStatus === validated.status) {
+      return {
+        branch: current,
+        previousStatus,
+        message: 'Status unchanged.',
+      };
+    }
+
+    // Update status
+    const branch = await this.repository.updateStatus(id, organizationId, validated.status);
+
+    // Emit status change event
+    await this.eventService.emitCustom('branch.status.changed', {
+      branchId: branch.id,
+      organizationId,
+      previousStatus,
+      newStatus: validated.status,
+      reason: validated.reason,
+      changedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return {
+      branch,
+      previousStatus,
+      message: `Branch status changed to ${validated.status}.`,
+    };
+  }
+
+  /**
+   * Sets a branch as the main branch.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Branch ID
+   * @param context - User context
+   * @returns Updated branch
+   */
+  async setAsMain(
+    organizationId: string,
+    id: string,
+    context?: UserContext
+  ): Promise<Branch> {
+    const branch = await this.repository.setAsMain(id, organizationId);
+
+    // Emit update event
+    await this.eventService.emitCustom('branch.updated', {
+      branchId: branch.id,
+      organizationId,
+      changes: { isMain: true },
+      updatedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return branch;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Delete Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Soft deletes a branch.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Branch ID
+   * @param context - User context
+   * @throws {AppException} If not found or has children
+   *
+   * @example
+   * ```typescript
+   * await branchService.delete('org_123', 'branch_456');
+   * ```
+   */
+  async delete(organizationId: string, id: string, context?: UserContext): Promise<void> {
+    const branch = await this.repository.findByIdOrThrow(id, organizationId);
+
+    // Check if branch has children
+    const children = await this.repository.findChildren(organizationId, id);
+    if (children.length > 0) {
+      throw new AppException('BRANCH_HAS_CHILDREN', 400, {
+        message: 'Cannot delete branch with child branches. Delete or reassign children first.',
+        childCount: children.length,
+      });
+    }
+
+    // Check if this is the main branch
+    if (branch.isMain) {
+      throw new AppException('CANNOT_DELETE_MAIN_BRANCH', 400, {
+        message: 'Cannot delete the main branch. Set another branch as main first.',
+      });
+    }
+
+    // Soft delete
+    await this.repository.softDelete(id, organizationId);
+
+    // Emit deletion event
+    await this.eventService.emitCustom('branch.deleted', {
+      branchId: branch.id,
+      organizationId,
+      name: branch.name,
+      deletedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+  }
+
+  /**
+   * Restores a soft-deleted branch.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Branch ID
+   * @param context - User context
+   * @returns Restored branch
+   */
+  async restore(
+    organizationId: string,
+    id: string,
+    context?: UserContext
+  ): Promise<Branch> {
+    const branch = await this.repository.restore(id, organizationId);
+
+    // Emit restore event
+    await this.eventService.emitCustom('branch.restored', {
+      branchId: branch.id,
+      organizationId,
+      name: branch.name,
+      restoredBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return branch;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Validation Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Checks if a branch code is available.
+   *
+   * @param organizationId - Organization ID
+   * @param code - Code to check
+   * @param excludeId - Optional ID to exclude
+   * @returns True if available
+   */
+  async isCodeAvailable(
+    organizationId: string,
+    code: string,
+    excludeId?: string
+  ): Promise<boolean> {
+    return !(await this.repository.codeExists(organizationId, code, excludeId));
+  }
+
+  // ---------------------------------------------------------------------------
+  // Helper Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Checks if setting a new parent would create a circular reference.
+   */
+  private async wouldCreateCircularReference(
+    organizationId: string,
+    branchId: string,
+    newParentId: string
+  ): Promise<boolean> {
+    let currentId: string | null = newParentId;
+
+    while (currentId) {
+      if (currentId === branchId) {
+        return true;
+      }
+
+      const parent = await this.repository.findById(currentId, organizationId);
+      currentId = parent?.parentId || null;
+    }
+
+    return false;
+  }
+
+  /**
+   * Validates input data against a Zod schema.
+   */
+  private validateInput<T>(data: unknown, schema: { parse: (data: unknown) => T }): T {
+    try {
+      return schema.parse(data);
+    } catch (error) {
+      if (error && typeof error === 'object' && 'errors' in error) {
+        const zodError = error as { errors: Array<{ path: string[]; message: string; code: string }> };
+        const validationErrors = zodError.errors.map((err) => ({
+          field: err.path.join('.'),
+          message: err.message,
+          rule: err.code,
+        }));
+        throw AppException.validation(validationErrors);
+      }
+      throw error;
+    }
+  }
+}

