+/**
+ * Branch Module Types
+ *
+ * Type definitions for the Branch module including:
+ * - Branch entity types
+ * - CRUD DTOs
+ * - Settings types
+ * - Event payloads
+ * - Query filters
+ *
+ * @module modules/_core/branch/types
+ *
+ * @example
+ * ```typescript
+ * import type {
+ *   Branch,
+ *   CreateBranchRequest,
+ *   BranchSettings,
+ * } from '@/modules/_core/branch/branch.types';
+ *
+ * async function createBranch(data: CreateBranchRequest): Promise<Branch> { ... }
+ * ```
+ */
+
+// -----------------------------------------------------------------------------
+// Enums (matching Prisma or module-specific)
+// -----------------------------------------------------------------------------
+
+/**
+ * Branch status enum
+ */
+export type BranchStatus = 'ACTIVE' | 'INACTIVE' | 'SUSPENDED';
+
+// -----------------------------------------------------------------------------
+// Core Entity Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Branch entity from Prisma
+ */
+export interface Branch {
+  /** Unique identifier (CUID) */
+  id: string;
+  /** Organization/tenant ID */
+  organizationId: string;
+  /** Branch name */
+  name: string;
+  /** Unique branch code (within organization) */
+  code: string;
+  /** Branch description (optional) */
+  description: string | null;
+  /** Contact phone (optional) */
+  phone: string | null;
+  /** Contact email (optional) */
+  email: string | null;
+  /** Branch address (JSON) */
+  address: BranchAddress | null;
+  /** Branch settings (JSON) */
+  settings: BranchSettings;
+  /** Current status */
+  status: BranchStatus;
+  /** Parent branch ID for hierarchy (optional) */
+  parentId: string | null;
+  /** Display order */
+  sortOrder: number;
+  /** Whether this is the main/default branch */
+  isMain: boolean;
+  /** Creation timestamp */
+  createdAt: Date;
+  /** Last update timestamp */
+  updatedAt: Date;
+  /** Soft delete timestamp */
+  deletedAt: Date | null;
+}
+
+/**
+ * Branch with related data
+ */
+export interface BranchWithRelations extends Branch {
+  /** Parent branch */
+  parent?: Branch | null;
+  /** Child branches */
+  children?: Branch[];
+  /** Associated organization */
+  organization?: {
+    id: string;
+    name: string;
+    slug: string;
+  };
+  /** Counts */
+  _count?: {
+    children: number;
+    menus: number;
+    tables: number;
+    orders: number;
+  };
+}
+
+// -----------------------------------------------------------------------------
+// Settings Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Branch address structure
+ */
+export interface BranchAddress {
+  /** Street address line 1 */
+  street1?: string;
+  /** Street address line 2 */
+  street2?: string;
+  /** City */
+  city?: string;
+  /** State/Province */
+  state?: string;
+  /** Postal/ZIP code */
+  postalCode?: string;
+  /** Country code (ISO 3166-1 alpha-2) */
+  country?: string;
+  /** Latitude for map display */
+  latitude?: number;
+  /** Longitude for map display */
+  longitude?: number;
+}
+
+/**
+ * Branch settings structure
+ */
+export interface BranchSettings {
+  /** Operating hours settings */
+  operatingHours?: OperatingHours;
+  /** Feature toggles */
+  features?: BranchFeatureSettings;
+  /** Display settings */
+  display?: BranchDisplaySettings;
+  /** Notification settings */
+  notifications?: BranchNotificationSettings;
+}
+
+/**
+ * Operating hours for each day
+ */
+export interface OperatingHours {
+  monday?: DayHours;
+  tuesday?: DayHours;
+  wednesday?: DayHours;
+  thursday?: DayHours;
+  friday?: DayHours;
+  saturday?: DayHours;
+  sunday?: DayHours;
+}
+
+/**
+ * Hours for a single day
+ */
+export interface DayHours {
+  /** Whether the branch is open */
+  isOpen: boolean;
+  /** Opening time (HH:mm format) */
+  open?: string;
+  /** Closing time (HH:mm format) */
+  close?: string;
+  /** Break times */
+  breaks?: Array<{ start: string; end: string }>;
+}
+
+/**
+ * Branch feature toggle settings
+ */
+export interface BranchFeatureSettings {
+  /** Enable online ordering for this branch */
+  enableOnlineOrdering?: boolean;
+  /** Enable table reservations */
+  enableReservations?: boolean;
+  /** Enable takeaway orders */
+  enableTakeaway?: boolean;
+  /** Enable delivery orders */
+  enableDelivery?: boolean;
+  /** Enable dine-in orders */
+  enableDineIn?: boolean;
+}
+
+/**
+ * Branch display settings
+ */
+export interface BranchDisplaySettings {
+  /** Custom display name (overrides branch name) */
+  displayName?: string;
+  /** Branch logo URL */
+  logo?: string;
+  /** Branch cover image URL */
+  coverImage?: string;
+  /** Theme color override */
+  themeColor?: string;
+}
+
+/**
+ * Branch notification settings
+ */
+export interface BranchNotificationSettings {
+  /** Email for order notifications */
+  orderNotificationEmail?: string;
+  /** Phone for SMS notifications */
+  orderNotificationPhone?: string;
+  /** Enable push notifications */
+  enablePushNotifications?: boolean;
+}
+
+// -----------------------------------------------------------------------------
+// Request/Response Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Create branch request
+ */
+export interface CreateBranchRequest {
+  /** Branch name */
+  name: string;
+  /** Unique branch code */
+  code: string;
+  /** Branch description (optional) */
+  description?: string;
+  /** Contact phone (optional) */
+  phone?: string;
+  /** Contact email (optional) */
+  email?: string;
+  /** Branch address (optional) */
+  address?: BranchAddress;
+  /** Initial settings (optional) */
+  settings?: Partial<BranchSettings>;
+  /** Parent branch ID (optional) */
+  parentId?: string;
+  /** Display order (optional) */
+  sortOrder?: number;
+  /** Whether this is the main branch */
+  isMain?: boolean;
+}
+
+/**
+ * Create branch response
+ */
+export interface CreateBranchResponse {
+  /** Created branch */
+  branch: Branch;
+  /** Success message */
+  message: string;
+}
+
+/**
+ * Update branch request
+ */
+export interface UpdateBranchRequest {
+  /** Branch name */
+  name?: string;
+  /** Unique branch code */
+  code?: string;
+  /** Branch description */
+  description?: string | null;
+  /** Contact phone */
+  phone?: string | null;
+  /** Contact email */
+  email?: string | null;
+  /** Branch address */
+  address?: BranchAddress | null;
+  /** Parent branch ID */
+  parentId?: string | null;
+  /** Display order */
+  sortOrder?: number;
+  /** Whether this is the main branch */
+  isMain?: boolean;
+}
+
+/**
+ * Update branch response
+ */
+export interface UpdateBranchResponse {
+  /** Updated branch */
+  branch: Branch;
+  /** Success message */
+  message: string;
+}
+
+/**
+ * Update branch settings request
+ */
+export interface UpdateBranchSettingsRequest {
+  /** Settings to update (merged with existing) */
+  settings: Partial<BranchSettings>;
+}
+
+/**
+ * Update branch settings response
+ */
+export interface UpdateBranchSettingsResponse {
+  /** Updated settings */
+  settings: BranchSettings;
+  /** Success message */
+  message: string;
+}
+
+/**
+ * Change branch status request
+ */
+export interface ChangeBranchStatusRequest {
+  /** New status */
+  status: BranchStatus;
+  /** Reason for status change (for audit) */
+  reason?: string;
+}
+
+/**
+ * Change branch status response
+ */
+export interface ChangeBranchStatusResponse {
+  /** Updated branch */
+  branch: Branch;
+  /** Previous status */
+  previousStatus: BranchStatus;
+  /** Success message */
+  message: string;
+}
+
+/**
+ * Branch summary for listings
+ */
+export interface BranchSummary {
+  /** Branch ID */
+  id: string;
+  /** Branch name */
+  name: string;
+  /** Branch code */
+  code: string;
+  /** Current status */
+  status: BranchStatus;
+  /** Whether this is the main branch */
+  isMain: boolean;
+  /** Parent branch ID */
+  parentId: string | null;
+  /** City from address */
+  city?: string;
+  /** Child count */
+  childCount?: number;
+  /** Creation date */
+  createdAt: Date;
+}
+
+// -----------------------------------------------------------------------------
+// Query/Filter Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Branch list query filters
+ */
+export interface BranchListFilters {
+  /** Filter by status */
+  status?: BranchStatus;
+  /** Filter by parent ID (null for root branches) */
+  parentId?: string | null;
+  /** Filter by main branch */
+  isMain?: boolean;
+  /** Search by name or code */
+  search?: string;
+  /** Include soft-deleted */
+  includeDeleted?: boolean;
+}
+
+/**
+ * Branch list query params
+ */
+export interface BranchListParams extends BranchListFilters {
+  /** Page number (1-indexed) */
+  page?: number;
+  /** Items per page */
+  perPage?: number;
+  /** Sort field */
+  sortBy?: 'name' | 'code' | 'createdAt' | 'sortOrder';
+  /** Sort direction */
+  sortOrder?: 'asc' | 'desc';
+}
+
+// -----------------------------------------------------------------------------
+// Event Payload Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Branch created event payload
+ */
+export interface BranchCreatedEvent {
+  /** Branch ID */
+  branchId: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Branch name */
+  name: string;
+  /** Branch code */
+  code: string;
+  /** Creator user ID (if applicable) */
+  createdBy?: string;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+/**
+ * Branch updated event payload
+ */
+export interface BranchUpdatedEvent {
+  /** Branch ID */
+  branchId: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Changed fields */
+  changes: Partial<Branch>;
+  /** User who made the change */
+  updatedBy?: string;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+/**
+ * Branch deleted event payload
+ */
+export interface BranchDeletedEvent {
+  /** Branch ID */
+  branchId: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Branch name (for reference) */
+  name: string;
+  /** User who deleted */
+  deletedBy?: string;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+/**
+ * Branch settings updated event payload
+ */
+export interface BranchSettingsUpdatedEvent {
+  /** Branch ID */
+  branchId: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Previous settings */
+  previousSettings: BranchSettings;
+  /** New settings */
+  newSettings: BranchSettings;
+  /** User who made the change */
+  updatedBy?: string;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+/**
+ * Branch status changed event payload
+ */
+export interface BranchStatusChangedEvent {
+  /** Branch ID */
+  branchId: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Previous status */
+  previousStatus: BranchStatus;
+  /** New status */
+  newStatus: BranchStatus;
+  /** Reason for change */
+  reason?: string;
+  /** User who made the change */
+  changedBy?: string;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+// -----------------------------------------------------------------------------
+// Hook Context Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Before create hook context
+ */
+export interface BeforeCreateContext {
+  /** Create request data */
+  data: CreateBranchRequest;
+  /** Organization ID */
+  organizationId: string;
+  /** User creating the branch */
+  userId?: string;
+}
+
+/**
+ * After create hook context
+ */
+export interface AfterCreateContext {
+  /** Created branch */
+  branch: Branch;
+  /** User who created the branch */
+  userId?: string;
+}
+
+/**
+ * Before update hook context
+ */
+export interface BeforeUpdateContext {
+  /** Branch ID */
+  branchId: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Update request data */
+  data: UpdateBranchRequest;
+  /** User making the update */
+  userId?: string;
+}
+
+/**
+ * After update hook context
+ */
+export interface AfterUpdateContext {
+  /** Updated branch */
+  branch: Branch;
+  /** Previous values */
+  previousData: Branch;
+  /** User who made the update */
+  userId?: string;
+}
+
+// -----------------------------------------------------------------------------
+// Module Settings Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Branch module settings
+ */
+export interface BranchModuleSettings {
+  /** Default branch code for new organizations */
+  defaultBranchCode: string;
+  /** Allow hierarchical branch structure */
+  allowBranchHierarchy: boolean;
+  /** Maximum hierarchy depth */
+  maxHierarchyDepth: number;
+  /** Require unique branch codes */
+  requireUniqueCode: boolean;
+  /** Inherit parent branch settings */
+  inheritParentSettings: boolean;
+}
+
+// -----------------------------------------------------------------------------
+// Type Guards
+// -----------------------------------------------------------------------------
+
+/**
+ * Type guard to check if an object is a valid Branch
+ */
+export function isBranch(obj: unknown): obj is Branch {
+  return (
+    typeof obj === 'object' &&
+    obj !== null &&
+    'id' in obj &&
+    'organizationId' in obj &&
+    'name' in obj &&
+    'code' in obj &&
+    'status' in obj
+  );
+}
+
+/**
+ * Type guard to check if settings is a valid BranchSettings
+ */
+export function isBranchSettings(obj: unknown): obj is BranchSettings {
+  if (typeof obj !== 'object' || obj === null) {
+    return false;
+  }
+  // Empty object is valid settings
+  if (Object.keys(obj).length === 0) {
+    return true;
+  }
+  // Check known keys
+  const knownKeys = ['operatingHours', 'features', 'display', 'notifications'];
+  return Object.keys(obj).every((key) => knownKeys.includes(key));
+}
+
+/**
+ * Valid branch status values
+ */
+export const BRANCH_STATUSES: BranchStatus[] = ['ACTIVE', 'INACTIVE', 'SUSPENDED'];
+
+/**
+ * Check if a value is a valid branch status
+ */
+export function isBranchStatus(value: unknown): value is BranchStatus {
+  return typeof value === 'string' && BRANCH_STATUSES.includes(value as BranchStatus);
+}

