+/**
+ * Media Repository
+ *
+ * Data access layer for Media entities.
+ * Handles tenant-scoped media operations with soft delete support.
+ *
+ * @module modules/_core/media/media.repository
+ *
+ * @example
+ * ```typescript
+ * import { MediaRepository } from '@/modules/_core/media/media.repository';
+ *
+ * const repo = container.resolve('MediaRepository');
+ * const media = await repo.findById(orgId, mediaId);
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+import { PrismaClient, MediaType, MediaStorage, Prisma } from '@prisma/client';
+
+import { TOKENS } from '@/core/kernel/container';
+import { AppException } from '@/core/exceptions/app.exception';
+import { notDeleted, softDelete } from '@/config/database';
+
+import type {
+  Media,
+  MediaListParams,
+  MediaSummary,
+  MediaMetadata,
+} from '@/modules/_core/media/media.types';
+
+// -----------------------------------------------------------------------------
+// Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Paginated result type
+ */
+export interface PaginatedResult<T> {
+  /** Array of entities */
+  data: T[];
+  /** Pagination metadata */
+  meta: {
+    page: number;
+    perPage: number;
+    total: number;
+    totalPages: number;
+  };
+}
+
+/**
+ * Create media data (input for repository)
+ */
+export interface CreateMediaData {
+  organizationId: string;
+  filename: string;
+  originalName: string;
+  mimeType: string;
+  size: number;
+  type: MediaType;
+  storage?: MediaStorage;
+  url: string;
+  thumbnailUrl?: string | null;
+  alt?: string | null;
+  metadata?: Prisma.JsonValue;
+}
+
+/**
+ * Update media data (input for repository)
+ */
+export interface UpdateMediaData {
+  alt?: string | null;
+  thumbnailUrl?: string | null;
+  metadata?: Prisma.JsonValue;
+}
+
+// -----------------------------------------------------------------------------
+// Constants
+// -----------------------------------------------------------------------------
+
+const DEFAULT_PER_PAGE = 20;
+const MAX_PER_PAGE = 100;
+
+// -----------------------------------------------------------------------------
+// Media Repository
+// -----------------------------------------------------------------------------
+
+/**
+ * Repository for Media entity operations.
+ *
+ * Handles all database operations for media including:
+ * - CRUD operations (tenant-scoped)
+ * - Pagination and filtering
+ * - Soft delete
+ *
+ * @remarks
+ * All operations are tenant-scoped using organizationId.
+ * Soft delete is enforced on all operations.
+ *
+ * @example
+ * ```typescript
+ * @injectable()
+ * class MediaService {
+ *   constructor(
+ *     @inject('MediaRepository') private repo: MediaRepository
+ *   ) {}
+ *
+ *   async getMedia(orgId: string, id: string) {
+ *     return this.repo.findById(orgId, id);
+ *   }
+ * }
+ * ```
+ */
+@injectable()
+export class MediaRepository {
+  constructor(
+    @inject(TOKENS.PrismaClient) private readonly prisma: PrismaClient
+  ) {}
+
+  // ---------------------------------------------------------------------------
+  // Read Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Finds all media for an organization with pagination and filtering
+   *
+   * @param organizationId - Organization ID (tenant)
+   * @param params - Query parameters (pagination, sorting, filtering)
+   * @returns Paginated list of media
+   *
+   * @example
+   * ```typescript
+   * const result = await repo.findAll(orgId, {
+   *   page: 1,
+   *   perPage: 20,
+   *   type: 'IMAGE',
+   * });
+   * ```
+   */
+  async findAll(
+    organizationId: string,
+    params: MediaListParams = {}
+  ): Promise<PaginatedResult<Media>> {
+    const {
+      page = 1,
+      perPage = DEFAULT_PER_PAGE,
+      type,
+      mimeType,
+      search,
+      createdAfter,
+      createdBefore,
+      includeDeleted = false,
+      tags,
+      sortBy = 'createdAt',
+      sortOrder = 'desc',
+    } = params;
+
+    // Normalize pagination
+    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
+    const normalizedPage = Math.max(1, page);
+    const skip = (normalizedPage - 1) * normalizedPerPage;
+
+    // Build where clause
+    const where: Prisma.MediaWhereInput = {
+      organizationId,
+      ...(includeDeleted ? {} : notDeleted),
+      ...(type && { type }),
+      ...(mimeType && { mimeType: { startsWith: mimeType } }),
+      ...(search && {
+        OR: [
+          { originalName: { contains: search, mode: 'insensitive' } },
+          { alt: { contains: search, mode: 'insensitive' } },
+        ],
+      }),
+      ...(createdAfter && { createdAt: { gte: createdAfter } }),
+      ...(createdBefore && { createdAt: { lte: createdBefore } }),
+      ...(tags && tags.length > 0 && {
+        metadata: {
+          path: ['tags'],
+          array_contains: tags,
+        },
+      }),
+    };
+
+    // Build orderBy
+    const orderBy: Prisma.MediaOrderByWithRelationInput = {
+      [sortBy]: sortOrder,
+    };
+
+    // Execute count and find in parallel
+    const [total, data] = await Promise.all([
+      this.prisma.media.count({ where }),
+      this.prisma.media.findMany({
+        where,
+        orderBy,
+        skip,
+        take: normalizedPerPage,
+      }),
+    ]);
+
+    return {
+      data: data.map((m) => this.mapToMedia(m)),
+      meta: {
+        page: normalizedPage,
+        perPage: normalizedPerPage,
+        total,
+        totalPages: Math.ceil(total / normalizedPerPage),
+      },
+    };
+  }
+
+  /**
+   * Finds all media as summaries (for galleries, etc.)
+   *
+   * @param organizationId - Organization ID
+   * @param params - Optional filtering params
+   * @returns Array of media summaries
+   */
+  async findAllSummaries(
+    organizationId: string,
+    params: Partial<MediaListParams> = {}
+  ): Promise<MediaSummary[]> {
+    const { type, includeDeleted = false } = params;
+
+    const where: Prisma.MediaWhereInput = {
+      organizationId,
+      ...(includeDeleted ? {} : notDeleted),
+      ...(type && { type }),
+    };
+
+    const media = await this.prisma.media.findMany({
+      where,
+      select: {
+        id: true,
+        originalName: true,
+        type: true,
+        url: true,
+        thumbnailUrl: true,
+        size: true,
+        createdAt: true,
+      },
+      orderBy: { createdAt: 'desc' },
+    });
+
+    return media;
+  }
+
+  /**
+   * Finds media by ID
+   *
+   * @param organizationId - Organization ID
+   * @param id - Media ID
+   * @returns Media or null
+   */
+  async findById(organizationId: string, id: string): Promise<Media | null> {
+    const result = await this.prisma.media.findFirst({
+      where: { id, organizationId, ...notDeleted },
+    });
+
+    return result ? this.mapToMedia(result) : null;
+  }
+
+  /**
+   * Finds media by ID or throws
+   *
+   * @param organizationId - Organization ID
+   * @param id - Media ID
+   * @returns Media
+   * @throws {AppException} If not found
+   */
+  async findByIdOrThrow(organizationId: string, id: string): Promise<Media> {
+    const media = await this.findById(organizationId, id);
+
+    if (!media) {
+      throw AppException.notFound('Media', id);
+    }
+
+    return media;
+  }
+
+  /**
+   * Finds media by filename
+   *
+   * @param organizationId - Organization ID
+   * @param filename - Stored filename
+   * @returns Media or null
+   */
+  async findByFilename(
+    organizationId: string,
+    filename: string
+  ): Promise<Media | null> {
+    const result = await this.prisma.media.findFirst({
+      where: { organizationId, filename, ...notDeleted },
+    });
+
+    return result ? this.mapToMedia(result) : null;
+  }
+
+  /**
+   * Finds multiple media by IDs
+   *
+   * @param organizationId - Organization ID
+   * @param ids - Array of media IDs
+   * @returns Array of media
+   */
+  async findByIds(organizationId: string, ids: string[]): Promise<Media[]> {
+    const results = await this.prisma.media.findMany({
+      where: {
+        id: { in: ids },
+        organizationId,
+        ...notDeleted,
+      },
+    });
+
+    return results.map((m) => this.mapToMedia(m));
+  }
+
+  /**
+   * Counts media for an organization
+   *
+   * @param organizationId - Organization ID
+   * @param type - Optional media type filter
+   * @returns Count
+   */
+  async count(organizationId: string, type?: MediaType): Promise<number> {
+    return this.prisma.media.count({
+      where: {
+        organizationId,
+        ...notDeleted,
+        ...(type && { type }),
+      },
+    });
+  }
+
+  /**
+   * Gets total storage used by organization
+   *
+   * @param organizationId - Organization ID
+   * @returns Total size in bytes
+   */
+  async getTotalStorageUsed(organizationId: string): Promise<number> {
+    const result = await this.prisma.media.aggregate({
+      where: {
+        organizationId,
+        ...notDeleted,
+      },
+      _sum: {
+        size: true,
+      },
+    });
+
+    return result._sum.size || 0;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Write Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Creates a new media record
+   *
+   * @param data - Create data
+   * @returns Created media
+   */
+  async create(data: CreateMediaData): Promise<Media> {
+    const result = await this.prisma.media.create({
+      data: {
+        organizationId: data.organizationId,
+        filename: data.filename,
+        originalName: data.originalName,
+        mimeType: data.mimeType,
+        size: data.size,
+        type: data.type,
+        storage: data.storage || MediaStorage.LOCAL,
+        url: data.url,
+        thumbnailUrl: data.thumbnailUrl || null,
+        alt: data.alt || null,
+        metadata: data.metadata || {},
+      },
+    });
+
+    return this.mapToMedia(result);
+  }
+
+  /**
+   * Creates multiple media records
+   *
+   * @param data - Array of create data
+   * @returns Created media count
+   */
+  async createMany(data: CreateMediaData[]): Promise<number> {
+    const result = await this.prisma.media.createMany({
+      data: data.map((d) => ({
+        organizationId: d.organizationId,
+        filename: d.filename,
+        originalName: d.originalName,
+        mimeType: d.mimeType,
+        size: d.size,
+        type: d.type,
+        storage: d.storage || MediaStorage.LOCAL,
+        url: d.url,
+        thumbnailUrl: d.thumbnailUrl || null,
+        alt: d.alt || null,
+        metadata: d.metadata || {},
+      })),
+    });
+
+    return result.count;
+  }
+
+  /**
+   * Updates a media record
+   *
+   * @param organizationId - Organization ID
+   * @param id - Media ID
+   * @param data - Update data
+   * @returns Updated media
+   * @throws {AppException} If not found
+   */
+  async update(
+    organizationId: string,
+    id: string,
+    data: UpdateMediaData
+  ): Promise<Media> {
+    // Verify exists
+    await this.findByIdOrThrow(organizationId, id);
+
+    const result = await this.prisma.media.update({
+      where: { id },
+      data: {
+        ...(data.alt !== undefined && { alt: data.alt }),
+        ...(data.thumbnailUrl !== undefined && { thumbnailUrl: data.thumbnailUrl }),
+        ...(data.metadata !== undefined && { metadata: data.metadata }),
+      },
+    });
+
+    return this.mapToMedia(result);
+  }
+
+  /**
+   * Updates media metadata (merge)
+   *
+   * @param organizationId - Organization ID
+   * @param id - Media ID
+   * @param metadata - Metadata to merge
+   * @returns Updated media
+   */
+  async updateMetadata(
+    organizationId: string,
+    id: string,
+    metadata: Prisma.JsonValue
+  ): Promise<Media> {
+    const media = await this.findByIdOrThrow(organizationId, id);
+
+    // Merge metadata
+    const currentMetadata = (media.metadata as Record<string, unknown>) || {};
+    const newMetadata = metadata as Record<string, unknown>;
+    const mergedMetadata = this.deepMerge(currentMetadata, newMetadata);
+
+    const result = await this.prisma.media.update({
+      where: { id },
+      data: { metadata: mergedMetadata },
+    });
+
+    return this.mapToMedia(result);
+  }
+
+  // ---------------------------------------------------------------------------
+  // Delete Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Soft deletes media
+   *
+   * @param organizationId - Organization ID
+   * @param id - Media ID
+   * @returns Deleted media
+   * @throws {AppException} If not found
+   */
+  async softDelete(organizationId: string, id: string): Promise<Media> {
+    await this.findByIdOrThrow(organizationId, id);
+
+    const result = await this.prisma.media.update({
+      where: { id },
+      data: softDelete(),
+    });
+
+    return this.mapToMedia(result);
+  }
+
+  /**
+   * Soft deletes multiple media
+   *
+   * @param organizationId - Organization ID
+   * @param ids - Array of media IDs
+   * @returns Number of deleted records
+   */
+  async softDeleteMany(organizationId: string, ids: string[]): Promise<number> {
+    const result = await this.prisma.media.updateMany({
+      where: {
+        id: { in: ids },
+        organizationId,
+        ...notDeleted,
+      },
+      data: softDelete(),
+    });
+
+    return result.count;
+  }
+
+  /**
+   * Restores a soft-deleted media
+   *
+   * @param organizationId - Organization ID
+   * @param id - Media ID
+   * @returns Restored media
+   */
+  async restore(organizationId: string, id: string): Promise<Media> {
+    // Find including deleted
+    const media = await this.prisma.media.findFirst({
+      where: { id, organizationId },
+    });
+
+    if (!media) {
+      throw AppException.notFound('Media', id);
+    }
+
+    const result = await this.prisma.media.update({
+      where: { id },
+      data: { deletedAt: null },
+    });
+
+    return this.mapToMedia(result);
+  }
+
+  /**
+   * Permanently deletes media (use with caution)
+   *
+   * @param organizationId - Organization ID
+   * @param id - Media ID
+   */
+  async hardDelete(organizationId: string, id: string): Promise<void> {
+    await this.prisma.media.deleteMany({
+      where: { id, organizationId },
+    });
+  }
+
+  // ---------------------------------------------------------------------------
+  // Helper Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Maps Prisma result to Media type
+   */
+  private mapToMedia(result: Prisma.MediaGetPayload<object>): Media {
+    return {
+      id: result.id,
+      organizationId: result.organizationId,
+      filename: result.filename,
+      originalName: result.originalName,
+      mimeType: result.mimeType,
+      size: result.size,
+      type: result.type,
+      storage: result.storage,
+      url: result.url,
+      thumbnailUrl: result.thumbnailUrl,
+      alt: result.alt,
+      metadata: result.metadata as MediaMetadata,
+      createdAt: result.createdAt,
+      updatedAt: result.updatedAt,
+      deletedAt: result.deletedAt,
+    };
+  }
+
+  /**
+   * Deep merges two objects
+   */
+  private deepMerge(
+    target: Record<string, unknown>,
+    source: Record<string, unknown>
+  ): Record<string, unknown> {
+    const result = { ...target };
+
+    for (const [key, value] of Object.entries(source)) {
+      if (value !== undefined && value !== null) {
+        if (typeof value === 'object' && !Array.isArray(value)) {
+          result[key] = this.deepMerge(
+            (result[key] as Record<string, unknown>) || {},
+            value as Record<string, unknown>
+          );
+        } else {
+          result[key] = value;
+        }
+      }
+    }
+
+    return result;
+  }
+}

