+/**
+ * Media Module Service
+ *
+ * Business logic service for the Media module.
+ * Handles file uploads, image processing, and media management.
+ *
+ * @module modules/_core/media/media.service
+ *
+ * @example
+ * ```typescript
+ * import { MediaService } from '@/modules/_core/media/media.service';
+ * import { resolve } from '@/core/kernel/container';
+ *
+ * const mediaService = resolve<MediaService>('MediaService');
+ *
+ * // Upload a file
+ * const result = await mediaService.upload(orgId, {
+ *   originalName: 'photo.jpg',
+ *   mimeType: 'image/jpeg',
+ *   size: 1024000,
+ *   buffer: fileBuffer,
+ * });
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+import { MediaType, Prisma } from '@prisma/client';
+import * as fs from 'fs/promises';
+import * as path from 'path';
+import * as crypto from 'crypto';
+
+import { TOKENS } from '@/core/kernel/container';
+import { AppException } from '@/core/exceptions/app.exception';
+import { EventService } from '@/core/services/event.service';
+
+import {
+  MediaRepository,
+  PaginatedResult,
+  CreateMediaData,
+} from '@/modules/_core/media/media.repository';
+
+import type {
+  Media,
+  UploadMediaRequest,
+  UploadMediaResponse,
+  UploadMultipleMediaRequest,
+  UploadMultipleMediaResponse,
+  UpdateMediaRequest,
+  UpdateMediaResponse,
+  MediaListParams,
+  MediaSummary,
+  ImageProcessingOptions,
+  ProcessingResult,
+} from '@/modules/_core/media/media.types';
+
+import {
+  uploadMediaSchema,
+  updateMediaSchema,
+  mediaListQuerySchema,
+  validateFileSize,
+  validateMimeType,
+  getMediaTypeFromMime,
+  generateUniqueFilename,
+  type UploadMediaInput,
+  type UpdateMediaInput,
+  type MediaListQueryInput,
+} from '@/modules/_core/media/media.schema';
+
+// -----------------------------------------------------------------------------
+// Types
+// -----------------------------------------------------------------------------
+
+/**
+ * User context for operations
+ */
+interface UserContext {
+  /** User ID making the request */
+  userId?: string;
+}
+
+// -----------------------------------------------------------------------------
+// Media Service
+// -----------------------------------------------------------------------------
+
+/**
+ * Media module business logic service.
+ *
+ * Handles all media-related business operations including:
+ * - File upload and validation
+ * - Image processing and optimization
+ * - Thumbnail generation
+ * - Media CRUD operations
+ *
+ * @example
+ * ```typescript
+ * @injectable()
+ * class SomeController {
+ *   constructor(
+ *     @inject('MediaService') private mediaService: MediaService,
+ *   ) {}
+ *
+ *   async handleUpload(req: Request, res: Response) {
+ *     const result = await this.mediaService.upload(orgId, req.body);
+ *     res.json(result);
+ *   }
+ * }
+ * ```
+ */
+@injectable()
+export class MediaService {
+  private readonly uploadDir: string;
+  private readonly publicUrl: string;
+
+  constructor(
+    @inject('MediaRepository') private readonly repository: MediaRepository,
+    @inject(TOKENS.EventService) private readonly eventService: EventService
+  ) {
+    // Configure upload directory (can be overridden by env)
+    this.uploadDir = process.env.UPLOAD_DIR || path.join(process.cwd(), 'public', 'uploads');
+    this.publicUrl = process.env.PUBLIC_URL || '/uploads';
+  }
+
+  // ---------------------------------------------------------------------------
+  // Read Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Lists media with pagination and filtering.
+   *
+   * @param organizationId - Organization ID
+   * @param params - Query parameters
+   * @returns Paginated list of media
+   *
+   * @example
+   * ```typescript
+   * const result = await mediaService.list(orgId, {
+   *   page: 1,
+   *   perPage: 20,
+   *   type: 'IMAGE',
+   * });
+   * ```
+   */
+  async list(
+    organizationId: string,
+    params: MediaListParams
+  ): Promise<PaginatedResult<Media>> {
+    const validated = this.validateInput(
+      params,
+      mediaListQuerySchema
+    ) as MediaListQueryInput;
+    return this.repository.findAll(organizationId, validated);
+  }
+
+  /**
+   * Lists media summaries (for galleries, selectors).
+   *
+   * @param organizationId - Organization ID
+   * @param params - Optional filtering params
+   * @returns Array of media summaries
+   */
+  async listSummaries(
+    organizationId: string,
+    params?: Partial<MediaListParams>
+  ): Promise<MediaSummary[]> {
+    return this.repository.findAllSummaries(organizationId, params);
+  }
+
+  /**
+   * Gets media by ID.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Media ID
+   * @returns Media or null
+   */
+  async getById(organizationId: string, id: string): Promise<Media | null> {
+    return this.repository.findById(organizationId, id);
+  }
+
+  /**
+   * Gets media by ID or throws.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Media ID
+   * @returns Media
+   * @throws {AppException} If not found
+   */
+  async getByIdOrThrow(organizationId: string, id: string): Promise<Media> {
+    return this.repository.findByIdOrThrow(organizationId, id);
+  }
+
+  /**
+   * Gets multiple media by IDs.
+   *
+   * @param organizationId - Organization ID
+   * @param ids - Array of media IDs
+   * @returns Array of media
+   */
+  async getByIds(organizationId: string, ids: string[]): Promise<Media[]> {
+    return this.repository.findByIds(organizationId, ids);
+  }
+
+  /**
+   * Counts media for an organization.
+   *
+   * @param organizationId - Organization ID
+   * @param type - Optional media type filter
+   * @returns Count
+   */
+  async count(organizationId: string, type?: MediaType): Promise<number> {
+    return this.repository.count(organizationId, type);
+  }
+
+  /**
+   * Gets storage usage for an organization.
+   *
+   * @param organizationId - Organization ID
+   * @returns Storage info
+   */
+  async getStorageUsage(
+    organizationId: string
+  ): Promise<{ used: number; count: number }> {
+    const [used, count] = await Promise.all([
+      this.repository.getTotalStorageUsed(organizationId),
+      this.repository.count(organizationId),
+    ]);
+
+    return { used, count };
+  }
+
+  // ---------------------------------------------------------------------------
+  // Upload Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Uploads a single file.
+   *
+   * Validates file, stores it, generates thumbnails if applicable,
+   * and creates database record.
+   *
+   * @param organizationId - Organization ID
+   * @param data - Upload request data
+   * @param context - User context
+   * @returns Upload response with media
+   * @throws {AppException} If validation fails
+   *
+   * @example
+   * ```typescript
+   * const result = await mediaService.upload(orgId, {
+   *   originalName: 'photo.jpg',
+   *   mimeType: 'image/jpeg',
+   *   size: 1024000,
+   *   buffer: fileBuffer,
+   * });
+   * console.log('Uploaded:', result.media.url);
+   * ```
+   */
+  async upload(
+    organizationId: string,
+    data: UploadMediaRequest,
+    context?: UserContext
+  ): Promise<UploadMediaResponse> {
+    // Validate input
+    const validated = this.validateInput(data, uploadMediaSchema) as UploadMediaInput;
+
+    // Validate MIME type
+    if (!validateMimeType(validated.mimeType)) {
+      throw AppException.invalidInput(
+        `Unsupported file type: ${validated.mimeType}`,
+        'mimeType'
+      );
+    }
+
+    // Validate file size
+    if (!validateFileSize(validated.mimeType, validated.size)) {
+      throw AppException.invalidInput(
+        'File size exceeds the maximum allowed limit',
+        'size'
+      );
+    }
+
+    // Generate unique filename
+    const filename = generateUniqueFilename(validated.originalName);
+    const mediaType = getMediaTypeFromMime(validated.mimeType);
+
+    // Ensure upload directory exists
+    const orgDir = path.join(this.uploadDir, organizationId);
+    await this.ensureDirectory(orgDir);
+
+    // Store file
+    const filePath = path.join(orgDir, filename);
+    if (data.buffer) {
+      await fs.writeFile(filePath, data.buffer);
+    }
+
+    // Generate URL
+    const url = `${this.publicUrl}/${organizationId}/${filename}`;
+
+    // Generate thumbnail for images
+    let thumbnailUrl: string | null = null;
+    if (mediaType === 'IMAGE' && validated.generateThumbnail) {
+      thumbnailUrl = await this.generateThumbnail(
+        organizationId,
+        filename,
+        data.buffer
+      );
+    }
+
+    // Create database record
+    const createData: CreateMediaData = {
+      organizationId,
+      filename,
+      originalName: validated.originalName,
+      mimeType: validated.mimeType,
+      size: validated.size,
+      type: mediaType,
+      url,
+      thumbnailUrl,
+      alt: validated.alt || null,
+      metadata: {
+        tags: validated.tags || [],
+        uploadedBy: context?.userId,
+        source: 'upload',
+      } as Prisma.JsonValue,
+    };
+
+    const media = await this.repository.create(createData);
+
+    // Emit upload event
+    await this.eventService.emitCustom('media.uploaded', {
+      mediaId: media.id,
+      organizationId,
+      originalName: media.originalName,
+      type: media.type,
+      size: media.size,
+      url: media.url,
+      uploadedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return {
+      media,
+      message: 'File uploaded successfully.',
+    };
+  }
+
+  /**
+   * Uploads multiple files.
+   *
+   * @param organizationId - Organization ID
+   * @param data - Multiple upload request
+   * @param context - User context
+   * @returns Upload response with results
+   */
+  async uploadMultiple(
+    organizationId: string,
+    data: UploadMultipleMediaRequest,
+    context?: UserContext
+  ): Promise<UploadMultipleMediaResponse> {
+    const results: Media[] = [];
+    const errors: Array<{ filename: string; message: string; code: string }> = [];
+
+    for (const file of data.files) {
+      try {
+        const result = await this.upload(organizationId, file, context);
+        results.push(result.media);
+      } catch (error) {
+        const appError = error instanceof AppException ? error : null;
+        errors.push({
+          filename: file.originalName,
+          message: appError?.message || 'Upload failed',
+          code: appError?.code || 'UPLOAD_FAILED',
+        });
+      }
+    }
+
+    return {
+      media: results,
+      successful: results.length,
+      failed: errors.length,
+      errors: errors.length > 0 ? errors : undefined,
+    };
+  }
+
+  // ---------------------------------------------------------------------------
+  // Update Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Updates media metadata.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Media ID
+   * @param data - Update request data
+   * @param context - User context
+   * @returns Update response
+   */
+  async update(
+    organizationId: string,
+    id: string,
+    data: UpdateMediaRequest,
+    context?: UserContext
+  ): Promise<UpdateMediaResponse> {
+    // Validate input
+    const validated = this.validateInput(data, updateMediaSchema) as UpdateMediaInput;
+
+    // Get current media
+    await this.repository.findByIdOrThrow(organizationId, id);
+
+    // Build update data
+    const updateData: Record<string, unknown> = {};
+    if (validated.alt !== undefined) updateData.alt = validated.alt;
+
+    // Merge metadata if provided
+    if (validated.metadata) {
+      const media = await this.repository.updateMetadata(
+        organizationId,
+        id,
+        validated.metadata as Prisma.JsonValue
+      );
+      return {
+        media,
+        message: 'Media updated successfully.',
+      };
+    }
+
+    // Update basic fields
+    const media = await this.repository.update(organizationId, id, updateData);
+
+    return {
+      media,
+      message: 'Media updated successfully.',
+    };
+  }
+
+  // ---------------------------------------------------------------------------
+  // Delete Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Deletes media (soft delete).
+   *
+   * @param organizationId - Organization ID
+   * @param id - Media ID
+   * @param context - User context
+   */
+  async delete(
+    organizationId: string,
+    id: string,
+    context?: UserContext
+  ): Promise<void> {
+    const media = await this.repository.findByIdOrThrow(organizationId, id);
+
+    // Soft delete
+    await this.repository.softDelete(organizationId, id);
+
+    // Emit deletion event
+    await this.eventService.emitCustom('media.deleted', {
+      mediaId: media.id,
+      organizationId,
+      originalName: media.originalName,
+      deletedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+  }
+
+  /**
+   * Deletes multiple media.
+   *
+   * @param organizationId - Organization ID
+   * @param ids - Array of media IDs
+   * @param context - User context
+   * @returns Number of deleted records
+   */
+  async deleteMany(
+    organizationId: string,
+    ids: string[],
+    context?: UserContext
+  ): Promise<number> {
+    const count = await this.repository.softDeleteMany(organizationId, ids);
+
+    // Emit deletion events
+    for (const id of ids) {
+      await this.eventService.emitCustom('media.deleted', {
+        mediaId: id,
+        organizationId,
+        originalName: 'bulk-delete',
+        deletedBy: context?.userId,
+        timestamp: new Date().toISOString(),
+      });
+    }
+
+    return count;
+  }
+
+  /**
+   * Restores a deleted media.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Media ID
+   * @param context - User context
+   * @returns Restored media
+   */
+  async restore(
+    organizationId: string,
+    id: string,
+    context?: UserContext
+  ): Promise<Media> {
+    return this.repository.restore(organizationId, id);
+  }
+
+  // ---------------------------------------------------------------------------
+  // Processing Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Processes an image with specified options.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Media ID
+   * @param options - Processing options
+   * @returns Processing result
+   */
+  async processImage(
+    organizationId: string,
+    id: string,
+    options: ImageProcessingOptions
+  ): Promise<ProcessingResult> {
+    const media = await this.repository.findByIdOrThrow(organizationId, id);
+
+    if (media.type !== 'IMAGE') {
+      throw AppException.invalidInput('Only images can be processed', 'type');
+    }
+
+    // In a real implementation, this would use sharp or similar
+    // For now, return a mock result
+    const result: ProcessingResult = {
+      url: media.url,
+      size: media.size,
+      dimensions: {
+        width: options.width || 800,
+        height: options.height || 600,
+      },
+      processingTime: 100,
+    };
+
+    // Update metadata
+    await this.repository.updateMetadata(organizationId, id, {
+      processing: {
+        processed: true,
+        originalSize: media.size,
+      },
+    } as Prisma.JsonValue);
+
+    // Emit processing event
+    await this.eventService.emitCustom('media.processed', {
+      mediaId: media.id,
+      organizationId,
+      result,
+      timestamp: new Date().toISOString(),
+    });
+
+    return result;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Helper Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Generates a thumbnail for an image.
+   *
+   * @param organizationId - Organization ID
+   * @param filename - Original filename
+   * @param buffer - Image buffer
+   * @returns Thumbnail URL
+   */
+  private async generateThumbnail(
+    organizationId: string,
+    filename: string,
+    buffer?: Buffer
+  ): Promise<string | null> {
+    if (!buffer) return null;
+
+    try {
+      // Generate thumbnail filename
+      const ext = path.extname(filename);
+      const baseName = path.basename(filename, ext);
+      const thumbnailFilename = `${baseName}_thumb${ext}`;
+
+      // In a real implementation, use sharp for image processing
+      // For now, just create a copy as placeholder
+      const orgDir = path.join(this.uploadDir, organizationId, 'thumbnails');
+      await this.ensureDirectory(orgDir);
+
+      const thumbnailPath = path.join(orgDir, thumbnailFilename);
+      await fs.writeFile(thumbnailPath, buffer);
+
+      return `${this.publicUrl}/${organizationId}/thumbnails/${thumbnailFilename}`;
+    } catch {
+      // Thumbnail generation failed, not critical
+      return null;
+    }
+  }
+
+  /**
+   * Ensures a directory exists.
+   *
+   * @param dir - Directory path
+   */
+  private async ensureDirectory(dir: string): Promise<void> {
+    try {
+      await fs.access(dir);
+    } catch {
+      await fs.mkdir(dir, { recursive: true });
+    }
+  }
+
+  /**
+   * Validates input data against a Zod schema.
+   */
+  private validateInput<T>(
+    data: unknown,
+    schema: { parse: (data: unknown) => T }
+  ): T {
+    try {
+      return schema.parse(data);
+    } catch (error) {
+      if (error && typeof error === 'object' && 'errors' in error) {
+        const zodError = error as {
+          errors: Array<{ path: string[]; message: string; code: string }>;
+        };
+        const validationErrors = zodError.errors.map((err) => ({
+          field: err.path.join('.'),
+          message: err.message,
+          rule: err.code,
+        }));
+        throw AppException.validation(validationErrors);
+      }
+      throw error;
+    }
+  }
+}

