+export interface MediaProcessedEvent {
+  /** Media ID */
+  mediaId: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Processing result */
+  result: ProcessingResult;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+/**
+ * Thumbnail created event payload
+ */
+export interface ThumbnailCreatedEvent {
