+// -----------------------------------------------------------------------------
+// Hook Context Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Before upload hook context
+ */
+export interface BeforeUploadContext {
+  /** Upload request data */
+  data: UploadMediaRequest;
+  /** Organization ID */
+  organizationId: string;
+  /** User ID */
+  userId?: string;
+}
+
+/**
+ * After upload hook context
+ */
+export interface AfterUploadContext {
+  /** Uploaded media */
+  media: Media;
+  /** User ID */
+  userId?: string;
+}
+
+/**
+ * Before delete hook context
+ */
+export interface BeforeDeleteContext {
+  /** Media to delete */
+  media: Media;
+  /** User ID */
+  userId?: string;
+}
+
+/**
+ * After delete hook context
+ */
+export interface AfterDeleteContext {
+  /** Deleted media ID */
+  mediaId: string;
+  /** Organization ID */
+  organizationId: string;
+  /** User ID */
+  userId?: string;
