+    medium: number;
+    large: number;
+  };
+  /** Storage provider (local, s3, cdn) */
+  storageProvider: 'local' | 's3' | 'cdn';
+  /** CDN enabled */
+  cdnEnabled: boolean;
+  /** Auto-optimize images */
+  autoOptimize: boolean;
+}
+
+// -----------------------------------------------------------------------------
+// Storage Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Storage configuration
+ */
+export interface StorageConfig {
+  /** Storage provider */
+  provider: MediaStorage;
+  /** Base path for storage */
+  basePath: string;
+  /** Public URL prefix */
+  publicUrl: string;
+  /** S3-specific config (if applicable) */
+  s3?: S3Config;
+}
+
+/**
+ * S3 configuration
+ */
+export interface S3Config {
+  /** Bucket name */
+  bucket: string;
+  /** AWS region */
+  region: string;
+  /** Access key ID */
+  accessKeyId?: string;
+  /** Secret access key */
+  secretAccessKey?: string;
+  /** Endpoint (for S3-compatible services) */
+  endpoint?: string;
+}
+
+// -----------------------------------------------------------------------------
+// Type Guards
+// -----------------------------------------------------------------------------
+
+/**
+ * Type guard to check if an object is a valid Media
+ */
+export function isMedia(obj: unknown): obj is Media {
+  return (
+    typeof obj === 'object' &&
+    obj !== null &&
+    'id' in obj &&
+    'organizationId' in obj &&
+    'filename' in obj &&
+    'url' in obj &&
+    'type' in obj
+  );
+}
+
+/**
+ * Type guard to check if a MIME type is an image
+ */
+export function isImageMimeType(mimeType: string): boolean {
+  return mimeType.startsWith('image/');
+}
+
+/**
+ * Type guard to check if a MIME type is a video
+ */
+export function isVideoMimeType(mimeType: string): boolean {
+  return mimeType.startsWith('video/');
+}
+
+/**
+ * Type guard to check if a MIME type is a document
+ */
+export function isDocumentMimeType(mimeType: string): boolean {
+  return (
+    mimeType.startsWith('application/pdf') ||
+    mimeType.startsWith('application/msword') ||
+    mimeType.startsWith('application/vnd.')
+  );
+}

