+/**
+ * Module Loader Module Definition
+ *
+ * Core module management system for E-Menum.
+ * Provides admin-level access to module discovery, activation, and lifecycle management.
+ *
+ * This is a CORE module - it cannot be disabled.
+ *
+ * @module modules/_core/module-loader/module-loader.module
+ *
+ * @example
+ * ```typescript
+ * import { ModuleLoaderModule } from '@/modules/_core/module-loader/module-loader.module';
+ *
+ * // Module is automatically discovered and loaded by ModuleLoader
+ * // Access module instance via DI container
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+import { TOKENS, registerSingleton, appContainer } from '@/core/kernel/container';
+import type { ModuleInstance } from '@/core/kernel/module-loader';
+import type { EventService } from '@/core/services/event.service';
+
+import { ModuleLoaderController } from '@/modules/_core/module-loader/module-loader.controller';
+import { ModuleLoaderService } from '@/modules/_core/module-loader/module-loader.service';
+import { moduleLoaderRoutes } from '@/modules/_core/module-loader/module-loader.routes';
+import type { ModuleLoaderSettings } from '@/modules/_core/module-loader/module-loader.types';
+
+// -----------------------------------------------------------------------------
+// Module Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Module loader module context for lifecycle hooks
+ */
+export interface ModuleLoaderModuleContext {
+  /** Event service for pub/sub */
+  events: EventService;
+  /** Module settings */
+  settings: ModuleLoaderSettings;
+  /** Logger function */
+  log: (message: string) => void;
+}
+
+/**
+ * Module loader module hook definitions
+ */
+export interface ModuleLoaderModuleHooks {
+  /** Called before module activation */
+  beforeModuleActivate?: (data: { moduleId: string }) => Promise<void>;
+  /** Called after module activation */
+  afterModuleActivate?: (data: { moduleId: string; duration: number }) => Promise<void>;
+  /** Called before module deactivation */
+  beforeModuleDeactivate?: (data: { moduleId: string }) => Promise<void>;
+  /** Called after module deactivation */
+  afterModuleDeactivate?: (data: { moduleId: string; duration: number }) => Promise<void>;
+}
+
+// -----------------------------------------------------------------------------
+// Module Loader Module Class
+// -----------------------------------------------------------------------------
+
+/**
+ * Module Loader Module
+ *
+ * Core module providing module management for E-Menum admin panel.
+ * Handles module discovery, activation, deactivation, and lifecycle.
+ *
+ * Features:
+ * - Module discovery and listing
+ * - Module activation/deactivation
+ * - Dependency resolution
+ * - Health checks
+ * - Admin menu integration
+ *
+ * @example
+ * ```typescript
+ * // Module is automatically loaded by ModuleLoader
+ * // Use ModuleLoaderService for business logic
+ * const moduleService = container.resolve('ModuleLoaderService');
+ * await moduleService.activateModule({ moduleId: 'menu' });
+ * ```
+ */
+@injectable()
+export class ModuleLoaderModule implements ModuleInstance {
+  // ---------------------------------------------------------------------------
+  // Static Properties
+  // ---------------------------------------------------------------------------
+
+  /** Module ID */
+  static readonly id = 'module-loader';
+
+  /** Module name */
+  static readonly name = 'Module Loader';
+
+  /** Module version */
+  static readonly version = '1.0.0';
+
+  /** Is core module (cannot be disabled) */
+  static readonly isCore = true;
+
+  /** Module routes configuration */
+  static readonly routes = moduleLoaderRoutes;
+
+  /** Providers (services) to register */
+  static readonly providers = [ModuleLoaderService];
+
+  /** Controllers to register */
+  static readonly controllers = [ModuleLoaderController];
+
+  // ---------------------------------------------------------------------------
+  // Instance Properties
+  // ---------------------------------------------------------------------------
+
+  /** Module hooks registry */
+  private hooks: ModuleLoaderModuleHooks = {};
+
+  /** Module initialized flag */
+  private initialized = false;
+
+  constructor(
+    @inject(TOKENS.EventService) private readonly eventService: EventService
+  ) {}
+
+  // ---------------------------------------------------------------------------
+  // ModuleInstance Lifecycle Hooks
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Called when module is loaded.
+   * Registers services with DI container.
+   */
+  async onLoad(): Promise<void> {
+    this.log('Loading module-loader module...');
+
+    // Register ModuleLoaderService with DI container
+    if (!appContainer.isRegistered('ModuleLoaderService')) {
+      registerSingleton('ModuleLoaderService', ModuleLoaderService);
+    }
+
+    this.log('Module-loader module loaded');
+  }
+
+  /**
+   * Called when module is enabled/activated.
+   * Sets up event listeners and registers routes.
+   */
+  async onEnable(): Promise<void> {
+    if (this.initialized) {
+      this.log('Module-loader module already initialized');
+      return;
+    }
+
+    this.log('Enabling module-loader module...');
+
+    // Subscribe to relevant events
+    this.setupEventListeners();
+
+    this.initialized = true;
+    this.log('Module-loader module enabled');
+
+    // Emit module activated event
+    await this.eventService.emitCustom('module.activated', {
+      moduleId: ModuleLoaderModule.id,
+      timestamp: new Date().toISOString(),
+    });
+  }
+
+  /**
+   * Called when module is disabled/deactivated.
+   * Core modules cannot be fully disabled, but this handles graceful pause.
+   */
+  async onDisable(): Promise<void> {
+    this.log('Module-loader module disable requested (core module - limited action)');
+
+    // Core modules cannot be fully disabled
+    // This would only be called during shutdown
+
+    this.initialized = false;
+    this.log('Module-loader module disabled');
+  }
+
+  /**
+   * Called when module is unloaded.
+   * Cleans up resources.
+   */
+  async onUnload(): Promise<void> {
+    this.log('Unloading module-loader module...');
+
+    // Clear hooks
+    this.hooks = {};
+
+    this.log('Module-loader module unloaded');
+  }
+
+  // ---------------------------------------------------------------------------
+  // ModuleInstance Interface Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Returns module routes for registration with Express.
+   *
+   * @returns Route configuration array
+   */
+  getRoutes(): unknown[] {
+    return [moduleLoaderRoutes];
+  }
+
+  /**
+   * Returns module controllers for registration with routing-controllers.
+   *
+   * @returns Controller class array
+   */
+  getControllers(): unknown[] {
+    return ModuleLoaderModule.controllers;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Hook System
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets current module hooks.
+   *
+   * @returns Module hooks object
+   */
+  getHooks(): ModuleLoaderModuleHooks {
+    return { ...this.hooks };
+  }
+
+  /**
+   * Registers a hook handler.
+   *
+   * @param hookName - Name of the hook
+   * @param handler - Hook handler function
+   *
+   * @example
+   * ```typescript
+   * moduleLoaderModule.registerHook('afterModuleActivate', async (data) => {
+   *   console.log('Module activated:', data.moduleId);
+   * });
+   * ```
+   */
+  registerHook<K extends keyof ModuleLoaderModuleHooks>(
+    hookName: K,
+    handler: ModuleLoaderModuleHooks[K]
+  ): void {
+    this.hooks[hookName] = handler;
+    this.log(`Registered hook: ${hookName}`);
+  }
+
+  /**
+   * Unregisters a hook handler.
+   *
+   * @param hookName - Name of the hook to unregister
+   */
+  unregisterHook(hookName: keyof ModuleLoaderModuleHooks): void {
+    delete this.hooks[hookName];
+    this.log(`Unregistered hook: ${hookName}`);
+  }
+
+  /**
+   * Executes a hook if registered.
+   *
+   * @param hookName - Name of the hook
+   * @param data - Data to pass to the hook
+   */
+  async executeHook<K extends keyof ModuleLoaderModuleHooks>(
+    hookName: K,
+    data: Parameters<NonNullable<ModuleLoaderModuleHooks[K]>>[0]
+  ): Promise<void> {
+    const hook = this.hooks[hookName];
+    if (hook) {
+      try {
+        await (hook as (data: typeof data) => Promise<void>)(data);
+      } catch (error) {
+        this.log(
+          `Hook execution error (${hookName}): ${error instanceof Error ? error.message : 'Unknown error'}`
+        );
+      }
+    }
+  }
+
+  // ---------------------------------------------------------------------------
+  // Event Listeners
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Sets up event listeners for the module loader module.
+   */
+  private setupEventListeners(): void {
+    // Listen for module events to log and track
+    this.eventService.on('module.activated', async (payload) => {
+      this.log(`Module activated event: ${payload.moduleId}`);
+    });
+
+    this.eventService.on('module.deactivated', async (payload) => {
+      this.log(`Module deactivated event: ${payload.moduleId}`);
+    });
+
+    this.log('Event listeners set up');
+  }
+
+  // ---------------------------------------------------------------------------
+  // Module Settings
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets default module settings.
+   *
+   * @returns Default module loader settings
+   */
+  static getDefaultSettings(): ModuleLoaderSettings {
+    return {
+      autoDiscovery: true,
+      autoActivateCoreModules: true,
+      checkDependencies: true,
+      enableHotReload: false,
+    };
+  }
+
+  // ---------------------------------------------------------------------------
+  // Utility Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Logs a message with module prefix.
+   *
+   * @param message - Message to log
+   */
+  private log(message: string): void {
+    // eslint-disable-next-line no-console
+    console.log(`[ModuleLoaderModule] ${message}`);
+  }
+
+  /**
+   * Checks if module is initialized.
+   *
+   * @returns True if module is initialized
+   */
+  isInitialized(): boolean {
+    return this.initialized;
+  }
+
+  /**
+   * Gets module metadata.
+   *
+   * @returns Module metadata object
+   */
+  static getMetadata() {
+    return {
+      id: ModuleLoaderModule.id,
+      name: ModuleLoaderModule.name,
+      version: ModuleLoaderModule.version,
+      isCore: ModuleLoaderModule.isCore,
+      routes: ModuleLoaderModule.routes,
+      providers: ModuleLoaderModule.providers.map((p) => p.name),
+      controllers: ModuleLoaderModule.controllers.map((c) => c.name),
+    };
+  }
+}
+
+// -----------------------------------------------------------------------------
+// Module Exports
+// -----------------------------------------------------------------------------
+
+/**
+ * Default export for module loader dynamic import
+ */
+export default ModuleLoaderModule;
+
+/**
+ * Export module metadata
+ */
+export const metadata = ModuleLoaderModule.getMetadata();

