@@ -0,0 +1,523 @@
+/**
+ * Module Loader Module Types
+ *
+ * Type definitions for the Module Loader admin module including:
+ * - Module state and status types
+ * - Request/Response DTOs
+ * - Event payloads
+ * - Settings types
+ *
+ * @module modules/_core/module-loader/module-loader.types
+ *
+ * @example
+ * ```typescript
+ * import type {
+ *   ModuleInfo,
+ *   ModuleActivateRequest,
+ *   ModuleListResponse,
+ * } from '@/modules/_core/module-loader/module-loader.types';
+ * ```
+ */
+
+import type {
+  ModuleManifest,
+  ModuleStatus,
+  ModuleCategory,
+  LoadedModule,
+} from '@/core/kernel/module-loader';
+
+// -----------------------------------------------------------------------------
+// Re-export Core Types
+// -----------------------------------------------------------------------------
+
+export type { ModuleManifest, ModuleStatus, ModuleCategory, LoadedModule };
+
+// -----------------------------------------------------------------------------
+// Module Info Types (API Response)
+// -----------------------------------------------------------------------------
+
+/**
+ * Module information for API responses
+ */
+export interface ModuleInfo {
+  /** Module unique identifier */
+  id: string;
+  /** Module display name */
+  name: string;
+  /** Module display name (human readable) */
+  displayName: string;
+  /** Module version (semver) */
+  version: string;
+  /** Module description */
+  description: string;
+  /** Module author */
+  author: string;
+  /** Module category */
+  category: ModuleCategory;
+  /** Current status */
+  status: ModuleStatus;
+  /** Is core module (cannot be disabled) */
+  isCore: boolean;
+  /** Is currently enabled */
+  isEnabled: boolean;
+  /** Load priority (lower = earlier) */
+  priority: number;
+  /** Required dependencies */
+  dependencies: string[];
+  /** Optional dependencies */
+  optionalDependencies: string[];
+  /** Modules that depend on this one */
+  dependents: string[];
+  /** Permissions provided by this module */
+  permissions: string[];
+  /** Events emitted by this module */
+  events: string[];
+  /** Admin menu configuration */
+  adminMenu?: {
+    label: string;
+    icon?: string;
+    route?: string;
+    position: number;
+  };
+  /** Timestamp when loaded */
+  loadedAt?: Date;
+  /** Error message if status is 'error' */
+  error?: string;
+}
+
+/**
+ * Module summary for list views
+ */
+export interface ModuleSummary {
+  /** Module ID */
+  id: string;
+  /** Display name */
+  displayName: string;
+  /** Module category */
+  category: ModuleCategory;
+  /** Current status */
+  status: ModuleStatus;
+  /** Is core module */
+  isCore: boolean;
+  /** Version */
+  version: string;
+  /** Icon class */
+  icon?: string;
+}
+
+// -----------------------------------------------------------------------------
+// Request Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Request to activate a module
+ */
+export interface ModuleActivateRequest {
+  /** Module ID to activate */
+  moduleId: string;
+  /** Force activation (skip dependency checks) */
+  force?: boolean;
+}
+
+/**
+ * Request to deactivate a module
+ */
+export interface ModuleDeactivateRequest {
+  /** Module ID to deactivate */
+  moduleId: string;
+  /** Force deactivation (even if dependents exist) */
+  force?: boolean;
+}
+
+/**
+ * Request to install a module
+ */
+export interface ModuleInstallRequest {
+  /** Module ID to install */
+  moduleId: string;
+  /** Run migrations */
+  runMigrations?: boolean;
+}
+
+/**
+ * Request to uninstall a module
+ */
+export interface ModuleUninstallRequest {
+  /** Module ID to uninstall */
+  moduleId: string;
+  /** Force uninstall (delete data) */
+  force?: boolean;
+  /** Keep data (soft uninstall) */
+  keepData?: boolean;
+}
+
+/**
+ * Request to upgrade a module
+ */
+export interface ModuleUpgradeRequest {
+  /** Module ID to upgrade */
+  moduleId: string;
+  /** Target version */
+  targetVersion: string;
+  /** Run migrations */
+  runMigrations?: boolean;
+}
+
+// -----------------------------------------------------------------------------
+// Response Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Module list response
+ */
+export interface ModuleListResponse {
+  /** List of modules */
+  modules: ModuleInfo[];
+  /** Module statistics */
+  stats: ModuleStats;
+}
+
+/**
+ * Module action response (activate, deactivate, etc.)
+ */
+export interface ModuleActionResponse {
+  /** Operation success status */
+  success: boolean;
+  /** Module info after action */
+  module?: ModuleInfo;
+  /** Success/error message */
+  message: string;
+  /** Warning messages */
+  warnings?: string[];
+}
+
+/**
+ * Module statistics
+ */
+export interface ModuleStats {
+  /** Total modules discovered */
+  total: number;
+  /** Count by status */
+  byStatus: Record<ModuleStatus, number>;
+  /** Count by category */
+  byCategory: Record<ModuleCategory, number>;
+  /** Active modules count */
+  active: number;
+  /** Core modules count */
+  core: number;
+  /** Modules with errors */
+  errors: number;
+}
+
+/**
+ * Module dependency check result
+ */
+export interface DependencyCheckResult {
+  /** Check passed */
+  valid: boolean;
+  /** Missing required dependencies */
+  missing: string[];
+  /** Circular dependencies detected */
+  circular: string[];
+  /** Available optional dependencies */
+  availableOptional: string[];
+  /** Recommended load order */
+  loadOrder: string[];
+}
+
+/**
+ * Module health check result
+ */
+export interface ModuleHealthCheckResult {
+  /** Module ID */
+  moduleId: string;
+  /** Health status */
+  status: 'healthy' | 'degraded' | 'unhealthy';
+  /** Status message */
+  message: string;
+  /** Health check details */
+  details?: Record<string, unknown>;
+  /** Check timestamp */
+  checkedAt: Date;
+}
+
+// -----------------------------------------------------------------------------
+// Query/Filter Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Module list query filters
+ */
+export interface ModuleListFilters {
+  /** Filter by category */
+  category?: ModuleCategory;
+  /** Filter by status */
+  status?: ModuleStatus;
+  /** Filter by core status */
+  isCore?: boolean;
+  /** Filter by enabled status */
+  isEnabled?: boolean;
+  /** Search in name/description */
+  search?: string;
+}
+
+/**
+ * Module list query params
+ */
+export interface ModuleListParams extends ModuleListFilters {
+  /** Sort field */
+  sortBy?: 'name' | 'category' | 'status' | 'priority';
+  /** Sort direction */
+  sortOrder?: 'asc' | 'desc';
+  /** Include stats */
+  includeStats?: boolean;
+}
+
+// -----------------------------------------------------------------------------
+// Event Payload Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Module activated event payload
+ */
+export interface ModuleActivatedEvent {
+  /** Module ID */
+  moduleId: string;
+  /** Module version */
+  version: string;
+  /** Activation timestamp */
+  activatedAt: string;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+/**
+ * Module deactivated event payload
+ */
+export interface ModuleDeactivatedEvent {
+  /** Module ID */
+  moduleId: string;
+  /** Module version */
+  version: string;
+  /** Deactivation timestamp */
+  deactivatedAt: string;
+  /** Reason for deactivation */
+  reason?: string;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+/**
+ * Module installed event payload
+ */
+export interface ModuleInstalledEvent {
+  /** Module ID */
+  moduleId: string;
+  /** Module version */
+  version: string;
+  /** Installation timestamp */
+  installedAt: string;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+/**
+ * Module uninstalled event payload
+ */
+export interface ModuleUninstalledEvent {
+  /** Module ID */
+  moduleId: string;
+  /** Module version */
+  version: string;
+  /** Whether data was deleted */
+  dataDeleted: boolean;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+/**
+ * Module upgraded event payload
+ */
+export interface ModuleUpgradedEvent {
+  /** Module ID */
+  moduleId: string;
+  /** Previous version */
+  fromVersion: string;
+  /** New version */
+  toVersion: string;
+  /** Upgrade timestamp */
+  upgradedAt: string;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+/**
+ * Module error event payload
+ */
+export interface ModuleErrorEvent {
+  /** Module ID */
+  moduleId: string;
+  /** Error message */
+  error: string;
+  /** Error details */
+  details?: Record<string, unknown>;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+// -----------------------------------------------------------------------------
+// Hook Context Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Before module activate hook context
+ */
+export interface BeforeModuleActivateContext {
+  /** Module to be activated */
+  module: LoadedModule;
+  /** Can prevent activation */
+  cancel: () => void;
+  /** Whether activation is cancelled */
+  cancelled: boolean;
+}
+
+/**
+ * After module activate hook context
+ */
+export interface AfterModuleActivateContext {
+  /** Activated module */
+  module: LoadedModule;
+  /** Activation duration in ms */
+  duration: number;
+}
+
+/**
+ * Before module deactivate hook context
+ */
+export interface BeforeModuleDeactivateContext {
+  /** Module to be deactivated */
+  module: LoadedModule;
+  /** Can prevent deactivation */
+  cancel: () => void;
+  /** Whether deactivation is cancelled */
+  cancelled: boolean;
+}
+
+/**
+ * After module deactivate hook context
+ */
+export interface AfterModuleDeactivateContext {
+  /** Deactivated module */
+  module: LoadedModule;
+  /** Deactivation duration in ms */
+  duration: number;
+}
+
+// -----------------------------------------------------------------------------
+// Module Settings Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Module loader settings
+ */
+export interface ModuleLoaderSettings {
+  /** Auto-discover modules on startup */
+  autoDiscovery: boolean;
+  /** Auto-activate core modules */
+  autoActivateCoreModules: boolean;
+  /** Check dependencies before activation */
+  checkDependencies: boolean;
+  /** Enable hot reload (dev only) */
+  enableHotReload: boolean;
+}
+
+// -----------------------------------------------------------------------------
+// Type Guards
+// -----------------------------------------------------------------------------
+
+/**
+ * Type guard to check if a string is a valid ModuleStatus
+ */
+export function isValidModuleStatus(status: string): status is ModuleStatus {
+  return ['discovered', 'validated', 'loaded', 'active', 'disabled', 'error'].includes(status);
+}
+
+/**
+ * Type guard to check if a string is a valid ModuleCategory
+ */
+export function isValidModuleCategory(category: string): category is ModuleCategory {
+  return ['core', 'feature', 'ai', 'integration', 'example', 'stub'].includes(category);
+}
+
+/**
+ * Type guard to check if module is active
+ */
+export function isModuleActive(module: LoadedModule): boolean {
+  return module.status === 'active';
+}
+
+/**
+ * Type guard to check if module is core
+ */
+export function isModuleCore(module: LoadedModule): boolean {
+  return module.manifest.core === true;
+}
+
+/**
+ * Type guard to check if module has error
+ */
+export function hasModuleError(module: LoadedModule): boolean {
+  return module.status === 'error' && !!module.error;
+}
+
+// -----------------------------------------------------------------------------
+// Helper Functions
+// -----------------------------------------------------------------------------
+
+/**
+ * Converts LoadedModule to ModuleInfo for API response
+ */
+export function toModuleInfo(module: LoadedModule, dependents: string[] = []): ModuleInfo {
+  return {
+    id: module.manifest.id,
+    name: module.manifest.name,
+    displayName: module.manifest.displayName,
+    version: module.manifest.version,
+    description: module.manifest.description,
+    author: module.manifest.author,
+    category: module.manifest.category,
+    status: module.status,
+    isCore: module.manifest.core,
+    isEnabled: module.status === 'active',
+    priority: module.manifest.priority,
+    dependencies: module.manifest.dependencies.required,
+    optionalDependencies: module.manifest.dependencies.optional,
+    dependents,
+    permissions: module.manifest.permissions,
+    events: module.manifest.events.emits,
+    adminMenu: module.manifest.admin.menu
+      ? {
+          label: module.manifest.admin.menu.label,
+          icon: module.manifest.admin.menu.icon,
+          position: module.manifest.admin.menu.position,
+        }
+      : undefined,
+    loadedAt: module.loadedAt,
+    error: module.error,
+  };
+}
+
+/**
+ * Converts ModuleInfo to ModuleSummary for list views
+ */
+export function toModuleSummary(module: ModuleInfo): ModuleSummary {
+  return {
+    id: module.id,
+    displayName: module.displayName,
+    category: module.category,
+    status: module.status,
+    isCore: module.isCore,
+    version: module.version,
+    icon: module.adminMenu?.icon,
+  };
+}

diff --git a/src/modules/_core/notification/notification.module.ts b/src/modules/_core/notification/notification.module.ts
