+++ b/src/modules/_core/notification/notification.module.ts
@@ -0,0 +1,403 @@
+/**
+ * Notification Module Definition
+ *
+ * Core notification management module for E-Menum.
+ * Provides in-app notifications and email notification delivery.
+ *
+ * This is a CORE module - it cannot be disabled.
+ *
+ * @module modules/_core/notification/notification.module
+ *
+ * @example
+ * ```typescript
+ * import { NotificationModule } from '@/modules/_core/notification/notification.module';
+ *
+ * // Module is automatically discovered and loaded by ModuleLoader
+ * // Access module instance via DI container
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+import { TOKENS, registerSingleton, appContainer } from '@/core/kernel/container';
+import type { ModuleInstance } from '@/core/kernel/module-loader';
+import type { EventService } from '@/core/services/event.service';
+
+import { NotificationController } from '@/modules/_core/notification/notification.controller';
+import { NotificationService } from '@/modules/_core/notification/notification.service';
+import { NotificationRepository } from '@/modules/_core/notification/notification.repository';
+import { notificationRoutes } from '@/modules/_core/notification/notification.routes';
+import type { NotificationModuleSettings } from '@/modules/_core/notification/notification.types';
+
+// -----------------------------------------------------------------------------
+// Module Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Notification module context for lifecycle hooks
+ */
+export interface NotificationModuleContext {
+  /** Event service for pub/sub */
+  events: EventService;
+  /** Module settings */
+  settings: NotificationModuleSettings;
+  /** Logger function */
+  log: (message: string) => void;
+}
+
+/**
+ * Notification module hook definitions
+ */
+export interface NotificationModuleHooks {
+  /** Called before notification is sent */
+  beforeSend?: (data: { userId: string; title: string; message: string }) => Promise<void>;
+  /** Called after notification is sent */
+  afterSend?: (data: { notificationId: string; emailSent: boolean }) => Promise<void>;
+  /** Called before notification is marked as read */
+  beforeRead?: (data: { notificationId: string }) => Promise<void>;
+  /** Called after notification is marked as read */
+  afterRead?: (data: { notificationId: string; readAt: Date }) => Promise<void>;
+}
+
+// -----------------------------------------------------------------------------
+// Notification Module Class
+// -----------------------------------------------------------------------------
+
+/**
+ * Notification Module
+ *
+ * Core module providing notification management for E-Menum.
+ * Handles in-app notifications and email notification delivery.
+ *
+ * Features:
+ * - In-app notifications
+ * - Email notifications (SMTP, SendGrid, SES)
+ * - Real-time notification delivery
+ * - Mark as read/unread
+ * - Notification counts and statistics
+ * - Broadcast to multiple users
+ *
+ * @example
+ * ```typescript
+ * // Module is automatically loaded by ModuleLoader
+ * // Use NotificationService for business logic
+ * const notificationService = container.resolve('NotificationService');
+ * await notificationService.create(userId, { ... });
+ * ```
+ */
+@injectable()
+export class NotificationModule implements ModuleInstance {
+  // ---------------------------------------------------------------------------
+  // Static Properties
+  // ---------------------------------------------------------------------------
+
+  /** Module ID */
+  static readonly id = 'notification';
+
+  /** Module name */
+  static readonly name = 'Notification Module';
+
+  /** Module version */
+  static readonly version = '1.0.0';
+
+  /** Is core module (cannot be disabled) */
+  static readonly isCore = true;
+
+  /** Module routes configuration */
+  static readonly routes = notificationRoutes;
+
+  /** Providers (services) to register */
+  static readonly providers = [NotificationService, NotificationRepository];
+
+  /** Controllers to register */
+  static readonly controllers = [NotificationController];
+
+  // ---------------------------------------------------------------------------
+  // Instance Properties
+  // ---------------------------------------------------------------------------
+
+  /** Module hooks registry */
+  private hooks: NotificationModuleHooks = {};
+
+  /** Module initialized flag */
+  private initialized = false;
+
+  constructor(
+    @inject(TOKENS.EventService) private readonly eventService: EventService
+  ) {}
+
+  // ---------------------------------------------------------------------------
+  // ModuleInstance Lifecycle Hooks
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Called when module is loaded.
+   * Registers services with DI container.
+   */
+  async onLoad(): Promise<void> {
+    this.log('Loading notification module...');
+
+    // Register NotificationRepository with DI container
+    if (!appContainer.isRegistered('NotificationRepository')) {
+      registerSingleton('NotificationRepository', NotificationRepository);
+    }
+
+    // Register NotificationService with DI container
+    if (!appContainer.isRegistered('NotificationService')) {
+      registerSingleton('NotificationService', NotificationService);
+    }
+
+    this.log('Notification module loaded');
+  }
+
+  /**
+   * Called when module is enabled/activated.
+   * Sets up event listeners and registers routes.
+   */
+  async onEnable(): Promise<void> {
+    if (this.initialized) {
+      this.log('Notification module already initialized');
+      return;
+    }
+
+    this.log('Enabling notification module...');
+
+    // Subscribe to relevant events
+    this.setupEventListeners();
+
+    this.initialized = true;
+    this.log('Notification module enabled');
+
+    // Emit module activated event
+    await this.eventService.emitCustom('module.activated', {
+      moduleId: NotificationModule.id,
+      timestamp: new Date().toISOString(),
+    });
+  }
+
+  /**
+   * Called when module is disabled/deactivated.
+   * Core modules cannot be fully disabled, but this handles graceful pause.
+   */
+  async onDisable(): Promise<void> {
+    this.log('Notification module disable requested (core module - limited action)');
+
+    // Core modules cannot be fully disabled
+    // This would only be called during shutdown
+
+    this.initialized = false;
+    this.log('Notification module disabled');
+  }
+
+  /**
+   * Called when module is unloaded.
+   * Cleans up resources.
+   */
+  async onUnload(): Promise<void> {
+    this.log('Unloading notification module...');
+
+    // Clear hooks
+    this.hooks = {};
+
+    this.log('Notification module unloaded');
+  }
+
+  // ---------------------------------------------------------------------------
+  // ModuleInstance Interface Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Returns module routes for registration with Express.
+   *
+   * @returns Route configuration array
+   */
+  getRoutes(): unknown[] {
+    return [notificationRoutes];
+  }
+
+  /**
+   * Returns module controllers for registration with routing-controllers.
+   *
+   * @returns Controller class array
+   */
+  getControllers(): unknown[] {
+    return NotificationModule.controllers;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Hook System
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets current module hooks.
+   *
+   * @returns Module hooks object
+   */
+  getHooks(): NotificationModuleHooks {
+    return { ...this.hooks };
+  }
+
+  /**
+   * Registers a hook handler.
+   *
+   * @param hookName - Name of the hook
+   * @param handler - Hook handler function
+   *
+   * @example
+   * ```typescript
+   * notificationModule.registerHook('afterSend', async (data) => {
+   *   console.log('Notification sent:', data.notificationId);
+   * });
+   * ```
+   */
+  registerHook<K extends keyof NotificationModuleHooks>(
+    hookName: K,
+    handler: NotificationModuleHooks[K]
+  ): void {
+    this.hooks[hookName] = handler;
+    this.log(`Registered hook: ${hookName}`);
+  }
+
+  /**
+   * Unregisters a hook handler.
+   *
+   * @param hookName - Name of the hook to unregister
+   */
+  unregisterHook(hookName: keyof NotificationModuleHooks): void {
+    delete this.hooks[hookName];
+    this.log(`Unregistered hook: ${hookName}`);
+  }
+
+  /**
+   * Executes a hook if registered.
+   *
+   * @param hookName - Name of the hook
+   * @param data - Data to pass to the hook
+   */
+  async executeHook<K extends keyof NotificationModuleHooks>(
+    hookName: K,
+    data: Parameters<NonNullable<NotificationModuleHooks[K]>>[0]
+  ): Promise<void> {
+    const hook = this.hooks[hookName];
+    if (hook) {
+      try {
+        await (hook as (data: typeof data) => Promise<void>)(data);
+      } catch (error) {
+        this.log(
+          `Hook execution error (${hookName}): ${error instanceof Error ? error.message : 'Unknown error'}`
+        );
+      }
+    }
+  }
+
+  // ---------------------------------------------------------------------------
+  // Event Listeners
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Sets up event listeners for the notification module.
+   */
+  private setupEventListeners(): void {
+    // Listen for order events to send notifications
+    this.eventService.on('order.created', async (payload) => {
+      this.log(`Order created event received: ${payload.orderId}`);
+      // Could trigger order notification
+    });
+
+    this.eventService.on('order.status.changed', async (payload) => {
+      this.log(`Order status changed: ${payload.orderId} -> ${payload.status}`);
+      // Could trigger status update notification
+    });
+
+    // Listen for subscription events
+    this.eventService.on('subscription.plan.changed', async (payload) => {
+      this.log(`Plan changed event received: ${payload.organizationId}`);
+      // Could trigger billing notification
+    });
+
+    // Listen for user events
+    this.eventService.on('user.created', async (payload) => {
+      this.log(`User created event received: ${payload.userId}`);
+      // Could trigger welcome notification
+    });
+
+    this.log('Event listeners set up');
+  }
+
+  // ---------------------------------------------------------------------------
+  // Module Settings
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets default module settings.
+   *
+   * @returns Default notification module settings
+   */
+  static getDefaultSettings(): NotificationModuleSettings {
+    return {
+      emailProvider: 'smtp',
+      emailEnabled: true,
+      inAppEnabled: true,
+      smsEnabled: false,
+      pushEnabled: false,
+      batchDelay: 5000,
+      maxRetries: 3,
+      retryDelay: 60000,
+      digestEnabled: false,
+      digestInterval: 'daily',
+    };
+  }
+
+  // ---------------------------------------------------------------------------
+  // Utility Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Logs a message with module prefix.
+   *
+   * @param message - Message to log
+   */
+  private log(message: string): void {
+    // eslint-disable-next-line no-console
+    console.log(`[NotificationModule] ${message}`);
+  }
+
+  /**
+   * Checks if module is initialized.
+   *
+   * @returns True if module is initialized
+   */
+  isInitialized(): boolean {
+    return this.initialized;
+  }
+
+  /**
+   * Gets module metadata.
+   *
+   * @returns Module metadata object
+   */
+  static getMetadata() {
+    return {
+      id: NotificationModule.id,
+      name: NotificationModule.name,
+      version: NotificationModule.version,
+      isCore: NotificationModule.isCore,
+      routes: NotificationModule.routes,
+      providers: NotificationModule.providers.map((p) => p.name),
+      controllers: NotificationModule.controllers.map((c) => c.name),
+    };
+  }
+}
+
+// -----------------------------------------------------------------------------
+// Module Exports
+// -----------------------------------------------------------------------------
+
+/**
+ * Default export for module loader dynamic import
+ */
+export default NotificationModule;
+
+/**
+ * Export module metadata
+ */
+export const metadata = NotificationModule.getMetadata();

