+/**
+ * Notification Module Types
+ *
+ * Type definitions for the Notification module including:
+ * - Notification entity types
+ * - Create/Update DTOs
+ * - Event payloads
+ * - Query filters
+ *
+ * @module modules/_core/notification/types
+ *
+ * @example
+ * ```typescript
+ * import type {
+ *   Notification,
+ *   CreateNotificationRequest,
+ *   NotificationListParams,
+ * } from '@/modules/_core/notification/notification.types';
+ *
+ * async function createNotification(data: CreateNotificationRequest): Promise<Notification> { ... }
+ * ```
+ */
+
+import type { NotificationType, NotificationStatus } from '@prisma/client';
+
+// -----------------------------------------------------------------------------
+// Core Entity Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Notification entity from Prisma
+ */
+export interface Notification {
+  /** Unique identifier (CUID) */
+  id: string;
+  /** User ID who receives the notification */
+  userId: string;
+  /** Organization ID (optional for system notifications) */
+  organizationId: string | null;
+  /** Notification type (SYSTEM, ORDER, BILLING, PROMO) */
+  type: NotificationType;
+  /** Notification status (UNREAD, READ) */
+  status: NotificationStatus;
+  /** Notification title */
+  title: string;
+  /** Notification message body */
+  message: string;
+  /** Optional link to navigate to */
+  link: string | null;
+  /** Additional metadata (JSON) */
+  metadata: NotificationMetadata;
+  /** Timestamp when notification was read */
+  readAt: Date | null;
+  /** Creation timestamp */
+  createdAt: Date;
+  /** Last update timestamp */
+  updatedAt: Date;
+}
+
+/**
+ * Notification with related user data
+ */
+export interface NotificationWithRelations extends Notification {
+  /** Associated user */
+  user?: {
+    id: string;
+    firstName: string;
+    lastName: string;
+    email: string;
+    avatar: string | null;
+  };
+  /** Associated organization */
+  organization?: {
+    id: string;
+    name: string;
+    slug: string;
+  } | null;
+}
+
+// -----------------------------------------------------------------------------
+// Metadata Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Notification metadata structure
+ */
+export interface NotificationMetadata {
+  /** Related resource type (e.g., 'order', 'menu', 'subscription') */
+  resourceType?: string;
+  /** Related resource ID */
+  resourceId?: string;
+  /** Action type (e.g., 'created', 'updated', 'cancelled') */
+  action?: string;
+  /** Priority level */
+  priority?: 'low' | 'normal' | 'high' | 'urgent';
+  /** Expiration date */
+  expiresAt?: string;
+  /** Email delivery status */
+  emailSent?: boolean;
+  /** Email sent at timestamp */
+  emailSentAt?: string;
+  /** Push notification status */
+  pushSent?: boolean;
+  /** SMS notification status */
+  smsSent?: boolean;
+  /** Custom data */
+  data?: Record<string, unknown>;
+}
+
+// -----------------------------------------------------------------------------
+// Request/Response Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Create notification request
+ */
+export interface CreateNotificationRequest {
+  /** User ID to notify */
+  userId: string;
+  /** Organization ID (optional) */
+  organizationId?: string | null;
+  /** Notification type */
+  type: NotificationType;
+  /** Notification title */
+  title: string;
+  /** Notification message */
+  message: string;
+  /** Optional link */
+  link?: string | null;
+  /** Additional metadata */
+  metadata?: NotificationMetadata;
+  /** Send email notification */
+  sendEmail?: boolean;
+  /** Send push notification */
+  sendPush?: boolean;
+}
+
+/**
+ * Create notification response
+ */
+export interface CreateNotificationResponse {
+  /** Created notification */
+  notification: Notification;
+  /** Success message */
+  message: string;
+}
+
+/**
+ * Broadcast notification request (to multiple users)
+ */
+export interface BroadcastNotificationRequest {
+  /** Array of user IDs to notify */
+  userIds: string[];
+  /** Organization ID (optional) */
+  organizationId?: string | null;
+  /** Notification type */
+  type: NotificationType;
+  /** Notification title */
+  title: string;
+  /** Notification message */
+  message: string;
+  /** Optional link */
+  link?: string | null;
+  /** Additional metadata */
+  metadata?: NotificationMetadata;
+  /** Send email notifications */
+  sendEmail?: boolean;
+}
+
+/**
+ * Broadcast notification response
+ */
+export interface BroadcastNotificationResponse {
+  /** Number of notifications created */
+  count: number;
+  /** Success message */
+  message: string;
+}
+
+/**
+ * Mark notification(s) as read request
+ */
+export interface MarkAsReadRequest {
+  /** Single notification ID or array of IDs */
+  notificationIds: string | string[];
+}
+
+/**
+ * Mark as read response
+ */
+export interface MarkAsReadResponse {
+  /** Number of notifications marked as read */
+  count: number;
+  /** Success message */
+  message: string;
+}
+
+/**
+ * Notification summary for listings
+ */
+export interface NotificationSummary {
+  /** Notification ID */
+  id: string;
+  /** Notification type */
+  type: NotificationType;
+  /** Notification status */
+  status: NotificationStatus;
+  /** Title */
+  title: string;
+  /** Message preview (truncated) */
+  messagePreview: string;
+  /** Link */
+  link: string | null;
+  /** Creation date */
+  createdAt: Date;
+}
+
+/**
+ * Notification count by status
+ */
+export interface NotificationCounts {
+  /** Total notifications */
+  total: number;
+  /** Unread notifications */
+  unread: number;
+  /** Read notifications */
+  read: number;
+  /** Counts by type */
+  byType: {
+    system: number;
+    order: number;
+    billing: number;
+    promo: number;
+  };
+}
+
+// -----------------------------------------------------------------------------
+// Query/Filter Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Notification list query filters
+ */
+export interface NotificationListFilters {
+  /** Filter by notification type */
+  type?: NotificationType;
+  /** Filter by status */
+  status?: NotificationStatus;
+  /** Filter by organization */
+  organizationId?: string;
+  /** Search in title or message */
+  search?: string;
+  /** Filter by creation date range */
+  createdAfter?: Date;
+  createdBefore?: Date;
+}
+
+/**
+ * Notification list query params
+ */
+export interface NotificationListParams extends NotificationListFilters {
+  /** Page number (1-indexed) */
+  page?: number;
+  /** Items per page */
+  perPage?: number;
+  /** Sort field */
+  sortBy?: 'createdAt' | 'type' | 'status';
+  /** Sort direction */
+  sortOrder?: 'asc' | 'desc';
+}
+
+// -----------------------------------------------------------------------------
+// Event Payload Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Notification created event payload
+ */
+export interface NotificationCreatedEvent {
+  /** Notification ID */
+  notificationId: string;
+  /** User ID */
+  userId: string;
+  /** Organization ID */
+  organizationId: string | null;
+  /** Notification type */
+  type: NotificationType;
+  /** Title */
+  title: string;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+/**
+ * Notification read event payload
+ */
+export interface NotificationReadEvent {
+  /** Notification ID */
+  notificationId: string;
+  /** User ID */
+  userId: string;
+  /** Read timestamp */
+  readAt: string;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+/**
+ * Notification deleted event payload
+ */
+export interface NotificationDeletedEvent {
+  /** Notification ID */
+  notificationId: string;
+  /** User ID */
+  userId: string;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+/**
+ * Notification broadcast event payload
+ */
+export interface NotificationBroadcastEvent {
+  /** Number of notifications sent */
+  count: number;
+  /** User IDs notified */
+  userIds: string[];
+  /** Organization ID */
+  organizationId: string | null;
+  /** Notification type */
+  type: NotificationType;
+  /** Title */
+  title: string;
+  /** Event timestamp */
+  timestamp: string;
+}
+
+// -----------------------------------------------------------------------------
+// Hook Context Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Before send hook context
+ */
+export interface BeforeSendContext {
+  /** Notification data to be created */
+  data: CreateNotificationRequest;
+  /** User ID */
+  userId: string;
+}
+
+/**
+ * After send hook context
+ */
+export interface AfterSendContext {
+  /** Created notification */
+  notification: Notification;
+  /** Whether email was sent */
+  emailSent: boolean;
+  /** Whether push was sent */
+  pushSent: boolean;
+}
+
+/**
+ * Before read hook context
+ */
+export interface BeforeReadContext {
+  /** Notification to be marked as read */
+  notification: Notification;
+  /** User ID */
+  userId: string;
+}
+
+/**
+ * After read hook context
+ */
+export interface AfterReadContext {
+  /** Notification that was marked as read */
+  notification: Notification;
+  /** Read timestamp */
+  readAt: Date;
+}
+
+// -----------------------------------------------------------------------------
+// Module Settings Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Notification module settings
+ */
+export interface NotificationModuleSettings {
+  /** Email provider (smtp, sendgrid, ses) */
+  emailProvider: 'smtp' | 'sendgrid' | 'ses';
+  /** Enable email notifications */
+  emailEnabled: boolean;
+  /** Enable in-app notifications */
+  inAppEnabled: boolean;
+  /** Enable SMS notifications */
+  smsEnabled: boolean;
+  /** Enable push notifications */
+  pushEnabled: boolean;
+  /** Batch processing delay in ms */
+  batchDelay: number;
+  /** Maximum retry attempts */
+  maxRetries: number;
+  /** Retry delay in ms */
+  retryDelay: number;
+  /** Enable digest mode */
+  digestEnabled: boolean;
+  /** Digest interval (hourly, daily, weekly) */
+  digestInterval: 'hourly' | 'daily' | 'weekly';
+}
+
+// -----------------------------------------------------------------------------
+// Email Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Email notification options
+ */
+export interface EmailNotificationOptions {
+  /** Recipient email address */
+  to: string;
+  /** Email subject */
+  subject: string;
+  /** Plain text body */
+  text?: string;
+  /** HTML body */
+  html?: string;
+  /** Email template name */
+  template?: string;
+  /** Template data */
+  templateData?: Record<string, unknown>;
+}
+
+/**
+ * Email send result
+ */
+export interface EmailSendResult {
+  /** Whether send was successful */
+  success: boolean;
+  /** Message ID from provider */
+  messageId?: string;
+  /** Error message if failed */
+  error?: string;
+}
+
+// -----------------------------------------------------------------------------
+// Type Guards
+// -----------------------------------------------------------------------------
+
+/**
+ * Type guard to check if an object is a valid Notification
+ */
+export function isNotification(obj: unknown): obj is Notification {
+  return (
+    typeof obj === 'object' &&
+    obj !== null &&
+    'id' in obj &&
+    'userId' in obj &&
+    'title' in obj &&
+    'message' in obj &&
+    'type' in obj &&
+    'status' in obj
+  );
+}
+
+/**
+ * Type guard to check if a notification is unread
+ */
+export function isUnread(notification: Notification): boolean {
+  return notification.status === 'UNREAD' && notification.readAt === null;
+}
+
+/**
+ * Type guard to check if a notification type is valid
+ */
+export function isValidNotificationType(type: string): type is NotificationType {
+  return ['SYSTEM', 'ORDER', 'BILLING', 'PROMO'].includes(type);
+}
+
+/**
+ * Type guard to check if a notification status is valid
+ */
+export function isValidNotificationStatus(status: string): status is NotificationStatus {
+  return ['UNREAD', 'READ'].includes(status);
+}
+
+// -----------------------------------------------------------------------------
+// Re-export Prisma Types
+// -----------------------------------------------------------------------------
+
+export type { NotificationType, NotificationStatus } from '@prisma/client';

