+  }
+
+  /**
+   * Updates an organization
+   *
+   * @param id - Organization ID
+   * @param data - Update data
+   * @returns Updated organization
+   * @throws {AppException} If not found
+   */
+  async update(id: string, data: UpdateOrganizationData): Promise<Organization> {
+    // Verify exists
+    await this.findByIdOrThrow(id);
+
+    const result = await this.prisma.organization.update({
+      where: { id },
+      data: {
+        ...(data.name !== undefined && { name: data.name }),
+        ...(data.slug !== undefined && { slug: data.slug }),
+        ...(data.email !== undefined && { email: data.email.toLowerCase() }),
+        ...(data.phone !== undefined && { phone: data.phone }),
+        ...(data.logo !== undefined && { logo: data.logo }),
+        ...(data.settings !== undefined && { settings: data.settings }),
+        ...(data.status !== undefined && { status: data.status }),
+        ...(data.planId !== undefined && { planId: data.planId }),
+        ...(data.trialEndsAt !== undefined && { trialEndsAt: data.trialEndsAt }),
+      },
+    });
+
+    return result as Organization;
+  }
+
+  /**
+   * Updates organization settings (merge)
+   *
+   * @param id - Organization ID
+   * @param settings - Settings to merge
+   * @returns Updated organization
+   */
+  async updateSettings(id: string, settings: Prisma.JsonValue): Promise<Organization> {
+    const organization = await this.findByIdOrThrow(id);
+
+    // Merge settings
+    const currentSettings = (organization.settings as Record<string, unknown>) || {};
+    const newSettings = settings as Record<string, unknown>;
+    const mergedSettings = this.deepMerge(currentSettings, newSettings);
+
+    const result = await this.prisma.organization.update({
+      where: { id },
+      data: { settings: mergedSettings },
+    });
+
+    return result as Organization;
+  }
+
+  /**
+   * Updates organization status
+   *
+   * @param id - Organization ID
+   * @param status - New status
+   * @returns Updated organization
+   */
+  async updateStatus(id: string, status: OrganizationStatus): Promise<Organization> {
+    await this.findByIdOrThrow(id);
+
+    const result = await this.prisma.organization.update({
+      where: { id },
+      data: { status },
+    });
+
+    return result as Organization;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Delete Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Soft deletes an organization
+   *
+   * @param id - Organization ID
+   * @returns Deleted organization
+   * @throws {AppException} If not found
+   */
+  async softDelete(id: string): Promise<Organization> {
+    await this.findByIdOrThrow(id);
+
+    const result = await this.prisma.organization.update({
+      where: { id },
+      data: softDelete(),
+    });
+
+    return result as Organization;
+  }
+
+  /**
+   * Restores a soft-deleted organization
+   *
+   * @param id - Organization ID
+   * @returns Restored organization
+   */
+  async restore(id: string): Promise<Organization> {
+    // Find including deleted
+    const organization = await this.prisma.organization.findFirst({
+      where: { id },
+    });
+
+    if (!organization) {
+      throw AppException.notFound('Organization', id);
+    }
+
+    const result = await this.prisma.organization.update({
+      where: { id },
+      data: { deletedAt: null },
+    });
+
+    return result as Organization;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Helper Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Deep merges two objects
+   */
+  private deepMerge(target: Record<string, unknown>, source: Record<string, unknown>): Record<string, unknown> {
+    const result = { ...target };
+
+    for (const [key, value] of Object.entries(source)) {
+      if (value !== undefined && value !== null) {
+        if (typeof value === 'object' && !Array.isArray(value)) {
+          result[key] = this.deepMerge(
+            (result[key] as Record<string, unknown>) || {},
+            value as Record<string, unknown>
+          );
+        } else {
+          result[key] = value;
+        }
+      }
+    }
+
+    return result;
+  }
+}

