+  return (
+    typeof value === 'string' &&
+    ['free', 'starter', 'professional', 'business', 'enterprise'].includes(value)
+  );
+}
+
+/**
+ * Helper to get tier order (for comparison)
+ */
+export function getTierOrder(tier: PlanTier): number {
+  const order: Record<PlanTier, number> = {
+    free: 0,
+    starter: 1,
+    professional: 2,
+    business: 3,
+    enterprise: 4,
+  };
+  return order[tier] ?? 0;
+}
+
+/**
+ * Helper to check if one tier is higher than another
+ */
+export function isTierHigher(tier1: PlanTier, tier2: PlanTier): boolean {
+  return getTierOrder(tier1) > getTierOrder(tier2);
+}

