index 0000000..5d81d47
--- /dev/null
+++ b/src/modules/_core/user/user.module.ts
@@ -0,0 +1,402 @@
+/**
+ * User Module Definition
+ *
+ * Core user management module for E-Menum.
+ * Provides user CRUD, role assignment, and profile management.
+ *
+ * This is a CORE module - it cannot be disabled.
+ *
+ * @module modules/_core/user/user.module
+ *
+ * @example
+ * ```typescript
+ * import { UserModule } from '@/modules/_core/user/user.module';
+ *
+ * // Module is automatically discovered and loaded by ModuleLoader
+ * // Access module instance via DI container
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+import { TOKENS, registerSingleton, appContainer } from '@/core/kernel/container';
+import type { ModuleInstance } from '@/core/kernel/module-loader';
+import type { EventService } from '@/core/services/event.service';
+
+import { UserController } from '@/modules/_core/user/user.controller';
+import { UserService } from '@/modules/_core/user/user.service';
+import { UserRepository } from '@/modules/_core/user/user.repository';
+import { userRoutes } from '@/modules/_core/user/user.routes';
+import type { UserModuleSettings } from '@/modules/_core/user/user.types';
+
+// -----------------------------------------------------------------------------
+// Module Types
+// -----------------------------------------------------------------------------
+
+/**
+ * User module context for lifecycle hooks
+ */
+export interface UserModuleContext {
+  /** Event service for pub/sub */
+  events: EventService;
+  /** Module settings */
+  settings: UserModuleSettings;
+  /** Logger function */
+  log: (message: string) => void;
+}
+
+/**
+ * User module hook definitions
+ */
+export interface UserModuleHooks {
+  /** Called before user creation */
+  beforeCreate?: (data: { email: string; organizationId: string }) => Promise<void>;
+  /** Called after user creation */
+  afterCreate?: (data: { userId: string }) => Promise<void>;
+  /** Called before user update */
+  beforeUpdate?: (data: { userId: string }) => Promise<void>;
+  /** Called after user update */
+  afterUpdate?: (data: { userId: string }) => Promise<void>;
+  /** Called before user deletion */
+  beforeDelete?: (data: { userId: string }) => Promise<void>;
+  /** Called after user deletion */
+  afterDelete?: (data: { userId: string }) => Promise<void>;
+  /** Called before role assignment */
+  beforeRoleAssign?: (data: { userId: string; roleId: string }) => Promise<void>;
+  /** Called after role assignment */
+  afterRoleAssign?: (data: { userId: string; roleId: string }) => Promise<void>;
+}
+
+// -----------------------------------------------------------------------------
+// User Module Class
+// -----------------------------------------------------------------------------
+
+/**
+ * User Module
+ *
+ * Core module providing user management for E-Menum.
+ * Handles user CRUD, role assignment, and profile management.
+ *
+ * Features:
+ * - User CRUD operations (tenant-scoped)
+ * - Profile management (self-update)
+ * - Role assignment and removal
+ * - Status management (active, invited, suspended)
+ * - Password management
+ * - User invitations
+ * - Soft delete with restore capability
+ *
+ * @example
+ * ```typescript
+ * // Module is automatically loaded by ModuleLoader
+ * // Use UserService for business logic
+ * const userService = container.resolve('UserService');
+ * await userService.create('org_123', {
+ *   email: 'user@example.com',
+ *   password: 'SecurePass123',
+ *   firstName: 'John',
+ *   lastName: 'Doe',
+ * });
+ * ```
+ */
+@injectable()
+export class UserModule implements ModuleInstance {
+  // ---------------------------------------------------------------------------
+  // Static Properties
+  // ---------------------------------------------------------------------------
+
+  /** Module ID */
+  static readonly id = 'user';
+
+  /** Module name */
+  static readonly name = 'User Module';
+
+  /** Module version */
+  static readonly version = '1.0.0';
+
+  /** Is core module (cannot be disabled) */
+  static readonly isCore = true;
+
+  /** Module routes configuration */
+  static readonly routes = userRoutes;
+
+  /** Providers (services) to register */
+  static readonly providers = [UserService, UserRepository];
+
+  /** Controllers to register */
+  static readonly controllers = [UserController];
+
+  // ---------------------------------------------------------------------------
+  // Instance Properties
+  // ---------------------------------------------------------------------------
+
+  /** Module hooks registry */
+  private hooks: UserModuleHooks = {};
+
+  /** Module initialized flag */
+  private initialized = false;
+
+  constructor(
+    @inject(TOKENS.EventService) private readonly eventService: EventService
+  ) {}
+
+  // ---------------------------------------------------------------------------
+  // ModuleInstance Lifecycle Hooks
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Called when module is loaded.
+   * Registers services with DI container.
+   */
+  async onLoad(): Promise<void> {
+    this.log('Loading user module...');
+
+    // Register UserRepository with DI container
+    if (!appContainer.isRegistered('UserRepository')) {
+      registerSingleton('UserRepository', UserRepository);
+    }
+
+    // Register UserService with DI container
+    if (!appContainer.isRegistered('UserService')) {
+      registerSingleton('UserService', UserService);
+    }
+
+    this.log('User module loaded');
+  }
+
+  /**
+   * Called when module is enabled/activated.
+   * Sets up event listeners and registers routes.
+   */
+  async onEnable(): Promise<void> {
+    if (this.initialized) {
+      this.log('User module already initialized');
+      return;
+    }
+
+    this.log('Enabling user module...');
+
+    // Subscribe to relevant events
+    this.setupEventListeners();
+
+    this.initialized = true;
+    this.log('User module enabled');
+
+    // Emit module activated event
+    await this.eventService.emitCustom('module.activated', {
+      moduleId: UserModule.id,
+      timestamp: new Date().toISOString(),
+    });
+  }
+
+  /**
+   * Called when module is disabled/deactivated.
+   * Core modules cannot be fully disabled, but this handles graceful pause.
+   */
+  async onDisable(): Promise<void> {
+    this.log('User module disable requested (core module - limited action)');
+
+    // Core modules cannot be fully disabled
+    // This would only be called during shutdown
+
+    this.initialized = false;
+    this.log('User module disabled');
+  }
+
+  /**
+   * Called when module is unloaded.
+   * Cleans up resources.
+   */
+  async onUnload(): Promise<void> {
+    this.log('Unloading user module...');
+
+    // Clear hooks
+    this.hooks = {};
+
+    this.log('User module unloaded');
+  }
+
+  // ---------------------------------------------------------------------------
+  // ModuleInstance Interface Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Returns module routes for registration with Express.
+   *
+   * @returns Route configuration array
+   */
+  getRoutes(): unknown[] {
+    return [userRoutes];
+  }
+
+  /**
+   * Returns module controllers for registration with routing-controllers.
+   *
+   * @returns Controller class array
+   */
+  getControllers(): unknown[] {
+    return UserModule.controllers;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Hook System
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets current module hooks.
+   *
+   * @returns Module hooks object
+   */
+  getHooks(): UserModuleHooks {
+    return { ...this.hooks };
+  }
+
+  /**
+   * Registers a hook handler.
+   *
+   * @param hookName - Name of the hook
+   * @param handler - Hook handler function
+   *
+   * @example
+   * ```typescript
+   * userModule.registerHook('afterCreate', async (data) => {
+   *   console.log('User created:', data.userId);
+   * });
+   * ```
+   */
+  registerHook<K extends keyof UserModuleHooks>(
+    hookName: K,
+    handler: UserModuleHooks[K]
+  ): void {
+    this.hooks[hookName] = handler;
+    this.log(`Registered hook: ${hookName}`);
+  }
+
+  /**
+   * Unregisters a hook handler.
+   *
+   * @param hookName - Name of the hook to unregister
+   */
+  unregisterHook(hookName: keyof UserModuleHooks): void {
+    delete this.hooks[hookName];
+    this.log(`Unregistered hook: ${hookName}`);
+  }
+
+  /**
+   * Executes a hook if registered.
+   *
+   * @param hookName - Name of the hook
+   * @param data - Data to pass to the hook
+   */
+  async executeHook<K extends keyof UserModuleHooks>(
+    hookName: K,
+    data: Parameters<NonNullable<UserModuleHooks[K]>>[0]
+  ): Promise<void> {
+    const hook = this.hooks[hookName];
+    if (hook) {
+      try {
+        await (hook as (data: typeof data) => Promise<void>)(data);
+      } catch (error) {
+        this.log(`Hook execution error (${hookName}): ${error instanceof Error ? error.message : 'Unknown error'}`);
+      }
+    }
+  }
+
+  // ---------------------------------------------------------------------------
+  // Event Listeners
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Sets up event listeners for the user module.
+   */
+  private setupEventListeners(): void {
+    // Listen for organization created - might need to create initial admin user
+    this.eventService.on('organization.created', async (payload) => {
+      this.log(`Organization created event received: ${payload.organizationId}`);
+      // Could auto-create organization owner user
+    });
+
+    // Listen for subscription changes that might affect user limits
+    this.eventService.on('subscription.plan.changed', async (payload) => {
+      this.log(`Plan changed event received: ${payload.organizationId}`);
+      // Could check user count against new plan limits
+    });
+
+    this.log('Event listeners set up');
+  }
+
+  // ---------------------------------------------------------------------------
+  // Module Settings
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets default module settings.
+   *
+   * @returns Default user module settings
+   */
+  static getDefaultSettings(): UserModuleSettings {
+    return {
+      defaultRole: 'staff',
+      requireEmailVerification: true,
+      allowSelfRegistration: false,
+      maxUsersPerOrg: 50,
+      passwordMinLength: 8,
+      passwordRequireUppercase: true,
+      passwordRequireNumbers: true,
+      sessionMaxAge: 604800000, // 7 days
+    };
+  }
+
+  // ---------------------------------------------------------------------------
+  // Utility Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Logs a message with module prefix.
+   *
+   * @param message - Message to log
+   */
+  private log(message: string): void {
+    // eslint-disable-next-line no-console
+    console.log(`[UserModule] ${message}`);
+  }
+
+  /**
+   * Checks if module is initialized.
+   *
+   * @returns True if module is initialized
+   */
+  isInitialized(): boolean {
+    return this.initialized;
+  }
+
+  /**
+   * Gets module metadata.
+   *
+   * @returns Module metadata object
+   */
+  static getMetadata() {
+    return {
+      id: UserModule.id,
+      name: UserModule.name,
+      version: UserModule.version,
+      isCore: UserModule.isCore,
+      routes: UserModule.routes,
+      providers: UserModule.providers.map((p) => p.name),
+      controllers: UserModule.controllers.map((c) => c.name),
+    };
+  }
+}
+
+// -----------------------------------------------------------------------------
+// Module Exports
+// -----------------------------------------------------------------------------
+
+/**
+ * Default export for module loader dynamic import
+ */
+export default UserModule;
+
+/**
+ * Export module metadata
+ */
+export const metadata = UserModule.getMetadata();

diff --git a/src/modules/_core/user/user.repository.ts b/src/modules/_core/user/user.repository.ts
