+/**
+ * Analytics Module Types
+ *
+ * Type definitions for future analytics module implementation.
+ * This file defines interfaces for analytics, reporting,
+ * and business intelligence features.
+ *
+ * @module modules/_stubs/analytics/types
+ *
+ * @example
+ * ```typescript
+ * import type {
+ *   IAnalyticsService,
+ *   SalesReport,
+ *   MenuPerformance,
+ * } from '@/modules/_stubs/analytics';
+ * ```
+ */
+
+// -----------------------------------------------------------------------------
+// Enums
+// -----------------------------------------------------------------------------
+
+/**
+ * Report type
+ */
+export enum ReportType {
+  /** Daily sales report */
+  DAILY_SALES = 'DAILY_SALES',
+  /** Weekly sales report */
+  WEEKLY_SALES = 'WEEKLY_SALES',
+  /** Monthly sales report */
+  MONTHLY_SALES = 'MONTHLY_SALES',
+  /** Menu performance report */
+  MENU_PERFORMANCE = 'MENU_PERFORMANCE',
+  /** Customer insights report */
+  CUSTOMER_INSIGHTS = 'CUSTOMER_INSIGHTS',
+  /** Peak hours report */
+  PEAK_HOURS = 'PEAK_HOURS',
+  /** Custom report */
+  CUSTOM = 'CUSTOM',
+}
+
+/**
+ * Time period for analytics
+ */
+export enum TimePeriod {
+  TODAY = 'TODAY',
+  YESTERDAY = 'YESTERDAY',
+  LAST_7_DAYS = 'LAST_7_DAYS',
+  LAST_30_DAYS = 'LAST_30_DAYS',
+  THIS_MONTH = 'THIS_MONTH',
+  LAST_MONTH = 'LAST_MONTH',
+  THIS_QUARTER = 'THIS_QUARTER',
+  THIS_YEAR = 'THIS_YEAR',
+  CUSTOM = 'CUSTOM',
+}
+
+/**
+ * Metric type
+ */
+export enum MetricType {
+  /** Total sales */
+  TOTAL_SALES = 'TOTAL_SALES',
+  /** Order count */
+  ORDER_COUNT = 'ORDER_COUNT',
+  /** Average order value */
+  AVERAGE_ORDER_VALUE = 'AVERAGE_ORDER_VALUE',
+  /** Customer count */
+  CUSTOMER_COUNT = 'CUSTOMER_COUNT',
+  /** Items sold */
+  ITEMS_SOLD = 'ITEMS_SOLD',
+  /** Revenue */
+  REVENUE = 'REVENUE',
+}
+
+// -----------------------------------------------------------------------------
+// Data Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Date range for queries
+ */
+export interface DateRange {
+  /** Start date */
+  startDate: Date;
+  /** End date */
+  endDate: Date;
+}
+
+/**
+ * Sales summary
+ */
+export interface SalesSummary {
+  /** Total sales amount */
+  totalSales: number;
+  /** Order count */
+  orderCount: number;
+  /** Average order value */
+  averageOrderValue: number;
+  /** Growth percentage vs previous period */
+  growthPercentage: number;
+  /** Period start */
+  periodStart: Date;
+  /** Period end */
+  periodEnd: Date;
+}
+
+/**
+ * Menu item performance
+ */
+export interface MenuItemPerformance {
+  /** Item ID */
+  itemId: string;
+  /** Item name */
+  itemName: string;
+  /** Category name */
+  categoryName: string;
+  /** Quantity sold */
+  quantitySold: number;
+  /** Total revenue */
+  totalRevenue: number;
+  /** Percentage of total sales */
+  salesPercentage: number;
+  /** Rank */
+  rank: number;
+}
+
+/**
+ * Peak hour data
+ */
+export interface PeakHourData {
+  /** Hour (0-23) */
+  hour: number;
+  /** Day of week (0-6, 0 = Sunday) */
+  dayOfWeek: number;
+  /** Average orders */
+  averageOrders: number;
+  /** Average revenue */
+  averageRevenue: number;
+  /** Is peak */
+  isPeak: boolean;
+}
+
+/**
+ * Customer segment
+ */
+export interface CustomerSegment {
+  /** Segment ID */
+  id: string;
+  /** Segment name */
+  name: string;
+  /** Customer count */
+  customerCount: number;
+  /** Average spending */
+  averageSpending: number;
+  /** Visit frequency */
+  visitFrequency: number;
+  /** Last activity */
+  lastActivity: Date;
+}
+
+/**
+ * Time series data point
+ */
+export interface TimeSeriesDataPoint {
+  /** Date */
+  date: Date;
+  /** Value */
+  value: number;
+  /** Label */
+  label?: string;
+}
+
+// -----------------------------------------------------------------------------
+// Report Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Sales report
+ */
+export interface SalesReport {
+  /** Report ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Report type */
+  type: ReportType;
+  /** Date range */
+  dateRange: DateRange;
+  /** Summary */
+  summary: SalesSummary;
+  /** Daily breakdown */
+  dailyData: TimeSeriesDataPoint[];
+  /** Generated at */
+  generatedAt: Date;
+}
+
+/**
+ * Menu performance report
+ */
+export interface MenuPerformanceReport {
+  /** Report ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Date range */
+  dateRange: DateRange;
+  /** Top performing items */
+  topItems: MenuItemPerformance[];
+  /** Low performing items */
+  lowItems: MenuItemPerformance[];
+  /** Category breakdown */
+  categoryBreakdown: Array<{
+    categoryId: string;
+    categoryName: string;
+    totalSales: number;
+    itemCount: number;
+    percentage: number;
+  }>;
+  /** Generated at */
+  generatedAt: Date;
+}
+
+/**
+ * Customer insights report
+ */
+export interface CustomerInsightsReport {
+  /** Report ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Date range */
+  dateRange: DateRange;
+  /** Total customers */
+  totalCustomers: number;
+  /** New customers */
+  newCustomers: number;
+  /** Returning customers */
+  returningCustomers: number;
+  /** Customer segments */
+  segments: CustomerSegment[];
+  /** Generated at */
+  generatedAt: Date;
+}
+
+// -----------------------------------------------------------------------------
+// Request Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Get analytics request
+ */
+export interface GetAnalyticsRequest {
+  /** Time period */
+  period: TimePeriod;
+  /** Custom date range (if period is CUSTOM) */
+  dateRange?: DateRange;
+  /** Metrics to retrieve */
+  metrics?: MetricType[];
+  /** Branch filter */
+  branchId?: string;
+}
+
+/**
+ * Generate report request
+ */
+export interface GenerateReportRequest {
+  /** Report type */
+  type: ReportType;
+  /** Date range */
+  dateRange: DateRange;
+  /** Branch filter */
+  branchId?: string;
+  /** Include details */
+  includeDetails?: boolean;
+  /** Export format */
+  exportFormat?: 'pdf' | 'csv' | 'excel';
+}
+
+// -----------------------------------------------------------------------------
+// Response Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Dashboard data
+ */
+export interface DashboardData {
+  /** Sales summary */
+  sales: SalesSummary;
+  /** Top items today */
+  topItems: MenuItemPerformance[];
+  /** Peak hours today */
+  peakHours: PeakHourData[];
+  /** Sales trend (last 7 days) */
+  salesTrend: TimeSeriesDataPoint[];
+  /** Last updated */
+  lastUpdated: Date;
+}
+
+/**
+ * Report result
+ */
+export interface ReportResult {
+  /** Success */
+  success: boolean;
+  /** Report ID */
+  reportId?: string;
+  /** Report URL (if exported) */
+  reportUrl?: string;
+  /** Report data */
+  data?: SalesReport | MenuPerformanceReport | CustomerInsightsReport;
+  /** Error message */
+  errorMessage?: string;
+}
+
+// -----------------------------------------------------------------------------
+// Service Interfaces
+// -----------------------------------------------------------------------------
+
+/**
+ * Analytics service interface
+ */
+export interface IAnalyticsService {
+  /**
+   * Get dashboard data
+   */
+  getDashboard(
+    organizationId: string,
+    branchId?: string
+  ): Promise<DashboardData>;
+
+  /**
+   * Get sales summary
+   */
+  getSalesSummary(
+    organizationId: string,
+    request: GetAnalyticsRequest
+  ): Promise<SalesSummary>;
+
+  /**
+   * Get menu performance
+   */
+  getMenuPerformance(
+    organizationId: string,
+    request: GetAnalyticsRequest
+  ): Promise<MenuItemPerformance[]>;
+
+  /**
+   * Get peak hours
+   */
+  getPeakHours(
+    organizationId: string,
+    request: GetAnalyticsRequest
+  ): Promise<PeakHourData[]>;
+
+  /**
+   * Track event
+   */
+  trackEvent(
+    organizationId: string,
+    eventName: string,
+    eventData: Record<string, unknown>
+  ): Promise<void>;
+}
+
+/**
+ * Report service interface
+ */
+export interface IReportService {
+  /**
+   * Generate report
+   */
+  generateReport(
+    organizationId: string,
+    request: GenerateReportRequest
+  ): Promise<ReportResult>;
+
+  /**
+   * Get report by ID
+   */
+  getReport(
+    organizationId: string,
+    reportId: string
+  ): Promise<ReportResult>;
+
+  /**
+   * List reports
+   */
+  listReports(
+    organizationId: string,
+    type?: ReportType
+  ): Promise<Array<{
+    id: string;
+    type: ReportType;
+    dateRange: DateRange;
+    generatedAt: Date;
+  }>>;
+
+  /**
+   * Export report
+   */
+  exportReport(
+    organizationId: string,
+    reportId: string,
+    format: 'pdf' | 'csv' | 'excel'
+  ): Promise<{ url: string }>;
+}
+
+// -----------------------------------------------------------------------------
+// Event Payload Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Report generated event payload
+ */
+export interface ReportGeneratedEventPayload {
+  organizationId: string;
+  reportId: string;
+  reportType: ReportType;
+  dateRange: DateRange;
+  timestamp: string;
+}
+
+/**
+ * Alert triggered event payload
+ */
+export interface AlertTriggeredEventPayload {
+  organizationId: string;
+  alertType: string;
+  metric: MetricType;
+  threshold: number;
+  actualValue: number;
+  timestamp: string;
+}

