+/**
+ * Campaign Module Types
+ *
+ * Type definitions for future campaign module implementation.
+ * This file defines interfaces for promotions, discounts,
+ * and marketing campaigns.
+ *
+ * @module modules/_stubs/campaign/types
+ *
+ * @example
+ * ```typescript
+ * import type {
+ *   ICampaignService,
+ *   Campaign,
+ *   DiscountRule,
+ * } from '@/modules/_stubs/campaign';
+ * ```
+ */
+
+// -----------------------------------------------------------------------------
+// Enums
+// -----------------------------------------------------------------------------
+
+/**
+ * Campaign status
+ */
+export enum CampaignStatus {
+  /** Draft - not yet active */
+  DRAFT = 'DRAFT',
+  /** Scheduled - will activate automatically */
+  SCHEDULED = 'SCHEDULED',
+  /** Active - currently running */
+  ACTIVE = 'ACTIVE',
+  /** Paused - temporarily stopped */
+  PAUSED = 'PAUSED',
+  /** Expired - ended */
+  EXPIRED = 'EXPIRED',
+  /** Cancelled - manually stopped */
+  CANCELLED = 'CANCELLED',
+}
+
+/**
+ * Discount type
+ */
+export enum DiscountType {
+  /** Percentage off */
+  PERCENTAGE = 'PERCENTAGE',
+  /** Fixed amount off */
+  FIXED_AMOUNT = 'FIXED_AMOUNT',
+  /** Free item */
+  FREE_ITEM = 'FREE_ITEM',
+  /** Buy X Get Y */
+  BUY_X_GET_Y = 'BUY_X_GET_Y',
+  /** Bundle price */
+  BUNDLE = 'BUNDLE',
+}
+
+/**
+ * Campaign type
+ */
+export enum CampaignType {
+  /** Promo code campaign */
+  PROMO_CODE = 'PROMO_CODE',
+  /** Automatic discount */
+  AUTOMATIC = 'AUTOMATIC',
+  /** Happy hour */
+  HAPPY_HOUR = 'HAPPY_HOUR',
+  /** Flash sale */
+  FLASH_SALE = 'FLASH_SALE',
+  /** Loyalty reward */
+  LOYALTY_REWARD = 'LOYALTY_REWARD',
+}
+
+/**
+ * Campaign target type
+ */
+export enum CampaignTarget {
+  /** All items */
+  ALL_ITEMS = 'ALL_ITEMS',
+  /** Specific items */
+  SPECIFIC_ITEMS = 'SPECIFIC_ITEMS',
+  /** Specific categories */
+  CATEGORIES = 'CATEGORIES',
+  /** Order total */
+  ORDER_TOTAL = 'ORDER_TOTAL',
+  /** Customer segment */
+  CUSTOMER_SEGMENT = 'CUSTOMER_SEGMENT',
+}
+
+// -----------------------------------------------------------------------------
+// Entity Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Campaign entity
+ */
+export interface Campaign {
+  /** Campaign ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Campaign name */
+  name: string;
+  /** Description */
+  description: string | null;
+  /** Campaign type */
+  type: CampaignType;
+  /** Campaign status */
+  status: CampaignStatus;
+  /** Promo code (if applicable) */
+  promoCode: string | null;
+  /** Discount rules */
+  discountRules: DiscountRule[];
+  /** Target configuration */
+  target: CampaignTargetConfig;
+  /** Conditions */
+  conditions: CampaignConditions;
+  /** Schedule */
+  schedule: CampaignSchedule;
+  /** Usage limits */
+  limits: CampaignLimits;
+  /** Current usage stats */
+  usage: CampaignUsage;
+  /** Priority (higher = applied first) */
+  priority: number;
+  /** Is combinable with other campaigns */
+  isCombinable: boolean;
+  /** Created at */
+  createdAt: Date;
+  /** Updated at */
+  updatedAt: Date;
+  /** Deleted at */
+  deletedAt: Date | null;
+}
+
+/**
+ * Discount rule
+ */
+export interface DiscountRule {
+  /** Rule ID */
+  id: string;
+  /** Discount type */
+  type: DiscountType;
+  /** Discount value (percentage or amount) */
+  value: number;
+  /** Max discount amount (for percentage) */
+  maxDiscount?: number;
+  /** Buy quantity (for BUY_X_GET_Y) */
+  buyQuantity?: number;
+  /** Get quantity (for BUY_X_GET_Y) */
+  getQuantity?: number;
+  /** Bundle items (for BUNDLE) */
+  bundleItems?: string[];
+  /** Bundle price (for BUNDLE) */
+  bundlePrice?: number;
+}
+
+/**
+ * Campaign target configuration
+ */
+export interface CampaignTargetConfig {
+  /** Target type */
+  type: CampaignTarget;
+  /** Item IDs (if SPECIFIC_ITEMS) */
+  itemIds?: string[];
+  /** Category IDs (if CATEGORIES) */
+  categoryIds?: string[];
+  /** Customer segment IDs (if CUSTOMER_SEGMENT) */
+  segmentIds?: string[];
+  /** Minimum order amount (if ORDER_TOTAL) */
+  minOrderAmount?: number;
+}
+
+/**
+ * Campaign conditions
+ */
+export interface CampaignConditions {
+  /** Minimum order amount */
+  minOrderAmount?: number;
+  /** Minimum item count */
+  minItemCount?: number;
+  /** First order only */
+  firstOrderOnly?: boolean;
+  /** Specific payment methods */
+  paymentMethods?: string[];
+  /** Specific branches */
+  branchIds?: string[];
+  /** Order types (dine-in, takeaway, delivery) */
+  orderTypes?: string[];
+}
+
+/**
+ * Campaign schedule
+ */
+export interface CampaignSchedule {
+  /** Start date */
+  startDate: Date;
+  /** End date */
+  endDate?: Date;
+  /** Active days of week (0-6) */
+  activeDays?: number[];
+  /** Active time ranges */
+  activeHours?: Array<{
+    start: string; // HH:mm
+    end: string;
+  }>;
+  /** Timezone */
+  timezone: string;
+}
+
+/**
+ * Campaign limits
+ */
+export interface CampaignLimits {
+  /** Total usage limit */
+  totalUsage?: number;
+  /** Per customer limit */
+  perCustomer?: number;
+  /** Per day limit */
+  perDay?: number;
+  /** Total budget */
+  totalBudget?: number;
+}
+
+/**
+ * Campaign usage stats
+ */
+export interface CampaignUsage {
+  /** Total times used */
+  totalUsed: number;
+  /** Total discount given */
+  totalDiscount: number;
+  /** Unique customers */
+  uniqueCustomers: number;
+  /** Last used at */
+  lastUsedAt?: Date;
+}
+
+/**
+ * Applied discount
+ */
+export interface AppliedDiscount {
+  /** Campaign ID */
+  campaignId: string;
+  /** Campaign name */
+  campaignName: string;
+  /** Discount type */
+  discountType: DiscountType;
+  /** Discount amount */
+  discountAmount: number;
+  /** Original amount */
+  originalAmount: number;
+  /** Final amount */
+  finalAmount: number;
+  /** Affected items */
+  affectedItems: string[];
+}
+
+// -----------------------------------------------------------------------------
+// Request Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Create campaign request
+ */
+export interface CreateCampaignRequest {
+  /** Campaign name */
+  name: string;
+  /** Description */
+  description?: string;
+  /** Campaign type */
+  type: CampaignType;
+  /** Promo code */
+  promoCode?: string;
+  /** Discount rules */
+  discountRules: Omit<DiscountRule, 'id'>[];
+  /** Target configuration */
+  target: CampaignTargetConfig;
+  /** Conditions */
+  conditions?: CampaignConditions;
+  /** Schedule */
+  schedule: Omit<CampaignSchedule, 'timezone'> & { timezone?: string };
+  /** Limits */
+  limits?: CampaignLimits;
+  /** Priority */
+  priority?: number;
+  /** Is combinable */
+  isCombinable?: boolean;
+}
+
+/**
+ * Update campaign request
+ */
+export interface UpdateCampaignRequest {
+  /** Campaign name */
+  name?: string;
+  /** Description */
+  description?: string | null;
+  /** Discount rules */
+  discountRules?: Omit<DiscountRule, 'id'>[];
+  /** Target configuration */
+  target?: CampaignTargetConfig;
+  /** Conditions */
+  conditions?: CampaignConditions;
+  /** Schedule */
+  schedule?: Partial<CampaignSchedule>;
+  /** Limits */
+  limits?: CampaignLimits;
+  /** Priority */
+  priority?: number;
+  /** Is combinable */
+  isCombinable?: boolean;
+}
+
+/**
+ * Apply discount request
+ */
+export interface ApplyDiscountRequest {
+  /** Order items */
+  items: Array<{
+    itemId: string;
+    quantity: number;
+    price: number;
+  }>;
+  /** Order subtotal */
+  subtotal: number;
+  /** Customer ID */
+  customerId?: string;
+  /** Promo code */
+  promoCode?: string;
+  /** Branch ID */
+  branchId?: string;
+  /** Order type */
+  orderType?: string;
+}
+
+// -----------------------------------------------------------------------------
+// Response Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Apply discount result
+ */
+export interface ApplyDiscountResult {
+  /** Success */
+  success: boolean;
+  /** Applied discounts */
+  appliedDiscounts: AppliedDiscount[];
+  /** Total discount */
+  totalDiscount: number;
+  /** Final total */
+  finalTotal: number;
+  /** Messages */
+  messages: string[];
+}
+
+/**
+ * Validate promo code result
+ */
+export interface ValidatePromoCodeResult {
+  /** Is valid */
+  isValid: boolean;
+  /** Campaign (if valid) */
+  campaign?: Campaign;
+  /** Error message (if invalid) */
+  errorMessage?: string;
+}
+
+// -----------------------------------------------------------------------------
+// Service Interfaces
+// -----------------------------------------------------------------------------
+
+/**
+ * Campaign service interface
+ */
+export interface ICampaignService {
+  /**
+   * Create campaign
+   */
+  create(
+    organizationId: string,
+    request: CreateCampaignRequest
+  ): Promise<Campaign>;
+
+  /**
+   * Update campaign
+   */
+  update(
+    organizationId: string,
+    campaignId: string,
+    request: UpdateCampaignRequest
+  ): Promise<Campaign>;
+
+  /**
+   * Activate campaign
+   */
+  activate(
+    organizationId: string,
+    campaignId: string
+  ): Promise<Campaign>;
+
+  /**
+   * Deactivate campaign
+   */
+  deactivate(
+    organizationId: string,
+    campaignId: string
+  ): Promise<Campaign>;
+
+  /**
+   * Delete campaign
+   */
+  delete(
+    organizationId: string,
+    campaignId: string
+  ): Promise<void>;
+
+  /**
+   * Get campaign by ID
+   */
+  getById(
+    organizationId: string,
+    campaignId: string
+  ): Promise<Campaign>;
+
+  /**
+   * List campaigns
+   */
+  list(
+    organizationId: string,
+    filters?: {
+      status?: CampaignStatus;
+      type?: CampaignType;
+    }
+  ): Promise<Campaign[]>;
+
+  /**
+   * Validate promo code
+   */
+  validatePromoCode(
+    organizationId: string,
+    promoCode: string
+  ): Promise<ValidatePromoCodeResult>;
+}
+
+/**
+ * Discount service interface
+ */
+export interface IDiscountService {
+  /**
+   * Apply discounts to order
+   */
+  applyDiscounts(
+    organizationId: string,
+    request: ApplyDiscountRequest
+  ): Promise<ApplyDiscountResult>;
+
+  /**
+   * Calculate potential savings
+   */
+  calculateSavings(
+    organizationId: string,
+    request: ApplyDiscountRequest
+  ): Promise<{
+    availableDiscounts: AppliedDiscount[];
+    maxSavings: number;
+  }>;
+
+  /**
+   * Record discount usage
+   */
+  recordUsage(
+    organizationId: string,
+    campaignId: string,
+    orderId: string,
+    customerId: string | null,
+    discountAmount: number
+  ): Promise<void>;
+}
+
+// -----------------------------------------------------------------------------
+// Event Payload Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Campaign created event payload
+ */
+export interface CampaignCreatedEventPayload {
+  organizationId: string;
+  campaignId: string;
+  campaignType: CampaignType;
+  timestamp: string;
+}
+
+/**
+ * Campaign activated event payload
+ */
+export interface CampaignActivatedEventPayload {
+  organizationId: string;
+  campaignId: string;
+  startDate: string;
+  endDate?: string;
+  timestamp: string;
+}
+
+/**
+ * Discount applied event payload
+ */
+export interface DiscountAppliedEventPayload {
+  organizationId: string;
+  campaignId: string;
+  orderId: string;
+  customerId?: string;
+  discountAmount: number;
+  timestamp: string;
+}

