+/**
+ * Feedback Module Types
+ *
+ * Type definitions for future feedback module implementation.
+ * This file defines interfaces for customer feedback, surveys,
+ * ratings, and review management.
+ *
+ * @module modules/_stubs/feedback/types
+ *
+ * @example
+ * ```typescript
+ * import type {
+ *   IFeedbackService,
+ *   Feedback,
+ *   Survey,
+ * } from '@/modules/_stubs/feedback';
+ * ```
+ */
+
+// -----------------------------------------------------------------------------
+// Enums
+// -----------------------------------------------------------------------------
+
+/**
+ * Feedback status
+ */
+export enum FeedbackStatus {
+  /** Feedback submitted, not reviewed */
+  NEW = 'NEW',
+  /** Feedback being reviewed */
+  REVIEWING = 'REVIEWING',
+  /** Response sent */
+  RESPONDED = 'RESPONDED',
+  /** Feedback resolved */
+  RESOLVED = 'RESOLVED',
+  /** Feedback archived */
+  ARCHIVED = 'ARCHIVED',
+}
+
+/**
+ * Feedback type
+ */
+export enum FeedbackType {
+  /** General feedback */
+  GENERAL = 'GENERAL',
+  /** Service feedback */
+  SERVICE = 'SERVICE',
+  /** Food quality feedback */
+  FOOD_QUALITY = 'FOOD_QUALITY',
+  /** Complaint */
+  COMPLAINT = 'COMPLAINT',
+  /** Suggestion */
+  SUGGESTION = 'SUGGESTION',
+  /** Compliment */
+  COMPLIMENT = 'COMPLIMENT',
+}
+
+/**
+ * Rating category
+ */
+export enum RatingCategory {
+  /** Overall experience */
+  OVERALL = 'OVERALL',
+  /** Food quality */
+  FOOD = 'FOOD',
+  /** Service quality */
+  SERVICE = 'SERVICE',
+  /** Ambiance */
+  AMBIANCE = 'AMBIANCE',
+  /** Value for money */
+  VALUE = 'VALUE',
+  /** Cleanliness */
+  CLEANLINESS = 'CLEANLINESS',
+}
+
+/**
+ * Survey status
+ */
+export enum SurveyStatus {
+  /** Survey is draft */
+  DRAFT = 'DRAFT',
+  /** Survey is active */
+  ACTIVE = 'ACTIVE',
+  /** Survey is paused */
+  PAUSED = 'PAUSED',
+  /** Survey is completed */
+  COMPLETED = 'COMPLETED',
+  /** Survey is archived */
+  ARCHIVED = 'ARCHIVED',
+}
+
+/**
+ * Question type
+ */
+export enum QuestionType {
+  /** Star rating (1-5) */
+  RATING = 'RATING',
+  /** Single choice */
+  SINGLE_CHOICE = 'SINGLE_CHOICE',
+  /** Multiple choice */
+  MULTIPLE_CHOICE = 'MULTIPLE_CHOICE',
+  /** Text input */
+  TEXT = 'TEXT',
+  /** NPS (0-10 scale) */
+  NPS = 'NPS',
+  /** Yes/No */
+  YES_NO = 'YES_NO',
+}
+
+/**
+ * Sentiment type
+ */
+export enum Sentiment {
+  /** Positive sentiment */
+  POSITIVE = 'POSITIVE',
+  /** Neutral sentiment */
+  NEUTRAL = 'NEUTRAL',
+  /** Negative sentiment */
+  NEGATIVE = 'NEGATIVE',
+}
+
+// -----------------------------------------------------------------------------
+// Entity Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Feedback entity
+ */
+export interface Feedback {
+  /** Feedback ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Branch ID */
+  branchId: string | null;
+  /** Order ID (if related to an order) */
+  orderId: string | null;
+  /** Customer ID (if registered) */
+  customerId: string | null;
+  /** Customer name */
+  customerName: string | null;
+  /** Customer email */
+  customerEmail: string | null;
+  /** Customer phone */
+  customerPhone: string | null;
+  /** Feedback type */
+  type: FeedbackType;
+  /** Status */
+  status: FeedbackStatus;
+  /** Overall rating (1-5) */
+  overallRating: number;
+  /** Individual ratings */
+  ratings: FeedbackRating[];
+  /** Feedback text */
+  comment: string | null;
+  /** Detected sentiment */
+  sentiment: Sentiment | null;
+  /** Response from business */
+  response: string | null;
+  /** Response date */
+  respondedAt: Date | null;
+  /** Responded by user ID */
+  respondedById: string | null;
+  /** Is public (can be shown on menu) */
+  isPublic: boolean;
+  /** Source */
+  source: string;
+  /** Created at */
+  createdAt: Date;
+  /** Updated at */
+  updatedAt: Date;
+}
+
+/**
+ * Feedback rating
+ */
+export interface FeedbackRating {
+  /** Category */
+  category: RatingCategory;
+  /** Rating value (1-5) */
+  rating: number;
+}
+
+/**
+ * Survey entity
+ */
+export interface Survey {
+  /** Survey ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Survey name */
+  name: string;
+  /** Description */
+  description: string | null;
+  /** Status */
+  status: SurveyStatus;
+  /** Questions */
+  questions: SurveyQuestion[];
+  /** Start date */
+  startDate: Date | null;
+  /** End date */
+  endDate: Date | null;
+  /** Response count */
+  responseCount: number;
+  /** Created at */
+  createdAt: Date;
+  /** Updated at */
+  updatedAt: Date;
+}
+
+/**
+ * Survey question
+ */
+export interface SurveyQuestion {
+  /** Question ID */
+  id: string;
+  /** Question text */
+  text: string;
+  /** Question type */
+  type: QuestionType;
+  /** Is required */
+  isRequired: boolean;
+  /** Options (for choice questions) */
+  options: string[] | null;
+  /** Display order */
+  order: number;
+}
+
+/**
+ * Survey response
+ */
+export interface SurveyResponse {
+  /** Response ID */
+  id: string;
+  /** Survey ID */
+  surveyId: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Customer ID */
+  customerId: string | null;
+  /** Customer email */
+  customerEmail: string | null;
+  /** Answers */
+  answers: SurveyAnswer[];
+  /** Completed at */
+  completedAt: Date;
+}
+
+/**
+ * Survey answer
+ */
+export interface SurveyAnswer {
+  /** Question ID */
+  questionId: string;
+  /** Answer value */
+  value: string | number | string[];
+}
+
+// -----------------------------------------------------------------------------
+// Request Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Submit feedback request
+ */
+export interface SubmitFeedbackRequest {
+  /** Branch ID */
+  branchId?: string;
+  /** Order ID */
+  orderId?: string;
+  /** Customer name */
+  customerName?: string;
+  /** Customer email */
+  customerEmail?: string;
+  /** Customer phone */
+  customerPhone?: string;
+  /** Feedback type */
+  type?: FeedbackType;
+  /** Overall rating */
+  overallRating: number;
+  /** Individual ratings */
+  ratings?: Array<{ category: RatingCategory; rating: number }>;
+  /** Comment */
+  comment?: string;
+  /** Allow public display */
+  allowPublic?: boolean;
+}
+
+/**
+ * Respond to feedback request
+ */
+export interface RespondToFeedbackRequest {
+  /** Feedback ID */
+  feedbackId: string;
+  /** Response text */
+  response: string;
+  /** Mark as resolved */
+  markResolved?: boolean;
+  /** Send notification to customer */
+  notifyCustomer?: boolean;
+}
+
+/**
+ * Create survey request
+ */
+export interface CreateSurveyRequest {
+  /** Survey name */
+  name: string;
+  /** Description */
+  description?: string;
+  /** Questions */
+  questions: Array<Omit<SurveyQuestion, 'id'>>;
+  /** Start date */
+  startDate?: string;
+  /** End date */
+  endDate?: string;
+}
+
+/**
+ * Submit survey response request
+ */
+export interface SubmitSurveyResponseRequest {
+  /** Survey ID */
+  surveyId: string;
+  /** Customer email */
+  customerEmail?: string;
+  /** Answers */
+  answers: Array<{ questionId: string; value: string | number | string[] }>;
+}
+
+// -----------------------------------------------------------------------------
+// Response Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Feedback summary
+ */
+export interface FeedbackSummary {
+  /** Total feedback count */
+  totalCount: number;
+  /** Average overall rating */
+  averageRating: number;
+  /** Rating distribution */
+  ratingDistribution: Record<number, number>;
+  /** Category averages */
+  categoryAverages: Record<RatingCategory, number>;
+  /** Sentiment distribution */
+  sentimentDistribution: Record<Sentiment, number>;
+  /** Period */
+  period: { start: Date; end: Date };
+}
+
+/**
+ * NPS Result
+ */
+export interface NPSResult {
+  /** NPS Score (-100 to 100) */
+  score: number;
+  /** Promoters count (9-10) */
+  promoters: number;
+  /** Passives count (7-8) */
+  passives: number;
+  /** Detractors count (0-6) */
+  detractors: number;
+  /** Total responses */
+  totalResponses: number;
+}
+
+// -----------------------------------------------------------------------------
+// Service Interfaces
+// -----------------------------------------------------------------------------
+
+/**
+ * Feedback service interface
+ */
+export interface IFeedbackService {
+  /**
+   * Submit feedback
+   */
+  submitFeedback(
+    organizationId: string,
+    request: SubmitFeedbackRequest
+  ): Promise<Feedback>;
+
+  /**
+   * Get feedback by ID
+   */
+  getFeedback(
+    organizationId: string,
+    feedbackId: string
+  ): Promise<Feedback>;
+
+  /**
+   * List feedback
+   */
+  listFeedback(
+    organizationId: string,
+    filters?: {
+      branchId?: string;
+      status?: FeedbackStatus;
+      type?: FeedbackType;
+      minRating?: number;
+      maxRating?: number;
+      startDate?: string;
+      endDate?: string;
+    }
+  ): Promise<Feedback[]>;
+
+  /**
+   * Respond to feedback
+   */
+  respondToFeedback(
+    organizationId: string,
+    request: RespondToFeedbackRequest
+  ): Promise<Feedback>;
+
+  /**
+   * Get feedback summary
+   */
