+/**
+ * Inventory Module Types
+ *
+ * Type definitions for future inventory module implementation.
+ * This file defines interfaces for stock management, suppliers,
+ * and inventory tracking.
+ *
+ * @module modules/_stubs/inventory/types
+ *
+ * @example
+ * ```typescript
+ * import type {
+ *   IInventoryService,
+ *   InventoryItem,
+ *   StockLevel,
+ * } from '@/modules/_stubs/inventory';
+ * ```
+ */
+
+// -----------------------------------------------------------------------------
+// Enums
+// -----------------------------------------------------------------------------
+
+/**
+ * Stock status
+ */
+export enum StockStatus {
+  /** In stock */
+  IN_STOCK = 'IN_STOCK',
+  /** Low stock */
+  LOW_STOCK = 'LOW_STOCK',
+  /** Out of stock */
+  OUT_OF_STOCK = 'OUT_OF_STOCK',
+  /** Discontinued */
+  DISCONTINUED = 'DISCONTINUED',
+}
+
+/**
+ * Transaction type
+ */
+export enum StockTransactionType {
+  /** Stock received */
+  RECEIVED = 'RECEIVED',
+  /** Stock sold (order) */
+  SOLD = 'SOLD',
+  /** Manual adjustment */
+  ADJUSTED = 'ADJUSTED',
+  /** Waste/spoilage */
+  WASTE = 'WASTE',
+  /** Transfer out */
+  TRANSFER_OUT = 'TRANSFER_OUT',
+  /** Transfer in */
+  TRANSFER_IN = 'TRANSFER_IN',
+  /** Return from customer */
+  RETURN = 'RETURN',
+}
+
+/**
+ * Unit of measure
+ */
+export enum UnitOfMeasure {
+  /** Piece/unit */
+  PIECE = 'PIECE',
+  /** Kilogram */
+  KG = 'KG',
+  /** Gram */
+  GRAM = 'GRAM',
+  /** Liter */
+  LITER = 'LITER',
+  /** Milliliter */
+  ML = 'ML',
+  /** Box */
+  BOX = 'BOX',
+  /** Pack */
+  PACK = 'PACK',
+}
+
+/**
+ * Purchase order status
+ */
+export enum PurchaseOrderStatus {
+  /** Draft */
+  DRAFT = 'DRAFT',
+  /** Submitted */
+  SUBMITTED = 'SUBMITTED',
+  /** Confirmed by supplier */
+  CONFIRMED = 'CONFIRMED',
+  /** Partially received */
+  PARTIALLY_RECEIVED = 'PARTIALLY_RECEIVED',
+  /** Fully received */
+  RECEIVED = 'RECEIVED',
+  /** Cancelled */
+  CANCELLED = 'CANCELLED',
+}
+
+// -----------------------------------------------------------------------------
+// Entity Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Inventory item
+ */
+export interface InventoryItem {
+  /** Item ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Branch ID (if branch-specific) */
+  branchId: string | null;
+  /** SKU */
+  sku: string;
+  /** Item name */
+  name: string;
+  /** Description */
+  description: string | null;
+  /** Category */
+  category: string | null;
+  /** Unit of measure */
+  unit: UnitOfMeasure;
+  /** Current quantity */
+  quantity: number;
+  /** Minimum stock level */
+  minStockLevel: number;
+  /** Maximum stock level */
+  maxStockLevel: number | null;
+  /** Reorder point */
+  reorderPoint: number;
+  /** Cost per unit */
+  costPerUnit: number;
+  /** Supplier ID */
+  supplierId: string | null;
+  /** Stock status */
+  status: StockStatus;
+  /** Menu item IDs using this inventory item */
+  linkedMenuItems: string[];
+  /** Created at */
+  createdAt: Date;
+  /** Updated at */
+  updatedAt: Date;
+}
+
+/**
+ * Stock level (per branch)
+ */
+export interface StockLevel {
+  /** Stock level ID */
+  id: string;
+  /** Inventory item ID */
+  inventoryItemId: string;
+  /** Branch ID */
+  branchId: string;
+  /** Current quantity */
+  quantity: number;
+  /** Reserved quantity (for pending orders) */
+  reservedQuantity: number;
+  /** Available quantity */
+  availableQuantity: number;
+  /** Status */
+  status: StockStatus;
+  /** Last counted at */
+  lastCountedAt: Date | null;
+  /** Updated at */
+  updatedAt: Date;
+}
+
+/**
+ * Stock transaction
+ */
+export interface StockTransaction {
+  /** Transaction ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Branch ID */
+  branchId: string;
+  /** Inventory item ID */
+  inventoryItemId: string;
+  /** Transaction type */
+  type: StockTransactionType;
+  /** Quantity (positive for in, negative for out) */
+  quantity: number;
+  /** Balance after transaction */
+  balance: number;
+  /** Cost per unit at time of transaction */
+  costPerUnit: number;
+  /** Total cost */
+  totalCost: number;
+  /** Reference (order ID, PO number, etc.) */
+  reference: string | null;
+  /** Notes */
+  notes: string | null;
+  /** Created by user ID */
+  createdBy: string;
+  /** Created at */
+  createdAt: Date;
+}
+
+/**
+ * Supplier
+ */
+export interface Supplier {
+  /** Supplier ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Supplier name */
+  name: string;
+  /** Contact name */
+  contactName: string | null;
+  /** Email */
+  email: string | null;
+  /** Phone */
+  phone: string | null;
+  /** Address */
+  address: string | null;
+  /** Tax ID */
+  taxId: string | null;
+  /** Payment terms (days) */
+  paymentTerms: number;
