+  ): Promise<StockTransaction[]>;
+
+  /**
+   * Record waste
+   */
+  recordWaste(
+    organizationId: string,
+    request: RecordWasteRequest
+  ): Promise<WasteRecord>;
+}
+
+// -----------------------------------------------------------------------------
+// Event Payload Types
+// -----------------------------------------------------------------------------
+
+/**
