+  branchId: string;
+  inventoryItemId: string;
+  itemName: string;
+  linkedMenuItems: string[];
+  timestamp: string;
+}
+
+/**
+ * Waste recorded event payload
+ */
+export interface WasteRecordedEventPayload {
+  organizationId: string;
+  branchId: string;
+  inventoryItemId: string;
+  quantity: number;
+  reason: string;
+  cost: number;
+  timestamp: string;
+}

