+  customerName: string | null;
+  /** Special instructions */
+  instructions: string | null;
+  /** Order type (dine-in, takeout, etc.) */
+  orderType: string;
+  /** Time received */
+  receivedAt: Date;
+  /** Time started */
+  startedAt: Date | null;
+  /** Time ready */
+  readyAt: Date | null;
+  /** Time served */
+  servedAt: Date | null;
+  /** Target time (when should be ready) */
+  targetTime: Date | null;
+  /** Is delayed */
+  isDelayed: boolean;
+  /** Wait time (seconds) */
+  waitTimeSeconds: number;
+}
+
+/**
+ * Kitchen order item
+ */
+export interface KitchenOrderItem {
+  /** Item ID */
+  id: string;
+  /** Menu item ID */
+  menuItemId: string;
+  /** Item name */
+  name: string;
+  /** Quantity */
+  quantity: number;
+  /** Status */
+  status: KitchenItemStatus;
+  /** Station ID */
+  stationId: string | null;
+  /** Modifiers */
+  modifiers: string[];
+  /** Special notes */
+  notes: string | null;
+  /** Preparation time (minutes) */
+  prepTimeMinutes: number;
+  /** Started at */
+  startedAt: Date | null;
+  /** Ready at */
+  readyAt: Date | null;
+}
+
+/**
+ * Kitchen station
+ */
+export interface KitchenStation {
