+  avgPrepTimeMinutes: number;
+}
+
+/**
+ * Kitchen alert
+ */
+export interface KitchenAlert {
+  /** Alert ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Branch ID */
+  branchId: string;
+  /** Alert type */
+  type: KitchenAlertType;
+  /** Related order ID */
+  orderId: string | null;
+  /** Related item ID */
+  itemId: string | null;
+  /** Related station ID */
+  stationId: string | null;
+  /** Message */
+  message: string;
+  /** Is acknowledged */
+  isAcknowledged: boolean;
+  /** Acknowledged by */
+  acknowledgedBy: string | null;
+  /** Created at */
+  createdAt: Date;
+  /** Acknowledged at */
+  acknowledgedAt: Date | null;
+}
+
+/**
+ * Kitchen display settings
+ */
+export interface KitchenDisplaySettings {
+  /** Organization ID */
