+  showCustomerNames: boolean;
+  /** Show order totals */
+  showOrderTotals: boolean;
+  /** Enable audio alerts */
+  audioAlertsEnabled: boolean;
+  /** Display columns */
+  displayColumns: number;
+  /** Group by station */
+  groupByStation: boolean;
+  /** Sort order */
+  sortOrder: 'oldest_first' | 'priority' | 'station';
+}
+
+// -----------------------------------------------------------------------------
+// Request Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Create station request
+ */
+export interface CreateStationRequest {
+  /** Branch ID */
+  branchId: string;
+  /** Station name */
+  name: string;
+  /** Station type */
+  type: StationType;
+  /** Color */
+  color?: string;
+  /** Assigned menu item IDs */
+  assignedItems?: string[];
+}
+
+/**
+ * Update station request
+ */
+export interface UpdateStationRequest {
+  /** Station name */
+  name?: string;
+  /** Station type */
+  type?: StationType;
+  /** Display order */
+  displayOrder?: number;
+  /** Is active */
+  isActive?: boolean;
+  /** Color */
+  color?: string;
+  /** Assigned menu item IDs */
+  assignedItems?: string[];
+}
+
+/**
+ * Update item status request
+ */
+export interface UpdateItemStatusRequest {
+  /** Item ID */
+  itemId: string;
+  /** New status */
+  status: KitchenItemStatus;
+}
+
+/**
+ * Bump order request
+ */
+export interface BumpOrderRequest {
+  /** Order ID */
+  orderId: string;
+  /** Bump to status */
+  status: KitchenOrderStatus;
+}
+
+// -----------------------------------------------------------------------------
+// Response Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Kitchen queue
+ */
+export interface KitchenQueue {
+  /** Station ID (null for all stations) */
+  stationId: string | null;
+  /** Orders in queue */
+  orders: KitchenOrder[];
+  /** Total count */
+  totalCount: number;
+  /** Oldest order wait time (seconds) */
+  oldestWaitTimeSeconds: number;
+  /** Average wait time (seconds) */
+  avgWaitTimeSeconds: number;
+}
+
+/**
+ * Kitchen performance
+ */
+export interface KitchenPerformance {
+  /** Period start */
+  periodStart: Date;
+  /** Period end */
+  periodEnd: Date;
+  /** Total orders */
+  totalOrders: number;
+  /** Completed orders */
+  completedOrders: number;
+  /** Average prep time (minutes) */
+  avgPrepTimeMinutes: number;
+  /** Orders on time percentage */
+  onTimePercentage: number;
+  /** Delayed orders */
+  delayedOrders: number;
+  /** Station breakdown */
+  stationPerformance: Array<{
+    stationId: string;
+    stationName: string;
+    itemsCompleted: number;
+    avgPrepTimeMinutes: number;
+  }>;
+}
+
+/**
+ * All-day count (running totals)
+ */
+export interface AllDayCount {
+  /** Item ID */
+  itemId: string;
+  /** Item name */
+  itemName: string;
+  /** Ordered count */
+  ordered: number;
+  /** Completed count */
+  completed: number;
+  /** In progress count */
+  inProgress: number;
+}
+
+// -----------------------------------------------------------------------------
+// Service Interfaces
+// -----------------------------------------------------------------------------
+
+/**
+ * Kitchen display service interface
+ */
+export interface IKitchenDisplayService {
+  /**
+   * Get kitchen queue
+   */
+  getQueue(
+    organizationId: string,
+    branchId: string,
+    stationId?: string
+  ): Promise<KitchenQueue>;
+
+  /**
+   * Get order details
+   */
+  getOrder(
+    organizationId: string,
+    orderId: string
+  ): Promise<KitchenOrder>;
+
+  /**
+   * Update order status
+   */
+  updateOrderStatus(
+    organizationId: string,
+    orderId: string,
+    status: KitchenOrderStatus
+  ): Promise<KitchenOrder>;
+
+  /**
+   * Update item status
+   */
+  updateItemStatus(
+    organizationId: string,
+    request: UpdateItemStatusRequest
+  ): Promise<KitchenOrderItem>;
+
+  /**
+   * Bump order (mark as ready/served)
+   */
+  bumpOrder(
+    organizationId: string,
+    request: BumpOrderRequest
+  ): Promise<KitchenOrder>;
+
+  /**
+   * Recall order
+   */
+  recallOrder(
+    organizationId: string,
+    orderId: string
+  ): Promise<KitchenOrder>;
+
+  /**
+   * Set order priority
+   */
+  setOrderPriority(
+    organizationId: string,
+    orderId: string,
+    priority: PriorityLevel
+  ): Promise<KitchenOrder>;
+
+  /**
+   * Get active alerts
+   */
+  getAlerts(
+    organizationId: string,
+    branchId: string
+  ): Promise<KitchenAlert[]>;
+
+  /**
+   * Acknowledge alert
+   */
+  acknowledgeAlert(
+    organizationId: string,
+    alertId: string
+  ): Promise<KitchenAlert>;
+
+  /**
+   * Get all-day counts
+   */
+  getAllDayCounts(
+    organizationId: string,
+    branchId: string
+  ): Promise<AllDayCount[]>;
+
+  /**
+   * Get kitchen performance
+   */
+  getPerformance(
+    organizationId: string,
+    branchId: string,
+    startDate: string,
+    endDate: string
+  ): Promise<KitchenPerformance>;
+}
+
+/**
+ * Order queue service interface
+ */
+export interface IOrderQueueService {
+  /**
+   * Add order to queue
+   */
+  addToQueue(
+    organizationId: string,
+    orderId: string
+  ): Promise<KitchenOrder>;
+
+  /**
+   * Remove order from queue
+   */
+  removeFromQueue(
+    organizationId: string,
+    orderId: string
+  ): Promise<void>;
+
+  /**
+   * Reorder queue
+   */
+  reorderQueue(
+    organizationId: string,
+    branchId: string,
+    orderIds: string[]
+  ): Promise<void>;
+
+  /**
+   * Get queue stats
+   */
+  getQueueStats(
+    organizationId: string,
+    branchId: string
+  ): Promise<{
+    totalOrders: number;
+    pendingOrders: number;
+    inProgressOrders: number;
+    readyOrders: number;
+    avgWaitTimeMinutes: number;
+  }>;
+}
+
+/**
+ * Station service interface
+ */
+export interface IStationService {
+  /**
+   * Create station
+   */
+  createStation(
+    organizationId: string,
+    request: CreateStationRequest
+  ): Promise<KitchenStation>;
+
+  /**
+   * Get station by ID
+   */
+  getStation(
+    organizationId: string,
+    stationId: string
+  ): Promise<KitchenStation>;
+
+  /**
+   * List stations
+   */
+  listStations(
+    organizationId: string,
+    branchId: string
+  ): Promise<KitchenStation[]>;
+
+  /**
+   * Update station
+   */
+  updateStation(
+    organizationId: string,
+    stationId: string,
+    request: UpdateStationRequest
+  ): Promise<KitchenStation>;
+
+  /**
+   * Delete station
+   */
+  deleteStation(
+    organizationId: string,
+    stationId: string
+  ): Promise<void>;
+
+  /**
+   * Assign items to station
+   */
+  assignItems(
+    organizationId: string,
+    stationId: string,
+    itemIds: string[]
+  ): Promise<KitchenStation>;
+}
+
+// -----------------------------------------------------------------------------
+// Event Payload Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Order received event payload
+ */
+export interface KdsOrderReceivedEventPayload {
+  organizationId: string;
+  branchId: string;
+  orderId: string;
+  orderNumber: string;
+  itemCount: number;
+  priority: PriorityLevel;
+  timestamp: string;
+}
+
+/**
+ * Order ready event payload
+ */
+export interface KdsOrderReadyEventPayload {
+  organizationId: string;
+  orderId: string;
+  orderNumber: string;
+  prepTimeMinutes: number;
+  timestamp: string;
+}
+
+/**
+ * Order delayed event payload
+ */
+export interface KdsOrderDelayedEventPayload {
+  organizationId: string;
+  orderId: string;
+  orderNumber: string;
+  delayedByMinutes: number;
+  timestamp: string;
+}
+
+/**
+ * Station alert event payload
+ */
+export interface KdsStationAlertEventPayload {
+  organizationId: string;
+  branchId: string;
+  stationId: string;
+  alertType: KitchenAlertType;
+  message: string;
+  queueCount: number;
+  timestamp: string;
+}

