+/**
+ * Loyalty Module Types
+ *
+ * Type definitions for future loyalty module implementation.
+ * This file defines interfaces for points system, rewards,
+ * and customer loyalty programs.
+ *
+ * @module modules/_stubs/loyalty/types
+ *
+ * @example
+ * ```typescript
+ * import type {
+ *   ILoyaltyService,
+ *   LoyaltyAccount,
+ *   Reward,
+ * } from '@/modules/_stubs/loyalty';
+ * ```
+ */
+
+// -----------------------------------------------------------------------------
+// Enums
+// -----------------------------------------------------------------------------
+
+/**
+ * Loyalty tier
+ */
+export enum LoyaltyTier {
+  /** Bronze tier */
+  BRONZE = 'BRONZE',
+  /** Silver tier */
+  SILVER = 'SILVER',
+  /** Gold tier */
+  GOLD = 'GOLD',
+  /** Platinum tier */
+  PLATINUM = 'PLATINUM',
+  /** Diamond tier */
+  DIAMOND = 'DIAMOND',
+}
+
+/**
+ * Transaction type
+ */
+export enum PointsTransactionType {
+  /** Points earned */
+  EARNED = 'EARNED',
+  /** Points redeemed */
+  REDEEMED = 'REDEEMED',
+  /** Points expired */
+  EXPIRED = 'EXPIRED',
+  /** Points adjusted (admin) */
+  ADJUSTED = 'ADJUSTED',
+  /** Bonus points */
+  BONUS = 'BONUS',
+  /** Referral points */
+  REFERRAL = 'REFERRAL',
+}
+
+/**
+ * Reward type
+ */
+export enum RewardType {
+  /** Discount reward */
+  DISCOUNT = 'DISCOUNT',
+  /** Free item reward */
+  FREE_ITEM = 'FREE_ITEM',
+  /** Free delivery */
+  FREE_DELIVERY = 'FREE_DELIVERY',
+  /** Exclusive access */
+  EXCLUSIVE_ACCESS = 'EXCLUSIVE_ACCESS',
+  /** Custom reward */
+  CUSTOM = 'CUSTOM',
+}
+
+/**
+ * Reward status
+ */
+export enum RewardStatus {
+  /** Available to claim */
+  AVAILABLE = 'AVAILABLE',
+  /** Claimed but not used */
+  CLAIMED = 'CLAIMED',
+  /** Used/redeemed */
+  USED = 'USED',
+  /** Expired */
+  EXPIRED = 'EXPIRED',
+}
+
+// -----------------------------------------------------------------------------
+// Entity Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Loyalty account
+ */
+export interface LoyaltyAccount {
+  /** Account ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Customer ID */
+  customerId: string;
+  /** Current tier */
+  tier: LoyaltyTier;
+  /** Current points balance */
+  pointsBalance: number;
+  /** Lifetime points earned */
+  lifetimePoints: number;
+  /** Points needed for next tier */
+  pointsToNextTier: number;
+  /** Current tier progress (percentage) */
+  tierProgress: number;
+  /** Member since */
+  memberSince: Date;
+  /** Last activity */
+  lastActivity: Date;
+  /** Referral code */
+  referralCode: string;
+  /** Referred by */
+  referredBy?: string;
+  /** Created at */
+  createdAt: Date;
+  /** Updated at */
+  updatedAt: Date;
+}
+
+/**
+ * Points transaction
+ */
+export interface PointsTransaction {
+  /** Transaction ID */
+  id: string;
+  /** Account ID */
+  accountId: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Transaction type */
+  type: PointsTransactionType;
+  /** Points amount (positive for earned, negative for spent) */
+  points: number;
+  /** Balance after transaction */
+  balance: number;
+  /** Related order ID */
+  orderId?: string;
+  /** Related reward ID */
+  rewardId?: string;
+  /** Description */
+  description: string;
+  /** Expires at (for earned points) */
+  expiresAt?: Date;
+  /** Created at */
+  createdAt: Date;
+}
+
+/**
+ * Reward definition
+ */
+export interface RewardDefinition {
+  /** Reward ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Reward name */
+  name: string;
+  /** Description */
+  description: string;
+  /** Reward type */
+  type: RewardType;
+  /** Points required */
+  pointsRequired: number;
+  /** Tier required */
+  tierRequired?: LoyaltyTier;
+  /** Reward value */
+  value: RewardValue;
+  /** Is active */
+  isActive: boolean;
+  /** Stock (null = unlimited) */
+  stock?: number;
+  /** Valid for days after claim */
+  validForDays: number;
+  /** Created at */
+  createdAt: Date;
+  /** Updated at */
+  updatedAt: Date;
+}
+
+/**
+ * Reward value (varies by type)
+ */
+export interface RewardValue {
+  /** Discount percentage (for DISCOUNT) */
+  discountPercentage?: number;
+  /** Discount amount (for DISCOUNT) */
+  discountAmount?: number;
+  /** Item ID (for FREE_ITEM) */
+  itemId?: string;
+  /** Item name (for FREE_ITEM) */
+  itemName?: string;
+  /** Custom data */
+  customData?: Record<string, unknown>;
+}
+
+/**
+ * Customer reward (claimed reward)
+ */
+export interface CustomerReward {
+  /** Customer reward ID */
+  id: string;
+  /** Account ID */
+  accountId: string;
+  /** Reward definition ID */
+  rewardId: string;
+  /** Reward details */
+  reward: RewardDefinition;
+  /** Status */
+  status: RewardStatus;
+  /** Points spent */
+  pointsSpent: number;
+  /** Claimed at */
+  claimedAt: Date;
+  /** Used at */
+  usedAt?: Date;
+  /** Expires at */
+  expiresAt: Date;
+  /** Order ID (if used) */
+  usedOnOrderId?: string;
+}
+
+/**
+ * Tier configuration
+ */
+export interface TierConfig {
+  /** Tier */
+  tier: LoyaltyTier;
+  /** Display name */
+  displayName: string;
+  /** Minimum points to achieve */
+  minPoints: number;
+  /** Points multiplier */
+  pointsMultiplier: number;
+  /** Benefits */
+  benefits: string[];
+  /** Exclusive rewards */
+  exclusiveRewards: string[];
+}
+
+/**
+ * Loyalty program configuration
+ */
+export interface LoyaltyProgramConfig {
+  /** Organization ID */
+  organizationId: string;
+  /** Program name */
+  programName: string;
+  /** Points per currency unit (e.g., 1 point per 1 TL) */
+  pointsPerUnit: number;
+  /** Currency unit */
+  currencyUnit: number;
+  /** Points expiry days (null = no expiry) */
+  pointsExpiryDays?: number;
+  /** Tier configuration */
+  tiers: TierConfig[];
+  /** Is active */
+  isActive: boolean;
+  /** Created at */
+  createdAt: Date;
+  /** Updated at */
+  updatedAt: Date;
+}
+
+// -----------------------------------------------------------------------------
+// Request Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Earn points request
+ */
+export interface EarnPointsRequest {
+  /** Customer ID */
+  customerId: string;
+  /** Order ID */
+  orderId: string;
+  /** Order amount */
+  orderAmount: number;
+  /** Bonus multiplier */
+  bonusMultiplier?: number;
+}
+
+/**
+ * Redeem points request
+ */
+export interface RedeemPointsRequest {
+  /** Customer ID */
+  customerId: string;
+  /** Points to redeem */
+  points: number;
+  /** Reward ID (if redeeming for reward) */
+  rewardId?: string;
+  /** Order ID (if applying to order) */
+  orderId?: string;
+}
+
+/**
+ * Claim reward request
+ */
+export interface ClaimRewardRequest {
+  /** Customer ID */
+  customerId: string;
+  /** Reward ID */
+  rewardId: string;
+}
+
+/**
+ * Use reward request
+ */
+export interface UseRewardRequest {
+  /** Customer ID */
+  customerId: string;
+  /** Customer reward ID */
+  customerRewardId: string;
+  /** Order ID */
+  orderId: string;
+}
+
+/**
+ * Create reward request
+ */
+export interface CreateRewardRequest {
+  /** Reward name */
+  name: string;
+  /** Description */
+  description?: string;
+  /** Reward type */
+  type: RewardType;
+  /** Points required */
+  pointsRequired: number;
+  /** Tier required */
+  tierRequired?: LoyaltyTier;
+  /** Reward value */
+  value: RewardValue;
+  /** Stock */
+  stock?: number;
+  /** Valid for days */
+  validForDays?: number;
+}
+
+// -----------------------------------------------------------------------------
+// Response Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Earn points result
+ */
+export interface EarnPointsResult {
+  /** Success */
+  success: boolean;
+  /** Points earned */
+  pointsEarned: number;
+  /** New balance */
+  newBalance: number;
+  /** Tier changed */
+  tierChanged: boolean;
+  /** New tier (if changed) */
+  newTier?: LoyaltyTier;
+  /** Transaction ID */
+  transactionId: string;
+}
+
+/**
+ * Redeem points result
+ */
+export interface RedeemPointsResult {
+  /** Success */
+  success: boolean;
+  /** Points redeemed */
+  pointsRedeemed: number;
+  /** New balance */
+  newBalance: number;
+  /** Value received */
+  valueReceived: number;
+  /** Transaction ID */
+  transactionId: string;
+}
+
+/**
+ * Account summary
+ */
+export interface AccountSummary {
+  /** Account */
+  account: LoyaltyAccount;
+  /** Available rewards */
+  availableRewards: RewardDefinition[];
+  /** Claimed rewards */
+  claimedRewards: CustomerReward[];
+  /** Recent transactions */
+  recentTransactions: PointsTransaction[];
+  /** Next tier info */
+  nextTierInfo?: {
+    tier: LoyaltyTier;
+    pointsNeeded: number;
+    benefits: string[];
+  };
+}
+
+// -----------------------------------------------------------------------------
+// Service Interfaces
+// -----------------------------------------------------------------------------
+
+/**
+ * Loyalty service interface
+ */
+export interface ILoyaltyService {
+  /**
+   * Get or create loyalty account
+   */
+  getAccount(
+    organizationId: string,
+    customerId: string
+  ): Promise<LoyaltyAccount>;
+
+  /**
+   * Get account summary
+   */
+  getAccountSummary(
+    organizationId: string,
+    customerId: string
+  ): Promise<AccountSummary>;
+
+  /**
+   * Earn points
+   */
+  earnPoints(
+    organizationId: string,
+    request: EarnPointsRequest
+  ): Promise<EarnPointsResult>;
+
+  /**
+   * Redeem points
+   */
+  redeemPoints(
+    organizationId: string,
+    request: RedeemPointsRequest
+  ): Promise<RedeemPointsResult>;
+
+  /**
+   * Get points history
+   */
+  getPointsHistory(
+    organizationId: string,
+    customerId: string,
+    limit?: number
+  ): Promise<PointsTransaction[]>;
+
+  /**
+   * Check tier upgrade
+   */
+  checkTierUpgrade(
+    organizationId: string,
+    customerId: string
+  ): Promise<{ upgraded: boolean; newTier?: LoyaltyTier }>;
+
+  /**
+   * Process referral
+   */
+  processReferral(
+    organizationId: string,
+    referrerCode: string,
+    newCustomerId: string
+  ): Promise<void>;
+}
+
+/**
+ * Reward service interface
+ */
+export interface IRewardService {
+  /**
+   * List available rewards
+   */
+  listRewards(
+    organizationId: string,
+    tier?: LoyaltyTier
+  ): Promise<RewardDefinition[]>;
+
+  /**
+   * Create reward
+   */
