@@ -0,0 +1,404 @@
+/**
+ * Payment Module Types
+ *
+ * Type definitions for future payment module implementation.
+ * This file defines interfaces for payment processing, gateways,
+ * and transaction management.
+ *
+ * @module modules/_stubs/payment/types
+ *
+ * @example
+ * ```typescript
+ * import type {
+ *   IPaymentService,
+ *   PaymentResult,
+ *   PaymentTransaction,
+ * } from '@/modules/_stubs/payment';
+ * ```
+ */
+
+// -----------------------------------------------------------------------------
+// Enums
+// -----------------------------------------------------------------------------
+
+/**
+ * Payment status
+ */
+export enum PaymentStatus {
+  /** Payment pending processing */
+  PENDING = 'PENDING',
+  /** Payment being processed */
+  PROCESSING = 'PROCESSING',
+  /** Payment completed successfully */
+  COMPLETED = 'COMPLETED',
+  /** Payment failed */
+  FAILED = 'FAILED',
+  /** Payment refunded */
+  REFUNDED = 'REFUNDED',
+  /** Payment partially refunded */
+  PARTIALLY_REFUNDED = 'PARTIALLY_REFUNDED',
+  /** Payment cancelled */
+  CANCELLED = 'CANCELLED',
+}
+
+/**
+ * Payment method types
+ */
+export enum PaymentMethod {
+  /** Credit card */
+  CREDIT_CARD = 'CREDIT_CARD',
+  /** Debit card */
+  DEBIT_CARD = 'DEBIT_CARD',
+  /** Bank transfer */
+  BANK_TRANSFER = 'BANK_TRANSFER',
+  /** Cash on delivery */
+  CASH = 'CASH',
+  /** Digital wallet */
+  WALLET = 'WALLET',
+}
+
+/**
+ * Payment gateway providers
+ */
+export enum PaymentGateway {
+  /** iyzico payment gateway */
+  IYZICO = 'IYZICO',
+  /** Stripe payment gateway */
+  STRIPE = 'STRIPE',
+  /** Manual entry (cash/pos) */
+  MANUAL = 'MANUAL',
+}
+
+// -----------------------------------------------------------------------------
+// Entity Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Payment transaction entity
+ */
+export interface PaymentTransaction {
+  /** Transaction ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Order ID */
+  orderId: string;
+  /** Amount in minor units (kuruş) */
+  amount: number;
+  /** Currency code (TRY) */
+  currency: string;
+  /** Payment status */
+  status: PaymentStatus;
+  /** Payment method */
+  method: PaymentMethod;
+  /** Payment gateway */
+  gateway: PaymentGateway;
+  /** External transaction ID */
+  externalId: string | null;
+  /** Refunded amount */
+  refundedAmount: number;
+  /** Error message if failed */
+  errorMessage: string | null;
+  /** Gateway response data */
+  gatewayResponse: Record<string, unknown> | null;
+  /** Transaction metadata */
+  metadata: Record<string, unknown> | null;
+  /** Created at */
+  createdAt: Date;
+  /** Updated at */
+  updatedAt: Date;
+}
+
+/**
+ * Payment method configuration
+ */
+export interface PaymentMethodConfig {
+  /** Method ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Gateway provider */
+  gateway: PaymentGateway;
+  /** Is enabled */
+  isEnabled: boolean;
+  /** Gateway credentials (encrypted) */
+  credentials: Record<string, unknown>;
+  /** Gateway-specific settings */
+  settings: Record<string, unknown>;
+  /** Created at */
+  createdAt: Date;
+  /** Updated at */
+  updatedAt: Date;
+}
+
+// -----------------------------------------------------------------------------
+// Request Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Process payment request
+ */
+export interface ProcessPaymentRequest {
+  /** Order ID */
+  orderId: string;
+  /** Amount in minor units */
+  amount: number;
+  /** Currency code */
+  currency?: string;
+  /** Payment method */
+  method: PaymentMethod;
+  /** Payment gateway */
+  gateway: PaymentGateway;
+  /** Card details (if applicable) */
+  card?: CardDetails;
+  /** Customer info */
+  customer?: CustomerInfo;
+  /** Additional metadata */
+  metadata?: Record<string, unknown>;
+}
+
+/**
+ * Card details
+ */
+export interface CardDetails {
+  /** Card holder name */
+  holderName: string;
+  /** Card number (tokenized) */
+  cardToken: string;
+  /** Expiry month */
+  expiryMonth: number;
+  /** Expiry year */
+  expiryYear: number;
+}
+
+/**
+ * Customer info for payment
+ */
+export interface CustomerInfo {
+  /** Customer ID */
+  id?: string;
+  /** Customer email */
+  email: string;
+  /** Customer phone */
+  phone?: string;
+  /** Customer name */
+  name: string;
+  /** Billing address */
+  address?: AddressInfo;
+}
+
+/**
+ * Address info
+ */
+export interface AddressInfo {
+  /** Street address */
+  street: string;
+  /** City */
+  city: string;
+  /** State/Province */
+  state?: string;
+  /** Postal code */
+  postalCode: string;
+  /** Country code */
+  country: string;
+}
+
+/**
+ * Refund request
+ */
+export interface RefundRequest {
+  /** Transaction ID */
+  transactionId: string;
+  /** Refund amount (partial or full) */
+  amount?: number;
+  /** Refund reason */
+  reason?: string;
+}
+
+// -----------------------------------------------------------------------------
+// Response Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Payment result
+ */
+export interface PaymentResult {
+  /** Operation success */
+  success: boolean;
+  /** Transaction ID */
+  transactionId?: string;
+  /** External transaction ID */
+  externalId?: string;
+  /** Payment status */
+  status: PaymentStatus;
+  /** Error code */
+  errorCode?: string;
+  /** Error message */
+  errorMessage?: string;
+  /** Gateway response */
+  gatewayResponse?: Record<string, unknown>;
+}
+
+/**
+ * Refund result
+ */
+export interface RefundResult {
+  /** Operation success */
+  success: boolean;
+  /** Refund ID */
+  refundId?: string;
+  /** Refunded amount */
+  refundedAmount: number;
+  /** New transaction status */
+  status: PaymentStatus;
+  /** Error message */
+  errorMessage?: string;
+}
+
+// -----------------------------------------------------------------------------
+// Service Interfaces
+// -----------------------------------------------------------------------------
+
+/**
+ * Payment service interface
+ *
+ * Main interface for payment processing operations.
+ */
+export interface IPaymentService {
+  /**
+   * Process a payment
+   */
+  processPayment(
+    organizationId: string,
+    request: ProcessPaymentRequest
+  ): Promise<PaymentResult>;
+
+  /**
+   * Refund a payment
+   */
+  refund(
+    organizationId: string,
+    request: RefundRequest
+  ): Promise<RefundResult>;
+
+  /**
+   * Get payment status
+   */
+  getPaymentStatus(
+    organizationId: string,
+    transactionId: string
+  ): Promise<PaymentTransaction>;
+
+  /**
+   * Get payments for an order
+   */
+  getOrderPayments(
+    organizationId: string,
+    orderId: string
+  ): Promise<PaymentTransaction[]>;
+
+  /**
+   * Cancel a pending payment
+   */
+  cancelPayment(
+    organizationId: string,
+    transactionId: string
+  ): Promise<PaymentResult>;
+}
+
+/**
+ * Payment gateway service interface
+ *
+ * Interface for payment gateway integrations.
+ */
+export interface IPaymentGatewayService {
+  /** Gateway identifier */
+  readonly gateway: PaymentGateway;
+
+  /**
+   * Initialize payment with gateway
+   */
+  initializePayment(
+    config: PaymentMethodConfig,
+    request: ProcessPaymentRequest
+  ): Promise<PaymentResult>;
+
+  /**
+   * Process refund with gateway
+   */
+  processRefund(
+    config: PaymentMethodConfig,
+    transactionId: string,
+    amount: number
+  ): Promise<RefundResult>;
+
+  /**
+   * Verify payment status with gateway
+   */
+  verifyPayment(
+    config: PaymentMethodConfig,
+    externalId: string
+  ): Promise<PaymentStatus>;
+
+  /**
+   * Handle webhook from gateway
+   */
+  handleWebhook(
+    config: PaymentMethodConfig,
+    payload: unknown
+  ): Promise<PaymentResult>;
+}
+
+// -----------------------------------------------------------------------------
+// Event Payload Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Payment initiated event payload
+ */
+export interface PaymentInitiatedEventPayload {
+  organizationId: string;
+  transactionId: string;
+  orderId: string;
+  amount: number;
+  method: PaymentMethod;
+  gateway: PaymentGateway;
+  timestamp: string;
+}
+
+/**
+ * Payment completed event payload
+ */
+export interface PaymentCompletedEventPayload {
+  organizationId: string;
+  transactionId: string;
+  orderId: string;
+  amount: number;
+  externalId: string | null;
+  timestamp: string;
+}
+
+/**
+ * Payment failed event payload
+ */
+export interface PaymentFailedEventPayload {
+  organizationId: string;
+  transactionId: string;
+  orderId: string;
+  errorCode: string;
+  errorMessage: string;
+  timestamp: string;
+}
+
+/**
+ * Payment refunded event payload
+ */
+export interface PaymentRefundedEventPayload {
+  organizationId: string;
+  transactionId: string;
+  orderId: string;
+  refundedAmount: number;
+  totalRefunded: number;
+  isFullRefund: boolean;
+  timestamp: string;
+}

