+/**
+ * POS Module Types
+ *
+ * Type definitions for future POS (Point of Sale) module implementation.
+ * This file defines interfaces for POS integration, order sync,
+ * and receipt management.
+ *
+ * @module modules/_stubs/pos/types
+ *
+ * @example
+ * ```typescript
+ * import type {
+ *   IPosService,
+ *   PosConnection,
+ *   PosOrder,
+ * } from '@/modules/_stubs/pos';
+ * ```
+ */
+
+// -----------------------------------------------------------------------------
+// Enums
+// -----------------------------------------------------------------------------
+
+/**
+ * POS provider
+ */
+export enum PosProvider {
+  /** Adisyo POS */
+  ADISYO = 'ADISYO',
+  /** Protel POS */
+  PROTEL = 'PROTEL',
+  /** Mikro POS */
+  MIKRO = 'MIKRO',
+  /** Generic REST API */
+  GENERIC_REST = 'GENERIC_REST',
+  /** Custom integration */
+  CUSTOM = 'CUSTOM',
+}
+
+/**
+ * POS connection status
+ */
+export enum PosConnectionStatus {
+  /** Connected and operational */
+  CONNECTED = 'CONNECTED',
+  /** Disconnected */
+  DISCONNECTED = 'DISCONNECTED',
+  /** Connection error */
+  ERROR = 'ERROR',
+  /** Connecting */
+  CONNECTING = 'CONNECTING',
+  /** Syncing data */
+  SYNCING = 'SYNCING',
+}
+
+/**
+ * Sync direction
+ */
+export enum SyncDirection {
+  /** From E-Menum to POS */
+  TO_POS = 'TO_POS',
+  /** From POS to E-Menum */
+  FROM_POS = 'FROM_POS',
+  /** Bidirectional */
+  BIDIRECTIONAL = 'BIDIRECTIONAL',
+}
+
+/**
+ * Sync entity type
+ */
+export enum SyncEntityType {
+  /** Order sync */
+  ORDER = 'ORDER',
+  /** Menu/Product sync */
+  MENU = 'MENU',
+  /** Category sync */
+  CATEGORY = 'CATEGORY',
+  /** Inventory sync */
+  INVENTORY = 'INVENTORY',
+  /** Customer sync */
+  CUSTOMER = 'CUSTOMER',
+  /** Payment sync */
+  PAYMENT = 'PAYMENT',
+}
+
+/**
+ * Sync status
+ */
+export enum SyncStatus {
+  /** Sync pending */
+  PENDING = 'PENDING',
+  /** Sync in progress */
+  IN_PROGRESS = 'IN_PROGRESS',
+  /** Sync completed */
+  COMPLETED = 'COMPLETED',
+  /** Sync failed */
+  FAILED = 'FAILED',
+  /** Sync skipped */
+  SKIPPED = 'SKIPPED',
+}
+
+// -----------------------------------------------------------------------------
+// Entity Types
+// -----------------------------------------------------------------------------
+
+/**
+ * POS connection entity
+ */
+export interface PosConnection {
+  /** Connection ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Branch ID */
+  branchId: string;
+  /** POS provider */
+  provider: PosProvider;
+  /** Connection name */
+  name: string;
+  /** Status */
+  status: PosConnectionStatus;
+  /** API endpoint URL */
+  apiEndpoint: string | null;
+  /** Credentials (encrypted) */
+  credentials: Record<string, unknown>;
+  /** Configuration */
+  config: PosConfig;
+  /** Last sync timestamp */
+  lastSyncAt: Date | null;
+  /** Last error */
+  lastError: string | null;
+  /** Created at */
+  createdAt: Date;
+  /** Updated at */
+  updatedAt: Date;
+}
+
+/**
+ * POS configuration
+ */
+export interface PosConfig {
+  /** Sync direction */
+  syncDirection: SyncDirection;
+  /** Auto sync enabled */
+  autoSyncEnabled: boolean;
+  /** Auto sync interval (minutes) */
+  autoSyncIntervalMinutes: number;
+  /** Entities to sync */
+  syncEntities: SyncEntityType[];
+  /** Menu mapping enabled */
+  menuMappingEnabled: boolean;
+  /** Receipt printing enabled */
+  receiptPrintingEnabled: boolean;
+  /** Cash drawer enabled */
+  cashDrawerEnabled: boolean;
+  /** Offline mode enabled */
+  offlineModeEnabled: boolean;
+}
+
+/**
+ * POS sync record
+ */
+export interface PosSyncRecord {
+  /** Record ID */
+  id: string;
+  /** Connection ID */
+  connectionId: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Entity type */
+  entityType: SyncEntityType;
+  /** Direction */
+  direction: SyncDirection;
+  /** Status */
+  status: SyncStatus;
+  /** Items synced */
+  itemsSynced: number;
+  /** Items failed */
+  itemsFailed: number;
+  /** Error message */
+  errorMessage: string | null;
+  /** Started at */
+  startedAt: Date;
+  /** Completed at */
+  completedAt: Date | null;
+  /** Duration (ms) */
+  durationMs: number | null;
+}
+
+/**
+ * POS order (external representation)
+ */
+export interface PosOrder {
+  /** POS order ID */
+  posOrderId: string;
+  /** E-Menum order ID */
+  emenumOrderId: string | null;
+  /** Order number */
+  orderNumber: string;
+  /** Table number */
+  tableNumber: string | null;
+  /** Order items */
+  items: PosOrderItem[];
+  /** Subtotal */
+  subtotal: number;
+  /** Tax */
+  tax: number;
+  /** Discount */
+  discount: number;
+  /** Total */
+  total: number;
+  /** Payment status */
+  paymentStatus: string;
+  /** Created at */
+  createdAt: Date;
+}
+
+/**
+ * POS order item
+ */
+export interface PosOrderItem {
+  /** POS item ID */
+  posItemId: string;
+  /** E-Menum item ID */
+  emenumItemId: string | null;
+  /** Item name */
+  name: string;
+  /** Quantity */
+  quantity: number;
+  /** Unit price */
+  unitPrice: number;
+  /** Total price */
+  totalPrice: number;
+  /** Modifiers */
+  modifiers: string[];
+  /** Notes */
+  notes: string | null;
+}
+
+/**
+ * Menu mapping
+ */
+export interface MenuMapping {
+  /** Mapping ID */
+  id: string;
+  /** Connection ID */
+  connectionId: string;
+  /** E-Menum item ID */
+  emenumItemId: string;
+  /** POS item ID */
+  posItemId: string;
+  /** POS item name */
+  posItemName: string;
+  /** Is active */
+  isActive: boolean;
+  /** Created at */
+  createdAt: Date;
+  /** Updated at */
+  updatedAt: Date;
+}
+
+// -----------------------------------------------------------------------------
+// Request Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Create POS connection request
+ */
+export interface CreatePosConnectionRequest {
+  /** Branch ID */
+  branchId: string;
+  /** POS provider */
+  provider: PosProvider;
+  /** Connection name */
+  name: string;
+  /** API endpoint (if applicable) */
+  apiEndpoint?: string;
+  /** Credentials */
+  credentials: Record<string, unknown>;
+  /** Configuration */
+  config?: Partial<PosConfig>;
+}
+
+/**
+ * Update POS connection request
+ */
+export interface UpdatePosConnectionRequest {
+  /** Connection name */
+  name?: string;
+  /** API endpoint */
+  apiEndpoint?: string;
+  /** Credentials */
+  credentials?: Record<string, unknown>;
+  /** Configuration */
+  config?: Partial<PosConfig>;
+}
+
+/**
+ * Sync request
+ */
+export interface SyncRequest {
+  /** Connection ID */
+  connectionId: string;
+  /** Entity types to sync */
+  entityTypes?: SyncEntityType[];
+  /** Force full sync */
+  fullSync?: boolean;
+}
+
+/**
+ * Create menu mapping request
+ */
+export interface CreateMenuMappingRequest {
+  /** Connection ID */
+  connectionId: string;
