+    connectionId: string
+  ): Promise<{ mapped: number; unmapped: number }>;
+}
+
+// -----------------------------------------------------------------------------
+// Event Payload Types
+// -----------------------------------------------------------------------------
+
+/**
+ * POS connected event payload
+ */
+export interface PosConnectedEventPayload {
