+  timestamp: string;
+}
+
+/**
+ * POS disconnected event payload
+ */
+export interface PosDisconnectedEventPayload {
+  organizationId: string;
+  connectionId: string;
+  reason: string;
+  timestamp: string;
+}
+
+/**
+ * POS order synced event payload
+ */
+export interface PosOrderSyncedEventPayload {
+  organizationId: string;
+  connectionId: string;
+  emenumOrderId: string;
+  posOrderId: string;
+  direction: SyncDirection;
+  timestamp: string;
+}
+
+/**
+ * POS sync failed event payload
+ */
+export interface PosSyncFailedEventPayload {
+  organizationId: string;
+  connectionId: string;
+  entityType: SyncEntityType;
+  errorMessage: string;
+  itemsFailed: number;
+  timestamp: string;
+}

