+/**
+ * Reservation Module Types
+ *
+ * Type definitions for future reservation module implementation.
+ * This file defines interfaces for reservation management,
+ * availability checking, and booking operations.
+ *
+ * @module modules/_stubs/reservation/types
+ *
+ * @example
+ * ```typescript
+ * import type {
+ *   IReservationService,
+ *   Reservation,
+ *   ReservationStatus,
+ * } from '@/modules/_stubs/reservation';
+ * ```
+ */
+
+// -----------------------------------------------------------------------------
+// Enums
+// -----------------------------------------------------------------------------
+
+/**
+ * Reservation status
+ */
+export enum ReservationStatus {
+  /** Reservation is pending confirmation */
+  PENDING = 'PENDING',
+  /** Reservation is confirmed */
+  CONFIRMED = 'CONFIRMED',
+  /** Reservation is cancelled */
+  CANCELLED = 'CANCELLED',
+  /** Guest has been seated */
+  SEATED = 'SEATED',
+  /** Reservation is completed */
+  COMPLETED = 'COMPLETED',
+  /** Guest did not show up */
+  NO_SHOW = 'NO_SHOW',
+  /** Reservation is on waitlist */
+  WAITLIST = 'WAITLIST',
+}
+
+/**
+ * Reservation source
+ */
+export enum ReservationSource {
+  /** Direct booking via phone/in-person */
+  DIRECT = 'DIRECT',
+  /** Online booking widget */
+  ONLINE = 'ONLINE',
+  /** Third-party platform */
+  THIRD_PARTY = 'THIRD_PARTY',
+  /** Walk-in converted to reservation */
+  WALK_IN = 'WALK_IN',
+}
+
+/**
+ * Time slot status
+ */
+export enum TimeSlotStatus {
+  /** Slot is available */
+  AVAILABLE = 'AVAILABLE',
+  /** Slot is partially available */
+  LIMITED = 'LIMITED',
+  /** Slot is fully booked */
+  FULL = 'FULL',
+  /** Slot is blocked */
+  BLOCKED = 'BLOCKED',
+}
+
+// -----------------------------------------------------------------------------
+// Entity Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Reservation entity
+ */
+export interface Reservation {
+  /** Reservation ID */
+  id: string;
+  /** Organization ID */
+  organizationId: string;
+  /** Branch ID */
+  branchId: string;
+  /** Customer ID (if registered) */
+  customerId: string | null;
+  /** Table ID (if assigned) */
+  tableId: string | null;
+  /** Guest name */
+  guestName: string;
+  /** Guest email */
+  guestEmail: string | null;
+  /** Guest phone */
+  guestPhone: string;
+  /** Party size */
+  partySize: number;
+  /** Reservation date */
+  reservationDate: Date;
+  /** Start time */
+  startTime: string;
+  /** End time (estimated) */
+  endTime: string | null;
+  /** Status */
+  status: ReservationStatus;
+  /** Source */
+  source: ReservationSource;
+  /** Special requests/notes */
+  notes: string | null;
+  /** Internal notes (staff only) */
+  internalNotes: string | null;
+  /** Confirmation code */
+  confirmationCode: string;
+  /** Deposit amount (if required) */
+  depositAmount: number | null;
+  /** Deposit paid */
+  depositPaid: boolean;
+  /** Reminder sent */
+  reminderSent: boolean;
+  /** Created by user ID */
+  createdById: string | null;
+  /** Created at */
+  createdAt: Date;
+  /** Updated at */
+  updatedAt: Date;
+  /** Cancelled at */
+  cancelledAt: Date | null;
+  /** Cancellation reason */
+  cancellationReason: string | null;
+}
+
+/**
+ * Time slot
+ */
+export interface TimeSlot {
+  /** Start time (HH:mm) */
+  startTime: string;
+  /** End time (HH:mm) */
+  endTime: string;
+  /** Status */
+  status: TimeSlotStatus;
+  /** Available capacity */
+  availableCapacity: number;
+  /** Total capacity */
+  totalCapacity: number;
+}
+
+/**
+ * Reservation settings
+ */
+export interface ReservationSettings {
+  /** Organization ID */
+  organizationId: string;
+  /** Minimum advance booking (hours) */
+  minAdvanceHours: number;
+  /** Maximum advance booking (days) */
+  maxAdvanceDays: number;
+  /** Default reservation duration (minutes) */
+  defaultDuration: number;
+  /** Slot interval (minutes) */
+  slotInterval: number;
+  /** Auto-confirm reservations */
+  autoConfirm: boolean;
+  /** Require deposit */
+  requireDeposit: boolean;
+  /** Deposit amount per person */
+  depositPerPerson: number;
+  /** Send reminder */
+  sendReminder: boolean;
+  /** Reminder hours before */
+  reminderHoursBefore: number;
+  /** Max party size */
+  maxPartySize: number;
+  /** Online booking enabled */
+  onlineBookingEnabled: boolean;
+}
+
+// -----------------------------------------------------------------------------
+// Request Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Create reservation request
+ */
+export interface CreateReservationRequest {
+  /** Branch ID */
+  branchId: string;
+  /** Guest name */
+  guestName: string;
+  /** Guest email */
+  guestEmail?: string;
+  /** Guest phone */
+  guestPhone: string;
+  /** Party size */
+  partySize: number;
+  /** Reservation date */
+  reservationDate: string;
+  /** Start time (HH:mm) */
+  startTime: string;
+  /** Special requests */
+  notes?: string;
+  /** Table preference ID */
+  preferredTableId?: string;
+  /** Source */
+  source?: ReservationSource;
+}
+
+/**
+ * Update reservation request
+ */
+export interface UpdateReservationRequest {
+  /** Guest name */
+  guestName?: string;
+  /** Guest email */
+  guestEmail?: string;
+  /** Guest phone */
+  guestPhone?: string;
+  /** Party size */
+  partySize?: number;
+  /** Reservation date */
+  reservationDate?: string;
+  /** Start time */
+  startTime?: string;
+  /** Notes */
+  notes?: string;
+  /** Table ID */
+  tableId?: string | null;
+  /** Status */
+  status?: ReservationStatus;
+  /** Internal notes */
+  internalNotes?: string;
+}
+
+/**
+ * Check availability request
+ */
+export interface CheckAvailabilityRequest {
+  /** Branch ID */
+  branchId: string;
+  /** Date */
+  date: string;
+  /** Party size */
+  partySize: number;
+  /** Preferred time (optional) */
+  preferredTime?: string;
+}
+
+/**
+ * Cancel reservation request
+ */
+export interface CancelReservationRequest {
+  /** Reservation ID */
+  reservationId: string;
+  /** Cancellation reason */
+  reason?: string;
+  /** Notify guest */
+  notifyGuest?: boolean;
+}
+
+// -----------------------------------------------------------------------------
+// Response Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Availability response
+ */
+export interface AvailabilityResponse {
+  /** Date */
+  date: string;
+  /** Available time slots */
+  timeSlots: TimeSlot[];
+  /** Is date available */
+  isAvailable: boolean;
+}
+
+/**
+ * Reservation result
+ */
+export interface ReservationResult {
+  /** Success */
+  success: boolean;
+  /** Reservation */
+  reservation?: Reservation;
+  /** Confirmation code */
+  confirmationCode?: string;
+  /** Error message */
+  errorMessage?: string;
+}
+
+// -----------------------------------------------------------------------------
+// Service Interfaces
+// -----------------------------------------------------------------------------
+
+/**
+ * Reservation service interface
+ */
+export interface IReservationService {
+  /**
+   * Create a reservation
+   */
+  createReservation(
+    organizationId: string,
+    request: CreateReservationRequest
+  ): Promise<ReservationResult>;
+
+  /**
+   * Update a reservation
+   */
+  updateReservation(
+    organizationId: string,
+    reservationId: string,
+    request: UpdateReservationRequest
+  ): Promise<ReservationResult>;
+
+  /**
+   * Cancel a reservation
+   */
+  cancelReservation(
+    organizationId: string,
+    request: CancelReservationRequest
+  ): Promise<ReservationResult>;
+
+  /**
+   * Get reservation by ID
+   */
+  getReservation(
+    organizationId: string,
+    reservationId: string
+  ): Promise<Reservation>;
+
+  /**
+   * Get reservation by confirmation code
+   */
+  getByConfirmationCode(
+    organizationId: string,
+    code: string
+  ): Promise<Reservation>;
+
+  /**
+   * List reservations
+   */
+  listReservations(
+    organizationId: string,
+    filters?: {
+      branchId?: string;
+      date?: string;
+      status?: ReservationStatus;
+      customerId?: string;
+    }
+  ): Promise<Reservation[]>;
+
+  /**
+   * Confirm a reservation
+   */
+  confirmReservation(
+    organizationId: string,
+    reservationId: string
+  ): Promise<ReservationResult>;
+
+  /**
+   * Mark reservation as seated
+   */
+  markAsSeated(
+    organizationId: string,
+    reservationId: string,
+    tableId: string
+  ): Promise<ReservationResult>;
+
+  /**
+   * Mark reservation as completed
+   */
+  markAsCompleted(
+    organizationId: string,
+    reservationId: string
+  ): Promise<ReservationResult>;
+
+  /**
+   * Mark reservation as no-show
+   */
+  markAsNoShow(
+    organizationId: string,
+    reservationId: string
+  ): Promise<ReservationResult>;
+}
+
+/**
+ * Availability service interface
+ */
+export interface IAvailabilityService {
+  /**
+   * Check availability for a date
+   */
+  checkAvailability(
+    organizationId: string,
+    request: CheckAvailabilityRequest
+  ): Promise<AvailabilityResponse>;
+
+  /**
+   * Get available dates for a period
+   */
+  getAvailableDates(
+    organizationId: string,
+    branchId: string,
+    startDate: string,
+    endDate: string,
+    partySize: number
+  ): Promise<Array<{ date: string; available: boolean }>>;
+
+  /**
+   * Block time slots
+   */
+  blockTimeSlots(
+    organizationId: string,
+    branchId: string,
+    date: string,
+    startTime: string,
+    endTime: string,
+    reason?: string
+  ): Promise<void>;
+
+  /**
+   * Unblock time slots
+   */
+  unblockTimeSlots(
+    organizationId: string,
+    branchId: string,
+    date: string,
+    startTime: string,
+    endTime: string
+  ): Promise<void>;
+}
+
+// -----------------------------------------------------------------------------
+// Event Payload Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Reservation created event payload
+ */
+export interface ReservationCreatedEventPayload {
+  organizationId: string;
+  branchId: string;
+  reservationId: string;
+  confirmationCode: string;
+  guestName: string;
+  partySize: number;
+  reservationDate: string;
+  startTime: string;
+  source: ReservationSource;
+  timestamp: string;
+}
+
+/**
+ * Reservation confirmed event payload
+ */
+export interface ReservationConfirmedEventPayload {
+  organizationId: string;
+  reservationId: string;
+  confirmationCode: string;
+  timestamp: string;
+}
+
+/**
+ * Reservation cancelled event payload
+ */
+export interface ReservationCancelledEventPayload {
+  organizationId: string;
+  reservationId: string;
+  reason: string | null;
+  cancelledBy: string | null;
+  timestamp: string;
+}
+
+/**
+ * Reservation no-show event payload
+ */
+export interface ReservationNoShowEventPayload {
+  organizationId: string;
+  reservationId: string;
+  guestPhone: string;
+  timestamp: string;
+}

