+/**
+ * Category Repository
+ *
+ * Data access layer for Category entities.
+ * Provides tenant-scoped database operations with CRUD support.
+ *
+ * @module modules/menu/category.repository
+ *
+ * @example
+ * ```typescript
+ * import { CategoryRepository } from '@/modules/menu/category.repository';
+ *
+ * const repo = container.resolve('CategoryRepository');
+ * const category = await repo.findBySlug('org_123', 'menu_456', 'appetizers');
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+import { PrismaClient, Prisma } from '@prisma/client';
+
+import { TOKENS } from '@/core/kernel/container';
+import { AppException } from '@/core/exceptions/app.exception';
+import { notDeleted, softDelete } from '@/config/database';
+
+import type {
+  Category,
+  CategoryWithRelations,
+  ListCategoriesQuery,
+} from '@/modules/menu/menu.types';
+
+// -----------------------------------------------------------------------------
+// Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Paginated result type
+ */
+export interface PaginatedResult<T> {
+  /** Array of entities */
+  data: T[];
+  /** Pagination metadata */
+  meta: {
+    page: number;
+    perPage: number;
+    total: number;
+    totalPages: number;
+  };
+}
+
+/**
+ * Category summary for list displays
+ */
+export interface CategorySummary {
+  /** Category ID */
+  id: string;
+  /** Category name */
+  name: string;
+  /** Category slug */
+  slug: string;
+  /** Menu ID */
+  menuId: string;
+  /** Parent ID */
+  parentId: string | null;
+  /** Active status */
+  isActive: boolean;
+  /** Sort order */
+  sortOrder: number;
+  /** Product count */
+  productCount: number;
+  /** Child count */
+  childCount: number;
+  /** Creation timestamp */
+  createdAt: Date;
+}
+
+/**
+ * Create category data (input for repository)
+ */
+export interface CreateCategoryData {
+  menuId: string;
+  parentId?: string | null;
+  name: string;
+  slug: string;
+  description?: string | null;
+  image?: string | null;
+  isActive?: boolean;
+  sortOrder?: number;
+}
+
+/**
+ * Update category data (input for repository)
+ */
+export interface UpdateCategoryData {
+  parentId?: string | null;
+  name?: string;
+  slug?: string;
+  description?: string | null;
+  image?: string | null;
+  isActive?: boolean;
+  sortOrder?: number;
+}
+
+// -----------------------------------------------------------------------------
+// Constants
+// -----------------------------------------------------------------------------
+
+const DEFAULT_PER_PAGE = 50;
+const MAX_PER_PAGE = 100;
+
+// -----------------------------------------------------------------------------
+// Category Repository
+// -----------------------------------------------------------------------------
+
+/**
+ * Repository for Category entity operations.
+ *
+ * Handles all database operations for categories including:
+ * - CRUD operations with tenant isolation
+ * - Slug lookups within menus
+ * - Hierarchical category support (parent/child)
+ * - Reordering operations
+ *
+ * @remarks
+ * All operations require organizationId for tenant isolation.
+ * Soft delete is enforced on all operations.
+ *
+ * @example
+ * ```typescript
+ * @injectable()
+ * class CategoryService {
+ *   constructor(
+ *     @inject('CategoryRepository') private repo: CategoryRepository
+ *   ) {}
+ *
+ *   async getBySlug(orgId: string, menuId: string, slug: string) {
+ *     return this.repo.findBySlug(orgId, menuId, slug);
+ *   }
+ * }
+ * ```
+ */
+@injectable()
+export class CategoryRepository {
+  constructor(
+    @inject(TOKENS.PrismaClient) private readonly prisma: PrismaClient
+  ) {}
+
+  // ---------------------------------------------------------------------------
+  // Read Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Finds all categories for an organization with pagination and filtering
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param params - Query parameters (pagination, sorting, filtering)
+   * @returns Paginated list of categories
+   *
+   * @example
+   * ```typescript
+   * const result = await repo.findAll('org_123', {
+   *   menuId: 'menu_456',
+   *   page: 1,
+   *   perPage: 50,
+   *   isActive: true,
+   * });
+   * ```
+   */
+  async findAll(
+    organizationId: string,
+    params: ListCategoriesQuery = {}
+  ): Promise<PaginatedResult<Category>> {
+    const {
+      menuId,
+      parentId,
+      isActive,
+      search,
+      page = 1,
+      perPage = DEFAULT_PER_PAGE,
+    } = params;
+
+    // Normalize pagination
+    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
+    const normalizedPage = Math.max(1, page);
+    const skip = (normalizedPage - 1) * normalizedPerPage;
+
+    // Build where clause
+    const where: Prisma.CategoryWhereInput = {
+      organizationId,
+      ...notDeleted,
+      ...(menuId !== undefined && { menuId }),
+      ...(parentId !== undefined && { parentId }),
+      ...(isActive !== undefined && { isActive }),
+      ...(search && {
+        OR: [
+          { name: { contains: search, mode: 'insensitive' } },
+          { slug: { contains: search, mode: 'insensitive' } },
+          { description: { contains: search, mode: 'insensitive' } },
+        ],
+      }),
+    };
+
+    // Execute count and find in parallel
+    const [total, data] = await Promise.all([
+      this.prisma.category.count({ where }),
+      this.prisma.category.findMany({
+        where,
+        orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+        skip,
+        take: normalizedPerPage,
+      }),
+    ]);
+
+    return {
+      data: data as Category[],
+      meta: {
+        page: normalizedPage,
+        perPage: normalizedPerPage,
+        total,
+        totalPages: Math.ceil(total / normalizedPerPage),
+      },
+    };
+  }
+
+  /**
+   * Finds all categories as summaries (for dropdowns, etc.)
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param menuId - Menu ID filter
+   * @param params - Optional filtering params
+   * @returns Array of category summaries
+   */
+  async findAllSummaries(
+    organizationId: string,
+    menuId: string,
+    params: Partial<ListCategoriesQuery> = {}
+  ): Promise<CategorySummary[]> {
+    const { isActive, parentId } = params;
+
+    const where: Prisma.CategoryWhereInput = {
+      organizationId,
+      menuId,
+      ...notDeleted,
+      ...(isActive !== undefined && { isActive }),
+      ...(parentId !== undefined && { parentId }),
+    };
+
+    const categories = await this.prisma.category.findMany({
+      where,
+      select: {
+        id: true,
+        name: true,
+        slug: true,
+        menuId: true,
+        parentId: true,
+        isActive: true,
+        sortOrder: true,
+        createdAt: true,
+        _count: {
+          select: {
+            products: {
+              where: notDeleted,
+            },
+            children: {
+              where: notDeleted,
+            },
+          },
+        },
+      },
+      orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+    });
+
+    return categories.map((cat) => ({
+      id: cat.id,
+      name: cat.name,
+      slug: cat.slug,
+      menuId: cat.menuId,
+      parentId: cat.parentId,
+      isActive: cat.isActive,
+      sortOrder: cat.sortOrder,
+      productCount: cat._count.products,
+      childCount: cat._count.children,
+      createdAt: cat.createdAt,
+    }));
+  }
+
+  /**
+   * Finds categories by menu ID
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param menuId - Menu ID
+   * @param parentId - Optional parent ID filter (null for root categories)
+   * @returns Array of categories
+   */
+  async findByMenuId(
+    organizationId: string,
+    menuId: string,
+    parentId?: string | null
+  ): Promise<Category[]> {
+    const where: Prisma.CategoryWhereInput = {
+      organizationId,
+      menuId,
+      ...notDeleted,
+      ...(parentId !== undefined && { parentId }),
+    };
+
+    const result = await this.prisma.category.findMany({
+      where,
+      orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+    });
+
+    return result as Category[];
+  }
+
+  /**
+   * Finds a category by ID with tenant isolation
+   *
+   * @param id - Category ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Category or null
+   */
+  async findById(id: string, organizationId: string): Promise<Category | null> {
+    const result = await this.prisma.category.findFirst({
+      where: { id, organizationId, ...notDeleted },
+    });
+
+    return result as Category | null;
+  }
+
+  /**
+   * Finds a category by ID with relations
+   *
+   * @param id - Category ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @param includeProducts - Include products in response
+   * @returns Category with relations or null
+   */
+  async findByIdWithRelations(
+    id: string,
+    organizationId: string,
+    includeProducts = false
+  ): Promise<CategoryWithRelations | null> {
+    const result = await this.prisma.category.findFirst({
+      where: { id, organizationId, ...notDeleted },
+      include: {
+        parent: true,
+        children: {
+          where: notDeleted,
+          orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+        },
+        ...(includeProducts && {
+          products: {
+            where: notDeleted,
+            orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+          },
+        }),
+      },
+    });
+
+    return result as CategoryWithRelations | null;
+  }
+
+  /**
+   * Finds a category by ID or throws
+   *
+   * @param id - Category ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Category
+   * @throws {AppException} If not found
+   */
+  async findByIdOrThrow(id: string, organizationId: string): Promise<Category> {
+    const category = await this.findById(id, organizationId);
+
+    if (!category) {
+      throw AppException.notFound('Category', id);
+    }
+
+    return category;
+  }
+
+  /**
+   * Finds a category by slug within a menu
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param menuId - Menu ID
+   * @param slug - Category slug
+   * @returns Category or null
+   */
+  async findBySlug(
+    organizationId: string,
+    menuId: string,
+    slug: string
+  ): Promise<Category | null> {
+    const result = await this.prisma.category.findFirst({
+      where: { organizationId, menuId, slug, ...notDeleted },
+    });
+
+    return result as Category | null;
+  }
+
+  /**
+   * Finds a category by slug or throws
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param menuId - Menu ID
+   * @param slug - Category slug
+   * @returns Category
+   * @throws {AppException} If not found
+   */
+  async findBySlugOrThrow(
+    organizationId: string,
+    menuId: string,
+    slug: string
+  ): Promise<Category> {
+    const category = await this.findBySlug(organizationId, menuId, slug);
+
+    if (!category) {
+      throw AppException.notFound('Category', slug);
+    }
+
+    return category;
+  }
+
+  /**
+   * Checks if a category slug exists within a menu
+   *
+   * @param organizationId - Organization ID
+   * @param menuId - Menu ID
+   * @param slug - Slug to check
+   * @param excludeId - Optional ID to exclude from check
+   * @returns True if slug exists
+   */
+  async slugExists(
+    organizationId: string,
+    menuId: string,
+    slug: string,
+    excludeId?: string
+  ): Promise<boolean> {
+    const count = await this.prisma.category.count({
+      where: {
+        organizationId,
+        menuId,
+        slug,
+        ...notDeleted,
+        ...(excludeId && { id: { not: excludeId } }),
+      },
+    });
+
+    return count > 0;
+  }
+
+  /**
+   * Counts categories for a menu
+   *
+   * @param organizationId - Organization ID
+   * @param menuId - Menu ID
+   * @param isActive - Optional active status filter
+   * @returns Count
+   */
+  async count(
+    organizationId: string,
+    menuId: string,
+    isActive?: boolean
+  ): Promise<number> {
+    return this.prisma.category.count({
+      where: {
+        organizationId,
+        menuId,
+        ...notDeleted,
+        ...(isActive !== undefined && { isActive }),
+      },
+    });
+  }
+
+  /**
+   * Counts categories across all menus for an organization
+   *
+   * @param organizationId - Organization ID
+   * @returns Count
+   */
+  async countAll(organizationId: string): Promise<number> {
+    return this.prisma.category.count({
+      where: {
+        organizationId,
+        ...notDeleted,
+      },
+    });
+  }
+
+  // ---------------------------------------------------------------------------
+  // Write Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Creates a new category
+   *
+   * @param organizationId - Organization ID for tenant association
+   * @param data - Create data
+   * @returns Created category
+   */
+  async create(organizationId: string, data: CreateCategoryData): Promise<Category> {
+    const result = await this.prisma.category.create({
+      data: {
+        organizationId,
+        menuId: data.menuId,
+        parentId: data.parentId || null,
+        name: data.name,
+        slug: data.slug,
+        description: data.description || null,
+        image: data.image || null,
+        isActive: data.isActive ?? true,
+        sortOrder: data.sortOrder ?? 0,
+      },
+    });
+
+    return result as Category;
+  }
+
+  /**
+   * Updates a category
+   *
+   * @param id - Category ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @param data - Update data
+   * @returns Updated category
+   * @throws {AppException} If not found
+   */
+  async update(
+    id: string,
+    organizationId: string,
+    data: UpdateCategoryData
+  ): Promise<Category> {
+    // Verify exists
+    await this.findByIdOrThrow(id, organizationId);
+
+    const result = await this.prisma.category.update({
+      where: { id },
+      data: {
+        ...(data.parentId !== undefined && { parentId: data.parentId }),
+        ...(data.name !== undefined && { name: data.name }),
+        ...(data.slug !== undefined && { slug: data.slug }),
+        ...(data.description !== undefined && { description: data.description }),
+        ...(data.image !== undefined && { image: data.image }),
+        ...(data.isActive !== undefined && { isActive: data.isActive }),
+        ...(data.sortOrder !== undefined && { sortOrder: data.sortOrder }),
+      },
+    });
+
+    return result as Category;
+  }
+
+  /**
+   * Updates category sort orders in batch
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param menuId - Menu ID
+   * @param items - Array of ID and sortOrder pairs
+   */
+  async reorder(
+    organizationId: string,
+    menuId: string,
+    items: Array<{ id: string; sortOrder: number }>
+  ): Promise<void> {
+    // Verify all categories exist and belong to the menu
+    const categoryIds = items.map((item) => item.id);
+    const existingCount = await this.prisma.category.count({
+      where: {
+        id: { in: categoryIds },
+        organizationId,
+        menuId,
+        ...notDeleted,
+      },
+    });
+
+    if (existingCount !== categoryIds.length) {
+      throw new AppException('INVALID_CATEGORIES', 400, {
+        message: 'Some categories do not exist or do not belong to this menu',
+      });
+    }
+
+    // Update sort orders in transaction
+    await this.prisma.$transaction(
+      items.map((item) =>
+        this.prisma.category.update({
+          where: { id: item.id },
+          data: { sortOrder: item.sortOrder },
+        })
+      )
+    );
+  }
+
+  /**
+   * Moves a category to a different parent
+   *
+   * @param id - Category ID
+   * @param organizationId - Organization ID
+   * @param newParentId - New parent ID (null for root)
+   * @returns Updated category
+   */
+  async moveToParent(
+    id: string,
+    organizationId: string,
+    newParentId: string | null
+  ): Promise<Category> {
+    // Verify category exists
+    const category = await this.findByIdOrThrow(id, organizationId);
+
+    // Prevent circular reference
+    if (newParentId) {
+      const parent = await this.findByIdOrThrow(newParentId, organizationId);
+      if (parent.parentId === id) {
+        throw new AppException('CIRCULAR_REFERENCE', 400, {
+          message: 'Cannot move category to its own child',
+        });
+      }
+    }
+
+    const result = await this.prisma.category.update({
+      where: { id },
+      data: { parentId: newParentId },
+    });
+
+    return result as Category;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Delete Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Soft deletes a category
+   *
+   * @param id - Category ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Deleted category
+   * @throws {AppException} If not found
+   */
+  async softDelete(id: string, organizationId: string): Promise<Category> {
+    await this.findByIdOrThrow(id, organizationId);
+
+    const result = await this.prisma.category.update({
+      where: { id },
+      data: softDelete(),
+    });
+
+    return result as Category;
+  }
+
+  /**
+   * Restores a soft-deleted category
+   *
+   * @param id - Category ID
+   * @param organizationId - Organization ID
+   * @returns Restored category
+   */
+  async restore(id: string, organizationId: string): Promise<Category> {
+    // Find including deleted
+    const category = await this.prisma.category.findFirst({
+      where: { id, organizationId },
+    });
+
+    if (!category) {
+      throw AppException.notFound('Category', id);
+    }
+
+    const result = await this.prisma.category.update({
+      where: { id },
+      data: { deletedAt: null },
+    });
+
+    return result as Category;
+  }
+
+  /**
+   * Soft deletes all categories in a menu
+   *
+   * @param organizationId - Organization ID
+   * @param menuId - Menu ID
+   * @returns Number of deleted categories
+   */
+  async softDeleteByMenuId(organizationId: string, menuId: string): Promise<number> {
+    const result = await this.prisma.category.updateMany({
+      where: {
+        organizationId,
+        menuId,
+        ...notDeleted,
+      },
+      data: softDelete(),
+    });
+
+    return result.count;
+  }
+}

