+/**
+ * Category Module Service
+ *
+ * Business logic service for the Category module.
+ * Handles category CRUD, hierarchy management, and reordering.
+ *
+ * @module modules/menu/category.service
+ *
+ * @example
+ * ```typescript
+ * import { CategoryService } from '@/modules/menu/category.service';
+ * import { resolve } from '@/core/kernel/container';
+ *
+ * const categoryService = resolve<CategoryService>('CategoryService');
+ *
+ * // Create a new category
+ * const result = await categoryService.create('org_123', {
+ *   menuId: 'menu_456',
+ *   name: 'Appetizers',
+ * });
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+
+import { TOKENS } from '@/core/kernel/container';
+import { AppException } from '@/core/exceptions/app.exception';
+import { EventService } from '@/core/services/event.service';
+
+import { CategoryRepository, PaginatedResult } from '@/modules/menu/category.repository';
+import { MenuRepository } from '@/modules/menu/menu.repository';
+
+import type {
+  Category,
+  CategoryWithRelations,
+  CreateCategoryRequest,
+  UpdateCategoryRequest,
+  ReorderCategoriesRequest,
+  ListCategoriesQuery,
+} from '@/modules/menu/menu.types';
+
+import {
+  createCategorySchema,
+  updateCategorySchema,
+  reorderCategoriesSchema,
+  listCategoriesQuerySchema,
+  generateSlug,
+  type CreateCategoryInput,
+  type UpdateCategoryInput,
+  type ReorderCategoriesInput,
+  type ListCategoriesQueryInput,
+} from '@/modules/menu/menu.schema';
+
+// -----------------------------------------------------------------------------
+// Types
+// -----------------------------------------------------------------------------
+
+/**
+ * User context for operations
+ */
+interface UserContext {
+  /** User ID making the request */
+  userId?: string;
+  /** Whether user is a platform admin */
+  isPlatformAdmin?: boolean;
+}
+
+/**
+ * Create category response
+ */
+export interface CreateCategoryResponse {
+  /** Created category */
+  category: Category;
+  /** Response message */
+  message: string;
+}
+
+/**
+ * Update category response
+ */
+export interface UpdateCategoryResponse {
+  /** Updated category */
+  category: Category;
+  /** Response message */
+  message: string;
+}
+
+/**
+ * Reorder categories response
+ */
+export interface ReorderCategoriesResponse {
+  /** Reordered category count */
+  count: number;
+  /** Response message */
+  message: string;
+}
+
+// -----------------------------------------------------------------------------
+// Category Service
+// -----------------------------------------------------------------------------
+
+/**
+ * Category module business logic service.
+ *
+ * Handles all category-related business operations including:
+ * - Category CRUD operations with tenant isolation
+ * - Hierarchical category management (parent/child)
+ * - Category reordering
+ * - Slug generation and uniqueness
+ *
+ * @example
+ * ```typescript
+ * @injectable()
+ * class SomeController {
+ *   constructor(
+ *     @inject('CategoryService') private categoryService: CategoryService,
+ *   ) {}
+ *
+ *   async handleCreate(req: Request, res: Response) {
+ *     const result = await this.categoryService.create(req.orgId, req.body);
+ *     res.json(result);
+ *   }
+ * }
+ * ```
+ */
+@injectable()
+export class CategoryService {
+  constructor(
+    @inject('CategoryRepository') private readonly repository: CategoryRepository,
+    @inject('MenuRepository') private readonly menuRepository: MenuRepository,
+    @inject(TOKENS.EventService) private readonly eventService: EventService
+  ) {}
+
+  // ---------------------------------------------------------------------------
+  // Read Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Lists categories for an organization with pagination and filtering.
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param params - Query parameters
+   * @returns Paginated list of categories
+   *
+   * @example
+   * ```typescript
+   * const result = await categoryService.list('org_123', {
+   *   menuId: 'menu_456',
+   *   page: 1,
+   *   perPage: 50,
+   *   isActive: true,
+   * });
+   * ```
+   */
+  async list(
+    organizationId: string,
+    params: ListCategoriesQuery
+  ): Promise<PaginatedResult<Category>> {
+    const validated = this.validateInput(params, listCategoriesQuerySchema) as ListCategoriesQueryInput;
+    return this.repository.findAll(organizationId, validated);
+  }
+
+  /**
+   * Lists category summaries for a menu (for dropdowns, etc.).
+   *
+   * @param organizationId - Organization ID
+   * @param menuId - Menu ID
+   * @param params - Optional filtering params
+   * @returns Array of category summaries
+   */
+  async listSummaries(
+    organizationId: string,
+    menuId: string,
+    params?: Partial<ListCategoriesQuery>
+  ) {
+    // Verify menu exists and belongs to org
+    await this.menuRepository.findByIdOrThrow(menuId, organizationId);
+    return this.repository.findAllSummaries(organizationId, menuId, params);
+  }
+
+  /**
+   * Gets categories by menu ID.
+   *
+   * @param organizationId - Organization ID
+   * @param menuId - Menu ID
+   * @param parentId - Optional parent ID filter (null for root categories)
+   * @returns Array of categories
+   */
+  async getByMenuId(
+    organizationId: string,
+    menuId: string,
+    parentId?: string | null
+  ): Promise<Category[]> {
+    // Verify menu exists and belongs to org
+    await this.menuRepository.findByIdOrThrow(menuId, organizationId);
+    return this.repository.findByMenuId(organizationId, menuId, parentId);
+  }
+
+  /**
+   * Gets a category by ID.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Category ID
+   * @returns Category or null
+   */
+  async getById(organizationId: string, id: string): Promise<Category | null> {
+    return this.repository.findById(id, organizationId);
+  }
+
+  /**
+   * Gets a category by ID with relations.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Category ID
+   * @param includeProducts - Include products in response
+   * @returns Category with relations
+   * @throws {AppException} If not found
+   */
+  async getByIdWithRelations(
+    organizationId: string,
+    id: string,
+    includeProducts = false
+  ): Promise<CategoryWithRelations> {
+    const category = await this.repository.findByIdWithRelations(
+      id,
+      organizationId,
+      includeProducts
+    );
+
+    if (!category) {
+      throw AppException.notFound('Category', id);
+    }
+
+    return category;
+  }
+
+  /**
+   * Gets a category by ID or throws.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Category ID
+   * @returns Category
+   * @throws {AppException} If not found
+   */
+  async getByIdOrThrow(organizationId: string, id: string): Promise<Category> {
+    return this.repository.findByIdOrThrow(id, organizationId);
+  }
+
+  /**
+   * Gets a category by slug within a menu.
+   *
+   * @param organizationId - Organization ID
+   * @param menuId - Menu ID
+   * @param slug - Category slug
+   * @returns Category or null
+   */
+  async getBySlug(
+    organizationId: string,
+    menuId: string,
+    slug: string
+  ): Promise<Category | null> {
+    return this.repository.findBySlug(organizationId, menuId, slug);
+  }
+
+  /**
+   * Counts categories for a menu.
+   *
+   * @param organizationId - Organization ID
+   * @param menuId - Menu ID
+   * @param isActive - Optional active status filter
+   * @returns Count
+   */
+  async count(
+    organizationId: string,
+    menuId: string,
+    isActive?: boolean
+  ): Promise<number> {
+    return this.repository.count(organizationId, menuId, isActive);
+  }
+
+  /**
+   * Counts all categories for an organization.
+   *
+   * @param organizationId - Organization ID
+   * @returns Count
+   */
+  async countAll(organizationId: string): Promise<number> {
+    return this.repository.countAll(organizationId);
+  }
+
+  // ---------------------------------------------------------------------------
+  // Write Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Creates a new category.
+   *
+   * Validates input, generates slug if not provided, creates category,
+   * and emits creation event.
+   *
+   * @param organizationId - Organization ID
+   * @param data - Create request data
+   * @param context - User context
+   * @returns Created category response
+   * @throws {AppException} If menu not found or slug already exists
+   *
+   * @example
+   * ```typescript
+   * const result = await categoryService.create('org_123', {
+   *   menuId: 'menu_456',
+   *   name: 'Appetizers',
+   * });
+   * console.log('Created:', result.category.id);
+   * ```
+   */
+  async create(
+    organizationId: string,
+    data: CreateCategoryRequest,
+    context?: UserContext
+  ): Promise<CreateCategoryResponse> {
+    // Validate input
+    const validated = this.validateInput(data, createCategorySchema) as CreateCategoryInput;
+
+    // Verify menu exists and belongs to org
+    await this.menuRepository.findByIdOrThrow(validated.menuId, organizationId);
+
+    // Verify parent exists if provided
+    if (validated.parentId) {
+      const parent = await this.repository.findById(validated.parentId, organizationId);
+      if (!parent) {
+        throw AppException.notFound('Parent Category', validated.parentId);
+      }
+      // Ensure parent is in the same menu
+      if (parent.menuId !== validated.menuId) {
+        throw new AppException('PARENT_MENU_MISMATCH', 400, {
+          message: 'Parent category must be in the same menu',
+        });
+      }
+    }
+
+    // Generate slug if not provided
+    let slug = validated.slug;
+    if (!slug) {
+      slug = generateSlug(validated.name);
+      // Ensure uniqueness within menu
+      let counter = 1;
+      const baseSlug = slug;
+      while (await this.repository.slugExists(organizationId, validated.menuId, slug)) {
+        slug = `${baseSlug}-${counter}`;
+        counter++;
+      }
+    } else {
+      // Check if provided slug exists
+      if (await this.repository.slugExists(organizationId, validated.menuId, slug)) {
+        throw AppException.alreadyExists('Category slug', slug);
+      }
+    }
+
+    // Create category
+    const category = await this.repository.create(organizationId, {
+      menuId: validated.menuId,
+      parentId: validated.parentId || null,
+      name: validated.name,
+      slug,
+      description: validated.description || null,
+      image: validated.image || null,
+      isActive: validated.isActive ?? true,
+      sortOrder: validated.sortOrder ?? 0,
+    });
+
+    // Emit creation event
+    await this.eventService.emitCustom('category.created', {
+      categoryId: category.id,
+      menuId: category.menuId,
+      organizationId,
+      name: category.name,
+      createdBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return {
+      category,
+      message: 'Category created successfully.',
+    };
+  }
+
+  /**
+   * Updates a category.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Category ID
+   * @param data - Update request data
+   * @param context - User context
+   * @returns Updated category response
+   * @throws {AppException} If not found or slug conflicts
+   */
+  async update(
+    organizationId: string,
+    id: string,
+    data: UpdateCategoryRequest,
+    context?: UserContext
+  ): Promise<UpdateCategoryResponse> {
+    // Validate input
+    const validated = this.validateInput(data, updateCategorySchema) as UpdateCategoryInput;
+
+    // Get current category
+    const current = await this.repository.findByIdOrThrow(id, organizationId);
+
+    // Check slug uniqueness if changing
+    if (validated.slug && validated.slug !== current.slug) {
+      if (
+        await this.repository.slugExists(
+          organizationId,
+          current.menuId,
+          validated.slug,
+          id
+        )
+      ) {
+        throw AppException.alreadyExists('Category slug', validated.slug);
+      }
+    }
+
+    // Verify new parent if changing
+    if (validated.parentId !== undefined && validated.parentId !== current.parentId) {
+      if (validated.parentId) {
+        // Cannot be own child
+        if (validated.parentId === id) {
+          throw new AppException('CIRCULAR_REFERENCE', 400, {
+            message: 'Category cannot be its own parent',
+          });
+        }
+
+        const parent = await this.repository.findById(validated.parentId, organizationId);
+        if (!parent) {
+          throw AppException.notFound('Parent Category', validated.parentId);
+        }
+
+        // Ensure parent is in the same menu
+        if (parent.menuId !== current.menuId) {
+          throw new AppException('PARENT_MENU_MISMATCH', 400, {
+            message: 'Parent category must be in the same menu',
+          });
+        }
+
+        // Prevent circular reference (parent being a child of this category)
+        if (parent.parentId === id) {
+          throw new AppException('CIRCULAR_REFERENCE', 400, {
+            message: 'Cannot move category to its own child',
+          });
+        }
+      }
+    }
+
+    // Build update data
+    const updateData: Record<string, unknown> = {};
+    if (validated.parentId !== undefined) updateData.parentId = validated.parentId;
+    if (validated.name !== undefined) updateData.name = validated.name;
+    if (validated.slug !== undefined) updateData.slug = validated.slug;
+    if (validated.description !== undefined) updateData.description = validated.description;
+    if (validated.image !== undefined) updateData.image = validated.image;
+    if (validated.isActive !== undefined) updateData.isActive = validated.isActive;
+    if (validated.sortOrder !== undefined) updateData.sortOrder = validated.sortOrder;
+
+    // Update category
+    const category = await this.repository.update(id, organizationId, updateData);
+
+    // Emit update event
+    await this.eventService.emitCustom('category.updated', {
+      categoryId: category.id,
+      menuId: category.menuId,
+      organizationId,
+      changes: updateData,
+      updatedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return {
+      category,
+      message: 'Category updated successfully.',
+    };
+  }
+
+  /**
+   * Reorders categories within a menu.
+   *
+   * @param organizationId - Organization ID
+   * @param data - Reorder request data
+   * @param context - User context
+   * @returns Reorder response
+   */
+  async reorder(
+    organizationId: string,
+    data: ReorderCategoriesRequest,
+    context?: UserContext
+  ): Promise<ReorderCategoriesResponse> {
+    // Validate input
+    const validated = this.validateInput(data, reorderCategoriesSchema) as ReorderCategoriesInput;
+
+    // Verify menu exists
+    await this.menuRepository.findByIdOrThrow(validated.menuId, organizationId);
+
+    // Reorder categories
+    await this.repository.reorder(organizationId, validated.menuId, validated.items);
+
+    // Emit reorder event
+    await this.eventService.emitCustom('category.reordered', {
+      menuId: validated.menuId,
+      organizationId,
+      items: validated.items,
+      reorderedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return {
+      count: validated.items.length,
+      message: 'Categories reordered successfully.',
+    };
+  }
+
+  /**
+   * Moves a category to a different parent.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Category ID
+   * @param newParentId - New parent ID (null for root)
+   * @param context - User context
+   * @returns Updated category
+   */
+  async moveToParent(
+    organizationId: string,
+    id: string,
+    newParentId: string | null,
+    context?: UserContext
+  ): Promise<Category> {
+    const category = await this.repository.moveToParent(id, organizationId, newParentId);
+
+    // Emit update event
+    await this.eventService.emitCustom('category.updated', {
+      categoryId: category.id,
+      menuId: category.menuId,
+      organizationId,
+      changes: { parentId: newParentId },
+      updatedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return category;
+  }
+
+  /**
+   * Toggles category active status.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Category ID
+   * @param context - User context
+   * @returns Updated category
+   */
+  async toggleActive(
+    organizationId: string,
+    id: string,
+    context?: UserContext
+  ): Promise<Category> {
+    const current = await this.repository.findByIdOrThrow(id, organizationId);
+    const category = await this.repository.update(id, organizationId, {
+      isActive: !current.isActive,
+    });
+
+    // Emit update event
+    await this.eventService.emitCustom('category.updated', {
+      categoryId: category.id,
+      menuId: category.menuId,
+      organizationId,
+      changes: { isActive: category.isActive },
+      updatedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return category;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Delete Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Soft deletes a category.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Category ID
+   * @param context - User context
+   * @throws {AppException} If not found or has children
+   *
+   * @example
+   * ```typescript
+   * await categoryService.delete('org_123', 'cat_456');
+   * ```
+   */
+  async delete(organizationId: string, id: string, context?: UserContext): Promise<void> {
+    const category = await this.repository.findByIdWithRelations(id, organizationId);
+
+    if (!category) {
+      throw AppException.notFound('Category', id);
+    }
+
+    // Check if has children
+    if (category.children && category.children.length > 0) {
+      throw new AppException('CATEGORY_HAS_CHILDREN', 400, {
+        message: 'Cannot delete category with subcategories. Delete or move children first.',
+        childCount: category.children.length,
+      });
+    }
+
+    // Check if has products
+    const productCount = await this.getProductCount(organizationId, id);
+    if (productCount > 0) {
+      throw new AppException('CATEGORY_HAS_PRODUCTS', 400, {
+        message: 'Cannot delete category with products. Delete or move products first.',
+        productCount,
+      });
+    }
+
+    // Soft delete
+    await this.repository.softDelete(id, organizationId);
+
+    // Emit deletion event
+    await this.eventService.emitCustom('category.deleted', {
+      categoryId: category.id,
+      menuId: category.menuId,
+      organizationId,
+      name: category.name,
+      deletedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+  }
+
+  /**
+   * Restores a soft-deleted category.
+   *
+   * @param organizationId - Organization ID
+   * @param id - Category ID
+   * @param context - User context
+   * @returns Restored category
+   */
+  async restore(
+    organizationId: string,
+    id: string,
+    context?: UserContext
+  ): Promise<Category> {
+    const category = await this.repository.restore(id, organizationId);
+
+    // Emit restore event
+    await this.eventService.emitCustom('category.restored', {
+      categoryId: category.id,
+      menuId: category.menuId,
+      organizationId,
+      name: category.name,
+      restoredBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return category;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Validation Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Checks if a slug is available within a menu.
+   *
+   * @param organizationId - Organization ID
+   * @param menuId - Menu ID
+   * @param slug - Slug to check
+   * @param excludeId - Optional ID to exclude
+   * @returns True if available
+   */
+  async isSlugAvailable(
+    organizationId: string,
+    menuId: string,
+    slug: string,
+    excludeId?: string
+  ): Promise<boolean> {
+    return !(await this.repository.slugExists(organizationId, menuId, slug, excludeId));
+  }
+
+  // ---------------------------------------------------------------------------
+  // Helper Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets product count for a category.
+   * This is a placeholder - would integrate with product repository.
+   */
+  private async getProductCount(
+    organizationId: string,
+    categoryId: string
+  ): Promise<number> {
+    // This would be replaced with actual product count when product repository is available
+    // For now, return 0 to allow deletion
+    return 0;
+  }
+
+  /**
+   * Validates input data against a Zod schema.
+   */
+  private validateInput<T>(data: unknown, schema: { parse: (data: unknown) => T }): T {
+    try {
+      return schema.parse(data);
+    } catch (error) {
+      if (error && typeof error === 'object' && 'errors' in error) {
+        const zodError = error as { errors: Array<{ path: string[]; message: string; code: string }> };
+        const validationErrors = zodError.errors.map((err) => ({
+          field: err.path.join('.'),
+          message: err.message,
+          rule: err.code,
+        }));
+        throw AppException.validation(validationErrors);
+      }
+      throw error;
+    }
+  }
+}

