+/**
+ * Menu Repository
+ *
+ * Data access layer for Menu entities.
+ * Provides tenant-scoped database operations with CRUD support.
+ *
+ * @module modules/menu/menu.repository
+ *
+ * @example
+ * ```typescript
+ * import { MenuRepository } from '@/modules/menu/menu.repository';
+ *
+ * const repo = container.resolve('MenuRepository');
+ * const menu = await repo.findBySlug('org_123', 'lunch-menu');
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+import { PrismaClient, Prisma } from '@prisma/client';
+
+import { TOKENS } from '@/core/kernel/container';
+import { AppException } from '@/core/exceptions/app.exception';
+import { notDeleted, softDelete } from '@/config/database';
+
+import type {
+  Menu,
+  MenuWithRelations,
+  ListMenusQuery,
+  MenuSettings,
+} from '@/modules/menu/menu.types';
+
+// -----------------------------------------------------------------------------
+// Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Paginated result type
+ */
+export interface PaginatedResult<T> {
+  /** Array of entities */
+  data: T[];
+  /** Pagination metadata */
+  meta: {
+    page: number;
+    perPage: number;
+    total: number;
+    totalPages: number;
+  };
+}
+
+/**
+ * Menu summary for list displays
+ */
+export interface MenuSummary {
+  /** Menu ID */
+  id: string;
+  /** Menu name */
+  name: string;
+  /** Menu slug */
+  slug: string;
+  /** Published status */
+  isPublished: boolean;
+  /** Default menu flag */
+  isDefault: boolean;
+  /** Branch ID */
+  branchId: string | null;
+  /** Category count */
+  categoryCount: number;
+  /** Product count */
+  productCount: number;
+  /** Creation timestamp */
+  createdAt: Date;
+}
+
+/**
+ * Create menu data (input for repository)
+ */
+export interface CreateMenuData {
+  name: string;
+  slug: string;
+  description?: string | null;
+  branchId?: string | null;
+  themeId?: string | null;
+  isDefault?: boolean;
+  settings?: Prisma.JsonValue;
+  sortOrder?: number;
+}
+
+/**
+ * Update menu data (input for repository)
+ */
+export interface UpdateMenuData {
+  name?: string;
+  slug?: string;
+  description?: string | null;
+  branchId?: string | null;
+  themeId?: string | null;
+  isDefault?: boolean;
+  isPublished?: boolean;
+  publishedAt?: Date | null;
+  settings?: Prisma.JsonValue;
+  sortOrder?: number;
+}
+
+// -----------------------------------------------------------------------------
+// Constants
+// -----------------------------------------------------------------------------
+
+const DEFAULT_PER_PAGE = 20;
+const MAX_PER_PAGE = 100;
+
+// -----------------------------------------------------------------------------
+// Menu Repository
+// -----------------------------------------------------------------------------
+
+/**
+ * Repository for Menu entity operations.
+ *
+ * Handles all database operations for menus including:
+ * - CRUD operations with tenant isolation
+ * - Slug lookups
+ * - Publishing operations
+ * - Pagination and search
+ *
+ * @remarks
+ * All operations require organizationId for tenant isolation.
+ * Soft delete is enforced on all operations.
+ *
+ * @example
+ * ```typescript
+ * @injectable()
+ * class MenuService {
+ *   constructor(
+ *     @inject('MenuRepository') private repo: MenuRepository
+ *   ) {}
+ *
+ *   async getBySlug(orgId: string, slug: string) {
+ *     return this.repo.findBySlug(orgId, slug);
+ *   }
+ * }
+ * ```
+ */
+@injectable()
+export class MenuRepository {
+  constructor(
+    @inject(TOKENS.PrismaClient) private readonly prisma: PrismaClient
+  ) {}
+
+  // ---------------------------------------------------------------------------
+  // Read Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Finds all menus for an organization with pagination and filtering
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param params - Query parameters (pagination, sorting, filtering)
+   * @returns Paginated list of menus
+   *
+   * @example
+   * ```typescript
+   * const result = await repo.findAll('org_123', {
+   *   page: 1,
+   *   perPage: 10,
+   *   isPublished: true,
+   *   sortBy: 'sortOrder',
+   * });
+   * ```
+   */
+  async findAll(
+    organizationId: string,
+    params: ListMenusQuery = {}
+  ): Promise<PaginatedResult<Menu>> {
+    const {
+      page = 1,
+      perPage = DEFAULT_PER_PAGE,
+      isPublished,
+      branchId,
+      search,
+      sortBy = 'sortOrder',
+      sortOrder = 'asc',
+    } = params;
+
+    // Normalize pagination
+    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
+    const normalizedPage = Math.max(1, page);
+    const skip = (normalizedPage - 1) * normalizedPerPage;
+
+    // Build where clause
+    const where: Prisma.MenuWhereInput = {
+      organizationId,
+      ...notDeleted,
+      ...(isPublished !== undefined && { isPublished }),
+      ...(branchId !== undefined && { branchId }),
+      ...(search && {
+        OR: [
+          { name: { contains: search, mode: 'insensitive' } },
+          { slug: { contains: search, mode: 'insensitive' } },
+          { description: { contains: search, mode: 'insensitive' } },
+        ],
+      }),
+    };
+
+    // Build orderBy
+    const orderBy: Prisma.MenuOrderByWithRelationInput = {
+      [sortBy]: sortOrder,
+    };
+
+    // Execute count and find in parallel
+    const [total, data] = await Promise.all([
+      this.prisma.menu.count({ where }),
+      this.prisma.menu.findMany({
+        where,
+        orderBy,
+        skip,
+        take: normalizedPerPage,
+      }),
+    ]);
+
+    return {
+      data: data as Menu[],
+      meta: {
+        page: normalizedPage,
+        perPage: normalizedPerPage,
+        total,
+        totalPages: Math.ceil(total / normalizedPerPage),
+      },
+    };
+  }
+
+  /**
+   * Finds all menus as summaries (for dropdowns, etc.)
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param params - Optional filtering params
+   * @returns Array of menu summaries
+   */
+  async findAllSummaries(
+    organizationId: string,
+    params: Partial<ListMenusQuery> = {}
+  ): Promise<MenuSummary[]> {
+    const { isPublished, branchId } = params;
+
+    const where: Prisma.MenuWhereInput = {
+      organizationId,
+      ...notDeleted,
+      ...(isPublished !== undefined && { isPublished }),
+      ...(branchId !== undefined && { branchId }),
+    };
+
+    const menus = await this.prisma.menu.findMany({
+      where,
+      select: {
+        id: true,
+        name: true,
+        slug: true,
+        isPublished: true,
+        isDefault: true,
+        branchId: true,
+        createdAt: true,
+        _count: {
+          select: {
+            categories: true,
+          },
+        },
+      },
+      orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+    });
+
+    // Get product counts through categories
+    const menuIds = menus.map((m) => m.id);
+    const productCounts = await this.prisma.category.groupBy({
+      by: ['menuId'],
+      where: {
+        menuId: { in: menuIds },
+        ...notDeleted,
+      },
+      _count: {
+        _all: true,
+      },
+    });
+
+    // Build product count map
+    const productCountMap = new Map(
+      productCounts.map((pc) => [pc.menuId, pc._count._all])
+    );
+
+    return menus.map((menu) => ({
+      id: menu.id,
+      name: menu.name,
+      slug: menu.slug,
+      isPublished: menu.isPublished,
+      isDefault: menu.isDefault,
+      branchId: menu.branchId,
+      categoryCount: menu._count.categories,
+      productCount: productCountMap.get(menu.id) || 0,
+      createdAt: menu.createdAt,
+    }));
+  }
+
+  /**
+   * Finds a menu by ID with tenant isolation
+   *
+   * @param id - Menu ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Menu or null
+   */
+  async findById(id: string, organizationId: string): Promise<Menu | null> {
+    const result = await this.prisma.menu.findFirst({
+      where: { id, organizationId, ...notDeleted },
+    });
+
+    return result as Menu | null;
+  }
+
+  /**
+   * Finds a menu by ID with relations
+   *
+   * @param id - Menu ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Menu with relations or null
+   */
+  async findByIdWithRelations(
+    id: string,
+    organizationId: string
+  ): Promise<MenuWithRelations | null> {
+    const result = await this.prisma.menu.findFirst({
+      where: { id, organizationId, ...notDeleted },
+      include: {
+        theme: true,
+        categories: {
+          where: notDeleted,
+          orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+        },
+        qrCodes: {
+          select: {
+            id: true,
+            menuId: true,
+            url: true,
+            imageUrl: true,
+          },
+        },
+        _count: {
+          select: {
+            categories: true,
+          },
+        },
+      },
+    });
+
+    return result as MenuWithRelations | null;
+  }
+
+  /**
+   * Finds a menu by ID or throws
+   *
+   * @param id - Menu ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Menu
+   * @throws {AppException} If not found
+   */
+  async findByIdOrThrow(id: string, organizationId: string): Promise<Menu> {
+    const menu = await this.findById(id, organizationId);
+
+    if (!menu) {
+      throw AppException.notFound('Menu', id);
+    }
+
+    return menu;
+  }
+
+  /**
+   * Finds a menu by slug within an organization
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param slug - Menu slug
+   * @returns Menu or null
+   */
+  async findBySlug(organizationId: string, slug: string): Promise<Menu | null> {
+    const result = await this.prisma.menu.findFirst({
+      where: { organizationId, slug, ...notDeleted },
+    });
+
+    return result as Menu | null;
+  }
+
+  /**
+   * Finds a menu by slug or throws
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param slug - Menu slug
+   * @returns Menu
+   * @throws {AppException} If not found
+   */
+  async findBySlugOrThrow(organizationId: string, slug: string): Promise<Menu> {
+    const menu = await this.findBySlug(organizationId, slug);
+
+    if (!menu) {
+      throw AppException.notFound('Menu', slug);
+    }
+
+    return menu;
+  }
+
+  /**
+   * Finds the default menu for an organization
+   *
+   * @param organizationId - Organization ID
+   * @returns Default menu or null
+   */
+  async findDefaultMenu(organizationId: string): Promise<Menu | null> {
+    const result = await this.prisma.menu.findFirst({
+      where: { organizationId, isDefault: true, ...notDeleted },
+    });
+
+    return result as Menu | null;
+  }
+
+  /**
+   * Finds all published menus for an organization
+   *
+   * @param organizationId - Organization ID
+   * @param branchId - Optional branch ID filter
+   * @returns Array of published menus
+   */
+  async findPublished(
+    organizationId: string,
+    branchId?: string
+  ): Promise<Menu[]> {
+    const result = await this.prisma.menu.findMany({
+      where: {
+        organizationId,
+        isPublished: true,
+        ...notDeleted,
+        ...(branchId && { branchId }),
+      },
+      orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+    });
+
+    return result as Menu[];
+  }
+
+  /**
+   * Checks if a menu slug exists within an organization
+   *
+   * @param organizationId - Organization ID
+   * @param slug - Slug to check
+   * @param excludeId - Optional ID to exclude from check
+   * @returns True if slug exists
+   */
+  async slugExists(
+    organizationId: string,
+    slug: string,
+    excludeId?: string
+  ): Promise<boolean> {
+    const count = await this.prisma.menu.count({
+      where: {
+        organizationId,
+        slug,
+        ...notDeleted,
+        ...(excludeId && { id: { not: excludeId } }),
+      },
+    });
+
+    return count > 0;
+  }
+
+  /**
+   * Counts menus for an organization
+   *
+   * @param organizationId - Organization ID
+   * @param isPublished - Optional published status filter
+   * @returns Count
+   */
+  async count(organizationId: string, isPublished?: boolean): Promise<number> {
+    return this.prisma.menu.count({
+      where: {
+        organizationId,
+        ...notDeleted,
+        ...(isPublished !== undefined && { isPublished }),
+      },
+    });
+  }
+
+  // ---------------------------------------------------------------------------
+  // Write Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Creates a new menu
+   *
+   * @param organizationId - Organization ID for tenant association
+   * @param data - Create data
+   * @returns Created menu
+   */
+  async create(organizationId: string, data: CreateMenuData): Promise<Menu> {
+    const result = await this.prisma.menu.create({
+      data: {
+        organizationId,
+        name: data.name,
+        slug: data.slug,
+        description: data.description || null,
+        branchId: data.branchId || null,
+        themeId: data.themeId || null,
+        isDefault: data.isDefault ?? false,
+        settings: data.settings || {},
+        sortOrder: data.sortOrder ?? 0,
+        isPublished: false,
+        publishedAt: null,
+      },
+    });
+
+    return result as Menu;
+  }
+
+  /**
+   * Updates a menu
+   *
+   * @param id - Menu ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @param data - Update data
+   * @returns Updated menu
+   * @throws {AppException} If not found
+   */
+  async update(
+    id: string,
+    organizationId: string,
+    data: UpdateMenuData
+  ): Promise<Menu> {
+    // Verify exists
+    await this.findByIdOrThrow(id, organizationId);
+
+    const result = await this.prisma.menu.update({
+      where: { id },
+      data: {
+        ...(data.name !== undefined && { name: data.name }),
+        ...(data.slug !== undefined && { slug: data.slug }),
+        ...(data.description !== undefined && { description: data.description }),
+        ...(data.branchId !== undefined && { branchId: data.branchId }),
+        ...(data.themeId !== undefined && { themeId: data.themeId }),
+        ...(data.isDefault !== undefined && { isDefault: data.isDefault }),
+        ...(data.isPublished !== undefined && { isPublished: data.isPublished }),
+        ...(data.publishedAt !== undefined && { publishedAt: data.publishedAt }),
+        ...(data.settings !== undefined && { settings: data.settings }),
+        ...(data.sortOrder !== undefined && { sortOrder: data.sortOrder }),
+      },
+    });
+
+    return result as Menu;
+  }
+
+  /**
+   * Updates menu settings (merge)
+   *
+   * @param id - Menu ID
+   * @param organizationId - Organization ID
+   * @param settings - Settings to merge
+   * @returns Updated menu
+   */
+  async updateSettings(
+    id: string,
+    organizationId: string,
+    settings: Prisma.JsonValue
+  ): Promise<Menu> {
+    const menu = await this.findByIdOrThrow(id, organizationId);
+
+    // Merge settings
+    const currentSettings = (menu.settings as Record<string, unknown>) || {};
+    const newSettings = settings as Record<string, unknown>;
+    const mergedSettings = this.deepMerge(currentSettings, newSettings);
+
+    const result = await this.prisma.menu.update({
+      where: { id },
+      data: { settings: mergedSettings },
+    });
+
+    return result as Menu;
+  }
+
+  /**
+   * Publishes a menu
+   *
+   * @param id - Menu ID
+   * @param organizationId - Organization ID
+   * @returns Published menu
+   */
+  async publish(id: string, organizationId: string): Promise<Menu> {
+    await this.findByIdOrThrow(id, organizationId);
+
+    const result = await this.prisma.menu.update({
+      where: { id },
+      data: {
+        isPublished: true,
+        publishedAt: new Date(),
+      },
+    });
+
+    return result as Menu;
+  }
+
+  /**
+   * Unpublishes a menu
+   *
+   * @param id - Menu ID
+   * @param organizationId - Organization ID
+   * @returns Unpublished menu
+   */
+  async unpublish(id: string, organizationId: string): Promise<Menu> {
+    await this.findByIdOrThrow(id, organizationId);
+
+    const result = await this.prisma.menu.update({
+      where: { id },
+      data: {
+        isPublished: false,
+      },
+    });
+
+    return result as Menu;
+  }
+
+  /**
+   * Sets a menu as the default menu (and unsets others)
+   *
+   * @param id - Menu ID to set as default
+   * @param organizationId - Organization ID
+   * @returns Updated menu
+   */
+  async setAsDefault(id: string, organizationId: string): Promise<Menu> {
+    await this.findByIdOrThrow(id, organizationId);
+
+    // Unset any existing default menu and set the new one
+    await this.prisma.$transaction([
+      this.prisma.menu.updateMany({
+        where: { organizationId, isDefault: true, ...notDeleted },
+        data: { isDefault: false },
+      }),
+      this.prisma.menu.update({
+        where: { id },
+        data: { isDefault: true },
+      }),
+    ]);
+
+    // Fetch and return the updated menu
+    return this.findByIdOrThrow(id, organizationId);
+  }
+
+  /**
+   * Duplicates a menu with its categories and products
+   *
+   * @param id - Menu ID to duplicate
+   * @param organizationId - Organization ID
+   * @param newName - Name for the duplicated menu
+   * @param newSlug - Slug for the duplicated menu
+   * @returns Duplicated menu
+   */
+  async duplicate(
+    id: string,
+    organizationId: string,
+    newName: string,
+    newSlug: string
+  ): Promise<Menu> {
+    const original = await this.findByIdOrThrow(id, organizationId);
+
+    // Create new menu with same settings but new name/slug
+    const result = await this.prisma.menu.create({
+      data: {
+        organizationId,
+        name: newName,
+        slug: newSlug,
+        description: original.description,
+        branchId: original.branchId,
+        themeId: original.themeId,
+        isDefault: false,
+        settings: original.settings,
+        sortOrder: original.sortOrder,
+        isPublished: false,
+        publishedAt: null,
+      },
+    });
+
+    return result as Menu;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Delete Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Soft deletes a menu
+   *
+   * @param id - Menu ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Deleted menu
+   * @throws {AppException} If not found
+   */
+  async softDelete(id: string, organizationId: string): Promise<Menu> {
+    await this.findByIdOrThrow(id, organizationId);
+
+    const result = await this.prisma.menu.update({
+      where: { id },
+      data: softDelete(),
+    });
+
+    return result as Menu;
+  }
+
+  /**
+   * Restores a soft-deleted menu
+   *
+   * @param id - Menu ID
+   * @param organizationId - Organization ID
+   * @returns Restored menu
+   */
+  async restore(id: string, organizationId: string): Promise<Menu> {
+    // Find including deleted
+    const menu = await this.prisma.menu.findFirst({
+      where: { id, organizationId },
+    });
+
+    if (!menu) {
+      throw AppException.notFound('Menu', id);
+    }
+
+    const result = await this.prisma.menu.update({
+      where: { id },
+      data: { deletedAt: null },
+    });
+
+    return result as Menu;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Helper Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Deep merges two objects
+   */
+  private deepMerge(
+    target: Record<string, unknown>,
+    source: Record<string, unknown>
+  ): Record<string, unknown> {
+    const result = { ...target };
+
+    for (const [key, value] of Object.entries(source)) {
+      if (value !== undefined && value !== null) {
+        if (typeof value === 'object' && !Array.isArray(value)) {
+          result[key] = this.deepMerge(
+            (result[key] as Record<string, unknown>) || {},
+            value as Record<string, unknown>
+          );
+        } else {
+          result[key] = value;
+        }
+      }
+    }
+
+    return result;
+  }
+}

