+/**
+ * Product Repository
+ *
+ * Data access layer for Product, ProductVariant, and ProductModifier entities.
+ * Provides tenant-scoped database operations with CRUD support.
+ *
+ * @module modules/menu/product.repository
+ *
+ * @example
+ * ```typescript
+ * import { ProductRepository } from '@/modules/menu/product.repository';
+ *
+ * const repo = container.resolve('ProductRepository');
+ * const product = await repo.findBySlug('org_123', 'cat_456', 'delicious-burger');
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+import { PrismaClient, Prisma } from '@prisma/client';
+
+import { TOKENS } from '@/core/kernel/container';
+import { AppException } from '@/core/exceptions/app.exception';
+import { notDeleted, softDelete } from '@/config/database';
+
+import type {
+  Product,
+  ProductWithRelations,
+  ProductVariant,
+  ProductModifier,
+  NutritionInfo,
+  ListProductsQuery,
+} from '@/modules/menu/menu.types';
+
+// -----------------------------------------------------------------------------
+// Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Paginated result type
+ */
+export interface PaginatedResult<T> {
+  /** Array of entities */
+  data: T[];
+  /** Pagination metadata */
+  meta: {
+    page: number;
+    perPage: number;
+    total: number;
+    totalPages: number;
+  };
+}
+
+/**
+ * Product summary for list displays
+ */
+export interface ProductSummary {
+  /** Product ID */
+  id: string;
+  /** Product name */
+  name: string;
+  /** Product slug */
+  slug: string;
+  /** Category ID */
+  categoryId: string;
+  /** Base price */
+  basePrice: Prisma.Decimal | string | number;
+  /** Currency */
+  currency: string;
+  /** Main image URL */
+  image: string | null;
+  /** Active status */
+  isActive: boolean;
+  /** Availability status */
+  isAvailable: boolean;
+  /** Featured flag */
+  isFeatured: boolean;
+  /** Sort order */
+  sortOrder: number;
+  /** Variant count */
+  variantCount: number;
+  /** Modifier count */
+  modifierCount: number;
+  /** Allergen count */
+  allergenCount: number;
+  /** Creation timestamp */
+  createdAt: Date;
+}
+
+/**
+ * Create product data (input for repository)
+ */
+export interface CreateProductData {
+  categoryId: string;
+  name: string;
+  slug: string;
+  description?: string | null;
+  shortDescription?: string | null;
+  basePrice: number;
+  currency?: string;
+  image?: string | null;
+  gallery?: string[];
+  isActive?: boolean;
+  isAvailable?: boolean;
+  isFeatured?: boolean;
+  isChefRecommended?: boolean;
+  preparationTime?: number | null;
+  calories?: number | null;
+  spicyLevel?: number | null;
+  tags?: string[];
+  sortOrder?: number;
+}
+
