+ * Update product data (input for repository)
+ */
+export interface UpdateProductData {
+  categoryId?: string;
+  name?: string;
+  slug?: string;
+  description?: string | null;
+  shortDescription?: string | null;
+  basePrice?: number;
+  currency?: string;
+  image?: string | null;
+  gallery?: string[];
+  isActive?: boolean;
+  isAvailable?: boolean;
+  isFeatured?: boolean;
+  isChefRecommended?: boolean;
+  preparationTime?: number | null;
+  calories?: number | null;
+  spicyLevel?: number | null;
+  tags?: string[];
+  sortOrder?: number;
+}
+
+/**
+ * Create variant data (input for repository)
+ */
+export interface CreateVariantData {
+  productId: string;
+  name: string;
+  price: number;
+  isDefault?: boolean;
+  isAvailable?: boolean;
+  sortOrder?: number;
+}
+
+/**
+ * Update variant data (input for repository)
+ */
+export interface UpdateVariantData {
