+  price?: number;
+  isDefault?: boolean;
+  isAvailable?: boolean;
+  sortOrder?: number;
+}
+
+/**
+ * Create modifier data (input for repository)
+ */
+export interface CreateModifierData {
+  productId: string;
+  name: string;
+  price: number;
+  isDefault?: boolean;
+  isRequired?: boolean;
+  maxQuantity?: number;
+  sortOrder?: number;
+}
+
+/**
+ * Update modifier data (input for repository)
+ */
+export interface UpdateModifierData {
+  name?: string;
+  price?: number;
+  isDefault?: boolean;
+  isRequired?: boolean;
+  maxQuantity?: number;
+  sortOrder?: number;
+}
+
+/**
+ * Create nutrition info data (input for repository)
+ */
+export interface CreateNutritionInfoData {
+  productId: string;
+  calories?: number | null;
+  protein?: number | null;
+  carbohydrates?: number | null;
+  fat?: number | null;
+  fiber?: number | null;
+  sodium?: number | null;
+  sugar?: number | null;
+  servingSize?: string | null;
+  servingUnit?: string | null;
+}
+
+// -----------------------------------------------------------------------------
+// Constants
+// -----------------------------------------------------------------------------
+
+const DEFAULT_PER_PAGE = 20;
+const MAX_PER_PAGE = 100;
+
+// -----------------------------------------------------------------------------
+// Product Repository
+// -----------------------------------------------------------------------------
+
+/**
+ * Repository for Product entity operations.
+ *
+ * Handles all database operations for products including:
+ * - CRUD operations with tenant isolation
+ * - Variant and modifier management
+ * - Allergen associations
+ * - Nutrition information
+ * - Pagination and search
+ *
+ * @remarks
+ * All operations require organizationId for tenant isolation.
+ * Soft delete is enforced on all operations.
+ *
+ * @example
+ * ```typescript
+ * @injectable()
+ * class ProductService {
+ *   constructor(
+ *     @inject('ProductRepository') private repo: ProductRepository
+ *   ) {}
+ *
+ *   async getBySlug(orgId: string, catId: string, slug: string) {
+ *     return this.repo.findBySlug(orgId, catId, slug);
+ *   }
+ * }
+ * ```
+ */
+@injectable()
+export class ProductRepository {
+  constructor(
+    @inject(TOKENS.PrismaClient) private readonly prisma: PrismaClient
+  ) {}
+
+  // ---------------------------------------------------------------------------
+  // Product Read Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Finds all products for an organization with pagination and filtering
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param params - Query parameters (pagination, sorting, filtering)
+   * @returns Paginated list of products
+   */
+  async findAll(
+    organizationId: string,
+    params: ListProductsQuery = {}
+  ): Promise<PaginatedResult<Product>> {
+    const {
+      categoryId,
+      menuId,
+      isActive,
+      isAvailable,
+      isFeatured,
+      allergenId,
+      search,
+      tags,
+      page = 1,
+      perPage = DEFAULT_PER_PAGE,
+      sortBy = 'sortOrder',
+      sortOrder = 'asc',
+    } = params;
+
+    // Normalize pagination
+    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
+    const normalizedPage = Math.max(1, page);
+    const skip = (normalizedPage - 1) * normalizedPerPage;
+
+    // Build where clause
+    const where: Prisma.ProductWhereInput = {
+      organizationId,
+      ...notDeleted,
+      ...(categoryId !== undefined && { categoryId }),
+      ...(isActive !== undefined && { isActive }),
+      ...(isAvailable !== undefined && { isAvailable }),
+      ...(isFeatured !== undefined && { isFeatured }),
+      ...(tags && tags.length > 0 && { tags: { hasSome: tags } }),
+      ...(allergenId && {
+        allergens: {
+          some: { allergenId },
+        },
+      }),
+      ...(menuId && {
+        category: {
+          menuId,
+          ...notDeleted,
+        },
+      }),
+      ...(search && {
+        OR: [
+          { name: { contains: search, mode: 'insensitive' } },
+          { slug: { contains: search, mode: 'insensitive' } },
+          { description: { contains: search, mode: 'insensitive' } },
+          { shortDescription: { contains: search, mode: 'insensitive' } },
+        ],
+      }),
+    };
+
+    // Build orderBy
+    const orderBy: Prisma.ProductOrderByWithRelationInput = {
+      [sortBy]: sortOrder,
+    };
+
+    // Execute count and find in parallel
+    const [total, data] = await Promise.all([
+      this.prisma.product.count({ where }),
+      this.prisma.product.findMany({
+        where,
+        orderBy,
+        skip,
+        take: normalizedPerPage,
+      }),
+    ]);
+
+    return {
+      data: data as Product[],
+      meta: {
+        page: normalizedPage,
+        perPage: normalizedPerPage,
+        total,
+        totalPages: Math.ceil(total / normalizedPerPage),
+      },
+    };
+  }
+
+  /**
+   * Finds all products with relations
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param params - Query parameters
+   * @returns Paginated list of products with relations
+   */
+  async findAllWithRelations(
+    organizationId: string,
+    params: ListProductsQuery = {}
+  ): Promise<PaginatedResult<ProductWithRelations>> {
+    const {
+      categoryId,
+      menuId,
+      isActive,
+      isAvailable,
+      isFeatured,
+      include = [],
+      search,
+      tags,
+      page = 1,
+      perPage = DEFAULT_PER_PAGE,
+      sortBy = 'sortOrder',
+      sortOrder = 'asc',
+    } = params;
+
+    // Normalize pagination
+    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
+    const normalizedPage = Math.max(1, page);
+    const skip = (normalizedPage - 1) * normalizedPerPage;
+
+    // Build where clause
+    const where: Prisma.ProductWhereInput = {
+      organizationId,
+      ...notDeleted,
+      ...(categoryId !== undefined && { categoryId }),
+      ...(isActive !== undefined && { isActive }),
+      ...(isAvailable !== undefined && { isAvailable }),
+      ...(isFeatured !== undefined && { isFeatured }),
+      ...(tags && tags.length > 0 && { tags: { hasSome: tags } }),
+      ...(menuId && {
+        category: {
+          menuId,
+          ...notDeleted,
+        },
+      }),
+      ...(search && {
+        OR: [
+          { name: { contains: search, mode: 'insensitive' } },
+          { slug: { contains: search, mode: 'insensitive' } },
+          { description: { contains: search, mode: 'insensitive' } },
+        ],
+      }),
+    };
+
+    // Build include clause based on requested relations
+    const includeClause: Prisma.ProductInclude = {};
+    if (include.includes('category')) {
+      includeClause.category = true;
+    }
+    if (include.includes('variants')) {
+      includeClause.variants = { orderBy: { sortOrder: 'asc' } };
+    }
+    if (include.includes('modifiers')) {
+      includeClause.modifiers = { orderBy: { sortOrder: 'asc' } };
+    }
+    if (include.includes('allergens')) {
+      includeClause.allergens = {
+        include: { allergen: true },
+      };
+    }
+    if (include.includes('nutritionInfo')) {
+      includeClause.nutritionInfo = true;
+    }
+
+    // Build orderBy
+    const orderBy: Prisma.ProductOrderByWithRelationInput = {
+      [sortBy]: sortOrder,
+    };
+
+    // Execute count and find in parallel
+    const [total, data] = await Promise.all([
+      this.prisma.product.count({ where }),
+      this.prisma.product.findMany({
+        where,
+        orderBy,
+        skip,
+        take: normalizedPerPage,
+        include: Object.keys(includeClause).length > 0 ? includeClause : undefined,
+      }),
+    ]);
+
+    return {
+      data: data as ProductWithRelations[],
+      meta: {
+        page: normalizedPage,
+        perPage: normalizedPerPage,
+        total,
+        totalPages: Math.ceil(total / normalizedPerPage),
+      },
+    };
+  }
+
+  /**
+   * Finds all products as summaries (for dropdowns, etc.)
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param categoryId - Optional category ID filter
+   * @param params - Optional filtering params
+   * @returns Array of product summaries
+   */
+  async findAllSummaries(
+    organizationId: string,
+    categoryId?: string,
+    params: Partial<ListProductsQuery> = {}
+  ): Promise<ProductSummary[]> {
+    const { isActive, isAvailable, isFeatured } = params;
+
+    const where: Prisma.ProductWhereInput = {
+      organizationId,
+      ...notDeleted,
+      ...(categoryId !== undefined && { categoryId }),
+      ...(isActive !== undefined && { isActive }),
+      ...(isAvailable !== undefined && { isAvailable }),
+      ...(isFeatured !== undefined && { isFeatured }),
+    };
+
+    const products = await this.prisma.product.findMany({
+      where,
+      select: {
+        id: true,
+        name: true,
+        slug: true,
+        categoryId: true,
+        basePrice: true,
+        currency: true,
+        image: true,
+        isActive: true,
+        isAvailable: true,
+        isFeatured: true,
+        sortOrder: true,
+        createdAt: true,
+        _count: {
+          select: {
+            variants: true,
+            modifiers: true,
+            allergens: true,
+          },
+        },
+      },
+      orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+    });
+
+    return products.map((product) => ({
+      id: product.id,
+      name: product.name,
+      slug: product.slug,
+      categoryId: product.categoryId,
+      basePrice: product.basePrice,
+      currency: product.currency,
+      image: product.image,
+      isActive: product.isActive,
+      isAvailable: product.isAvailable,
+      isFeatured: product.isFeatured,
+      sortOrder: product.sortOrder,
+      variantCount: product._count.variants,
+      modifierCount: product._count.modifiers,
+      allergenCount: product._count.allergens,
+      createdAt: product.createdAt,
+    }));
+  }
+
+  /**
+   * Finds products by category ID
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param categoryId - Category ID
+   * @returns Array of products
+   */
+  async findByCategoryId(
+    organizationId: string,
+    categoryId: string
+  ): Promise<Product[]> {
+    const result = await this.prisma.product.findMany({
+      where: {
+        organizationId,
+        categoryId,
+        ...notDeleted,
+      },
+      orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+    });
+
+    return result as Product[];
+  }
+
+  /**
+   * Finds a product by ID with tenant isolation
+   *
+   * @param id - Product ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Product or null
+   */
+  async findById(id: string, organizationId: string): Promise<Product | null> {
+    const result = await this.prisma.product.findFirst({
+      where: { id, organizationId, ...notDeleted },
+    });
+
+    return result as Product | null;
+  }
+
+  /**
+   * Finds a product by ID with relations
+   *
+   * @param id - Product ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Product with relations or null
+   */
+  async findByIdWithRelations(
+    id: string,
+    organizationId: string
+  ): Promise<ProductWithRelations | null> {
+    const result = await this.prisma.product.findFirst({
+      where: { id, organizationId, ...notDeleted },
+      include: {
+        category: true,
+        variants: { orderBy: { sortOrder: 'asc' } },
+        modifiers: { orderBy: { sortOrder: 'asc' } },
+        allergens: {
+          include: { allergen: true },
+        },
+        nutritionInfo: true,
+      },
+    });
+
+    return result as ProductWithRelations | null;
+  }
+
+  /**
+   * Finds a product by ID or throws
+   *
+   * @param id - Product ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Product
+   * @throws {AppException} If not found
+   */
+  async findByIdOrThrow(id: string, organizationId: string): Promise<Product> {
+    const product = await this.findById(id, organizationId);
+
+    if (!product) {
+      throw AppException.notFound('Product', id);
+    }
+
+    return product;
+  }
+
+  /**
+   * Finds a product by slug within a category
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param categoryId - Category ID
+   * @param slug - Product slug
+   * @returns Product or null
+   */
+  async findBySlug(
+    organizationId: string,
+    categoryId: string,
+    slug: string
+  ): Promise<Product | null> {
+    const result = await this.prisma.product.findFirst({
+      where: { organizationId, categoryId, slug, ...notDeleted },
+    });
+
+    return result as Product | null;
+  }
+
+  /**
+   * Checks if a product slug exists within a category
+   *
+   * @param organizationId - Organization ID
+   * @param categoryId - Category ID
+   * @param slug - Slug to check
+   * @param excludeId - Optional ID to exclude from check
+   * @returns True if slug exists
+   */
+  async slugExists(
+    organizationId: string,
+    categoryId: string,
+    slug: string,
+    excludeId?: string
+  ): Promise<boolean> {
+    const count = await this.prisma.product.count({
+      where: {
+        organizationId,
+        categoryId,
+        slug,
+        ...notDeleted,
+        ...(excludeId && { id: { not: excludeId } }),
+      },
+    });
+
+    return count > 0;
+  }
+
+  /**
+   * Counts products for a category
+   *
+   * @param organizationId - Organization ID
+   * @param categoryId - Category ID
+   * @param isActive - Optional active status filter
+   * @returns Count
+   */
+  async count(
+    organizationId: string,
+    categoryId?: string,
+    isActive?: boolean
+  ): Promise<number> {
+    return this.prisma.product.count({
+      where: {
+        organizationId,
+        ...notDeleted,
+        ...(categoryId !== undefined && { categoryId }),
+        ...(isActive !== undefined && { isActive }),
+      },
+    });
+  }
+
+  /**
+   * Finds featured products for an organization
+   *
+   * @param organizationId - Organization ID
+   * @param limit - Maximum number of products to return
+   * @returns Array of featured products
+   */
+  async findFeatured(organizationId: string, limit = 10): Promise<Product[]> {
+    const result = await this.prisma.product.findMany({
+      where: {
+        organizationId,
+        isFeatured: true,
+        isActive: true,
+        isAvailable: true,
+        ...notDeleted,
+      },
+      orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
+      take: limit,
+    });
+
+    return result as Product[];
+  }
+
+  // ---------------------------------------------------------------------------
+  // Product Write Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Creates a new product
+   *
+   * @param organizationId - Organization ID for tenant association
+   * @param data - Create data
+   * @returns Created product
+   */
+  async create(organizationId: string, data: CreateProductData): Promise<Product> {
+    const result = await this.prisma.product.create({
+      data: {
+        organizationId,
+        categoryId: data.categoryId,
+        name: data.name,
+        slug: data.slug,
+        description: data.description || null,
+        shortDescription: data.shortDescription || null,
+        basePrice: new Prisma.Decimal(data.basePrice),
+        currency: data.currency ?? 'TRY',
+        image: data.image || null,
+        gallery: data.gallery ?? [],
+        isActive: data.isActive ?? true,
+        isAvailable: data.isAvailable ?? true,
+        isFeatured: data.isFeatured ?? false,
+        isChefRecommended: data.isChefRecommended ?? false,
+        preparationTime: data.preparationTime ?? null,
+        calories: data.calories ?? null,
+        spicyLevel: data.spicyLevel ?? null,
+        tags: data.tags ?? [],
+        sortOrder: data.sortOrder ?? 0,
+      },
+    });
+
+    return result as Product;
+  }
+
+  /**
+   * Creates a product with variants, modifiers, allergens, and nutrition info
+   *
+   * @param organizationId - Organization ID
+   * @param data - Create data
+   * @param variants - Variants to create
+   * @param modifiers - Modifiers to create
+   * @param allergenIds - Allergen IDs to associate
+   * @param nutritionInfo - Nutrition info to create
+   * @returns Created product with relations
+   */
+  async createWithRelations(
+    organizationId: string,
+    data: CreateProductData,
+    variants?: Omit<CreateVariantData, 'productId'>[],
+    modifiers?: Omit<CreateModifierData, 'productId'>[],
+    allergenIds?: string[],
+    nutritionInfo?: Omit<CreateNutritionInfoData, 'productId'>
+  ): Promise<ProductWithRelations> {
+    const result = await this.prisma.$transaction(async (tx) => {
+      // Create product
+      const product = await tx.product.create({
+        data: {
+          organizationId,
+          categoryId: data.categoryId,
+          name: data.name,
+          slug: data.slug,
+          description: data.description || null,
+          shortDescription: data.shortDescription || null,
+          basePrice: new Prisma.Decimal(data.basePrice),
+          currency: data.currency ?? 'TRY',
+          image: data.image || null,
+          gallery: data.gallery ?? [],
+          isActive: data.isActive ?? true,
+          isAvailable: data.isAvailable ?? true,
+          isFeatured: data.isFeatured ?? false,
+          isChefRecommended: data.isChefRecommended ?? false,
+          preparationTime: data.preparationTime ?? null,
+          calories: data.calories ?? null,
+          spicyLevel: data.spicyLevel ?? null,
+          tags: data.tags ?? [],
+          sortOrder: data.sortOrder ?? 0,
+        },
+      });
+
+      // Create variants
+      if (variants && variants.length > 0) {
+        await tx.productVariant.createMany({
+          data: variants.map((v, index) => ({
+            productId: product.id,
+            name: v.name,
+            price: new Prisma.Decimal(v.price),
+            isDefault: v.isDefault ?? (index === 0),
+            isAvailable: v.isAvailable ?? true,
+            sortOrder: v.sortOrder ?? index,
+          })),
+        });
+      }
+
+      // Create modifiers
+      if (modifiers && modifiers.length > 0) {
+        await tx.productModifier.createMany({
+          data: modifiers.map((m, index) => ({
+            productId: product.id,
+            name: m.name,
+            price: new Prisma.Decimal(m.price),
+            isDefault: m.isDefault ?? false,
+            isRequired: m.isRequired ?? false,
+            maxQuantity: m.maxQuantity ?? 1,
+            sortOrder: m.sortOrder ?? index,
+          })),
+        });
+      }
+
+      // Create allergen associations
+      if (allergenIds && allergenIds.length > 0) {
+        await tx.productAllergen.createMany({
+          data: allergenIds.map((allergenId) => ({
+            productId: product.id,
+            allergenId,
+          })),
+        });
+      }
+
+      // Create nutrition info
+      if (nutritionInfo) {
+        await tx.nutritionInfo.create({
+          data: {
+            productId: product.id,
+            calories: nutritionInfo.calories ?? null,
+            protein: nutritionInfo.protein ? new Prisma.Decimal(nutritionInfo.protein) : null,
+            carbohydrates: nutritionInfo.carbohydrates ? new Prisma.Decimal(nutritionInfo.carbohydrates) : null,
+            fat: nutritionInfo.fat ? new Prisma.Decimal(nutritionInfo.fat) : null,
+            fiber: nutritionInfo.fiber ? new Prisma.Decimal(nutritionInfo.fiber) : null,
+            sodium: nutritionInfo.sodium ? new Prisma.Decimal(nutritionInfo.sodium) : null,
+            sugar: nutritionInfo.sugar ? new Prisma.Decimal(nutritionInfo.sugar) : null,
+            servingSize: nutritionInfo.servingSize ?? null,
+            servingUnit: nutritionInfo.servingUnit ?? null,
+          },
+        });
+      }
+
+      // Return product with relations
+      return tx.product.findUnique({
+        where: { id: product.id },
+        include: {
+          category: true,
+          variants: { orderBy: { sortOrder: 'asc' } },
+          modifiers: { orderBy: { sortOrder: 'asc' } },
+          allergens: { include: { allergen: true } },
+          nutritionInfo: true,
+        },
+      });
+    });
+
+    return result as ProductWithRelations;
+  }
+
+  /**
+   * Updates a product
+   *
+   * @param id - Product ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @param data - Update data
+   * @returns Updated product
+   * @throws {AppException} If not found
+   */
+  async update(
+    id: string,
+    organizationId: string,
+    data: UpdateProductData
+  ): Promise<Product> {
+    // Verify exists
+    await this.findByIdOrThrow(id, organizationId);
+
+    const result = await this.prisma.product.update({
+      where: { id },
+      data: {
+        ...(data.categoryId !== undefined && { categoryId: data.categoryId }),
+        ...(data.name !== undefined && { name: data.name }),
+        ...(data.slug !== undefined && { slug: data.slug }),
+        ...(data.description !== undefined && { description: data.description }),
+        ...(data.shortDescription !== undefined && { shortDescription: data.shortDescription }),
+        ...(data.basePrice !== undefined && { basePrice: new Prisma.Decimal(data.basePrice) }),
+        ...(data.currency !== undefined && { currency: data.currency }),
+        ...(data.image !== undefined && { image: data.image }),
+        ...(data.gallery !== undefined && { gallery: data.gallery }),
+        ...(data.isActive !== undefined && { isActive: data.isActive }),
+        ...(data.isAvailable !== undefined && { isAvailable: data.isAvailable }),
+        ...(data.isFeatured !== undefined && { isFeatured: data.isFeatured }),
+        ...(data.isChefRecommended !== undefined && { isChefRecommended: data.isChefRecommended }),
+        ...(data.preparationTime !== undefined && { preparationTime: data.preparationTime }),
+        ...(data.calories !== undefined && { calories: data.calories }),
+        ...(data.spicyLevel !== undefined && { spicyLevel: data.spicyLevel }),
+        ...(data.tags !== undefined && { tags: data.tags }),
+        ...(data.sortOrder !== undefined && { sortOrder: data.sortOrder }),
+      },
+    });
+
+    return result as Product;
+  }
+
+  /**
+   * Updates product sort orders in batch
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param categoryId - Category ID
+   * @param items - Array of ID and sortOrder pairs
+   */
+  async reorder(
+    organizationId: string,
+    categoryId: string,
+    items: Array<{ id: string; sortOrder: number }>
+  ): Promise<void> {
+    // Verify all products exist and belong to the category
+    const productIds = items.map((item) => item.id);
+    const existingCount = await this.prisma.product.count({
+      where: {
+        id: { in: productIds },
+        organizationId,
+        categoryId,
+        ...notDeleted,
+      },
+    });
+
+    if (existingCount !== productIds.length) {
+      throw new AppException('INVALID_PRODUCTS', 400, {
+        message: 'Some products do not exist or do not belong to this category',
+      });
+    }
+
+    // Update sort orders in transaction
+    await this.prisma.$transaction(
+      items.map((item) =>
+        this.prisma.product.update({
+          where: { id: item.id },
+          data: { sortOrder: item.sortOrder },
+        })
+      )
+    );
+  }
+
+  /**
+   * Soft deletes a product
+   *
+   * @param id - Product ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Deleted product
+   * @throws {AppException} If not found
+   */
+  async softDelete(id: string, organizationId: string): Promise<Product> {
+    await this.findByIdOrThrow(id, organizationId);
+
+    const result = await this.prisma.product.update({
+      where: { id },
+      data: softDelete(),
+    });
+
+    return result as Product;
+  }
+
+  /**
+   * Restores a soft-deleted product
+   *
+   * @param id - Product ID
+   * @param organizationId - Organization ID
+   * @returns Restored product
+   */
+  async restore(id: string, organizationId: string): Promise<Product> {
+    // Find including deleted
+    const product = await this.prisma.product.findFirst({
+      where: { id, organizationId },
+    });
+
+    if (!product) {
+      throw AppException.notFound('Product', id);
+    }
+
+    const result = await this.prisma.product.update({
+      where: { id },
+      data: { deletedAt: null },
+    });
+
+    return result as Product;
+  }
+
+  /**
+   * Soft deletes all products in a category
+   *
+   * @param organizationId - Organization ID
+   * @param categoryId - Category ID
+   * @returns Number of deleted products
+   */
+  async softDeleteByCategoryId(organizationId: string, categoryId: string): Promise<number> {
+    const result = await this.prisma.product.updateMany({
+      where: {
+        organizationId,
+        categoryId,
+        ...notDeleted,
+      },
+      data: softDelete(),
+    });
+
+    return result.count;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Variant Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Creates a product variant
+   *
+   * @param data - Create data
+   * @returns Created variant
+   */
+  async createVariant(data: CreateVariantData): Promise<ProductVariant> {
+    const result = await this.prisma.productVariant.create({
+      data: {
+        productId: data.productId,
+        name: data.name,
+        price: new Prisma.Decimal(data.price),
+        isDefault: data.isDefault ?? false,
+        isAvailable: data.isAvailable ?? true,
+        sortOrder: data.sortOrder ?? 0,
+      },
+    });
+
+    return result as ProductVariant;
+  }
+
+  /**
+   * Updates a product variant
+   *
+   * @param id - Variant ID
+   * @param productId - Product ID (for ownership verification)
+   * @param data - Update data
+   * @returns Updated variant
+   */
+  async updateVariant(
+    id: string,
+    productId: string,
+    data: UpdateVariantData
+  ): Promise<ProductVariant> {
+    // Verify variant belongs to product
+    const variant = await this.prisma.productVariant.findFirst({
+      where: { id, productId },
+    });
+
+    if (!variant) {
+      throw AppException.notFound('ProductVariant', id);
+    }
+
+    const result = await this.prisma.productVariant.update({
+      where: { id },
+      data: {
+        ...(data.name !== undefined && { name: data.name }),
+        ...(data.price !== undefined && { price: new Prisma.Decimal(data.price) }),
+        ...(data.isDefault !== undefined && { isDefault: data.isDefault }),
+        ...(data.isAvailable !== undefined && { isAvailable: data.isAvailable }),
+        ...(data.sortOrder !== undefined && { sortOrder: data.sortOrder }),
+      },
+    });
+
+    return result as ProductVariant;
+  }
+
+  /**
+   * Deletes a product variant
+   *
+   * @param id - Variant ID
+   * @param productId - Product ID (for ownership verification)
+   */
+  async deleteVariant(id: string, productId: string): Promise<void> {
+    // Verify variant belongs to product
+    const variant = await this.prisma.productVariant.findFirst({
+      where: { id, productId },
+    });
+
+    if (!variant) {
+      throw AppException.notFound('ProductVariant', id);
+    }
+
+    await this.prisma.productVariant.delete({
+      where: { id },
+    });
+  }
+
+  /**
+   * Finds all variants for a product
+   *
+   * @param productId - Product ID
+   * @returns Array of variants
+   */
+  async findVariants(productId: string): Promise<ProductVariant[]> {
+    const result = await this.prisma.productVariant.findMany({
+      where: { productId },
+      orderBy: { sortOrder: 'asc' },
+    });
+
+    return result as ProductVariant[];
+  }
+
+  /**
+   * Sets a variant as default (and unsets others)
+   *
+   * @param id - Variant ID to set as default
+   * @param productId - Product ID
+   * @returns Updated variant
+   */
+  async setDefaultVariant(id: string, productId: string): Promise<ProductVariant> {
+    // Verify variant belongs to product
+    const variant = await this.prisma.productVariant.findFirst({
+      where: { id, productId },
+    });
+
+    if (!variant) {
+      throw AppException.notFound('ProductVariant', id);
+    }
+
+    // Unset any existing default and set the new one
+    await this.prisma.$transaction([
+      this.prisma.productVariant.updateMany({
+        where: { productId, isDefault: true },
+        data: { isDefault: false },
+      }),
+      this.prisma.productVariant.update({
+        where: { id },
+        data: { isDefault: true },
+      }),
+    ]);
+
+    // Return updated variant
+    const result = await this.prisma.productVariant.findUnique({
+      where: { id },
+    });
+
+    return result as ProductVariant;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Modifier Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Creates a product modifier
+   *
+   * @param data - Create data
+   * @returns Created modifier
+   */
+  async createModifier(data: CreateModifierData): Promise<ProductModifier> {
+    const result = await this.prisma.productModifier.create({
+      data: {
+        productId: data.productId,
+        name: data.name,
+        price: new Prisma.Decimal(data.price),
+        isDefault: data.isDefault ?? false,
+        isRequired: data.isRequired ?? false,
+        maxQuantity: data.maxQuantity ?? 1,
+        sortOrder: data.sortOrder ?? 0,
+      },
+    });
+
+    return result as ProductModifier;
+  }
+
+  /**
+   * Updates a product modifier
+   *
+   * @param id - Modifier ID
+   * @param productId - Product ID (for ownership verification)
+   * @param data - Update data
+   * @returns Updated modifier
+   */
+  async updateModifier(
+    id: string,
+    productId: string,
+    data: UpdateModifierData
+  ): Promise<ProductModifier> {
+    // Verify modifier belongs to product
+    const modifier = await this.prisma.productModifier.findFirst({
+      where: { id, productId },
+    });
+
+    if (!modifier) {
+      throw AppException.notFound('ProductModifier', id);
+    }
+
+    const result = await this.prisma.productModifier.update({
+      where: { id },
+      data: {
+        ...(data.name !== undefined && { name: data.name }),
+        ...(data.price !== undefined && { price: new Prisma.Decimal(data.price) }),
+        ...(data.isDefault !== undefined && { isDefault: data.isDefault }),
+        ...(data.isRequired !== undefined && { isRequired: data.isRequired }),
+        ...(data.maxQuantity !== undefined && { maxQuantity: data.maxQuantity }),
+        ...(data.sortOrder !== undefined && { sortOrder: data.sortOrder }),
+      },
+    });
+
+    return result as ProductModifier;
+  }
+
+  /**
+   * Deletes a product modifier
+   *
+   * @param id - Modifier ID
+   * @param productId - Product ID (for ownership verification)
+   */
+  async deleteModifier(id: string, productId: string): Promise<void> {
+    // Verify modifier belongs to product
+    const modifier = await this.prisma.productModifier.findFirst({
+      where: { id, productId },
+    });
+
+    if (!modifier) {
+      throw AppException.notFound('ProductModifier', id);
+    }
+
+    await this.prisma.productModifier.delete({
+      where: { id },
+    });
+  }
+
+  /**
+   * Finds all modifiers for a product
+   *
+   * @param productId - Product ID
+   * @returns Array of modifiers
+   */
+  async findModifiers(productId: string): Promise<ProductModifier[]> {
+    const result = await this.prisma.productModifier.findMany({
+      where: { productId },
+      orderBy: { sortOrder: 'asc' },
+    });
+
+    return result as ProductModifier[];
+  }
+
+  // ---------------------------------------------------------------------------
+  // Allergen Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Sets allergens for a product (replaces existing)
+   *
+   * @param productId - Product ID
+   * @param allergenIds - Array of allergen IDs
+   */
+  async setAllergens(productId: string, allergenIds: string[]): Promise<void> {
+    await this.prisma.$transaction([
+      // Delete existing associations
+      this.prisma.productAllergen.deleteMany({
+        where: { productId },
+      }),
+      // Create new associations
+      this.prisma.productAllergen.createMany({
+        data: allergenIds.map((allergenId) => ({
+          productId,
+          allergenId,
+        })),
+      }),
+    ]);
+  }
+
+  /**
+   * Adds an allergen to a product
+   *
+   * @param productId - Product ID
+   * @param allergenId - Allergen ID
+   */
+  async addAllergen(productId: string, allergenId: string): Promise<void> {
+    // Check if already exists
+    const existing = await this.prisma.productAllergen.findUnique({
+      where: {
+        productId_allergenId: { productId, allergenId },
+      },
+    });
+
+    if (!existing) {
+      await this.prisma.productAllergen.create({
+        data: { productId, allergenId },
+      });
+    }
+  }
+
+  /**
+   * Removes an allergen from a product
+   *
+   * @param productId - Product ID
+   * @param allergenId - Allergen ID
+   */
+  async removeAllergen(productId: string, allergenId: string): Promise<void> {
+    await this.prisma.productAllergen.deleteMany({
+      where: { productId, allergenId },
+    });
+  }
+
+  // ---------------------------------------------------------------------------
+  // Nutrition Info Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Creates or updates nutrition info for a product
+   *
+   * @param productId - Product ID
+   * @param data - Nutrition info data
+   * @returns Created/updated nutrition info
+   */
+  async upsertNutritionInfo(
+    productId: string,
+    data: Omit<CreateNutritionInfoData, 'productId'>
+  ): Promise<NutritionInfo> {
+    const result = await this.prisma.nutritionInfo.upsert({
+      where: { productId },
+      create: {
+        productId,
+        calories: data.calories ?? null,
+        protein: data.protein ? new Prisma.Decimal(data.protein) : null,
+        carbohydrates: data.carbohydrates ? new Prisma.Decimal(data.carbohydrates) : null,
+        fat: data.fat ? new Prisma.Decimal(data.fat) : null,
+        fiber: data.fiber ? new Prisma.Decimal(data.fiber) : null,
+        sodium: data.sodium ? new Prisma.Decimal(data.sodium) : null,
+        sugar: data.sugar ? new Prisma.Decimal(data.sugar) : null,
+        servingSize: data.servingSize ?? null,
+        servingUnit: data.servingUnit ?? null,
+      },
+      update: {
+        ...(data.calories !== undefined && { calories: data.calories }),
+        ...(data.protein !== undefined && { protein: data.protein ? new Prisma.Decimal(data.protein) : null }),
+        ...(data.carbohydrates !== undefined && { carbohydrates: data.carbohydrates ? new Prisma.Decimal(data.carbohydrates) : null }),
+        ...(data.fat !== undefined && { fat: data.fat ? new Prisma.Decimal(data.fat) : null }),
+        ...(data.fiber !== undefined && { fiber: data.fiber ? new Prisma.Decimal(data.fiber) : null }),
+        ...(data.sodium !== undefined && { sodium: data.sodium ? new Prisma.Decimal(data.sodium) : null }),
+        ...(data.sugar !== undefined && { sugar: data.sugar ? new Prisma.Decimal(data.sugar) : null }),
+        ...(data.servingSize !== undefined && { servingSize: data.servingSize }),
+        ...(data.servingUnit !== undefined && { servingUnit: data.servingUnit }),
+      },
+    });
+
+    return result as NutritionInfo;
+  }
+
+  /**
+   * Deletes nutrition info for a product
+   *
+   * @param productId - Product ID
+   */
+  async deleteNutritionInfo(productId: string): Promise<void> {
+    await this.prisma.nutritionInfo.deleteMany({
+      where: { productId },
+    });
+  }
+
+  /**
+   * Finds nutrition info for a product
+   *
+   * @param productId - Product ID
+   * @returns Nutrition info or null
+   */
+  async findNutritionInfo(productId: string): Promise<NutritionInfo | null> {
+    const result = await this.prisma.nutritionInfo.findUnique({
+      where: { productId },
+    });
+
+    return result as NutritionInfo | null;
+  }
+}

