+/**
+ * QR Code Generation Service
+ *
+ * Business logic service for QR code generation and management.
+ * Generates QR codes for menus, tables, and custom links.
+ *
+ * @module modules/menu/qrcode.service
+ *
+ * @example
+ * ```typescript
+ * import { QRCodeService } from '@/modules/menu/qrcode.service';
+ * import { resolve } from '@/core/kernel/container';
+ *
+ * const qrCodeService = resolve<QRCodeService>('QRCodeService');
+ *
+ * // Generate a QR code for a menu
+ * const result = await qrCodeService.generateQRCode('org_123', {
+ *   menuId: 'menu_456',
+ *   type: 'MENU',
+ * });
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+import { PrismaClient, QRCodeType } from '@prisma/client';
+import * as QRCode from 'qrcode';
+import * as crypto from 'crypto';
+import * as fs from 'fs/promises';
+import * as path from 'path';
+
+import { TOKENS } from '@/core/kernel/container';
+import { AppException } from '@/core/exceptions/app.exception';
+import { EventService } from '@/core/services/event.service';
+import { env } from '@/config/env';
+
+// -----------------------------------------------------------------------------
+// Types
+// -----------------------------------------------------------------------------
+
+/**
+ * QR Code entity (from Prisma)
+ */
+export interface QRCodeEntity {
+  /** QR Code ID */
+  id: string;
+  /** Organization ID (tenant) */
+  organizationId: string;
+  /** Menu ID */
+  menuId: string;
+  /** Table ID (optional) */
+  tableId: string | null;
+  /** Unique code identifier */
+  code: string;
+  /** QR Code type */
+  type: QRCodeType;
+  /** Public URL the QR code points to */
+  url: string;
+  /** URL of the QR code image */
+  imageUrl: string | null;
+  /** Number of scans */
+  scansCount: number;
+  /** Active status */
+  isActive: boolean;
+  /** Expiration date */
+  expiresAt: Date | null;
+  /** Creation timestamp */
+  createdAt: Date;
+  /** Last update timestamp */
+  updatedAt: Date;
+}
+
+/**
+ * Generate QR Code request
+ */
+export interface GenerateQRCodeRequest {
+  /** Menu ID */
+  menuId: string;
+  /** Table ID (optional, for table-specific QR codes) */
+  tableId?: string;
+  /** QR Code type */
+  type?: QRCodeType;
+  /** Custom expiration date */
+  expiresAt?: Date;
+}
+
+/**
+ * Generate QR Code response
+ */
+export interface GenerateQRCodeResponse {
+  /** Created QR code entity */
+  qrCode: QRCodeEntity;
+  /** Base64 encoded QR code image */
+  imageBase64?: string;
+  /** Response message */
+  message: string;
+}
+
+/**
+ * Regenerate QR Code response
+ */
+export interface RegenerateQRCodeResponse {
+  /** Updated QR code entity */
+  qrCode: QRCodeEntity;
+  /** Response message */
+  message: string;
+}
+
+/**
+ * QR Code generation options
+ */
+export interface QRCodeGenerationOptions {
+  /** QR code width in pixels */
+  width?: number;
+  /** Error correction level */
+  errorCorrectionLevel?: 'L' | 'M' | 'Q' | 'H';
+  /** Margin (quiet zone) */
+  margin?: number;
+  /** Dark color (hex) */
+  darkColor?: string;
+  /** Light color (hex) */
+  lightColor?: string;
+  /** Output format */
+  format?: 'png' | 'svg' | 'dataURL';
+}
+
+/**
+ * QR Code list query parameters
+ */
+export interface ListQRCodesQuery {
+  /** Filter by menu ID */
+  menuId?: string;
+  /** Filter by table ID */
+  tableId?: string;
+  /** Filter by type */
+  type?: QRCodeType;
+  /** Filter by active status */
+  isActive?: boolean;
+  /** Page number */
+  page?: number;
+  /** Items per page */
+  perPage?: number;
+}
+
+/**
+ * Paginated result
+ */
+export interface PaginatedResult<T> {
+  /** Data array */
+  data: T[];
+  /** Pagination metadata */
+  meta: {
+    page: number;
+    perPage: number;
+    total: number;
+    totalPages: number;
+  };
+}
+
+/**
+ * User context for operations
+ */
+interface UserContext {
+  /** User ID making the request */
+  userId?: string;
+}
+
+// -----------------------------------------------------------------------------
+// Constants
+// -----------------------------------------------------------------------------
+
+/** Default QR code width in pixels */
+const DEFAULT_QR_WIDTH = 400;
+
+/** Default error correction level */
+const DEFAULT_ERROR_CORRECTION: 'L' | 'M' | 'Q' | 'H' = 'M';
+
+/** Default margin */
+const DEFAULT_MARGIN = 2;
+
+/** Default items per page */
+const DEFAULT_PER_PAGE = 20;
+
+/** Maximum items per page */
+const MAX_PER_PAGE = 100;
+
+// -----------------------------------------------------------------------------
+// QR Code Service
+// -----------------------------------------------------------------------------
+
+/**
+ * QR Code generation and management service.
+ *
+ * Handles all QR code-related business operations including:
+ * - QR code generation for menus and tables
+ * - QR code image storage
+ * - QR code activation/deactivation
+ * - QR code regeneration
+ *
+ * @example
+ * ```typescript
+ * @injectable()
+ * class MenuController {
+ *   constructor(
+ *     @inject('QRCodeService') private qrCodeService: QRCodeService,
+ *   ) {}
+ *
+ *   async handleGenerateQR(req: Request, res: Response) {
+ *     const result = await this.qrCodeService.generateQRCode(
+ *       req.organization.id,
+ *       { menuId: req.params.menuId }
+ *     );
+ *     res.json(result);
+ *   }
+ * }
+ * ```
+ */
+@injectable()
+export class QRCodeService {
+  private readonly uploadDir: string;
+  private readonly publicUrl: string;
+  private readonly appDomain: string;
+
+  constructor(
+    @inject(TOKENS.PrismaClient) private readonly prisma: PrismaClient,
+    @inject(TOKENS.EventService) private readonly eventService: EventService
+  ) {
+    // Configure upload directory
+    this.uploadDir = process.env.UPLOAD_DIR || path.join(process.cwd(), 'public', 'uploads', 'qrcodes');
+    this.publicUrl = process.env.PUBLIC_URL || '/uploads/qrcodes';
+    this.appDomain = env.APP_DOMAIN || 'localhost:3000';
+  }
+
+  // ---------------------------------------------------------------------------
+  // Read Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Lists QR codes for an organization with pagination.
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param params - Query parameters
+   * @returns Paginated list of QR codes
+   *
+   * @example
+   * ```typescript
+   * const result = await qrCodeService.list('org_123', {
+   *   menuId: 'menu_456',
+   *   isActive: true,
+   * });
+   * ```
+   */
+  async list(
+    organizationId: string,
+    params: ListQRCodesQuery = {}
+  ): Promise<PaginatedResult<QRCodeEntity>> {
+    this.validateOrganizationId(organizationId);
+
+    const {
+      menuId,
+      tableId,
+      type,
+      isActive,
+      page = 1,
+      perPage = DEFAULT_PER_PAGE,
+    } = params;
+
+    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
+    const normalizedPage = Math.max(1, page);
+    const skip = (normalizedPage - 1) * normalizedPerPage;
+
+    // Build where clause
+    const where = {
+      organizationId,
+      ...(menuId && { menuId }),
+      ...(tableId && { tableId }),
+      ...(type && { type }),
+      ...(isActive !== undefined && { isActive }),
+    };
+
+    // Execute count and find in parallel
+    const [total, data] = await Promise.all([
+      this.prisma.qRCode.count({ where }),
+      this.prisma.qRCode.findMany({
+        where,
+        orderBy: { createdAt: 'desc' },
+        skip,
+        take: normalizedPerPage,
+      }),
+    ]);
+
+    return {
+      data: data as QRCodeEntity[],
+      meta: {
+        page: normalizedPage,
+        perPage: normalizedPerPage,
+        total,
+        totalPages: Math.ceil(total / normalizedPerPage),
+      },
+    };
+  }
+
+  /**
+   * Gets a QR code by ID.
+   *
+   * @param organizationId - Organization ID
+   * @param id - QR Code ID
+   * @returns QR code or null
+   */
+  async getById(organizationId: string, id: string): Promise<QRCodeEntity | null> {
+    this.validateOrganizationId(organizationId);
+
+    const qrCode = await this.prisma.qRCode.findFirst({
+      where: {
+        id,
+        organizationId,
+      },
+    });
+
+    return qrCode as QRCodeEntity | null;
+  }
+
+  /**
+   * Gets a QR code by ID or throws.
+   *
+   * @param organizationId - Organization ID
+   * @param id - QR Code ID
+   * @returns QR code
+   * @throws {AppException} If not found
+   */
+  async getByIdOrThrow(organizationId: string, id: string): Promise<QRCodeEntity> {
+    const qrCode = await this.getById(organizationId, id);
+
+    if (!qrCode) {
+      throw AppException.notFound('QRCode', id);
+    }
+
+    return qrCode;
+  }
+
+  /**
+   * Gets a QR code by its unique code.
+   *
+   * @param code - Unique code identifier
+   * @returns QR code or null
+   */
+  async getByCode(code: string): Promise<QRCodeEntity | null> {
+    const qrCode = await this.prisma.qRCode.findUnique({
+      where: { code },
+    });
+
+    return qrCode as QRCodeEntity | null;
+  }
+
+  /**
+   * Gets QR codes for a specific menu.
+   *
+   * @param organizationId - Organization ID
+   * @param menuId - Menu ID
+   * @returns Array of QR codes
+   */
+  async getByMenuId(organizationId: string, menuId: string): Promise<QRCodeEntity[]> {
+    this.validateOrganizationId(organizationId);
+
+    const qrCodes = await this.prisma.qRCode.findMany({
+      where: {
+        organizationId,
+        menuId,
+      },
+      orderBy: { createdAt: 'desc' },
+    });
+
+    return qrCodes as QRCodeEntity[];
+  }
+
+  /**
+   * Gets a QR code for a specific table.
+   *
+   * @param organizationId - Organization ID
+   * @param tableId - Table ID
+   * @returns QR code or null
+   */
+  async getByTableId(organizationId: string, tableId: string): Promise<QRCodeEntity | null> {
+    this.validateOrganizationId(organizationId);
+
+    const qrCode = await this.prisma.qRCode.findFirst({
+      where: {
+        organizationId,
+        tableId,
+        isActive: true,
+      },
+    });
+
+    return qrCode as QRCodeEntity | null;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Write Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Generates a new QR code for a menu or table.
+   *
+   * @param organizationId - Organization ID
+   * @param data - Generation request data
+   * @param options - QR code generation options
+   * @param context - User context
+   * @returns Generated QR code response
+   *
+   * @example
+   * ```typescript
+   * const result = await qrCodeService.generateQRCode('org_123', {
+   *   menuId: 'menu_456',
+   *   type: 'MENU',
+   * });
+   * console.log('QR Code URL:', result.qrCode.url);
+   * ```
+   */
+  async generateQRCode(
+    organizationId: string,
+    data: GenerateQRCodeRequest,
+    options: QRCodeGenerationOptions = {},
+    context?: UserContext
+  ): Promise<GenerateQRCodeResponse> {
+    this.validateOrganizationId(organizationId);
+
+    // Verify menu exists
+    const menu = await this.prisma.menu.findFirst({
+      where: {
+        id: data.menuId,
+        organizationId,
+        deletedAt: null,
+      },
+    });
+
+    if (!menu) {
+      throw AppException.notFound('Menu', data.menuId);
+    }
+
+    // If tableId is provided, verify table exists
+    if (data.tableId) {
+      const table = await this.prisma.table.findFirst({
+        where: {
+          id: data.tableId,
+          organizationId,
+          deletedAt: null,
+        },
+      });
+
+      if (!table) {
+        throw AppException.notFound('Table', data.tableId);
+      }
+
+      // Check if table already has an active QR code
+      const existingQR = await this.prisma.qRCode.findFirst({
+        where: {
+          tableId: data.tableId,
+          isActive: true,
+        },
+      });
+
+      if (existingQR) {
+        throw AppException.alreadyExists('QRCode for table', data.tableId);
+      }
+    }
+
+    // Generate unique code
+    const code = this.generateUniqueCode();
+
+    // Determine QR code type
+    const type = data.type || (data.tableId ? 'TABLE' : 'MENU');
+
+    // Build the public URL that the QR code will point to
+    const protocol = env.NODE_ENV === 'production' ? 'https' : 'http';
+    const publicUrl = data.tableId
+      ? `${protocol}://${this.appDomain}/m/${menu.slug}?table=${data.tableId}&code=${code}`
+      : `${protocol}://${this.appDomain}/m/${menu.slug}?code=${code}`;
+
+    // Generate QR code image
+    const imageBuffer = await this.generateQRCodeImage(publicUrl, options);
+
+    // Save QR code image
+    const imageUrl = await this.saveQRCodeImage(organizationId, code, imageBuffer);
+
+    // Create database record
+    const qrCode = await this.prisma.qRCode.create({
+      data: {
+        organizationId,
+        menuId: data.menuId,
+        tableId: data.tableId || null,
+        code,
+        type: type as QRCodeType,
+        url: publicUrl,
+        imageUrl,
+        isActive: true,
+        expiresAt: data.expiresAt || null,
+      },
+    });
+
+    // Emit event
+    await this.eventService.emitCustom('qrcode.created', {
+      qrCodeId: qrCode.id,
+      organizationId,
+      menuId: qrCode.menuId,
+      tableId: qrCode.tableId,
+      type: qrCode.type,
+      url: qrCode.url,
+      createdBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return {
+      qrCode: qrCode as QRCodeEntity,
+      imageBase64: imageBuffer.toString('base64'),
+      message: 'QR code generated successfully.',
+    };
+  }
+
+  /**
+   * Regenerates a QR code with a new code and image.
+   *
+   * @param organizationId - Organization ID
+   * @param id - QR Code ID
+   * @param options - QR code generation options
+   * @param context - User context
+   * @returns Regenerated QR code response
+   */
+  async regenerateQRCode(
+    organizationId: string,
+    id: string,
+    options: QRCodeGenerationOptions = {},
+    context?: UserContext
+  ): Promise<RegenerateQRCodeResponse> {
+    const existing = await this.getByIdOrThrow(organizationId, id);
+
+    // Generate new unique code
+    const code = this.generateUniqueCode();
+
+    // Get menu slug
+    const menu = await this.prisma.menu.findUnique({
+      where: { id: existing.menuId },
+      select: { slug: true },
+    });
+
+    if (!menu) {
+      throw AppException.notFound('Menu', existing.menuId);
+    }
+
+    // Build the new public URL
+    const protocol = env.NODE_ENV === 'production' ? 'https' : 'http';
+    const publicUrl = existing.tableId
+      ? `${protocol}://${this.appDomain}/m/${menu.slug}?table=${existing.tableId}&code=${code}`
+      : `${protocol}://${this.appDomain}/m/${menu.slug}?code=${code}`;
+
+    // Generate new QR code image
+    const imageBuffer = await this.generateQRCodeImage(publicUrl, options);
+
+    // Delete old image if exists
+    if (existing.imageUrl) {
+      await this.deleteQRCodeImage(existing.imageUrl);
+    }
+
+    // Save new QR code image
+    const imageUrl = await this.saveQRCodeImage(organizationId, code, imageBuffer);
+
+    // Update database record
+    const qrCode = await this.prisma.qRCode.update({
+      where: { id },
+      data: {
+        code,
+        url: publicUrl,
+        imageUrl,
+        scansCount: 0, // Reset scan count
+      },
+    });
+
+    // Emit event
+    await this.eventService.emitCustom('qrcode.regenerated', {
+      qrCodeId: qrCode.id,
+      organizationId,
+      previousCode: existing.code,
+      newCode: code,
+      regeneratedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return {
+      qrCode: qrCode as QRCodeEntity,
+      message: 'QR code regenerated successfully.',
+    };
+  }
+
+  /**
+   * Activates a QR code.
+   *
+   * @param organizationId - Organization ID
+   * @param id - QR Code ID
+   * @param context - User context
+   * @returns Updated QR code
+   */
+  async activate(
+    organizationId: string,
+    id: string,
+    context?: UserContext
+  ): Promise<QRCodeEntity> {
+    const existing = await this.getByIdOrThrow(organizationId, id);
+
+    if (existing.isActive) {
+      return existing;
+    }
+
+    const qrCode = await this.prisma.qRCode.update({
+      where: { id },
+      data: { isActive: true },
+    });
+
+    // Emit event
+    await this.eventService.emitCustom('qrcode.activated', {
+      qrCodeId: qrCode.id,
+      organizationId,
+      activatedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return qrCode as QRCodeEntity;
+  }
+
+  /**
+   * Deactivates a QR code.
+   *
+   * @param organizationId - Organization ID
+   * @param id - QR Code ID
+   * @param context - User context
+   * @returns Updated QR code
+   */
+  async deactivate(
+    organizationId: string,
+    id: string,
+    context?: UserContext
+  ): Promise<QRCodeEntity> {
+    const existing = await this.getByIdOrThrow(organizationId, id);
+
+    if (!existing.isActive) {
+      return existing;
+    }
+
+    const qrCode = await this.prisma.qRCode.update({
+      where: { id },
+      data: { isActive: false },
+    });
+
+    // Emit event
+    await this.eventService.emitCustom('qrcode.deactivated', {
+      qrCodeId: qrCode.id,
+      organizationId,
+      deactivatedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return qrCode as QRCodeEntity;
+  }
+
+  /**
+   * Records a QR code scan.
+   *
+   * @param code - QR code unique code
+   * @param metadata - Scan metadata (user agent, IP, etc.)
+   * @returns Updated QR code
+   */
+  async recordScan(
+    code: string,
+    metadata: {
+      userAgent?: string;
+      ipAddress?: string;
+      referrer?: string;
+      deviceType?: string;
+      browser?: string;
+      os?: string;
+      country?: string;
+      city?: string;
+    } = {}
+  ): Promise<QRCodeEntity | null> {
+    const qrCode = await this.prisma.qRCode.findUnique({
+      where: { code },
+    });
+
+    if (!qrCode) {
+      return null;
+    }
+
+    // Check if expired
+    if (qrCode.expiresAt && qrCode.expiresAt < new Date()) {
+      return null;
+    }
+
+    // Check if active
+    if (!qrCode.isActive) {
+      return null;
+    }
+
+    // Create scan record
+    await this.prisma.qRScan.create({
+      data: {
+        qrCodeId: qrCode.id,
+        organizationId: qrCode.organizationId,
+        ...metadata,
+        scannedAt: new Date(),
+      },
+    });
+
+    // Increment scan count
+    const updated = await this.prisma.qRCode.update({
+      where: { id: qrCode.id },
+      data: {
+        scansCount: {
+          increment: 1,
+        },
+      },
+    });
+
+    // Emit event
+    await this.eventService.emitCustom('qrcode.scanned', {
+      qrCodeId: qrCode.id,
+      organizationId: qrCode.organizationId,
+      menuId: qrCode.menuId,
+      tableId: qrCode.tableId,
+      scansCount: updated.scansCount,
+      metadata,
+      timestamp: new Date().toISOString(),
+    });
+
+    return updated as QRCodeEntity;
+  }
+
+  /**
+   * Deletes a QR code (hard delete, as QR codes are regenerable).
+   *
+   * @param organizationId - Organization ID
+   * @param id - QR Code ID
+   * @param context - User context
+   */
+  async delete(
+    organizationId: string,
+    id: string,
+    context?: UserContext
+  ): Promise<void> {
+    const existing = await this.getByIdOrThrow(organizationId, id);
+
+    // Delete image file if exists
+    if (existing.imageUrl) {
+      await this.deleteQRCodeImage(existing.imageUrl);
+    }
+
+    // Delete QR code (cascades to scans)
+    await this.prisma.qRCode.delete({
+      where: { id },
+    });
+
+    // Emit event
+    await this.eventService.emitCustom('qrcode.deleted', {
+      qrCodeId: id,
+      organizationId,
+      menuId: existing.menuId,
+      deletedBy: context?.userId,
+      timestamp: new Date().toISOString(),
+    });
+  }
+
+  /**
+   * Gets scan statistics for a QR code.
+   *
+   * @param organizationId - Organization ID
+   * @param id - QR Code ID
+   * @param days - Number of days to include (default 30)
+   * @returns Scan statistics
+   */
+  async getScanStats(
+    organizationId: string,
+    id: string,
+    days = 30
+  ): Promise<{
+    totalScans: number;
+    scansInPeriod: number;
+    scansByDay: Array<{ date: string; count: number }>;
+    topDeviceTypes: Array<{ deviceType: string; count: number }>;
+    topCountries: Array<{ country: string; count: number }>;
+  }> {
+    const qrCode = await this.getByIdOrThrow(organizationId, id);
+
+    const startDate = new Date();
+    startDate.setDate(startDate.getDate() - days);
+
+    // Get scans in period
+    const scans = await this.prisma.qRScan.findMany({
+      where: {
+        qrCodeId: qrCode.id,
+        scannedAt: { gte: startDate },
+      },
+      orderBy: { scannedAt: 'asc' },
+    });
+
+    // Aggregate by day
+    const scansByDayMap = new Map<string, number>();
+    const deviceTypeCounts = new Map<string, number>();
+    const countryCounts = new Map<string, number>();
+
+    for (const scan of scans) {
+      // By day
+      const dateKey = scan.scannedAt.toISOString().split('T')[0];
+      scansByDayMap.set(dateKey, (scansByDayMap.get(dateKey) || 0) + 1);
+
+      // By device type
+      if (scan.deviceType) {
+        deviceTypeCounts.set(
+          scan.deviceType,
+          (deviceTypeCounts.get(scan.deviceType) || 0) + 1
+        );
+      }
+
+      // By country
+      if (scan.country) {
+        countryCounts.set(
+          scan.country,
+          (countryCounts.get(scan.country) || 0) + 1
+        );
+      }
+    }
+
+    // Convert maps to arrays
+    const scansByDay = Array.from(scansByDayMap.entries())
+      .map(([date, count]) => ({ date, count }))
+      .sort((a, b) => a.date.localeCompare(b.date));
+
+    const topDeviceTypes = Array.from(deviceTypeCounts.entries())
+      .map(([deviceType, count]) => ({ deviceType, count }))
+      .sort((a, b) => b.count - a.count)
+      .slice(0, 5);
+
+    const topCountries = Array.from(countryCounts.entries())
+      .map(([country, count]) => ({ country, count }))
+      .sort((a, b) => b.count - a.count)
+      .slice(0, 5);
+
+    return {
+      totalScans: qrCode.scansCount,
+      scansInPeriod: scans.length,
+      scansByDay,
+      topDeviceTypes,
+      topCountries,
+    };
+  }
+
+  // ---------------------------------------------------------------------------
+  // Helper Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Generates a unique code for a QR code.
+   *
+   * @returns Unique code string
+   */
+  private generateUniqueCode(): string {
+    const timestamp = Date.now().toString(36);
+    const randomPart = crypto.randomBytes(4).toString('hex');
+    return `qr_${timestamp}_${randomPart}`;
+  }
+
+  /**
+   * Generates a QR code image.
+   *
+   * @param url - URL to encode
+   * @param options - Generation options
+   * @returns Image buffer
+   */
+  private async generateQRCodeImage(
+    url: string,
+    options: QRCodeGenerationOptions = {}
+  ): Promise<Buffer> {
+    const {
+      width = DEFAULT_QR_WIDTH,
+      errorCorrectionLevel = DEFAULT_ERROR_CORRECTION,
+      margin = DEFAULT_MARGIN,
+      darkColor = '#000000',
+      lightColor = '#ffffff',
+    } = options;
+
+    const qrOptions: QRCode.QRCodeToBufferOptions = {
+      width,
+      errorCorrectionLevel,
+      margin,
+      color: {
+        dark: darkColor,
+        light: lightColor,
+      },
+    };
+
+    return QRCode.toBuffer(url, qrOptions);
+  }
+
+  /**
+   * Generates a QR code as a Data URL (base64).
+   *
+   * @param url - URL to encode
+   * @param options - Generation options
+   * @returns Data URL string
+   */
+  async generateQRCodeDataURL(
+    url: string,
+    options: QRCodeGenerationOptions = {}
+  ): Promise<string> {
+    const {
+      width = DEFAULT_QR_WIDTH,
+      errorCorrectionLevel = DEFAULT_ERROR_CORRECTION,
+      margin = DEFAULT_MARGIN,
+      darkColor = '#000000',
+      lightColor = '#ffffff',
+    } = options;
+
+    return QRCode.toDataURL(url, {
+      width,
+      errorCorrectionLevel,
+      margin,
+      color: {
+        dark: darkColor,
+        light: lightColor,
+      },
+    });
+  }
+
+  /**
+   * Saves a QR code image to disk.
+   *
+   * @param organizationId - Organization ID
+   * @param code - QR code unique code
+   * @param buffer - Image buffer
+   * @returns Public URL of the saved image
+   */
+  private async saveQRCodeImage(
+    organizationId: string,
+    code: string,
+    buffer: Buffer
+  ): Promise<string> {
+    // Ensure directory exists
+    const orgDir = path.join(this.uploadDir, organizationId);
+    await this.ensureDirectory(orgDir);
+
+    // Save file
+    const filename = `${code}.png`;
+    const filePath = path.join(orgDir, filename);
+    await fs.writeFile(filePath, buffer);
+
+    // Return public URL
+    return `${this.publicUrl}/${organizationId}/${filename}`;
+  }
+
+  /**
+   * Deletes a QR code image from disk.
+   *
+   * @param imageUrl - Image URL to delete
+   */
+  private async deleteQRCodeImage(imageUrl: string): Promise<void> {
+    try {
+      // Extract file path from URL
+      const relativePath = imageUrl.replace(this.publicUrl, '');
+      const filePath = path.join(this.uploadDir, relativePath);
+
+      await fs.unlink(filePath);
+    } catch {
+      // Ignore errors if file doesn't exist
+    }
+  }
+
+  /**
+   * Ensures a directory exists.
+   *
+   * @param dir - Directory path
+   */
+  private async ensureDirectory(dir: string): Promise<void> {
+    try {
+      await fs.access(dir);
+    } catch {
+      await fs.mkdir(dir, { recursive: true });
+    }
+  }
+
+  /**
+   * Validates that the organizationId is provided.
+   *
+   * @param organizationId - Organization ID to validate
+   * @throws {AppException} When organizationId is missing
+   */
+  private validateOrganizationId(organizationId: string): void {
+    if (!organizationId) {
+      throw new AppException('TENANT_CONTEXT_MISSING', 400, {
+        message: 'Organization ID is required for this operation',
+      });
+    }
+  }
+}

