+/**
+ * Cart Module Service
+ *
+ * Business logic service for the shopping cart functionality.
+ * Handles cart CRUD, item management, and total calculations.
+ * Uses Redis for fast session-based cart storage.
+ *
+ * @module modules/order/cart.service
+ *
+ * @example
+ * ```typescript
+ * import { CartService } from '@/modules/order/cart.service';
+ * import { resolve } from '@/core/kernel/container';
+ *
+ * const cartService = resolve<CartService>('CartService');
+ *
+ * // Add item to cart
+ * const cart = await cartService.addItem('org_123', 'session_456', {
+ *   productId: 'prod_789',
+ *   quantity: 2,
+ * });
+ * ```
+ */
+
+import { injectable, inject } from 'tsyringe';
+
+import { TOKENS } from '@/core/kernel/container';
+import { AppException } from '@/core/exceptions/app.exception';
+import { EventService } from '@/core/services/event.service';
+import { redis, getCache, setCache, deleteCache } from '@/config/redis';
+
+import type {
+  OrderItemModifier,
+  CreateOrderItemRequest,
+  OrderType,
+} from '@/modules/order/order.types';
+
+import {
+  createOrderItemSchema,
+  calculateOrderTotals,
+  type CreateOrderItemInput,
+} from '@/modules/order/order.schema';
+
+// -----------------------------------------------------------------------------
+// Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Cart item stored in the cart
+ */
+export interface CartItem {
+  /** Cart item ID (unique within cart) */
+  id: string;
+  /** Product ID */
+  productId: string;
+  /** Variant ID (optional) */
+  variantId: string | null;
+  /** Product name (snapshot for display) */
+  productName: string;
+  /** Variant name (snapshot for display) */
+  variantName: string | null;
+  /** Quantity */
+  quantity: number;
+  /** Unit price at time of adding */
+  unitPrice: number;
+  /** Selected modifiers with details */
+  modifiers: OrderItemModifier[];
+  /** Item notes */
+  notes: string | null;
+  /** Total price for this item (unit * quantity + modifiers) */
+  totalPrice: number;
+  /** Timestamp when added */
+  addedAt: string;
+  /** Timestamp when last updated */
+  updatedAt: string;
+}
+
+/**
+ * Cart entity
+ */
+export interface Cart {
+  /** Cart ID (session ID or customer ID) */
+  id: string;
+  /** Organization ID (tenant) */
+  organizationId: string;
+  /** Customer ID (optional, for authenticated users) */
+  customerId: string | null;
+  /** Table ID (optional, for dine-in) */
+  tableId: string | null;
+  /** Order type */
+  orderType: OrderType;
+  /** Cart items */
+  items: CartItem[];
+  /** Subtotal amount */
+  subtotal: number;
+  /** Tax amount */
+  taxAmount: number;
+  /** Discount amount */
+  discountAmount: number;
+  /** Total amount */
+  totalAmount: number;
+  /** Currency code */
+  currency: string;
+  /** Cart notes */
+  notes: string | null;
+  /** Creation timestamp */
+  createdAt: string;
+  /** Last update timestamp */
+  updatedAt: string;
+}
+
+/**
+ * Add item request
+ */
+export interface AddCartItemRequest extends CreateOrderItemRequest {}
+
+/**
+ * Update cart item request
+ */
+export interface UpdateCartItemRequest {
+  /** New quantity */
+  quantity?: number;
+  /** Item notes */
+  notes?: string | null;
+  /** Updated modifiers */
+  modifiers?: Array<{
+    id: string;
+    quantity?: number;
+  }>;
+}
+
+/**
+ * User context for operations
+ */
+interface UserContext {
+  /** User ID making the request */
+  userId?: string;
+  /** Customer ID for authenticated customers */
+  customerId?: string;
+}
+
+/**
+ * Product lookup result (simplified for cart operations)
+ */
+interface ProductInfo {
+  id: string;
+  name: string;
+  basePrice: number;
+  isAvailable: boolean;
+  variants?: Array<{
+    id: string;
+    name: string;
+    price: number;
+  }>;
+  modifiers?: Array<{
+    id: string;
+    name: string;
+    price: number;
+  }>;
+}
+
+/**
+ * Add item response
+ */
+export interface AddItemResponse {
+  /** Updated cart */
+  cart: Cart;
+  /** Added item */
+  item: CartItem;
+  /** Response message */
+  message: string;
+}
+
+/**
+ * Update item response
+ */
