+
+// -----------------------------------------------------------------------------
+// Constants
+// -----------------------------------------------------------------------------
+
+/**
+ * Cart cache key prefix
+ */
+const CART_KEY_PREFIX = 'cart:';
+
+/**
+ * Cart TTL in seconds (24 hours)
+ */
+const CART_TTL_SECONDS = 86400;
+
+/**
+ * Default currency
+ */
+const DEFAULT_CURRENCY = 'TRY';
+
+/**
+ * Default tax rate (percentage)
+ */
+const DEFAULT_TAX_RATE = 10;
+
+/**
+ * Maximum items per cart
+ */
+const MAX_CART_ITEMS = 50;
+
+// -----------------------------------------------------------------------------
+// Cart Service
+// -----------------------------------------------------------------------------
+
+/**
+ * Cart module business logic service.
+ *
+ * Handles all cart-related business operations including:
+ * - Cart CRUD operations with tenant isolation
+ * - Adding, updating, removing items
+ * - Calculating totals with tax and discounts
+ * - Redis-based storage for performance
+ * - Event emission for cart changes
+ *
+ * @example
+ * ```typescript
+ * @injectable()
+ * class SomeController {
+ *   constructor(
+ *     @inject('CartService') private cartService: CartService,
+ *   ) {}
+ *
+ *   async handleAddItem(req: Request, res: Response) {
+ *     const result = await this.cartService.addItem(
+ *       req.orgId,
+ *       req.sessionId,
+ *       req.body
+ *     );
+ *     res.json(result);
+ *   }
+ * }
+ * ```
+ */
+@injectable()
+export class CartService {
+  constructor(
+    @inject(TOKENS.EventService) private readonly eventService: EventService
+  ) {}
+
+  // ---------------------------------------------------------------------------
+  // Read Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets cart by session/cart ID.
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param cartId - Cart/Session ID
+   * @returns Cart or null if not found
+   *
+   * @example
+   * ```typescript
+   * const cart = await cartService.getCart('org_123', 'session_456');
+   * if (cart) {
+   *   console.log('Items:', cart.items.length);
+   * }
+   * ```
+   */
+  async getCart(organizationId: string, cartId: string): Promise<Cart | null> {
+    const key = this.getCartKey(organizationId, cartId);
+    return getCache<Cart>(key);
+  }
+
+  /**
+   * Gets cart or creates a new empty cart.
+   *
+   * @param organizationId - Organization ID
+   * @param cartId - Cart/Session ID
+   * @param options - Cart options
+   * @returns Cart (existing or new)
+   */
+  async getOrCreateCart(
+    organizationId: string,
+    cartId: string,
+    options?: {
+      customerId?: string;
+      tableId?: string;
+      orderType?: OrderType;
+    }
+  ): Promise<Cart> {
+    let cart = await this.getCart(organizationId, cartId);
+
+    if (!cart) {
+      cart = this.createEmptyCart(organizationId, cartId, options);
+      await this.saveCart(cart);
+    }
+
+    return cart;
+  }
+
+  /**
+   * Gets cart item by ID.
+   *
+   * @param organizationId - Organization ID
+   * @param cartId - Cart/Session ID
+   * @param itemId - Cart item ID
+   * @returns Cart item or null
+   */
+  async getCartItem(
+    organizationId: string,
+    cartId: string,
+    itemId: string
+  ): Promise<CartItem | null> {
+    const cart = await this.getCart(organizationId, cartId);
+    if (!cart) return null;
+
+    return cart.items.find((item) => item.id === itemId) || null;
+  }
+
+  /**
+   * Gets cart items count.
+   *
+   * @param organizationId - Organization ID
+   * @param cartId - Cart/Session ID
+   * @returns Number of items in cart
+   */
+  async getItemCount(organizationId: string, cartId: string): Promise<number> {
+    const cart = await this.getCart(organizationId, cartId);
+    if (!cart) return 0;
+
+    return cart.items.reduce((sum, item) => sum + item.quantity, 0);
+  }
+
+  /**
+   * Checks if cart exists.
+   *
+   * @param organizationId - Organization ID
+   * @param cartId - Cart/Session ID
+   * @returns True if cart exists
+   */
+  async exists(organizationId: string, cartId: string): Promise<boolean> {
+    const key = this.getCartKey(organizationId, cartId);
+    const exists = await redis.exists(key);
+    return exists === 1;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Write Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Adds an item to the cart.
+   *
+   * @param organizationId - Organization ID
+   * @param cartId - Cart/Session ID
+   * @param data - Add item request data
+   * @param productInfo - Product information (from product service)
+   * @param context - User context
+   * @returns Add item response
+   *
+   * @example
+   * ```typescript
+   * const result = await cartService.addItem('org_123', 'session_456', {
+   *   productId: 'prod_789',
+   *   quantity: 2,
+   * }, productInfo);
+   * ```
+   */
+  async addItem(
+    organizationId: string,
+    cartId: string,
+    data: AddCartItemRequest,
+    productInfo: ProductInfo,
+    context?: UserContext
+  ): Promise<AddItemResponse> {
+    // Validate input
+    const validated = this.validateInput(data, createOrderItemSchema) as CreateOrderItemInput;
+
+    // Validate product is available
+    if (!productInfo.isAvailable) {
+      throw new AppException('PRODUCT_NOT_AVAILABLE', 400, {
+        message: 'Product is not available for ordering',
+        productId: validated.productId,
+      });
+    }
+
+    // Get or create cart
+    const cart = await this.getOrCreateCart(organizationId, cartId, {
+      customerId: context?.customerId,
+    });
+
+    // Check max items limit
+    if (cart.items.length >= MAX_CART_ITEMS) {
+      throw new AppException('CART_ITEM_LIMIT_EXCEEDED', 400, {
+        message: `Maximum ${MAX_CART_ITEMS} items allowed per cart`,
+        limit: MAX_CART_ITEMS,
+      });
+    }
+
+    // Get price from variant or base price
+    let unitPrice = productInfo.basePrice;
+    let variantName: string | null = null;
+
+    if (validated.variantId && productInfo.variants) {
+      const variant = productInfo.variants.find((v) => v.id === validated.variantId);
+      if (!variant) {
+        throw AppException.notFound('ProductVariant', validated.variantId);
+      }
+      unitPrice = variant.price;
+      variantName = variant.name;
+    }
+
+    // Resolve modifiers
+    const resolvedModifiers: OrderItemModifier[] = [];
+    if (validated.modifiers && validated.modifiers.length > 0 && productInfo.modifiers) {
+      for (const mod of validated.modifiers) {
+        const modifier = productInfo.modifiers.find((m) => m.id === mod.id);
+        if (!modifier) {
+          throw AppException.notFound('ProductModifier', mod.id);
+        }
+        resolvedModifiers.push({
+          id: modifier.id,
+          name: modifier.name,
+          price: modifier.price,
+          quantity: mod.quantity || 1,
+        });
+      }
+    }
+
+    // Check if same product/variant/modifiers already in cart
+    const existingItemIndex = cart.items.findIndex(
+      (item) =>
+        item.productId === validated.productId &&
+        item.variantId === (validated.variantId || null) &&
+        this.modifiersMatch(item.modifiers, resolvedModifiers)
+    );
+
+    let cartItem: CartItem;
+    const now = new Date().toISOString();
+
+    if (existingItemIndex >= 0) {
+      // Update existing item quantity
+      const existingItem = cart.items[existingItemIndex];
+      existingItem.quantity += validated.quantity;
+      existingItem.totalPrice = this.calculateItemTotal(
+        existingItem.unitPrice,
+        existingItem.quantity,
+        existingItem.modifiers
+      );
+      existingItem.updatedAt = now;
+      cartItem = existingItem;
+    } else {
+      // Create new cart item
+      cartItem = {
+        id: this.generateItemId(),
+        productId: validated.productId,
+        variantId: validated.variantId || null,
+        productName: productInfo.name,
+        variantName,
+        quantity: validated.quantity,
+        unitPrice,
+        modifiers: resolvedModifiers,
+        notes: validated.notes || null,
+        totalPrice: this.calculateItemTotal(unitPrice, validated.quantity, resolvedModifiers),
+        addedAt: now,
+        updatedAt: now,
+      };
+      cart.items.push(cartItem);
+    }
+
+    // Recalculate cart totals
+    this.recalculateCartTotals(cart);
+    cart.updatedAt = now;
+
+    // Save cart
+    await this.saveCart(cart);
+
+    // Emit event
+    await this.eventService.emitCustom('cart.item_added', {
+      cartId: cart.id,
+      organizationId,
+      itemId: cartItem.id,
+      productId: cartItem.productId,
+      quantity: cartItem.quantity,
+      customerId: cart.customerId,
+      timestamp: now,
+    });
+
+    return {
+      cart,
+      item: cartItem,
+      message: existingItemIndex >= 0
+        ? 'Item quantity updated successfully.'
+        : 'Item added to cart successfully.',
+    };
+  }
+
+  /**
+   * Updates a cart item.
+   *
+   * @param organizationId - Organization ID
+   * @param cartId - Cart/Session ID
+   * @param itemId - Cart item ID
+   * @param data - Update request data
+   * @param productInfo - Product information (for modifier updates)
+   * @param context - User context
+   * @returns Update item response
+   */
+  async updateItem(
+    organizationId: string,
+    cartId: string,
+    itemId: string,
+    data: UpdateCartItemRequest,
+    productInfo?: ProductInfo,
+    context?: UserContext
+  ): Promise<UpdateItemResponse> {
+    // Get cart
+    const cart = await this.getCart(organizationId, cartId);
+    if (!cart) {
+      throw AppException.notFound('Cart', cartId);
+    }
+
+    // Find item
+    const itemIndex = cart.items.findIndex((item) => item.id === itemId);
+    if (itemIndex < 0) {
+      throw AppException.notFound('CartItem', itemId);
+    }
+
+    const item = cart.items[itemIndex];
+    const now = new Date().toISOString();
+
+    // Update quantity
+    if (data.quantity !== undefined) {
+      if (data.quantity < 1) {
+        throw new AppException('INVALID_QUANTITY', 400, {
+          message: 'Quantity must be at least 1',
+        });
+      }
+      item.quantity = data.quantity;
+    }
+
+    // Update notes
+    if (data.notes !== undefined) {
+      item.notes = data.notes;
+    }
+
+    // Update modifiers if provided
+    if (data.modifiers !== undefined && productInfo?.modifiers) {
+      const resolvedModifiers: OrderItemModifier[] = [];
+      for (const mod of data.modifiers) {
+        const modifier = productInfo.modifiers.find((m) => m.id === mod.id);
+        if (!modifier) {
+          throw AppException.notFound('ProductModifier', mod.id);
+        }
+        resolvedModifiers.push({
+          id: modifier.id,
+          name: modifier.name,
+          price: modifier.price,
+          quantity: mod.quantity || 1,
+        });
+      }
+      item.modifiers = resolvedModifiers;
+    }
+
+    // Recalculate item total
+    item.totalPrice = this.calculateItemTotal(item.unitPrice, item.quantity, item.modifiers);
+    item.updatedAt = now;
+
+    // Recalculate cart totals
+    this.recalculateCartTotals(cart);
+    cart.updatedAt = now;
+
+    // Save cart
+    await this.saveCart(cart);
+
+    // Emit event
+    await this.eventService.emitCustom('cart.item_updated', {
+      cartId: cart.id,
+      organizationId,
+      itemId: item.id,
+      productId: item.productId,
+      quantity: item.quantity,
+      customerId: cart.customerId,
+      timestamp: now,
+    });
+
+    return {
+      cart,
+      item,
+      message: 'Cart item updated successfully.',
+    };
+  }
+
+  /**
+   * Removes an item from the cart.
+   *
+   * @param organizationId - Organization ID
+   * @param cartId - Cart/Session ID
+   * @param itemId - Cart item ID
+   * @param context - User context
+   * @returns Remove item response
+   */
+  async removeItem(
+    organizationId: string,
+    cartId: string,
+    itemId: string,
+    context?: UserContext
+  ): Promise<RemoveItemResponse> {
+    // Get cart
+    const cart = await this.getCart(organizationId, cartId);
+    if (!cart) {
+      throw AppException.notFound('Cart', cartId);
+    }
+
+    // Find and remove item
+    const itemIndex = cart.items.findIndex((item) => item.id === itemId);
+    if (itemIndex < 0) {
+      throw AppException.notFound('CartItem', itemId);
+    }
+
+    const removedItem = cart.items[itemIndex];
+    cart.items.splice(itemIndex, 1);
+
+    const now = new Date().toISOString();
+
+    // Recalculate cart totals
+    this.recalculateCartTotals(cart);
+    cart.updatedAt = now;
+
+    // Save cart
+    await this.saveCart(cart);
+
+    // Emit event
+    await this.eventService.emitCustom('cart.item_removed', {
+      cartId: cart.id,
+      organizationId,
+      itemId: removedItem.id,
+      productId: removedItem.productId,
+      customerId: cart.customerId,
+      timestamp: now,
+    });
+
+    return {
+      cart,
+      message: 'Item removed from cart successfully.',
+    };
+  }
+
+  /**
+   * Clears all items from the cart.
+   *
+   * @param organizationId - Organization ID
+   * @param cartId - Cart/Session ID
+   * @param context - User context
+   * @returns Clear cart response
+   */
+  async clearCart(
+    organizationId: string,
+    cartId: string,
+    context?: UserContext
+  ): Promise<ClearCartResponse> {
+    // Get cart
+    const cart = await this.getCart(organizationId, cartId);
+    if (!cart) {
+      return { message: 'Cart is already empty.' };
+    }
+
+    const itemCount = cart.items.length;
+
+    // Delete cart from Redis
+    const key = this.getCartKey(organizationId, cartId);
+    await deleteCache(key);
+
+    // Emit event
+    await this.eventService.emitCustom('cart.cleared', {
+      cartId: cart.id,
+      organizationId,
+      itemCount,
+      customerId: cart.customerId,
+      timestamp: new Date().toISOString(),
+    });
+
+    return {
+      message: 'Cart cleared successfully.',
+    };
+  }
+
+  /**
+   * Updates cart metadata (notes, table, order type).
+   *
+   * @param organizationId - Organization ID
+   * @param cartId - Cart/Session ID
+   * @param data - Update data
+   * @param context - User context
+   * @returns Updated cart
+   */
+  async updateCart(
+    organizationId: string,
+    cartId: string,
+    data: {
+      notes?: string | null;
+      tableId?: string | null;
+      orderType?: OrderType;
+      customerId?: string | null;
+    },
+    context?: UserContext
+  ): Promise<Cart> {
+    // Get or create cart
+    const cart = await this.getOrCreateCart(organizationId, cartId, {
+      customerId: context?.customerId,
+    });
+
+    const now = new Date().toISOString();
+
+    // Update fields
+    if (data.notes !== undefined) cart.notes = data.notes;
+    if (data.tableId !== undefined) cart.tableId = data.tableId;
+    if (data.orderType !== undefined) cart.orderType = data.orderType;
+    if (data.customerId !== undefined) cart.customerId = data.customerId;
+
+    cart.updatedAt = now;
+
+    // Save cart
+    await this.saveCart(cart);
+
+    return cart;
+  }
+
+  /**
+   * Applies a discount to the cart.
+   *
+   * @param organizationId - Organization ID
+   * @param cartId - Cart/Session ID
+   * @param discountAmount - Discount amount to apply
+   * @param context - User context
+   * @returns Updated cart
+   */
+  async applyDiscount(
+    organizationId: string,
+    cartId: string,
+    discountAmount: number,
+    context?: UserContext
+  ): Promise<Cart> {
+    // Get cart
+    const cart = await this.getCart(organizationId, cartId);
+    if (!cart) {
+      throw AppException.notFound('Cart', cartId);
+    }
+
+    // Validate discount
+    if (discountAmount < 0) {
+      throw new AppException('INVALID_DISCOUNT', 400, {
+        message: 'Discount amount cannot be negative',
+      });
+    }
+
+    if (discountAmount > cart.subtotal) {
+      throw new AppException('DISCOUNT_EXCEEDS_SUBTOTAL', 400, {
+        message: 'Discount amount cannot exceed subtotal',
+        subtotal: cart.subtotal,
+        discountAmount,
+      });
+    }
+
+    const now = new Date().toISOString();
+
+    // Apply discount and recalculate
+    cart.discountAmount = discountAmount;
+    this.recalculateCartTotals(cart);
+    cart.updatedAt = now;
+
+    // Save cart
+    await this.saveCart(cart);
+
+    // Emit event
+    await this.eventService.emitCustom('cart.discount_applied', {
+      cartId: cart.id,
+      organizationId,
+      discountAmount,
+      customerId: cart.customerId,
+      timestamp: now,
+    });
+
+    return cart;
+  }
+
+  /**
+   * Transfers a guest cart to a customer cart.
+   *
+   * @param organizationId - Organization ID
+   * @param guestCartId - Guest cart/session ID
+   * @param customerId - Customer ID
+   * @param customerCartId - Customer cart ID (optional, defaults to customerId)
+   * @returns Merged cart
+   */
+  async transferToCustomer(
+    organizationId: string,
+    guestCartId: string,
+    customerId: string,
+    customerCartId?: string
+  ): Promise<Cart> {
+    const targetCartId = customerCartId || customerId;
+
+    // Get guest cart
+    const guestCart = await this.getCart(organizationId, guestCartId);
+    if (!guestCart || guestCart.items.length === 0) {
+      // Return or create customer cart
+      return this.getOrCreateCart(organizationId, targetCartId, { customerId });
+    }
+
+    // Get or create customer cart
+    const customerCart = await this.getOrCreateCart(organizationId, targetCartId, { customerId });
+
+    const now = new Date().toISOString();
+
+    // Merge items (add guest items to customer cart)
+    for (const guestItem of guestCart.items) {
+      // Check if same item exists in customer cart
+      const existingIndex = customerCart.items.findIndex(
+        (item) =>
+          item.productId === guestItem.productId &&
+          item.variantId === guestItem.variantId &&
+          this.modifiersMatch(item.modifiers, guestItem.modifiers)
+      );
+
+      if (existingIndex >= 0) {
+        // Merge quantities
+        customerCart.items[existingIndex].quantity += guestItem.quantity;
+        customerCart.items[existingIndex].totalPrice = this.calculateItemTotal(
+          customerCart.items[existingIndex].unitPrice,
+          customerCart.items[existingIndex].quantity,
+          customerCart.items[existingIndex].modifiers
+        );
+        customerCart.items[existingIndex].updatedAt = now;
+      } else {
+        // Add new item
+        guestItem.id = this.generateItemId();
+        guestItem.updatedAt = now;
+        customerCart.items.push(guestItem);
+      }
+    }
+
+    // Recalculate totals
+    this.recalculateCartTotals(customerCart);
+    customerCart.updatedAt = now;
+
+    // Save customer cart
+    await this.saveCart(customerCart);
+
+    // Delete guest cart
+    await deleteCache(this.getCartKey(organizationId, guestCartId));
+
+    // Emit event
+    await this.eventService.emitCustom('cart.transferred', {
+      guestCartId,
+      customerCartId: customerCart.id,
+      organizationId,
+      customerId,
+      itemCount: customerCart.items.length,
+      timestamp: now,
+    });
+
+    return customerCart;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Helper Methods
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Gets the Redis key for a cart.
+   */
+  private getCartKey(organizationId: string, cartId: string): string {
+    return `${CART_KEY_PREFIX}${organizationId}:${cartId}`;
+  }
+
+  /**
+   * Creates an empty cart object.
+   */
+  private createEmptyCart(
+    organizationId: string,
+    cartId: string,
+    options?: {
+      customerId?: string;
+      tableId?: string;
+      orderType?: OrderType;
+    }
+  ): Cart {
+    const now = new Date().toISOString();
+
+    return {
+      id: cartId,
+      organizationId,
+      customerId: options?.customerId || null,
+      tableId: options?.tableId || null,
+      orderType: options?.orderType || 'DINE_IN',
+      items: [],
+      subtotal: 0,
+      taxAmount: 0,
+      discountAmount: 0,
+      totalAmount: 0,
+      currency: DEFAULT_CURRENCY,
+      notes: null,
+      createdAt: now,
+      updatedAt: now,
+    };
+  }
+
+  /**
+   * Saves cart to Redis.
+   */
+  private async saveCart(cart: Cart): Promise<void> {
+    const key = this.getCartKey(cart.organizationId, cart.id);
+    await setCache(key, cart, { ttl: CART_TTL_SECONDS });
+  }
+
+  /**
+   * Generates a unique cart item ID.
+   */
+  private generateItemId(): string {
+    return `ci_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
+  }
+
+  /**
+   * Calculates total price for an item.
+   */
+  private calculateItemTotal(
+    unitPrice: number,
+    quantity: number,
+    modifiers: OrderItemModifier[]
+  ): number {
+    const baseTotal = unitPrice * quantity;
+    const modifiersTotal = modifiers.reduce(
+      (sum, mod) => sum + mod.price * mod.quantity * quantity,
+      0
+    );
+    return Math.round((baseTotal + modifiersTotal) * 100) / 100;
+  }
+
+  /**
+   * Recalculates cart totals.
+   */
+  private recalculateCartTotals(cart: Cart): void {
+    // Calculate subtotal from items
+    cart.subtotal = cart.items.reduce((sum, item) => sum + item.totalPrice, 0);
+    cart.subtotal = Math.round(cart.subtotal * 100) / 100;
+
+    // Use calculateOrderTotals for consistent calculation
+    const itemsForCalc = cart.items.map((item) => ({
+      quantity: item.quantity,
+      unitPrice: item.unitPrice,
+      modifiers: item.modifiers,
+    }));
+
+    const totals = calculateOrderTotals(itemsForCalc, DEFAULT_TAX_RATE, cart.discountAmount);
+
+    cart.subtotal = totals.subtotal;
+    cart.taxAmount = totals.taxAmount;
+    cart.totalAmount = totals.totalAmount;
+  }
+
+  /**
+   * Checks if two modifier arrays match.
+   */
+  private modifiersMatch(
+    modifiers1: OrderItemModifier[],
+    modifiers2: OrderItemModifier[]
+  ): boolean {
+    if (modifiers1.length !== modifiers2.length) return false;
+
+    const sorted1 = [...modifiers1].sort((a, b) => a.id.localeCompare(b.id));
+    const sorted2 = [...modifiers2].sort((a, b) => a.id.localeCompare(b.id));
+
+    return sorted1.every(
+      (mod, index) =>
+        mod.id === sorted2[index].id && mod.quantity === sorted2[index].quantity
+    );
+  }
+
+  /**
+   * Validates input data against a Zod schema.
+   */
+  private validateInput<T>(data: unknown, schema: { parse: (data: unknown) => T }): T {
+    try {
+      return schema.parse(data);
+    } catch (error) {
+      if (error && typeof error === 'object' && 'errors' in error) {
+        const zodError = error as { errors: Array<{ path: string[]; message: string; code: string }> };
+        const validationErrors = zodError.errors.map((err) => ({
+          field: err.path.join('.'),
+          message: err.message,
+          rule: err.code,
+        }));
+        throw AppException.validation(validationErrors);
+      }
+      throw error;
+    }
+  }
+}

