+
+// -----------------------------------------------------------------------------
+// Types
+// -----------------------------------------------------------------------------
+
+/**
+ * Paginated result type
+ */
+export interface PaginatedResult<T> {
+  /** Array of entities */
+  data: T[];
+  /** Pagination metadata */
+  meta: {
+    page: number;
+    perPage: number;
+    total: number;
+    totalPages: number;
+  };
+}
+
+/**
+ * Order summary for list displays
+ */
+export interface OrderSummary {
+  /** Order ID */
+  id: string;
+  /** Order number */
+  orderNumber: string;
+  /** Order status */
+  status: OrderStatus;
+  /** Order type */
+  type: OrderType;
+  /** Table number */
+  tableNumber: string | null;
+  /** Item count */
