+}
+
+/**
+ * Create order data (input for repository)
+ */
+export interface CreateOrderData {
+  orderNumber: string;
+  branchId?: string | null;
+  tableId?: string | null;
+  customerId?: string | null;
+  staffId?: string | null;
+  status?: OrderStatus;
+  type?: OrderType;
+  subtotal: number;
+  taxAmount: number;
+  discountAmount?: number;
+  totalAmount: number;
+  currency?: string;
