+  totalPrice?: number;
+  notes?: string | null;
+  status?: OrderItemStatus;
+}
+
+// -----------------------------------------------------------------------------
+// Constants
+// -----------------------------------------------------------------------------
+
+const DEFAULT_PER_PAGE = 20;
+const MAX_PER_PAGE = 100;
+
+// -----------------------------------------------------------------------------
+// Order Repository
+// -----------------------------------------------------------------------------
+
+/**
+ * Repository for Order entity operations.
+ *
+ * Handles all database operations for orders including:
+ * - CRUD operations with tenant isolation
+ * - Order number lookups within organizations
+ * - Status management
+ * - Order items management
+ *
+ * @remarks
+ * All operations require organizationId for tenant isolation.
+ *
+ * @example
+ * ```typescript
+ * @injectable()
+ * class OrderService {
+ *   constructor(
+ *     @inject('OrderRepository') private repo: OrderRepository
+ *   ) {}
+ *
+ *   async getByOrderNumber(orgId: string, orderNumber: string) {
+ *     return this.repo.findByOrderNumber(orgId, orderNumber);
+ *   }
+ * }
+ * ```
+ */
+@injectable()
+export class OrderRepository {
+  constructor(
+    @inject(TOKENS.PrismaClient) private readonly prisma: PrismaClient
+  ) {}
+
+  // ---------------------------------------------------------------------------
+  // Read Operations
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Finds all orders for an organization with pagination and filtering
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param params - Query parameters (pagination, sorting, filtering)
+   * @returns Paginated list of orders
+   *
+   * @example
+   * ```typescript
+   * const result = await repo.findAll('org_123', {
+   *   status: 'PENDING',
+   *   page: 1,
+   *   perPage: 20,
+   * });
+   * ```
+   */
+  async findAll(
+    organizationId: string,
+    params: ListOrdersQuery = {}
+  ): Promise<PaginatedResult<Order>> {
+    const {
+      status,
+      type,
+      branchId,
+      tableId,
+      customerId,
+      dateFrom,
+      dateTo,
+      search,
+      page = 1,
+      perPage = DEFAULT_PER_PAGE,
+      sortBy = 'createdAt',
+      sortOrder = 'desc',
+    } = params;
+
+    // Normalize pagination
+    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
+    const normalizedPage = Math.max(1, page);
+    const skip = (normalizedPage - 1) * normalizedPerPage;
+
+    // Build where clause
+    const where: Prisma.OrderWhereInput = {
+      organizationId,
+      ...(status !== undefined && { status }),
+      ...(type !== undefined && { type }),
+      ...(branchId !== undefined && { branchId }),
+      ...(tableId !== undefined && { tableId }),
+      ...(customerId !== undefined && { customerId }),
+      ...(dateFrom && { createdAt: { gte: new Date(dateFrom) } }),
+      ...(dateTo && { createdAt: { lte: new Date(dateTo) } }),
+      ...(search && {
+        orderNumber: { contains: search, mode: 'insensitive' },
+      }),
+    };
+
+    // Build orderBy clause
+    const orderBy: Prisma.OrderOrderByWithRelationInput = { [sortBy]: sortOrder };
+
+    // Execute count and find in parallel
+    const [total, data] = await Promise.all([
+      this.prisma.order.count({ where }),
+      this.prisma.order.findMany({
+        where,
+        orderBy,
+        skip,
+        take: normalizedPerPage,
+      }),
+    ]);
+
+    return {
+      data: data as Order[],
+      meta: {
+        page: normalizedPage,
+        perPage: normalizedPerPage,
+        total,
+        totalPages: Math.ceil(total / normalizedPerPage),
+      },
+    };
+  }
+
+  /**
+   * Finds all orders as summaries (for quick displays)
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param params - Optional filtering params
+   * @returns Array of order summaries
+   */
+  async findAllSummaries(
+    organizationId: string,
+    params: Partial<ListOrdersQuery> = {}
+  ): Promise<OrderSummary[]> {
+    const { status, type, tableId } = params;
+
+    const where: Prisma.OrderWhereInput = {
+      organizationId,
+      ...(status !== undefined && { status }),
+      ...(type !== undefined && { type }),
+      ...(tableId !== undefined && { tableId }),
+    };
+
+    const orders = await this.prisma.order.findMany({
+      where,
+      select: {
+        id: true,
+        orderNumber: true,
+        status: true,
+        type: true,
+        totalAmount: true,
+        createdAt: true,
+        table: {
+          select: {
+            number: true,
+          },
+        },
+        _count: {
+          select: {
+            items: true,
+          },
+        },
+      },
+      orderBy: { createdAt: 'desc' },
+    });
+
+    return orders.map((order) => ({
+      id: order.id,
+      orderNumber: order.orderNumber,
+      status: order.status as OrderStatus,
+      type: order.type as OrderType,
+      tableNumber: order.table?.number || null,
+      itemCount: order._count.items,
+      totalAmount: Number(order.totalAmount),
+      createdAt: order.createdAt,
+    }));
+  }
+
+  /**
+   * Finds active orders (not completed or cancelled)
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param tableId - Optional table ID filter
+   * @returns Array of active orders
+   */
+  async findActiveOrders(
+    organizationId: string,
+    tableId?: string
+  ): Promise<Order[]> {
+    const result = await this.prisma.order.findMany({
+      where: {
+        organizationId,
+        status: {
+          notIn: ['COMPLETED', 'CANCELLED'],
+        },
+        ...(tableId && { tableId }),
+      },
+      orderBy: { createdAt: 'desc' },
+    });
+
+    return result as Order[];
+  }
+
+  /**
+   * Finds orders by status
+   *
+   * @param organizationId - Organization ID for tenant isolation
+   * @param status - Order status
+   * @returns Array of orders
+   */
+  async findByStatus(organizationId: string, status: OrderStatus): Promise<Order[]> {
+    const result = await this.prisma.order.findMany({
+      where: {
+        organizationId,
+        status,
+      },
+      orderBy: { createdAt: 'asc' },
+    });
+
+    return result as Order[];
+  }
+
+  /**
+   * Finds a order by ID with tenant isolation
+   *
+   * @param id - Order ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Order or null
+   */
+  async findById(id: string, organizationId: string): Promise<Order | null> {
+    const result = await this.prisma.order.findFirst({
+      where: { id, organizationId },
+    });
+
+    return result as Order | null;
+  }
+
+  /**
+   * Finds a order by ID with relations
+   *
+   * @param id - Order ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @param include - Relations to include
+   * @returns Order with relations or null
