+    return result as OrderWithRelations | null;
+  }
+
+  /**
+   * Finds a order by ID or throws
+   *
+   * @param id - Order ID
+   * @param organizationId - Organization ID for tenant isolation
+   * @returns Order
+   * @throws {AppException} If not found
