+++ b/src/shared/decorators/authorized.decorator.ts
@@ -0,0 +1,431 @@
+/**
+ * Authorized Decorator
+ *
+ * Method decorator for permission-based authorization using CASL.
+ * Works with routing-controllers and the permission middleware.
+ *
+ * @module shared/decorators/authorized
+ */
+
+import { UseMiddleware, Action } from 'routing-controllers';
+import { Request, Response, NextFunction, RequestHandler } from 'express';
+import {
+  PermissionAction,
+  PermissionSubject,
+  PermissionRequest,
+  PlanTier,
+  defineAbilitiesFor,
+} from '@/core/middleware/permission.middleware';
+import { AppException } from '@/core/exceptions/app.exception';
+import { AuthenticatedRequest, AuthUser } from '@/core/middleware/auth.middleware';
+import { TenantOrganization, OptionalTenantRequest } from '@/core/middleware/tenant.middleware';
+
+// -----------------------------------------------------------------------------
+// Type Definitions
+// -----------------------------------------------------------------------------
+
+/**
+ * Permission string format: 'resource.action'
+ * @example 'menu.view', 'menu.create', 'order.manage'
+ */
+export type PermissionString = `${Lowercase<PermissionSubject>}.${PermissionAction}`;
+
+/**
+ * Permission specification - can be a string or [action, subject] tuple
+ */
+export type PermissionSpec = PermissionString | [PermissionAction, PermissionSubject];
+
+/**
+ * Options for the Authorized decorator
+ */
+export interface AuthorizedOptions {
+  /**
+   * Array of required permissions. User must have ALL of these.
+   */
+  permissions?: PermissionSpec[];
+
+  /**
+   * Minimum plan tier required for this endpoint.
+   */
+  minPlan?: PlanTier;
+
+  /**
+   * Required roles (any of these). User must have at least one of these roles.
+   */
+  roles?: string[];
+
+  /**
+   * Allow any of the permissions instead of requiring all.
+   * @default false (require all)
+   */
+  anyPermission?: boolean;
+}
+
+// -----------------------------------------------------------------------------
+// Helper Functions
+// -----------------------------------------------------------------------------
+
+/**
+ * Parses a permission string into action and subject tuple
+ *
+ * @param permission - Permission string (e.g., 'menu.create')
+ * @returns Tuple of [action, subject]
+ */
+function parsePermissionString(
+  permission: PermissionString
+): [PermissionAction, PermissionSubject] {
+  const [subject, action] = permission.split('.') as [string, PermissionAction];
+
+  // Convert subject to PascalCase for CASL
+  const subjectPascal = subject.charAt(0).toUpperCase() + subject.slice(1);
+
+  return [action, subjectPascal as PermissionSubject];
+}
+
+/**
+ * Normalizes permission spec to [action, subject] tuple
+ */
+function normalizePermission(
+  spec: PermissionSpec
+): [PermissionAction, PermissionSubject] {
+  if (Array.isArray(spec)) {
+    return spec;
+  }
+  return parsePermissionString(spec);
+}
+
+/**
+ * Plan tier hierarchy for comparison
+ */
+const PLAN_HIERARCHY: PlanTier[] = ['free', 'starter', 'professional', 'business', 'enterprise'];
+
+/**
+ * Gets the numeric level of a plan tier
+ */
+function getPlanLevel(tier: PlanTier | string | null | undefined): number {
+  if (!tier) return 0;
+  const index = PLAN_HIERARCHY.indexOf(tier as PlanTier);
+  return index >= 0 ? index : 0;
+}
+
+// -----------------------------------------------------------------------------
+// Middleware Factory
+// -----------------------------------------------------------------------------
+
+/**
+ * Creates an authorization middleware with the specified options
+ *
+ * @param options - Authorization options
+ * @returns Express middleware function
+ */
+function createAuthorizationMiddleware(options: AuthorizedOptions): RequestHandler {
+  return (req: Request, _res: Response, next: NextFunction): void => {
+    try {
+      const authReq = req as AuthenticatedRequest & OptionalTenantRequest & PermissionRequest;
+
+      // Check if user is authenticated
+      if (!authReq.user) {
+        throw AppException.unauthorized('Authentication required');
+      }
+
+      const user = authReq.user;
+      const organization = authReq.organization;
+
+      // Check role requirements
+      if (options.roles && options.roles.length > 0) {
+        if (!options.roles.includes(user.role)) {
+          throw AppException.forbidden(
+            `Role '${user.role}' is not authorized. Required: ${options.roles.join(', ')}`
+          );
+        }
+      }
+
+      // Build CASL ability if not already set
+      let ability = authReq.ability;
+      if (!ability) {
+        // Determine plan tier
+        let planTier: PlanTier = 'free';
+        if (organization?.settings) {
+          const settings = organization.settings as Record<string, unknown>;
+          planTier = (settings.planTier as PlanTier) || 'free';
+        }
+
+        // Build ability
+        ability = defineAbilitiesFor(user, organization, planTier);
+        authReq.ability = ability;
+      }
+
+      // Check plan tier requirement
+      if (options.minPlan) {
+        let currentTier: PlanTier = 'free';
+        if (organization?.settings) {
+          const settings = organization.settings as Record<string, unknown>;
+          currentTier = (settings.planTier as PlanTier) || 'free';
+        }
+
+        const currentLevel = getPlanLevel(currentTier);
+        const requiredLevel = getPlanLevel(options.minPlan);
+
+        if (currentLevel < requiredLevel) {
+          throw AppException.insufficientPlan('this feature', options.minPlan);
+        }
+      }
+
+      // Check permission requirements
+      if (options.permissions && options.permissions.length > 0) {
+        const permissions = options.permissions.map(normalizePermission);
+
+        if (options.anyPermission) {
+          // ANY permission mode - user needs at least one permission
+          const hasAny = permissions.some(([action, subject]) =>
+            ability.can(action, subject)
+          );
+
+          if (!hasAny) {
+            const permList = options.permissions.join(' or ');
+            throw AppException.forbidden(`Missing permission: ${permList}`);
+          }
+        } else {
+          // ALL permissions mode (default) - user needs all permissions
+          const missingPermissions = permissions.filter(
+            ([action, subject]) => !ability.can(action, subject)
+          );
+
+          if (missingPermissions.length > 0) {
+            const missing = missingPermissions
+              .map(([a, s]) => `${s.toLowerCase()}.${a}`)
+              .join(', ');
+            throw AppException.forbidden(`Missing permissions: ${missing}`);
+          }
+        }
+      }
+
+      next();
+    } catch (error) {
+      next(error);
+    }
+  };
+}
+
+// -----------------------------------------------------------------------------
+// Main Decorator
+// -----------------------------------------------------------------------------
+
+/**
+ * Method decorator for authorization with CASL permission checking.
+ *
+ * This decorator enforces authentication and optionally checks:
+ * - Required permissions (RBAC/ABAC via CASL)
+ * - Minimum plan tier
+ * - Allowed roles
+ *
+ * The decorator works with the routing-controllers library and integrates
+ * with the auth, tenant, and permission middleware.
+ *
+ * @param options - Authorization options or array of permission strings
+ * @returns Method decorator
+ *
+ * @example Basic usage with permission strings
+ * ```typescript
+ * import { Authorized } from '@/shared/decorators';
+ *
+ * @JsonController('/api/v1/menus')
+ * export class MenuController extends BaseController {
+ *
+ *   @Get('/')
+ *   @Authorized(['menu.view'])
+ *   async list(@CurrentOrg() org: TenantOrganization) {
+ *     // Only users with menu.view permission can access
+ *   }
+ *
+ *   @Post('/')
+ *   @Authorized(['menu.create'])
+ *   async create(@CurrentOrg() org: TenantOrganization, @Body() data: CreateMenuDto) {
+ *     // Only users with menu.create permission can access
+ *   }
+ *
+ *   @Delete('/:id')
+ *   @Authorized(['menu.delete'])
+ *   async delete(@Param('id') id: string, @CurrentOrg() org: TenantOrganization) {
+ *     // Only users with menu.delete permission can access
+ *   }
+ * }
+ * ```
+ *
+ * @example With multiple permissions (all required)
+ * ```typescript
+ * @Post('/:menuId/categories/:categoryId/products')
+ * @Authorized(['menu.update', 'product.create'])
+ * async addProduct(
+ *   @Param('menuId') menuId: string,
+ *   @Param('categoryId') categoryId: string,
+ *   @Body() data: CreateProductDto,
+ * ) {
+ *   // User must have both menu.update AND product.create permissions
+ * }
+ * ```
+ *
+ * @example With any permission mode
+ * ```typescript
+ * @Put('/:id')
+ * @Authorized({
+ *   permissions: ['menu.update', 'menu.manage'],
+ *   anyPermission: true,
+ * })
+ * async update(@Param('id') id: string, @Body() data: UpdateMenuDto) {
+ *   // User needs either menu.update OR menu.manage permission
+ * }
+ * ```
+ *
+ * @example With plan tier requirement
+ * ```typescript
+ * @Post('/ai/generate')
+ * @Authorized({
+ *   permissions: ['ai.use'],
+ *   minPlan: 'professional',
+ * })
+ * async generateWithAI(@Body() data: AIGenerateDto) {
+ *   // Only professional plan or higher can access AI features
+ * }
+ * ```
+ *
+ * @example With role requirement
+ * ```typescript
+ * @Delete('/organization')
+ * @Authorized({
+ *   roles: ['owner'],
+ * })
+ * async deleteOrganization(@CurrentOrg() org: TenantOrganization) {
+ *   // Only owners can delete the organization
+ * }
+ * ```
+ *
+ * @example Combined requirements
+ * ```typescript
+ * @Post('/subscription/upgrade')
+ * @Authorized({
+ *   permissions: ['subscription.manage'],
+ *   roles: ['owner', 'manager'],
+ *   minPlan: 'starter',
+ * })
+ * async upgradeSubscription(@Body() data: UpgradeDto) {
+ *   // Owner or manager with subscription.manage permission on starter+ plan
+ * }
+ * ```
+ *
+ * @example Authentication only (no specific permissions)
+ * ```typescript
+ * @Get('/profile')
+ * @Authorized() // Just requires authentication
+ * async getProfile(@CurrentUser() user: AuthUser) {
+ *   // Any authenticated user can access
+ * }
+ * ```
+ */
+export function Authorized(
+  options?: PermissionSpec[] | AuthorizedOptions
+): MethodDecorator {
+  // Normalize options
+  let normalizedOptions: AuthorizedOptions;
+
+  if (!options) {
+    // No options - just require authentication
+    normalizedOptions = {};
+  } else if (Array.isArray(options)) {
+    // Array of permission strings
+    normalizedOptions = { permissions: options };
+  } else {
+    // Full options object
+    normalizedOptions = options;
+  }
+
+  // Create the authorization middleware
+  const authMiddleware = createAuthorizationMiddleware(normalizedOptions);
+
+  // Return the decorator that applies the middleware
+  return UseMiddleware(authMiddleware);
+}
+
+// -----------------------------------------------------------------------------
+// Utility Decorators
+// -----------------------------------------------------------------------------
+
+/**
+ * Decorator that requires specific roles.
+ * Shorthand for @Authorized({ roles: [...] })
+ *
+ * @param roles - Array of allowed roles
+ * @returns Method decorator
+ *
+ * @example
+ * ```typescript
+ * @Delete('/admin/users/:id')
+ * @RequireRoles(['owner', 'manager'])
+ * async deleteUser(@Param('id') id: string) {
+ *   // Only owners and managers can access
+ * }
+ * ```
+ */
+export function RequireRoles(roles: string[]): MethodDecorator {
+  return Authorized({ roles });
+}
+
+/**
+ * Decorator that requires a minimum plan tier.
+ * Shorthand for @Authorized({ minPlan: tier })
+ *
+ * @param tier - Minimum plan tier required
+ * @returns Method decorator
+ *
+ * @example
+ * ```typescript
+ * @Post('/analytics/export')
+ * @RequirePlan('professional')
+ * async exportAnalytics() {
+ *   // Only professional plan or higher can export
+ * }
+ * ```
+ */
+export function RequirePlan(tier: PlanTier): MethodDecorator {
+  return Authorized({ minPlan: tier });
+}
+
+/**
+ * Decorator that requires any of the specified permissions.
+ * Shorthand for @Authorized({ permissions, anyPermission: true })
+ *
+ * @param permissions - Array of permissions (any one is sufficient)
+ * @returns Method decorator
+ *
+ * @example
+ * ```typescript
+ * @Put('/menus/:id')
+ * @RequireAnyPermission(['menu.update', 'menu.manage'])
+ * async updateMenu(@Param('id') id: string, @Body() data: UpdateMenuDto) {
+ *   // User needs either menu.update OR menu.manage
+ * }
+ * ```
+ */
+export function RequireAnyPermission(permissions: PermissionSpec[]): MethodDecorator {
+  return Authorized({ permissions, anyPermission: true });
+}
+
+/**
+ * Decorator that requires all of the specified permissions.
+ * Shorthand for @Authorized({ permissions, anyPermission: false })
+ *
+ * @param permissions - Array of permissions (all are required)
+ * @returns Method decorator
+ *
+ * @example
+ * ```typescript
+ * @Post('/menus/:id/publish')
+ * @RequireAllPermissions(['menu.update', 'menu.publish'])
+ * async publishMenu(@Param('id') id: string) {
+ *   // User needs both menu.update AND menu.publish
+ * }
+ * ```
+ */
+export function RequireAllPermissions(permissions: PermissionSpec[]): MethodDecorator {
+  return Authorized({ permissions, anyPermission: false });
+}

