@@ -0,0 +1,151 @@
+/**
+ * CurrentUser Decorator
+ *
+ * Parameter decorator for extracting the authenticated user from request.
+ * Works with routing-controllers and the auth middleware.
+ *
+ * @module shared/decorators/current-user
+ */
+
+import { createParamDecorator } from 'routing-controllers';
+import { Request } from 'express';
+import { AuthUser, AuthenticatedRequest } from '@/core/middleware/auth.middleware';
+import { AppException } from '@/core/exceptions/app.exception';
+
+/**
+ * Options for the CurrentUser decorator
+ */
+export interface CurrentUserOptions {
+  /**
+   * Whether the user is required. If true, throws unauthorized when no user.
+   * @default true
+   */
+  required?: boolean;
+}
+
+/**
+ * Parameter decorator that extracts the authenticated user from the request.
+ *
+ * The decorator retrieves the `user` object attached by the auth middleware
+ * and provides it as a parameter to the controller method.
+ *
+ * @param options - Decorator options
+ * @returns Parameter decorator
+ *
+ * @throws {AppException} UNAUTHORIZED - When user is not authenticated (if required: true)
+ *
+ * @example
+ * ```typescript
+ * import { CurrentUser } from '@/shared/decorators';
+ * import { AuthUser } from '@/core/middleware/auth.middleware';
+ *
+ * @JsonController('/api/v1/profile')
+ * @injectable()
+ * export class ProfileController extends BaseController {
+ *
+ *   @Get('/')
+ *   async getProfile(
+ *     @CurrentUser() user: AuthUser,
+ *   ): Promise<ApiResponse<UserProfile>> {
+ *     const profile = await this.userService.getProfile(user.id);
+ *     return this.success(profile);
+ *   }
+ *
+ *   // Optional user (for public endpoints with optional personalization)
+ *   @Get('/public')
+ *   async getPublicData(
+ *     @CurrentUser({ required: false }) user?: AuthUser,
+ *   ): Promise<ApiResponse<PublicData>> {
+ *     if (user) {
+ *       // Personalized response
+ *     }
+ *     return this.success(data);
+ *   }
+ * }
+ * ```
+ */
+export function CurrentUser(options: CurrentUserOptions = {}): ParameterDecorator {
+  const { required = true } = options;
+
+  return createParamDecorator({
+    required,
+    value: (action): AuthUser | undefined => {
+      const req = action.request as AuthenticatedRequest;
+
+      if (!req.user) {
+        if (required) {
+          throw AppException.unauthorized('Authentication required');
+        }
+        return undefined;
+      }
+
+      return req.user;
+    },
+  });
+}
+
+/**
+ * Gets the current user from request.
+ * Utility function for use in middleware or services.
+ *
+ * @param req - Express request object
+ * @returns Authenticated user
+ * @throws {AppException} UNAUTHORIZED - When user is not authenticated
+ *
+ * @example
+ * ```typescript
+ * import { getCurrentUser } from '@/shared/decorators';
+ *
+ * const user = getCurrentUser(req);
+ * const menus = await menuService.findAll(user.organizationId);
+ * ```
+ */
+export function getCurrentUser(req: Request): AuthUser {
+  const authReq = req as AuthenticatedRequest;
+
+  if (!authReq.user) {
+    throw AppException.unauthorized('Authentication required');
+  }
+
+  return authReq.user;
+}
+
+/**
+ * Gets the current user from request, or undefined if not authenticated.
+ * Utility function for use in middleware or services where auth is optional.
+ *
+ * @param req - Express request object
+ * @returns Authenticated user or undefined
+ *
+ * @example
+ * ```typescript
+ * import { getCurrentUserOptional } from '@/shared/decorators';
+ *
+ * const user = getCurrentUserOptional(req);
+ * if (user) {
+ *   // Show personalized content
+ * }
+ * ```
+ */
+export function getCurrentUserOptional(req: Request): AuthUser | undefined {
+  return (req as AuthenticatedRequest).user;
+}
+
+/**
+ * Checks if the request has an authenticated user.
+ *
+ * @param req - Express request object
+ * @returns True if user is authenticated
+ *
+ * @example
+ * ```typescript
+ * import { isAuthenticated } from '@/shared/decorators';
+ *
+ * if (isAuthenticated(req)) {
+ *   const user = getCurrentUser(req);
+ * }
+ * ```
+ */
+export function isAuthenticated(req: Request): boolean {
+  return (req as AuthenticatedRequest).user !== undefined;
+}

