+/**
+ * ============================================================================
+ * E-Menum Example Theme - Main Stylesheet
+ * ============================================================================
+ *
+ * This is a minimal, well-documented example stylesheet for theme developers.
+ *
+ * KEY PRINCIPLES:
+ * 1. Use CSS variables for ALL colors - no hardcoded colors
+ * 2. Support dark mode via [data-theme="dark"]
+ * 3. Support high contrast mode via prefers-contrast
+ * 4. Support reduced motion via prefers-reduced-motion
+ * 5. Minimum touch targets: 48x48px
+ * 6. WCAG 2.1 AA compliant
+ *
+ * FILE STRUCTURE:
+ * 1. CSS Custom Properties (Variables)
+ * 2. Base Styles
+ * 3. Accessibility
+ * 4. Layout Components
+ * 5. UI Components
+ * 6. Utilities
+ */
+
+
+/* ============================================================================
+   1. CSS CUSTOM PROPERTIES (Design Tokens)
+   ============================================================================
+
+   IMPORTANT: All colors MUST be defined as CSS variables.
+   This allows:
+   - Easy dark mode support
+   - Brand color customization per restaurant
+   - High contrast mode support
+*/
+
+:root {
+  /* === BRAND COLORS ===
+     These can be overridden per restaurant via inline styles
+  */
+  --brand-primary: #6366f1;       /* Main brand color */
+  --brand-primary-light: #818cf8; /* Hover state */
+  --brand-primary-dark: #4f46e5;  /* Active state */
+  --brand-on-primary: #ffffff;    /* Text on primary color */
+
+  /* === SURFACE COLORS (Light Mode) ===
+     Surface colors for backgrounds and cards
+  */
+  --surface: #f8fafc;             /* Page background */
+  --surface-card: #ffffff;        /* Card backgrounds */
+  --surface-elevated: #f1f5f9;    /* Elevated elements */
+
+  /* === TEXT COLORS (Light Mode) ===
+     Semantic text colors for consistent typography
+  */
+  --text-primary: #0f172a;        /* Main text */
+  --text-secondary: #475569;      /* Secondary text */
+  --text-muted: #94a3b8;          /* Muted/disabled text */
+
+  /* === BORDER COLORS === */
+  --border: #e2e8f0;              /* Default borders */
+  --border-strong: #cbd5e1;       /* Emphasized borders */
+
+  /* === SEMANTIC COLORS ===
+     Status colors for feedback
+  */
+  --color-success: #10b981;
+  --color-warning: #f59e0b;
+  --color-error: #ef4444;
+
+  /* === SPACING SCALE ===
+     Consistent spacing throughout the theme
+  */
+  --space-1: 0.25rem;  /* 4px */
+  --space-2: 0.5rem;   /* 8px */
+  --space-3: 0.75rem;  /* 12px */
+  --space-4: 1rem;     /* 16px */
+  --space-6: 1.5rem;   /* 24px */
+  --space-8: 2rem;     /* 32px */
+
+  /* === BORDER RADIUS === */
+  --radius-sm: 0.25rem;
+  --radius-md: 0.5rem;
+  --radius-lg: 0.75rem;
+  --radius-xl: 1rem;
+  --radius-full: 9999px;
+
+  /* === TYPOGRAPHY === */
+  --font-sans: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
+
+  /* === TRANSITIONS === */
+  --transition: 200ms ease-out;
+
+  /* === Z-INDEX SCALE === */
+  --z-sticky: 20;
+  --z-fixed: 30;
+  --z-modal: 50;
+
+  /* === TOUCH TARGETS ===
+     Minimum size for touch interactions (WCAG 2.5.5)
+  */
+  --touch-target: 48px;
+}
+
+
+/* === DARK MODE ===
+   Override colors when data-theme="dark"
+*/
+[data-theme="dark"] {
+  --surface: #0f172a;
+  --surface-card: #1e293b;
+  --surface-elevated: #334155;
+
+  --text-primary: #f8fafc;
+  --text-secondary: #cbd5e1;
+  --text-muted: #64748b;
+
+  --border: #334155;
+  --border-strong: #475569;
+}
+
+
+/* === HIGH CONTRAST MODE ===
+   Override for users who need higher contrast
+*/
+@media (prefers-contrast: high) {
+  :root {
+    --text-primary: #000000;
+    --border: #000000;
+  }
+
+  [data-theme="dark"] {
+    --text-primary: #ffffff;
+    --border: #ffffff;
+  }
+}
+
+
+/* === REDUCED MOTION ===
+   Disable animations for users who prefer reduced motion
+*/
+@media (prefers-reduced-motion: reduce) {
+  *,
+  *::before,
+  *::after {
+    animation-duration: 0.01ms !important;
+    transition-duration: 0.01ms !important;
+  }
+}
+
+
+/* ============================================================================
+   2. BASE STYLES
+   ============================================================================ */
+
+*,
+*::before,
+*::after {
+  box-sizing: border-box;
+  margin: 0;
+  padding: 0;
+}
+
+html {
+  font-size: 16px;
+  -webkit-text-size-adjust: 100%;
+  scroll-behavior: smooth;
+}
+
+body {
+  font-family: var(--font-sans);
+  line-height: 1.6;
+  color: var(--text-primary);
+  background-color: var(--surface);
+  min-height: 100vh;
+}
+
+h1, h2, h3, h4, h5, h6 {
+  font-weight: 600;
+  line-height: 1.3;
+}
+
+a {
+  color: var(--brand-primary);
+  text-decoration: none;
+}
+
+img {
+  max-width: 100%;
+  height: auto;
+  display: block;
+}
+
+
+/* ============================================================================
+   3. ACCESSIBILITY
+   ============================================================================ */
+
+/* Skip Link - allows keyboard users to skip navigation */
+.skip-link {
+  position: absolute;
+  top: -100%;
+  left: 0;
+  z-index: 9999;
+  padding: 1rem;
+  background-color: var(--brand-primary);
+  color: var(--brand-on-primary);
+  font-weight: 500;
+}
+
+.skip-link:focus {
+  top: 0;
+  outline: 2px solid var(--brand-on-primary);
+  outline-offset: 2px;
+}
+
+/* Screen Reader Only - visually hidden but accessible */
+.sr-only {
+  position: absolute;
+  width: 1px;
+  height: 1px;
+  padding: 0;
+  margin: -1px;
+  overflow: hidden;
+  clip: rect(0, 0, 0, 0);
+  white-space: nowrap;
+  border: 0;
+}
+
+/* Focus visible - clear focus indicators */
+:focus-visible {
+  outline: 2px solid var(--brand-primary);
+  outline-offset: 2px;
+}
+
+
+/* ============================================================================
+   4. LAYOUT COMPONENTS
+   ============================================================================ */
+
+/* === HEADER === */
+.header {
+  position: sticky;
+  top: 0;
+  z-index: var(--z-sticky);
+  background-color: var(--surface-card);
+  border-bottom: 1px solid var(--border);
+}
+
+.header-inner {
+  display: flex;
+  align-items: center;
+  gap: var(--space-3);
+  height: 64px;
+  padding: 0 var(--space-4);
+}
+
+.header-brand {
+  display: flex;
+  align-items: center;
+  gap: var(--space-2);
+  color: inherit;
+}
+
+.header-logo {
+  width: 40px;
+  height: 40px;
+  border-radius: var(--radius-lg);
+  object-fit: contain;
+}
+
+.header-logo-fallback {
+  width: 40px;
+  height: 40px;
+  border-radius: var(--radius-lg);
+  background-color: var(--brand-primary);
+  color: var(--brand-on-primary);
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  font-weight: 700;
+  font-size: 1.25rem;
+}
+
+.header-title {
+  font-weight: 600;
+  font-size: 1rem;
+}
+
+/* Hide title on mobile */
+@media (max-width: 639px) {
+  .header-title {
+    display: none;
+  }
+}
+
+
+/* === FOOTER === */
+.footer {
+  background-color: var(--surface-card);
+  border-top: 1px solid var(--border);
+  margin-top: auto;
+}
+
+.footer-inner {
+  padding: var(--space-6) var(--space-4);
+  text-align: center;
+}
+
+.footer-restaurant {
+  margin-bottom: var(--space-4);
+}
+
+.footer-title {
+  font-size: 1.25rem;
+  margin-bottom: var(--space-2);
+}
+
+.footer-address {
+  color: var(--text-muted);
+  font-size: 0.875rem;
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  gap: var(--space-1);
+}
+
+.footer-actions {
+  display: flex;
+  justify-content: center;
+  gap: var(--space-2);
+  margin-top: var(--space-3);
+}
+
+.footer-allergen-notice {
+  background-color: var(--surface-elevated);
+  border-radius: var(--radius-lg);
+  padding: var(--space-3);
+  margin-bottom: var(--space-4);
+  color: var(--color-warning);
+  font-size: 0.75rem;
+  display: flex;
+  align-items: flex-start;
+  gap: var(--space-2);
+  text-align: left;
+}
+
+.footer-divider {
+  border: none;
+  border-top: 1px solid var(--border);
+  margin: var(--space-4) 0;
+}
+
+.footer-branding {
+  margin-bottom: var(--space-2);
+}
+
+.footer-brand-link {
+  color: var(--text-muted);
+  font-size: 0.875rem;
+  display: inline-flex;
+  align-items: center;
+  gap: var(--space-1);
+}
+
+.footer-brand-link strong {
+  color: var(--brand-primary);
+}
+
+.footer-copyright {
+  color: var(--text-muted);
+  font-size: 0.75rem;
+  margin-bottom: var(--space-2);
+}
+
+.footer-legal {
+  display: flex;
+  justify-content: center;
+  gap: var(--space-2);
+  font-size: 0.75rem;
+}
+
+.footer-legal a {
+  color: var(--text-muted);
+}
+
+.footer-legal a:hover {
+  color: var(--text-primary);
+}
+
+
+/* ============================================================================
+   5. UI COMPONENTS
+   ============================================================================ */
+
+/* === BUTTONS === */
+.btn {
+  display: inline-flex;
+  align-items: center;
+  justify-content: center;
+  gap: var(--space-2);
+  padding: var(--space-3) var(--space-4);
+  font-size: 0.9375rem;
+  font-weight: 500;
+  font-family: inherit;
+  line-height: 1.4;
+  cursor: pointer;
+  border: 1px solid transparent;
+  border-radius: var(--radius-lg);
+  transition: all var(--transition);
+  min-height: var(--touch-target);
+  -webkit-tap-highlight-color: transparent;
+}
+
+.btn:disabled {
+  opacity: 0.5;
+  cursor: not-allowed;
+}
+
+.btn-primary {
+  background-color: var(--brand-primary);
+  color: var(--brand-on-primary);
+}
+
+.btn-primary:hover:not(:disabled) {
+  background-color: var(--brand-primary-dark);
+}
+
+.btn-outline {
+  background-color: transparent;
+  border-color: var(--border-strong);
+  color: var(--text-primary);
+}
+
+.btn-outline:hover:not(:disabled) {
+  background-color: var(--surface-elevated);
+}
+
+.btn-icon {
+  padding: var(--space-3);
+  min-width: var(--touch-target);
+  background: none;
+  border: none;
+  color: var(--text-secondary);
+}
+
+.btn-icon:hover {
+  background-color: var(--surface-elevated);
+  color: var(--text-primary);
+}
+
+.btn-sm {
+  padding: var(--space-2) var(--space-3);
+  font-size: 0.875rem;
+  min-height: 40px;
+}
+
+
+/* === BADGES === */
+.badge {
+  display: inline-flex;
+  align-items: center;
+  gap: var(--space-1);
+  padding: var(--space-1) var(--space-2);
+  font-size: 0.75rem;
+  font-weight: 500;
+  border-radius: var(--radius-full);
+  background-color: var(--surface-elevated);
+  color: var(--text-secondary);
+}
+
+.badge-primary {
+  background-color: color-mix(in srgb, var(--brand-primary) 15%, transparent);
+  color: var(--brand-primary);
+}
+
+.badge-success {
+  background-color: color-mix(in srgb, var(--color-success) 15%, transparent);
+  color: var(--color-success);
+}
+
+.badge-warning {
+  background-color: color-mix(in srgb, var(--color-warning) 15%, transparent);
+  color: var(--color-warning);
+}
+
+
+/* === ALERTS === */
+.alert {
+  display: flex;
+  align-items: center;
+  gap: var(--space-2);
+  padding: var(--space-3) var(--space-4);
